import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum PaymentStatus {
  SUCCESS = 'SUCCESS',
  PENDING = 'PENDING',
  FAILED = 'FAILED',
  REFUNDED = 'REFUNDED'
}

export enum PaymentMethod {
  CREDIT = 'Crédito',
  DEBIT = 'Débito',
  PIX = 'PIX',
  VOUCHER = 'Voucher'
}

export interface Transaction {
  id: string;
  timestamp: string;
  amount: number;
  method: PaymentMethod;
  status: PaymentStatus;
  terminalId: string;
  segment: string;
}

import { GoogleGenAI } from "@google/genai";
import { Transaction } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const getSmartInsights = async (transactions: Transaction[]) => {
  const prompt = `
    Analise estas transações de um sistema TEF (Transferência Eletrônica de Fundos):
    ${JSON.stringify(transactions)}

    Como um consultor financeiro de pagamentos, forneça 3 insights estratégicos curtos sobre:
    1. Desempenho dos métodos de pagamento (qual está rendendo mais).
    2. Alerta sobre falhas se houver.
    3. Sugestão para melhorar a conversão em PDV.

    Escreva de forma profissional e encorajadora em Português do Brasil.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Estamos processando seus dados para gerar novos insights.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Erro ao conectar com a IA para insights financeiros.";
  }
};

