import React from 'react';

interface StatCardProps {
  label: string;
  value: string | number;
  trend?: string;
  trendUp?: boolean;
  icon: string;
  color: string;
}

const StatCard: React.FC<StatCardProps> = ({ label, value, trend, trendUp, icon, color }) => {
  return (
