import React from 'react';
import { Transaction, PaymentStatus } from '../types';

interface TransactionTableProps {
  transactions: Transaction[];
}

const TransactionTable: React.FC<TransactionTableProps> = ({ transactions }) => {
  const getStatusStyle = (status: PaymentStatus) => {
    switch (status) {
      case PaymentStatus.SUCCESS: return 'bg-emerald-50 text-emerald-700 ring-1 ring-emerald-200';
      case PaymentStatus.FAILED: return 'bg-rose-50 text-rose-700 ring-1 ring-rose-200';
      case PaymentStatus.PENDING: return 'bg-amber-50 text-amber-700 ring-1 ring-amber-200';
      case PaymentStatus.REFUNDED: return 'bg-slate-100 text-slate-600 ring-1 ring-slate-300';
    }
  };

  const getStatusLabel = (status: PaymentStatus) => {
    switch (status) {
      case PaymentStatus.SUCCESS: return 'Aprovado';
      case PaymentStatus.FAILED: return 'Recusado';
      case PaymentStatus.PENDING: return 'Processando';
      case PaymentStatus.REFUNDED: return 'Estornado';
    }
  };

  return (
    <div className="bg-white rounded-3xl border border-slate-200 overflow-hidden shadow-sm">
      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50/80 border-b border-slate-100">
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Transação</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Data & Hora</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Valor</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Método</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Segmento</th>
              <th className="px-6 py-4 text-xs font-bold text-slate-500 uppercase tracking-widest">Status</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {transactions.map((tx) => (
              <tr key={tx.id} className="hover:bg-slate-50/40 transition-colors group">
                <td className="px-6 py-4 font-mono text-xs font-bold text-slate-400 group-hover:text-indigo-600">{tx.id}</td>
                <td className="px-6 py-4 text-sm text-slate-600">
                  {new Date(tx.timestamp).toLocaleString('pt-BR', { dateStyle: 'short', timeStyle: 'short' })}
                </td>
                <td className="px-6 py-4 text-sm font-black text-slate-900 whitespace-nowrap">
                  R$ {tx.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                </td>
                <td className="px-6 py-4">
                  <span className="inline-flex items-center px-2.5 py-0.5 text-[10px] font-black bg-indigo-50 text-indigo-700 rounded-md uppercase tracking-wider">
                    {tx.method}
                  </span>
                </td>
                <td className="px-6 py-4 text-sm font-medium text-slate-500">{tx.segment}</td>
                <td className="px-6 py-4">
                  <span className={`inline-flex items-center px-3 py-1 text-[11px] font-bold rounded-full ${getStatusStyle(tx.status)}`}>
                    {getStatusLabel(tx.status)}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default TransactionTable;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import { MOCK_TRANSACTIONS, CHART_DATA } from './constants';
import { PaymentMethod, PaymentStatus, Transaction } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>(MOCK_TRANSACTIONS);
  const [insights, setInsights] = useState<string>('Analisando seu fluxo de caixa...');
  const [isSimulating, setIsSimulating] = useState(false);

  // Computed Stats
  const stats = useMemo(() => {
    const successful = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const totalVolume = successful.reduce((acc, curr) => acc + curr.amount, 0);
    const successRate = ((successful.length / transactions.length) * 100).toFixed(1);
    const avgTicket = successful.length > 0 ? (totalVolume / successful.length).toFixed(2) : '0.00';

    return { totalVolume, successRate, avgTicket, count: transactions.length };
  }, [transactions]);

  useEffect(() => {
    const fetchAI = async () => {
      const result = await getSmartInsights(transactions);
      setInsights(result);
    };
    fetchAI();
  }, [transactions]);

  const simulateTransaction = () => {
    setIsSimulating(true);
    setTimeout(() => {
      const methods = [PaymentMethod.CREDIT, PaymentMethod.DEBIT, PaymentMethod.PIX];
      const segments = ['Restaurante', 'Farmácia', 'Supermercado', 'Loja de Conveniência'];
      const statuses = [PaymentStatus.SUCCESS, PaymentStatus.SUCCESS, PaymentStatus.FAILED, PaymentStatus.SUCCESS];

      const newTx: Transaction = {
        id: `TX-${Math.floor(1000 + Math.random() * 9000)}`,
        timestamp: new Date().toISOString(),
        amount: parseFloat((Math.random() * 450 + 5).toFixed(2)),
        method: methods[Math.floor(Math.random() * methods.length)],
        segment: segments[Math.floor(Math.random() * segments.length)],
        status: statuses[Math.floor(Math.random() * statuses.length)],
        terminalId: `TERM-0${Math.floor(Math.random() * 5 + 1)}`
      };

      setTransactions(prev => [newTx, ...prev]);
      setIsSimulating(false);
    }, 1500);
  };

  const renderDashboard = () => (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard label="Volume Bruto" value={`R$ ${stats.totalVolume.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} trend="14.2%" trendUp={true} icon="💵" color="bg-indigo-50 text-indigo-600" />
        <StatCard label="Transações" value={stats.count} trend="5.1%" trendUp={true} icon="💳" color="bg-blue-50 text-blue-600" />
        <StatCard label="Taxa de Sucesso" value={`${stats.successRate}%`} trend="0.4%" trendUp={false} icon="📈" color="bg-emerald-50 text-emerald-600" />
        <StatCard label="Ticket Médio" value={`R$ ${parseFloat(stats.avgTicket).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} icon="🏷️" color="bg-amber-50 text-amber-600" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
          <div className="flex items-center justify-between mb-8">
            <h3 className="text-xl font-black text-slate-800 tracking-tight">Fluxo de Transações (Tempo Real)</h3>
            <div className="flex gap-2">
              <span className="flex items-center gap-1.5 px-3 py-1 bg-slate-50 rounded-full text-[10px] font-bold text-slate-500 uppercase">Hoje</span>
            </div>
          </div>
          <div className="h-[320px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={CHART_DATA}>
                <defs>
                  <linearGradient id="colorVal" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#6366f1" stopOpacity={0.15}/>
                    <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="4 4" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11, fontWeight: 600}} dy={10} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11, fontWeight: 600}} dx={-10} />
                <Tooltip 
                  contentStyle={{borderRadius: '20px', border: 'none', boxShadow: '0 10px 30px rgba(0,0,0,0.08)', padding: '15px'}}
                  itemStyle={{fontWeight: '900', color: '#4f46e5'}}
                  labelStyle={{color: '#64748b', marginBottom: '5px', fontWeight: 'bold'}}
                />
                <Area type="monotone" dataKey="valor" stroke="#6366f1" strokeWidth={4} fillOpacity={1} fill="url(#colorVal)" animationDuration={2000} />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="flex flex-col gap-6">
          <div className="bg-gradient-to-br from-indigo-600 via-indigo-700 to-slate-900 p-8 rounded-[2.5rem] text-white shadow-2xl shadow-indigo-200 flex-1 relative overflow-hidden group">
            <div className="absolute -right-4 -top-4 w-32 h-32 bg-white/5 rounded-full blur-3xl group-hover:bg-white/10 transition-colors"></div>
            <div className="relative z-10 flex flex-col h-full">
              <div className="flex items-center gap-3 mb-6">
                <span className="text-3xl filter drop-shadow-md">✨</span>
                <h3 className="text-xl font-bold tracking-tight">Nexus Intelligence</h3>
              </div>
              <div className="flex-1 bg-white/10 backdrop-blur-xl rounded-3xl p-6 border border-white/10 shadow-inner text-sm leading-relaxed font-medium">
                {insights.split('\n').map((line, i) => (
                  <p key={i} className="mb-3 last:mb-0 opacity-90">{line}</p>
                ))}
              </div>
              <button className="mt-8 w-full py-4 bg-white text-indigo-700 rounded-2xl font-black text-sm uppercase tracking-widest hover:bg-slate-50 transition-all shadow-xl hover:-translate-y-1 active:translate-y-0">
                Relatório Full AI
              </button>
            </div>
          </div>
        </div>
      </div>

      <div className="space-y-6">
        <div className="flex items-center justify-between px-2">
          <h3 className="text-xl font-black text-slate-800 tracking-tight">Últimos Processamentos</h3>
          <button 
            onClick={() => setActiveTab('transactions')}
            className="text-xs font-black text-indigo-600 hover:text-indigo-800 uppercase tracking-widest flex items-center gap-2"
          >
            Ver Histórico Completo <span>→</span>
          </button>
        </div>
        <TransactionTable transactions={transactions.slice(0, 6)} />
      </div>
    </div>
  );

  const renderSimulator = () => (
    <div className="max-w-3xl mx-auto py-12 animate-in slide-in-from-bottom-8 duration-500">
      <div className="bg-white p-12 rounded-[3rem] border border-slate-100 shadow-2xl shadow-slate-200/50 text-center relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-2 bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500"></div>
        <div className="w-24 h-24 bg-indigo-50 text-indigo-600 rounded-3xl flex items-center justify-center text-4xl mx-auto mb-8 shadow-inner">
          🕹️
        </div>
        <h3 className="text-3xl font-black text-slate-900 mb-4 tracking-tight">TEF Terminal Simulator</h3>
        <p className="text-slate-500 text-lg mb-12 max-w-md mx-auto">
          Inicie transações sintéticas para testar a integração do host e o fluxo de dados em tempo real.
        </p>

        <div className="bg-slate-900 rounded-[2rem] p-8 border border-slate-800 mb-10 text-left font-mono text-xs leading-relaxed overflow-hidden relative group">
          <div className="flex gap-2 absolute top-4 right-4">
            <div className="w-2 h-2 rounded-full bg-slate-700"></div>
            <div className="w-2 h-2 rounded-full bg-slate-700"></div>
            <div className="w-2 h-2 rounded-full bg-slate-700"></div>
          </div>
          <div className="space-y-1">
            <p className="text-indigo-400 font-bold"># INITIALIZING TEF KERNEL v2.5.4</p>
            <p className="text-slate-500 opacity-60">System Ready. Awaiting trigger...</p>
            {isSimulating && (
              <div className="space-y-1">
                <p className="text-amber-400 animate-pulse">> CONNECTING TO ACQUIRER GATEWAY...</p>
                <p className="text-slate-400">> PACKET SENT (ISO8583: 0200)</p>
                <p className="text-slate-400">> ENCRYPTING PAYLOAD (AES-256)</p>
                <p className="text-emerald-400 animate-bounce font-bold">> RESPONSE RECEIVED: AUTH_OK</p>
              </div>
            )}
            {!isSimulating && transactions.length > MOCK_TRANSACTIONS.length && (
              <p className="text-emerald-500 font-bold">> LAST TRANSACTION SUCCESSFUL: {transactions[0].id}</p>
            )}
          </div>
        </div>

        <button 
          disabled={isSimulating}
          onClick={simulateTransaction}
          className={`group w-full py-6 rounded-2xl font-black text-xl transition-all duration-300 transform flex items-center justify-center gap-4 ${
            isSimulating 
              ? 'bg-slate-100 text-slate-400 cursor-not-allowed' 
              : 'bg-indigo-600 text-white hover:bg-indigo-700 hover:scale-[1.02] shadow-xl hover:shadow-indigo-300'
          }`}
        >
          {isSimulating ? (
            <div className="flex items-center gap-3">
              <svg className="animate-spin h-6 w-6 text-slate-400" viewBox="0 0 24 24">
                <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
              </svg>
              PROCESSANDO...
            </div>
          ) : (
            <>INICIAR TRANSAÇÃO MOCK <span className="group-hover:translate-x-2 transition-transform">⚡</span></>
          )}
        </button>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />

      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-20 bg-white/70 backdrop-blur-md border-b border-slate-100 sticky top-0 z-40 flex items-center justify-between px-10">
          <div>
            <h2 className="text-xl font-black text-slate-900 tracking-tight">
              {activeTab === 'dashboard' ? 'Overview Geral' : activeTab.charAt(0).toUpperCase() + activeTab.slice(1)}
            </h2>
            <p className="text-[10px] text-slate-500 font-bold uppercase tracking-widest mt-0.5">Nexus Payment Cloud • v2.0</p>
          </div>

          <div className="flex items-center gap-6">
            <div className="flex -space-x-3 overflow-hidden">
              <img className="inline-block h-8 w-8 rounded-full ring-2 ring-white" src="https://picsum.photos/seed/p1/32/32" alt="" />
              <img className="inline-block h-8 w-8 rounded-full ring-2 ring-white" src="https://picsum.photos/seed/p2/32/32" alt="" />
            </div>
            <div className="h-8 w-[1px] bg-slate-100"></div>
            <div className="flex items-center gap-4">
              <div className="text-right">
                <p className="text-xs font-black text-slate-900 leading-tight">Admin Nexus</p>
                <p className="text-[10px] text-indigo-600 font-bold uppercase tracking-widest">Master User</p>
              </div>
              <div className="w-10 h-10 bg-slate-100 rounded-2xl flex items-center justify-center text-lg shadow-inner ring-1 ring-slate-200/50">
                👤
              </div>
            </div>
          </div>
        </header>

        <main className="p-10 max-w-[1400px] w-full mx-auto pb-20">
          {activeTab === 'dashboard' && renderDashboard()}
          {activeTab === 'transactions' && (
            <div className="space-y-8 animate-in fade-in slide-in-from-top-4 duration-500">
              <div className="flex items-center justify-between">
                <div>
                  <h3 className="text-2xl font-black text-slate-900 tracking-tight">Log Consolidado</h3>
                  <p className="text-sm text-slate-500 mt-1">Sincronizado com o gateway central de adquirentes.</p>
                </div>
                <div className="flex gap-3">
                  <button className="px-5 py-2.5 bg-white border border-slate-200 rounded-xl text-xs font-bold text-slate-600 hover:bg-slate-50 shadow-sm transition-all">Filtros Avançados</button>
                  <button className="px-5 py-2.5 bg-slate-900 text-white rounded-xl text-xs font-bold hover:bg-slate-800 shadow-xl transition-all">Exportar Dados</button>
                </div>
              </div>
              <TransactionTable transactions={transactions} />
            </div>
          )}
          {activeTab === 'simulator' && renderSimulator()}

          {!['dashboard', 'transactions', 'simulator'].includes(activeTab) && (
            <div className="flex flex-col items-center justify-center h-[50vh] text-slate-300">
              <div className="text-8xl mb-6 grayscale opacity-20">🚧</div>
              <p className="text-xl font-black tracking-tight uppercase opacity-40">Módulo em Integração</p>
              <button 
                onClick={() => setActiveTab('dashboard')}
                className="mt-6 text-sm font-bold text-indigo-600 hover:underline"
              >
                Voltar ao Painel
              </button>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

export enum PaymentStatus {
  SUCCESS = 'SUCCESS',
  PENDING = 'PENDING',
  FAILED = 'FAILED',
  REFUNDED = 'REFUNDED'
}

export enum PaymentMethod {
  CREDIT = 'Crédito',
  DEBIT = 'Débito',
  PIX = 'PIX',
  VOUCHER = 'Voucher'
}

export enum FiscalStatus {
  AUTHORIZED = 'Autorizada',
  REJECTED = 'Rejeitada',
  CONTINGENCY = 'Contingência',
  CANCELED = 'Cancelada'
}

export interface Transaction {
