import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [insights, setInsights] = useState<string>('Auditando registros fiscais...');
  const [isSimulating, setIsSimulating] = useState(false);
  const [loading, setLoading] = useState(true);

  // Fetch initial data from PHP API
  useEffect(() => {
    const loadData = async () => {
      try {
        const [txRes, certRes] = await Promise.all([
          fetch(`${API_URL}?action=get_transactions`),
          fetch(`${API_URL}?action=get_certificates`)
        ]);

        const txData = await txRes.json();
        const certData = await certRes.json();

        if (Array.isArray(txData)) setTransactions(txData);
        if (Array.isArray(certData)) setCertificates(certData);
      } catch (error) {
        console.error("Failed to fetch data from PHP API:", error);
      } finally {
        setLoading(false);
      }
    };
    loadData();
  }, []);

  const stats = useMemo(() => {
    const successful = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const pixTotal = successful.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    const fiscalAuthorized = transactions.filter(t => t.fiscalStatus === FiscalStatus.AUTHORIZED).length;

    return { 
      total: successful.reduce((acc, curr) => acc + Number(curr.amount), 0),
      pixShare: ((pixTotal / (successful.reduce((a, b) => a + Number(b.amount), 0) || 1)) * 100).toFixed(1),
      fiscalHealth: ((fiscalAuthorized / (transactions.filter(t => t.fiscalNoteId).length || 1)) * 100).toFixed(1),
      count: transactions.length 
    };
  }, [transactions]);

  useEffect(() => {
    if (transactions.length > 0) {
      const fetchAI = async () => {
        const result = await getSmartInsights(transactions);
        setInsights(result);
      };
      fetchAI();
    }
  }, [transactions]);

  const simulateTransaction = async () => {
    setIsSimulating(true);
    const isPix = Math.random() > 0.5;
    const newTx: Transaction = {
      id: `TX-${Math.floor(1000 + Math.random() * 9000)}`,
      timestamp: new Date().toISOString().slice(0, 19).replace('T', ' '), // MySQL Format
      amount: parseFloat((Math.random() * 200 + 10).toFixed(2)),
      method: isPix ? PaymentMethod.PIX : PaymentMethod.CREDIT,
      segment: 'Varejo Geral',
      status: PaymentStatus.SUCCESS,
      terminalId: 'PDV-01',
      fiscalNoteId: Math.random() > 0.1 ? String(Math.floor(6000 + Math.random() * 1000)) : undefined,
      fiscalStatus: Math.random() > 0.1 ? FiscalStatus.AUTHORIZED : FiscalStatus.CONTINGENCY
    };

    try {
      await fetch(`${API_URL}?action=save_transaction`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newTx)
      });
      setTransactions(prev => [newTx, ...prev]);
    } catch (error) {
      console.error("Error saving transaction:", error);
    } finally {
      setIsSimulating(false);
    }
  };

  const renderDashboard = () => (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard label="Vendas Brutas" value={`R$ ${stats.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} trend="DB Sync" trendUp={true} icon="💰" color="bg-indigo-50 text-indigo-600" />
        <StatCard label="Penetração PIX" value={`${stats.pixShare}%`} trend="Real" trendUp={true} icon="⚡" color="bg-emerald-50 text-emerald-600" />
        <StatCard label="Saúde Fiscal" value={`${stats.fiscalHealth}%`} icon="📑" color="bg-blue-50 text-blue-600" />
        <StatCard label="Total Transações" value={stats.count} icon="🔄" color="bg-slate-50 text-slate-600" />
      </div>

      <FiscalMonitor states={SEFAZ_STATES} />

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
          <h3 className="text-xl font-black text-slate-800 mb-8 tracking-tight">Performance Financeira</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={CHART_DATA}>
