import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [insights, setInsights] = useState<string>('Auditando registros fiscais...');
  const [isSimulating, setIsSimulating] = useState(false);
  const [loading, setLoading] = useState(true);

  // Fetch initial data from PHP API
  useEffect(() => {
    const loadData = async () => {
      try {
        const [txRes, certRes] = await Promise.all([
          fetch(`${API_URL}?action=get_transactions`),
          fetch(`${API_URL}?action=get_certificates`)
        ]);

        const txData = await txRes.json();
        const certData = await certRes.json();

        if (Array.isArray(txData)) setTransactions(txData);
        if (Array.isArray(certData)) setCertificates(certData);
      } catch (error) {
        console.error("Failed to fetch data from PHP API:", error);
      } finally {
        setLoading(false);
      }
    };
    loadData();
  }, []);

  const stats = useMemo(() => {
    const successful = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const pixTotal = successful.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    const fiscalAuthorized = transactions.filter(t => t.fiscalStatus === FiscalStatus.AUTHORIZED).length;

    return { 
      total: successful.reduce((acc, curr) => acc + Number(curr.amount), 0),
      pixShare: ((pixTotal / (successful.reduce((a, b) => a + Number(b.amount), 0) || 1)) * 100).toFixed(1),
      fiscalHealth: ((fiscalAuthorized / (transactions.filter(t => t.fiscalNoteId).length || 1)) * 100).toFixed(1),
      count: transactions.length 
    };
  }, [transactions]);

  useEffect(() => {
    if (transactions.length > 0) {
      const fetchAI = async () => {
        const result = await getSmartInsights(transactions);
        setInsights(result);
      };
      fetchAI();
    }
  }, [transactions]);

  const simulateTransaction = async () => {
    setIsSimulating(true);
    const isPix = Math.random() > 0.5;
    const newTx: Transaction = {
      id: `TX-${Math.floor(1000 + Math.random() * 9000)}`,
      timestamp: new Date().toISOString().slice(0, 19).replace('T', ' '), // MySQL Format
      amount: parseFloat((Math.random() * 200 + 10).toFixed(2)),
      method: isPix ? PaymentMethod.PIX : PaymentMethod.CREDIT,
      segment: 'Varejo Geral',
      status: PaymentStatus.SUCCESS,
      terminalId: 'PDV-01',
      fiscalNoteId: Math.random() > 0.1 ? String(Math.floor(6000 + Math.random() * 1000)) : undefined,
      fiscalStatus: Math.random() > 0.1 ? FiscalStatus.AUTHORIZED : FiscalStatus.CONTINGENCY
    };

    try {
      await fetch(`${API_URL}?action=save_transaction`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newTx)
      });
      setTransactions(prev => [newTx, ...prev]);
    } catch (error) {
      console.error("Error saving transaction:", error);
    } finally {
      setIsSimulating(false);
    }
  };

  const renderDashboard = () => (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard label="Vendas Brutas" value={`R$ ${stats.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} trend="DB Sync" trendUp={true} icon="💰" color="bg-indigo-50 text-indigo-600" />
        <StatCard label="Penetração PIX" value={`${stats.pixShare}%`} trend="Real" trendUp={true} icon="⚡" color="bg-emerald-50 text-emerald-600" />
        <StatCard label="Saúde Fiscal" value={`${stats.fiscalHealth}%`} icon="📑" color="bg-blue-50 text-blue-600" />
        <StatCard label="Total Transações" value={stats.count} icon="🔄" color="bg-slate-50 text-slate-600" />
      </div>

      <FiscalMonitor states={SEFAZ_STATES} />

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
          <h3 className="text-xl font-black text-slate-800 mb-8 tracking-tight">Performance Financeira</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={CHART_DATA}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                <Tooltip contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)'}} />
                <Area type="monotone" dataKey="valor" stroke="#6366f1" strokeWidth={3} fill="#6366f110" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>
        <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white flex flex-col">
          <h3 className="text-xl font-bold mb-6 flex items-center gap-2">✨ Insights de IA</h3>
          <div className="flex-1 bg-white/5 rounded-3xl p-5 text-sm font-medium leading-relaxed overflow-auto">
            {insights}
          </div>
          <button className="mt-6 w-full py-4 bg-indigo-600 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-indigo-500 transition-all">Sincronizar SEFAZ</button>
        </div>
      </div>
    </div>
  );

  const renderCertificates = () => (
    <div className="space-y-8 animate-in slide-in-from-right-4 duration-500">
      <div className="flex justify-between items-center">
        <h3 className="text-2xl font-black text-slate-900">Certificados Digitais (DB)</h3>
        <button className="px-6 py-3 bg-indigo-600 text-white rounded-2xl font-bold text-sm shadow-lg shadow-indigo-200 hover:scale-105 transition-all">+ Novo Certificado</button>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {certificates.map(cert => (
          <div key={cert.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 relative group overflow-hidden">
            <div className={`absolute top-0 right-0 w-16 h-16 opacity-10 flex items-center justify-center text-4xl -mr-4 -mt-4 rotate-12`}>
              {cert.type === 'A1' ? '📄' : '🏷️'}
            </div>
            <div className="mb-4">
              <span className={`px-2.5 py-1 rounded-lg text-[10px] font-black uppercase ${
                cert.status === 'Ativo' ? 'bg-emerald-50 text-emerald-600' : 
                cert.status === 'Alerta' ? 'bg-amber-50 text-amber-600' : 'bg-rose-50 text-rose-600'
              }`}>
                {cert.status}
              </span>
            </div>
            <h4 className="font-bold text-slate-800 mb-1">{cert.alias}</h4>
            <p className="text-xs text-slate-500 mb-4 font-mono">ID: {cert.id} | UF: {cert.state}</p>
            <div className="pt-4 border-t border-slate-50 flex justify-between items-end">
              <div>
                <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Expira em</p>
                {/* Fix: use cert.expirationDate as defined in the DigitalCertificate interface */}
                <p className="text-sm font-black text-slate-700">{new Date(cert.expirationDate).toLocaleDateString('pt-BR')}</p>
              </div>
              <button className="p-2 bg-slate-50 rounded-xl hover:bg-slate-100 text-indigo-600 transition-colors">⚙️</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} />
      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-20 bg-white/70 backdrop-blur-md border-b border-slate-100 sticky top-0 z-40 flex items-center justify-between px-10">
          <div className="flex flex-col">
            <h2 className="text-xl font-black text-slate-900 leading-none">Nexus Hub</h2>
            <span className="text-[10px] font-bold text-indigo-500 mt-1">Sincronizado com MySQL</span>
          </div>
          <div className="flex items-center gap-4">
            <div className="px-3 py-1 bg-emerald-50 text-emerald-600 rounded-full text-[10px] font-black uppercase tracking-wider">Host: Localhost</div>
            <div className="w-10 h-10 bg-slate-100 rounded-2xl flex items-center justify-center border border-slate-200 shadow-inner">👤</div>
          </div>
        </header>

        <main className="p-10 max-w-[1400px] w-full mx-auto">
          {loading ? (
            <div className="h-[60vh] flex flex-col items-center justify-center text-slate-400">
              <div className="w-12 h-12 border-4 border-indigo-200 border-t-indigo-600 rounded-full animate-spin mb-4"></div>
              <p className="font-bold text-sm">CONECTANDO AO BANCO DE DADOS...</p>
            </div>
          ) : (
            <>
              {activeTab === 'dashboard' && renderDashboard()}
              {activeTab === 'certificates' && renderCertificates()}
              {activeTab === 'fiscal' && (
                <div className="space-y-6">
                  <h3 className="text-2xl font-black text-slate-900">Monitor Fiscal NFC-e</h3>
                  <TransactionTable transactions={transactions.filter(t => !!t.fiscalNoteId)} />
                </div>
              )}
              {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}
              {activeTab === 'simulator' && (
                <div className="max-w-xl mx-auto py-20 text-center">
                   <div className="bg-white p-10 rounded-[3rem] shadow-2xl border border-slate-100">
                      <div className="w-48 h-48 bg-slate-50 mx-auto mb-8 rounded-3xl flex items-center justify-center border-2 border-dashed border-slate-200">
                        {isSimulating ? (
                          <div className="animate-spin text-4xl">⌛</div>
                        ) : (
                          <div className="text-6xl">📱</div>
                        )}
                      </div>
                      <h3 className="text-2xl font-black text-slate-900 mb-6 tracking-tight">Terminal Venda Rápida</h3>
                      <div className="flex gap-4 mb-8">
                        <button onClick={simulateTransaction} disabled={isSimulating} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-bold hover:bg-indigo-700 transition-all shadow-lg">Vender Crédito</button>
                        <button onClick={simulateTransaction} disabled={isSimulating} className="flex-1 py-4 bg-emerald-600 text-white rounded-2xl font-bold hover:bg-emerald-700 transition-all shadow-lg">Gerar PIX</button>
                      </div>
                      <p className="text-xs text-slate-400 font-medium">As vendas são salvas permanentemente no banco de dados nexustef.</p>
                   </div>
                </div>
              )}
            </>
          )}
        </main>
      </div>
    </div>
  );
};

