import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginData, setLoginData] = useState({ username: '', password: '' });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [insights, setInsights] = useState<string>('Auditando registros fiscais...');
  const [isSimulating, setIsSimulating] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Persistence check
  useEffect(() => {
    const saved = localStorage.getItem('nexus_user');
    if (saved) {
      setCurrentUser(JSON.parse(saved));
    }
    setLoading(false);
  }, []);

  // Fetch data
  useEffect(() => {
    if (!currentUser) return;

    const loadData = async () => {
      try {
        const [txRes, certRes] = await Promise.all([
          fetch(`${API_URL}?action=get_transactions`),
          fetch(`${API_URL}?action=get_certificates`)
        ]);

        const txData = await txRes.json();
        const certData = await certRes.json();

        if (Array.isArray(txData)) setTransactions(txData);
        if (Array.isArray(certData)) setCertificates(certData);

        if (currentUser.role === UserRole.MASTER) {
          const userRes = await fetch(`${API_URL}?action=get_users`);
          const userData = await userRes.json();
          if (Array.isArray(userData)) setUsersList(userData);
        }
      } catch (error) {
        console.error("API Error:", error);
      }
    };
    loadData();
  }, [currentUser]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    try {
      const res = await fetch(`${API_URL}?action=login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(loginData)
      });
      const data = await res.json();
      if (data.status === 'success') {
        setCurrentUser(data.user);
        localStorage.setItem('nexus_user', JSON.stringify(data.user));
      } else {
        setError(data.message);
      }
    } catch (err) {
      setError('Erro ao conectar com o servidor PHP.');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('nexus_user');
    setActiveTab('dashboard');
  };

  const stats = useMemo(() => {
    const successful = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const pixTotal = successful.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    const fiscalAuthorized = transactions.filter(t => t.fiscalStatus === FiscalStatus.AUTHORIZED).length;

    return { 
      total: successful.reduce((acc, curr) => acc + Number(curr.amount), 0),
      pixShare: ((pixTotal / (successful.reduce((a, b) => a + Number(b.amount), 0) || 1)) * 100).toFixed(1),
      fiscalHealth: ((fiscalAuthorized / (transactions.filter(t => t.fiscalNoteId).length || 1)) * 100).toFixed(1),
      count: transactions.length 
    };
  }, [transactions]);

  useEffect(() => {
    if (transactions.length > 0) {
      getSmartInsights(transactions).then(setInsights);
    }
  }, [transactions]);

  const simulateTransaction = async () => {
    setIsSimulating(true);
    const isPix = Math.random() > 0.5;
    const newTx: Transaction = {
      id: `TX-${Math.floor(1000 + Math.random() * 9000)}`,
      timestamp: new Date().toISOString().slice(0, 19).replace('T', ' '),
      amount: parseFloat((Math.random() * 200 + 10).toFixed(2)),
      method: isPix ? PaymentMethod.PIX : PaymentMethod.CREDIT,
      segment: 'Varejo Geral',
      status: PaymentStatus.SUCCESS,
      terminalId: 'PDV-01',
      fiscalNoteId: Math.random() > 0.1 ? String(Math.floor(6000 + Math.random() * 1000)) : undefined,
      fiscalStatus: Math.random() > 0.1 ? FiscalStatus.AUTHORIZED : FiscalStatus.CONTINGENCY
    };

    try {
      await fetch(`${API_URL}?action=save_transaction`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newTx)
      });
      setTransactions(prev => [newTx, ...prev]);
    } catch (e) {} finally { setIsSimulating(false); }
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6">
        <div className="bg-white p-12 rounded-[3rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300">
          <div className="flex flex-col items-center mb-10">
            <div className="w-16 h-16 bg-indigo-600 rounded-3xl flex items-center justify-center text-3xl font-black text-white mb-4 shadow-xl shadow-indigo-200">N</div>
            <h1 className="text-3xl font-black text-slate-900">NexusTEF</h1>
            <p className="text-slate-400 font-bold text-[10px] uppercase tracking-[0.3em] mt-1">Acesso Restrito</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-6">
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Usuário</label>
              <input 
                type="text" 
                value={loginData.username}
                onChange={e => setLoginData({...loginData, username: e.target.value})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-4 px-6 text-slate-800 focus:ring-2 focus:ring-indigo-500 transition-all font-medium"
                placeholder="Ex: master"
                required
              />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Senha</label>
              <input 
                type="password" 
                value={loginData.password}
                onChange={e => setLoginData({...loginData, password: e.target.value})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-4 px-6 text-slate-800 focus:ring-2 focus:ring-indigo-500 transition-all font-medium"
                placeholder="••••••••"
                required
              />
            </div>
            {error && <div className="p-4 bg-rose-50 text-rose-600 rounded-2xl text-xs font-bold text-center">{error}</div>}
            <button className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-widest hover:bg-indigo-700 shadow-xl shadow-indigo-100 transition-all">
              Entrar no Nexus
            </button>
          </form>
          <p className="text-center mt-8 text-[10px] text-slate-300 font-bold uppercase tracking-widest">v3.0.0 Stable Build</p>
        </div>
      </div>
    );
  }

  const renderDashboard = () => (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard label="Vendas Brutas" value={`R$ ${stats.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} icon="💰" color="bg-indigo-50 text-indigo-600" />
        <StatCard label="Penetração PIX" value={`${stats.pixShare}%`} icon="⚡" color="bg-emerald-50 text-emerald-600" />
        <StatCard label="Saúde Fiscal" value={`${stats.fiscalHealth}%`} icon="📑" color="bg-blue-50 text-blue-600" />
        <StatCard label="Total Transações" value={stats.count} icon="🔄" color="bg-slate-50 text-slate-600" />
      </div>
      <FiscalMonitor states={SEFAZ_STATES} />
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
          <h3 className="text-xl font-black text-slate-800 mb-8 tracking-tight">Fluxo de Caixa</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={CHART_DATA}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                <Tooltip />
                <Area type="monotone" dataKey="valor" stroke="#6366f1" strokeWidth={3} fill="#6366f110" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>
        <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white flex flex-col">
          <h3 className="text-xl font-bold mb-6">✨ IA Consultora</h3>
          <div className="flex-1 bg-white/5 rounded-3xl p-5 text-sm leading-relaxed overflow-auto">{insights}</div>
        </div>
      </div>
    </div>
  );

  const renderUsers = () => (
    <div className="space-y-8 animate-in slide-in-from-bottom-8 duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h3 className="text-2xl font-black text-slate-900">Gerenciamento de Equipe</h3>
          <p className="text-slate-500 text-sm">Controle quem tem acesso ao painel NexusTEF.</p>
        </div>
        <button className="px-6 py-3 bg-indigo-600 text-white rounded-2xl font-bold text-sm">+ Novo Usuário</button>
      </div>
      <div className="bg-white rounded-[2.5rem] border border-slate-100 overflow-hidden">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nome Completo</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Login</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nível</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Criado em</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {usersList.map(u => (
              <tr key={u.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-8 py-5">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center font-bold">{u.name.charAt(0)}</div>
                    <span className="font-bold text-slate-800">{u.name}</span>
                  </div>
                </td>
                <td className="px-8 py-5 text-sm font-mono text-slate-500">@{u.username}</td>
                <td className="px-8 py-5">
                  <span className={`px-3 py-1 rounded-full text-[10px] font-black ${
                    u.role === UserRole.MASTER ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-100 text-slate-600'
                  }`}>{u.role}</span>
                </td>
                <td className="px-8 py-5 text-xs text-slate-400">{new Date(u.created_at!).toLocaleDateString('pt-BR')}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} currentUser={currentUser} onLogout={handleLogout} />
      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-20 bg-white/70 backdrop-blur-md border-b border-slate-100 sticky top-0 z-40 flex items-center justify-between px-10">
          <div className="flex flex-col">
            <h2 className="text-xl font-black text-slate-900">Nexus Hub</h2>
            <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-wider">{activeTab}</span>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-right">
              <p className="text-xs font-black text-slate-900 leading-tight">{currentUser.name}</p>
              <p className="text-[9px] text-indigo-600 font-bold uppercase tracking-widest">{currentUser.role}</p>
            </div>
            <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center border border-indigo-100 shadow-inner font-bold">
              {currentUser.name.charAt(0)}
            </div>
          </div>
        </header>
        <main className="p-10 max-w-[1400px] w-full mx-auto">
          {activeTab === 'dashboard' && renderDashboard()}
          {activeTab === 'users' && renderUsers()}
          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}
          {activeTab === 'fiscal' && <TransactionTable transactions={transactions.filter(t => !!t.fiscalNoteId)} />}
          {activeTab === 'certificates' && (
             <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {certificates.map(cert => (
                  <div key={cert.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm">
                    <span className="text-[10px] font-black text-indigo-500 uppercase mb-2 block">{cert.type}</span>
                    <h4 className="font-bold text-slate-800">{cert.alias}</h4>
                    <p className="text-xs text-slate-400 mt-1">Expira: {new Date(cert.expirationDate).toLocaleDateString('pt-BR')}</p>
                  </div>
                ))}
             </div>
          )}
          {activeTab === 'simulator' && (
            <div className="max-w-xl mx-auto py-20 text-center">
              <div className="bg-white p-12 rounded-[3rem] shadow-2xl border border-slate-100">
                <div className="text-6xl mb-8">💳</div>
                <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Simulador de Transação</h3>
                <button onClick={simulateTransaction} disabled={isSimulating} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-widest hover:bg-indigo-700 shadow-xl transition-all">
                  {isSimulating ? 'Processando...' : 'Simular Venda Agora'}
                </button>
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginData, setLoginData] = useState({ username: '', password: '' });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [insights, setInsights] = useState<string>('Auditando registros fiscais...');
  const [isSimulating, setIsSimulating] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Modal States
  const [showUserModal, setShowUserModal] = useState(false);
  const [showCertModal, setShowCertModal] = useState(false);
  const [newUserData, setNewUserData] = useState({ name: '', username: '', password: '', role: UserRole.OPERATOR });
  const [newCertData, setNewCertData] = useState({ id: '', alias: '', expirationDate: '', state: 'SP', status: 'Ativo' as any, type: 'A1' as any });

  // Persistence check
  useEffect(() => {
    const saved = localStorage.getItem('nexus_user');
    if (saved) {
      setCurrentUser(JSON.parse(saved));
    }
    setLoading(false);
  }, []);

  const loadData = async () => {
    if (!currentUser) return;
    try {
      const [txRes, certRes] = await Promise.all([
        fetch(`${API_URL}?action=get_transactions`),
        fetch(`${API_URL}?action=get_certificates`)
      ]);

      const txData = await txRes.json();
      const certData = await certRes.json();

      if (Array.isArray(txData)) setTransactions(txData);
      if (Array.isArray(certData)) {
        // Map field names if they come from MySQL directly
        const mappedCerts = certData.map(c => ({
          ...c,
          expirationDate: c.expiration_date || c.expirationDate
        }));
        setCertificates(mappedCerts);
      }

      if (currentUser.role === UserRole.MASTER) {
        const userRes = await fetch(`${API_URL}?action=get_users`);
        const userData = await userRes.json();
        if (Array.isArray(userData)) setUsersList(userData);
      }
    } catch (error) {
      console.error("API Error:", error);
    }
  };

  // Fetch data on login or change
  useEffect(() => {
    loadData();
  }, [currentUser]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    try {
      const res = await fetch(`${API_URL}?action=login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(loginData)
      });
      const data = await res.json();
      if (data.status === 'success') {
        setCurrentUser(data.user);
        localStorage.setItem('nexus_user', JSON.stringify(data.user));
      } else {
        setError(data.message);
      }
    } catch (err) {
      setError('Erro ao conectar com o servidor PHP.');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('nexus_user');
    setActiveTab('dashboard');
  };

  const handleSaveUser = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const res = await fetch(`${API_URL}?action=save_user`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newUserData)
      });
      const data = await res.json();
      if (data.status === 'success') {
        setShowUserModal(false);
        setNewUserData({ name: '', username: '', password: '', role: UserRole.OPERATOR });
        loadData();
      }
    } catch (e) {
      console.error(e);
    }
  };

  const handleSaveCert = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const certToSave = { ...newCertData, id: `CERT-${Math.floor(Math.random()*10000)}` };
      const res = await fetch(`${API_URL}?action=save_certificate`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(certToSave)
      });
      const data = await res.json();
      if (data.status === 'success') {
        setShowCertModal(false);
        setNewCertData({ id: '', alias: '', expirationDate: '', state: 'SP', status: 'Ativo', type: 'A1' });
        loadData();
      }
    } catch (e) {
      console.error(e);
    }
  };

  const stats = useMemo(() => {
    const successful = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const pixTotal = successful.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    const fiscalAuthorized = transactions.filter(t => t.fiscalStatus === FiscalStatus.AUTHORIZED).length;

    return { 
      total: successful.reduce((acc, curr) => acc + Number(curr.amount), 0),
      pixShare: ((pixTotal / (successful.reduce((a, b) => a + Number(b.amount), 0) || 1)) * 100).toFixed(1),
      fiscalHealth: ((fiscalAuthorized / (transactions.filter(t => t.fiscalNoteId).length || 1)) * 100).toFixed(1),
      count: transactions.length 
    };
  }, [transactions]);

  useEffect(() => {
    if (transactions.length > 0) {
      getSmartInsights(transactions).then(setInsights);
    }
  }, [transactions]);

  const simulateTransaction = async () => {
    setIsSimulating(true);
    const isPix = Math.random() > 0.5;
    const newTx: Transaction = {
      id: `TX-${Math.floor(1000 + Math.random() * 9000)}`,
      timestamp: new Date().toISOString().slice(0, 19).replace('T', ' '),
      amount: parseFloat((Math.random() * 200 + 10).toFixed(2)),
      method: isPix ? PaymentMethod.PIX : PaymentMethod.CREDIT,
      segment: 'Varejo Geral',
      status: PaymentStatus.SUCCESS,
      terminalId: 'PDV-01',
      fiscalNoteId: Math.random() > 0.1 ? String(Math.floor(6000 + Math.random() * 1000)) : undefined,
      fiscalStatus: Math.random() > 0.1 ? FiscalStatus.AUTHORIZED : FiscalStatus.CONTINGENCY
    };

    try {
      await fetch(`${API_URL}?action=save_transaction`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newTx)
      });
      setTransactions(prev => [newTx, ...prev]);
    } catch (e) {} finally { setIsSimulating(false); }
  };

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6">
        <div className="bg-white p-12 rounded-[3rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300">
          <div className="flex flex-col items-center mb-10">
            <div className="w-16 h-16 bg-indigo-600 rounded-3xl flex items-center justify-center text-3xl font-black text-white mb-4 shadow-xl shadow-indigo-200">N</div>
            <h1 className="text-3xl font-black text-slate-900">NexusTEF</h1>
            <p className="text-slate-400 font-bold text-[10px] uppercase tracking-[0.3em] mt-1">Acesso Restrito</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-6">
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Usuário</label>
              <input 
                type="text" 
                value={loginData.username}
                onChange={e => setLoginData({...loginData, username: e.target.value})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-4 px-6 text-slate-800 focus:ring-2 focus:ring-indigo-500 transition-all font-medium"
                placeholder="Ex: master"
                required
              />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Senha</label>
              <input 
                type="password" 
                value={loginData.password}
                onChange={e => setLoginData({...loginData, password: e.target.value})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-4 px-6 text-slate-800 focus:ring-2 focus:ring-indigo-500 transition-all font-medium"
                placeholder="••••••••"
                required
              />
            </div>
            {error && <div className="p-4 bg-rose-50 text-rose-600 rounded-2xl text-xs font-bold text-center">{error}</div>}
            <button className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-widest hover:bg-indigo-700 shadow-xl shadow-indigo-100 transition-all">
              Entrar no Nexus
            </button>
          </form>
          <p className="text-center mt-8 text-[10px] text-slate-300 font-bold uppercase tracking-widest">v4.0.0 Stable Build</p>
        </div>
      </div>
    );
  }

  const renderDashboard = () => (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard label="Vendas Brutas" value={`R$ ${stats.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} icon="💰" color="bg-indigo-50 text-indigo-600" />
        <StatCard label="Penetração PIX" value={`${stats.pixShare}%`} icon="⚡" color="bg-emerald-50 text-emerald-600" />
        <StatCard label="Saúde Fiscal" value={`${stats.fiscalHealth}%`} icon="📑" color="bg-blue-50 text-blue-600" />
        <StatCard label="Total Transações" value={stats.count} icon="🔄" color="bg-slate-50 text-slate-600" />
      </div>
      <FiscalMonitor states={SEFAZ_STATES} />
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
          <h3 className="text-xl font-black text-slate-800 mb-8 tracking-tight">Fluxo de Caixa</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={CHART_DATA}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                <Tooltip />
                <Area type="monotone" dataKey="valor" stroke="#6366f1" strokeWidth={3} fill="#6366f110" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>
        <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white flex flex-col">
          <h3 className="text-xl font-bold mb-6">✨ IA Consultora</h3>
          <div className="flex-1 bg-white/5 rounded-3xl p-5 text-sm leading-relaxed overflow-auto">{insights}</div>
        </div>
      </div>
    </div>
  );

  const renderUsers = () => (
    <div className="space-y-8 animate-in slide-in-from-bottom-8 duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h3 className="text-2xl font-black text-slate-900">Gerenciamento de Equipe</h3>
          <p className="text-slate-500 text-sm">Controle quem tem acesso ao painel NexusTEF.</p>
        </div>
        <button 
          onClick={() => setShowUserModal(true)}
          className="px-6 py-3 bg-indigo-600 text-white rounded-2xl font-bold text-sm shadow-lg hover:scale-105 transition-all"
        >
          + Novo Usuário
        </button>
      </div>
      <div className="bg-white rounded-[2.5rem] border border-slate-100 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nome Completo</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Login</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nível</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Criado em</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {usersList.map(u => (
              <tr key={u.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-8 py-5">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center font-bold">{u.name.charAt(0)}</div>
                    <span className="font-bold text-slate-800">{u.name}</span>
                  </div>
                </td>
                <td className="px-8 py-5 text-sm font-mono text-slate-500">@{u.username}</td>
                <td className="px-8 py-5">
                  <span className={`px-3 py-1 rounded-full text-[10px] font-black ${
                    u.role === UserRole.MASTER ? 'bg-indigo-100 text-indigo-700' : 
                    u.role === UserRole.ADMIN ? 'bg-blue-100 text-blue-700' : 'bg-slate-100 text-slate-600'
                  }`}>{u.role}</span>
                </td>
                <td className="px-8 py-5 text-xs text-slate-400">{u.created_at ? new Date(u.created_at).toLocaleDateString('pt-BR') : 'Original'}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {showUserModal && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-6">
          <div className="bg-white p-10 rounded-[3rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-200">
            <h3 className="text-2xl font-black text-slate-900 mb-6">Cadastrar Funcionário</h3>
            <form onSubmit={handleSaveUser} className="space-y-4">
              <input 
                type="text" placeholder="Nome Completo" required
                value={newUserData.name} onChange={e => setNewUserData({...newUserData, name: e.target.value})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium"
              />
              <input 
                type="text" placeholder="Login de Acesso" required
                value={newUserData.username} onChange={e => setNewUserData({...newUserData, username: e.target.value})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium"
              />
              <input 
                type="password" placeholder="Senha Provisória" required
                value={newUserData.password} onChange={e => setNewUserData({...newUserData, password: e.target.value})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium"
              />
              <select 
                value={newUserData.role} onChange={e => setNewUserData({...newUserData, role: e.target.value as any})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium"
              >
                <option value={UserRole.OPERATOR}>Operador (Vendas)</option>
                <option value={UserRole.ADMIN}>Administrador (Vendas + Fiscal)</option>
              </select>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowUserModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-bold">Salvar</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );

  const renderCertificates = () => (
    <div className="space-y-8 animate-in slide-in-from-right-4 duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h3 className="text-2xl font-black text-slate-900">Certificados Digitais</h3>
          <p className="text-slate-500 text-sm">Gerencie os certificados A1/A3 para todos os estados.</p>
        </div>
        <button 
          onClick={() => setShowCertModal(true)}
          className="px-6 py-3 bg-indigo-600 text-white rounded-2xl font-bold text-sm shadow-lg hover:scale-105 transition-all"
        >
          + Novo Certificado
        </button>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {certificates.map(cert => (
          <div key={cert.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-shadow">
            <span className="text-[10px] font-black text-indigo-500 uppercase mb-2 block">{cert.type} - {cert.state}</span>
            <h4 className="font-bold text-slate-800">{cert.alias}</h4>
            <div className="flex justify-between items-center mt-4">
              <p className="text-xs text-slate-400 font-medium">Vencimento: {new Date(cert.expirationDate).toLocaleDateString('pt-BR')}</p>
              <div className={`px-2 py-0.5 rounded text-[8px] font-black uppercase ${cert.status === 'Ativo' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                {cert.status}
              </div>
            </div>
          </div>
        ))}
      </div>

      {showCertModal && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-6">
          <div className="bg-white p-10 rounded-[3rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-200">
            <h3 className="text-2xl font-black text-slate-900 mb-6 tracking-tight">Configurar Certificado</h3>
            <form onSubmit={handleSaveCert} className="space-y-4">
              <input 
                type="text" placeholder="Apelido (Ex: Matriz SP)" required
                value={newCertData.alias} onChange={e => setNewCertData({...newCertData, alias: e.target.value})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium"
              />
              <div className="grid grid-cols-2 gap-4">
                <input 
                  type="date" required
                  value={newCertData.expirationDate} onChange={e => setNewCertData({...newCertData, expirationDate: e.target.value})}
                  className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium"
                />
                <select 
                  value={newCertData.state} onChange={e => setNewCertData({...newCertData, state: e.target.value})}
                  className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium"
                >
                  <option value="SP">São Paulo</option>
                  <option value="RJ">Rio de Janeiro</option>
                  <option value="MG">Minas Gerais</option>
                  <option value="RS">Rio Grande do Sul</option>
                  <option value="PR">Paraná</option>
                  <option value="BA">Bahia</option>
                </select>
              </div>
              <div className="grid grid-cols-2 gap-4">
                <select 
                  value={newCertData.type} onChange={e => setNewCertData({...newCertData, type: e.target.value as any})}
                  className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium"
                >
                  <option value="A1">Tipo A1 (Arquivo)</option>
                  <option value="A3">Tipo A3 (Cartão/Token)</option>
                </select>
                <div className="p-4 bg-indigo-50 border border-indigo-100 rounded-2xl text-[10px] text-indigo-600 font-bold flex items-center justify-center">
                  🔐 Upload Automático
                </div>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowCertModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-bold">Configurar</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} currentUser={currentUser} onLogout={handleLogout} />
      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-20 bg-white/70 backdrop-blur-md border-b border-slate-100 sticky top-0 z-40 flex items-center justify-between px-10">
          <div className="flex flex-col">
            <h2 className="text-xl font-black text-slate-900">Nexus Hub</h2>
            <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-wider">{activeTab}</span>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-right">
              <p className="text-xs font-black text-slate-900 leading-tight">{currentUser.name}</p>
              <p className="text-[9px] text-indigo-600 font-bold uppercase tracking-widest">{currentUser.role}</p>
            </div>
            <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center border border-indigo-100 shadow-inner font-bold">
              {currentUser.name.charAt(0)}
            </div>
          </div>
        </header>
        <main className="p-10 max-w-[1400px] w-full mx-auto">
          {activeTab === 'dashboard' && renderDashboard()}
          {activeTab === 'users' && renderUsers()}
          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}
          {activeTab === 'fiscal' && (
            <div className="space-y-6">
               <h3 className="text-2xl font-black text-slate-900">Monitor Fiscal NFC-e</h3>
               <TransactionTable transactions={transactions.filter(t => !!t.fiscalNoteId)} />
            </div>
          )}
          {activeTab === 'certificates' && renderCertificates()}
          {activeTab === 'simulator' && (
            <div className="max-w-xl mx-auto py-20 text-center">
              <div className="bg-white p-12 rounded-[3rem] shadow-2xl border border-slate-100">
                <div className="text-6xl mb-8">💳</div>
                <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Simulador de Transação</h3>
                <div className="flex gap-4 mb-6">
                    <button onClick={simulateTransaction} disabled={isSimulating} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-widest hover:bg-indigo-700 shadow-xl transition-all">
                      {isSimulating ? '⏳' : 'Cartão'}
                    </button>
                    <button onClick={simulateTransaction} disabled={isSimulating} className="flex-1 py-5 bg-emerald-600 text-white rounded-2xl font-black uppercase tracking-widest hover:bg-emerald-700 shadow-xl transition-all">
                      {isSimulating ? '⏳' : 'PIX'}
                    </button>
                </div>
                <p className="text-xs text-slate-400 font-bold">Gera automaticamente Nota Fiscal via API SEFAZ integrada.</p>
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginData, setLoginData] = useState({ username: '', password: '' });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [insights, setInsights] = useState<string>('Auditando registros fiscais...');
  const [isSimulating, setIsSimulating] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [setupRequired, setSetupRequired] = useState<boolean>(false);

  // Modal States
  const [showUserModal, setShowUserModal] = useState(false);
  const [showCertModal, setShowCertModal] = useState(false);
  const [newUserData, setNewUserData] = useState({ name: '', username: '', password: '', role: UserRole.OPERATOR });
  const [newCertData, setNewCertData] = useState({ id: '', alias: '', expirationDate: '', state: 'SP', status: 'Ativo' as any, type: 'A1' as any });

  // Persistence and Setup Check
  useEffect(() => {
    const checkSetup = async () => {
      try {
        const res = await fetch(`${API_URL}?action=check_setup`);
        const data = await res.json();
        setSetupRequired(data.setup_required);
      } catch (e) {
        console.error("Setup check failed", e);
      }

      const saved = localStorage.getItem('nexus_user');
      if (saved) {
        setCurrentUser(JSON.parse(saved));
      }
      setLoading(false);
    };
    checkSetup();
  }, []);

  const loadData = async () => {
    if (!currentUser) return;
    try {
      const [txRes, certRes] = await Promise.all([
        fetch(`${API_URL}?action=get_transactions`),
        fetch(`${API_URL}?action=get_certificates`)
      ]);

      const txData = await txRes.json();
      const certData = await certRes.json();

      if (Array.isArray(txData)) setTransactions(txData);
      if (Array.isArray(certData)) {
        const mappedCerts = certData.map(c => ({
          ...c,
          expirationDate: c.expiration_date || c.expirationDate
        }));
        setCertificates(mappedCerts);
      }

      if (currentUser.role === UserRole.MASTER) {
        const userRes = await fetch(`${API_URL}?action=get_users`);
        const userData = await userRes.json();
        if (Array.isArray(userData)) setUsersList(userData);
      }
    } catch (error) {
      console.error("API Error:", error);
    }
  };

  useEffect(() => {
    loadData();
  }, [currentUser]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    try {
      const res = await fetch(`${API_URL}?action=login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(loginData)
      });
      const data = await res.json();
      if (data.status === 'success') {
        setCurrentUser(data.user);
        localStorage.setItem('nexus_user', JSON.stringify(data.user));
      } else {
        setError(data.message);
      }
    } catch (err) {
      setError('Erro ao conectar com o servidor PHP.');
    }
  };

  const handleSetup = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      // Força role MASTER no setup inicial
      const payload = { ...newUserData, role: UserRole.MASTER };
      const res = await fetch(`${API_URL}?action=save_user`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload)
      });
      const data = await res.json();
      if (data.status === 'success') {
        setSetupRequired(false);
        setLoginData({ username: newUserData.username, password: newUserData.password });
        setNewUserData({ name: '', username: '', password: '', role: UserRole.OPERATOR });
      }
    } catch (e) {
      setError('Erro no setup inicial.');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('nexus_user');
    setActiveTab('dashboard');
  };

  const handleSaveUser = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const res = await fetch(`${API_URL}?action=save_user`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newUserData)
      });
      const data = await res.json();
      if (data.status === 'success') {
        setShowUserModal(false);
        setNewUserData({ name: '', username: '', password: '', role: UserRole.OPERATOR });
        loadData();
      }
    } catch (e) {
      console.error(e);
    }
  };

  const handleSaveCert = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const certToSave = { ...newCertData, id: `CERT-${Math.floor(Math.random()*10000)}` };
      const res = await fetch(`${API_URL}?action=save_certificate`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(certToSave)
      });
      const data = await res.json();
      if (data.status === 'success') {
        setShowCertModal(false);
        setNewCertData({ id: '', alias: '', expirationDate: '', state: 'SP', status: 'Ativo', type: 'A1' });
        loadData();
      }
    } catch (e) {
      console.error(e);
    }
  };

  const stats = useMemo(() => {
    const successful = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const pixTotal = successful.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    const fiscalAuthorized = transactions.filter(t => t.fiscalStatus === FiscalStatus.AUTHORIZED).length;

    return { 
      total: successful.reduce((acc, curr) => acc + Number(curr.amount), 0),
      pixShare: ((pixTotal / (successful.reduce((a, b) => a + Number(b.amount), 0) || 1)) * 100).toFixed(1),
      fiscalHealth: ((fiscalAuthorized / (transactions.filter(t => t.fiscalNoteId).length || 1)) * 100).toFixed(1),
      count: transactions.length 
    };
  }, [transactions]);

  useEffect(() => {
    if (transactions.length > 0) {
      getSmartInsights(transactions).then(setInsights);
    }
  }, [transactions]);

  const simulateTransaction = async () => {
    setIsSimulating(true);
    const isPix = Math.random() > 0.5;
    const newTx: Transaction = {
      id: `TX-${Math.floor(1000 + Math.random() * 9000)}`,
      timestamp: new Date().toISOString().slice(0, 19).replace('T', ' '),
      amount: parseFloat((Math.random() * 200 + 10).toFixed(2)),
      method: isPix ? PaymentMethod.PIX : PaymentMethod.CREDIT,
      segment: 'Varejo Geral',
      status: PaymentStatus.SUCCESS,
      terminalId: 'PDV-01',
      fiscalNoteId: Math.random() > 0.1 ? String(Math.floor(6000 + Math.random() * 1000)) : undefined,
      fiscalStatus: Math.random() > 0.1 ? FiscalStatus.AUTHORIZED : FiscalStatus.CONTINGENCY
    };

    try {
      await fetch(`${API_URL}?action=save_transaction`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newTx)
      });
      setTransactions(prev => [newTx, ...prev]);
    } catch (e) {} finally { setIsSimulating(false); }
  };

  // Render Setup Screen
  if (setupRequired) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6">
        <div className="bg-white p-12 rounded-[3rem] w-full max-w-lg shadow-2xl animate-in fade-in duration-700">
          <div className="flex flex-col items-center mb-8">
            <div className="w-20 h-20 bg-indigo-600 rounded-[2rem] flex items-center justify-center text-4xl font-black text-white mb-6 shadow-2xl shadow-indigo-200">N</div>
            <h1 className="text-3xl font-black text-slate-900">Configuração Inicial</h1>
            <p className="text-slate-400 font-bold text-xs uppercase tracking-widest mt-2">Crie sua Conta Master Nexus</p>
          </div>

          <form onSubmit={handleSetup} className="space-y-5">
            <div className="grid grid-cols-1 gap-4">
              <input 
                type="text" placeholder="Nome Completo (Ex: Administrador)" required
                value={newUserData.name} onChange={e => setNewUserData({...newUserData, name: e.target.value})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-4 px-6 text-slate-800 font-medium"
              />
              <input 
                type="text" placeholder="Usuário (Login)" required
                value={newUserData.username} onChange={e => setNewUserData({...newUserData, username: e.target.value})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-4 px-6 text-slate-800 font-medium"
              />
              <input 
                type="password" placeholder="Senha Master (Ex: 12345678)" required
                value={newUserData.password} onChange={e => setNewUserData({...newUserData, password: e.target.value})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-4 px-6 text-slate-800 font-medium"
              />
            </div>
            <button className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-widest hover:bg-indigo-700 shadow-xl transition-all">
              Finalizar Instalação
            </button>
          </form>
        </div>
      </div>
    );
  }

  if (!currentUser) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-6">
        <div className="bg-white p-12 rounded-[3rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300">
          <div className="flex flex-col items-center mb-10">
            <div className="w-16 h-16 bg-indigo-600 rounded-3xl flex items-center justify-center text-3xl font-black text-white mb-4 shadow-xl shadow-indigo-200">N</div>
            <h1 className="text-3xl font-black text-slate-900">NexusTEF</h1>
            <p className="text-slate-400 font-bold text-[10px] uppercase tracking-[0.3em] mt-1">Acesso Restrito</p>
          </div>

          <form onSubmit={handleLogin} className="space-y-6">
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Usuário</label>
              <input 
                type="text" 
                value={loginData.username}
                onChange={e => setLoginData({...loginData, username: e.target.value})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-4 px-6 text-slate-800 focus:ring-2 focus:ring-indigo-500 transition-all font-medium"
                placeholder="Ex: master"
                required
              />
            </div>
            <div>
              <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2 px-1">Senha</label>
              <input 
                type="password" 
                value={loginData.password}
                onChange={e => setLoginData({...loginData, password: e.target.value})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-4 px-6 text-slate-800 focus:ring-2 focus:ring-indigo-500 transition-all font-medium"
                placeholder="••••••••"
                required
              />
            </div>
            {error && <div className="p-4 bg-rose-50 text-rose-600 rounded-2xl text-xs font-bold text-center">{error}</div>}
            <button className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-widest hover:bg-indigo-700 shadow-xl shadow-indigo-100 transition-all">
              Entrar no Nexus
            </button>
          </form>
          <p className="text-center mt-8 text-[10px] text-slate-300 font-bold uppercase tracking-widest">v5.0.0 Alpha Build</p>
        </div>
      </div>
    );
  }

  const renderDashboard = () => (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard label="Vendas Brutas" value={`R$ ${stats.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} icon="💰" color="bg-indigo-50 text-indigo-600" />
        <StatCard label="Penetração PIX" value={`${stats.pixShare}%`} icon="⚡" color="bg-emerald-50 text-emerald-600" />
        <StatCard label="Saúde Fiscal" value={`${stats.fiscalHealth}%`} icon="📑" color="bg-blue-50 text-blue-600" />
        <StatCard label="Total Transações" value={stats.count} icon="🔄" color="bg-slate-50 text-slate-600" />
      </div>
      <FiscalMonitor states={SEFAZ_STATES} />
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
          <h3 className="text-xl font-black text-slate-800 mb-8 tracking-tight">Fluxo de Caixa</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={CHART_DATA}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                <Tooltip />
                <Area type="monotone" dataKey="valor" stroke="#6366f1" strokeWidth={3} fill="#6366f110" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>
        <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white flex flex-col">
          <h3 className="text-xl font-bold mb-6">✨ IA Consultora</h3>
          <div className="flex-1 bg-white/5 rounded-3xl p-5 text-sm leading-relaxed overflow-auto">{insights}</div>
        </div>
      </div>
    </div>
  );

  const renderUsers = () => (
    <div className="space-y-8 animate-in slide-in-from-bottom-8 duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h3 className="text-2xl font-black text-slate-900">Gerenciamento de Equipe</h3>
          <p className="text-slate-500 text-sm">Controle quem tem acesso ao painel NexusTEF.</p>
        </div>
        <button 
          onClick={() => setShowUserModal(true)}
          className="px-6 py-3 bg-indigo-600 text-white rounded-2xl font-bold text-sm shadow-lg hover:scale-105 transition-all"
        >
          + Novo Usuário
        </button>
      </div>
      <div className="bg-white rounded-[2.5rem] border border-slate-100 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nome Completo</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Login</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nível</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Criado em</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {usersList.map(u => (
              <tr key={u.id} className="hover:bg-slate-50/50 transition-colors">
                <td className="px-8 py-5">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-xl flex items-center justify-center font-bold">{u.name.charAt(0)}</div>
                    <span className="font-bold text-slate-800">{u.name}</span>
                  </div>
                </td>
                <td className="px-8 py-5 text-sm font-mono text-slate-500">@{u.username}</td>
                <td className="px-8 py-5">
                  <span className={`px-3 py-1 rounded-full text-[10px] font-black ${
                    u.role === UserRole.MASTER ? 'bg-indigo-100 text-indigo-700' : 
                    u.role === UserRole.ADMIN ? 'bg-blue-100 text-blue-700' : 'bg-slate-100 text-slate-600'
                  }`}>{u.role}</span>
                </td>
                <td className="px-8 py-5 text-xs text-slate-400">{u.created_at ? new Date(u.created_at).toLocaleDateString('pt-BR') : 'Original'}</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {showUserModal && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-6">
          <div className="bg-white p-10 rounded-[3rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-200">
            <h3 className="text-2xl font-black text-slate-900 mb-6 tracking-tight">Cadastrar Usuário</h3>
            <form onSubmit={handleSaveUser} className="space-y-4">
              <input 
                type="text" placeholder="Nome Completo" required
                value={newUserData.name} onChange={e => setNewUserData({...newUserData, name: e.target.value})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium"
              />
              <input 
                type="text" placeholder="Login de Acesso" required
                value={newUserData.username} onChange={e => setNewUserData({...newUserData, username: e.target.value})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium"
              />
              <input 
                type="password" placeholder="Senha" required
                value={newUserData.password} onChange={e => setNewUserData({...newUserData, password: e.target.value})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium"
              />
              <select 
                value={newUserData.role} onChange={e => setNewUserData({...newUserData, role: e.target.value as any})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium"
              >
                <option value={UserRole.MASTER}>MASTER (Acesso Total)</option>
                <option value={UserRole.ADMIN}>ADMINISTRADOR (Vendas + Fiscal)</option>
                <option value={UserRole.OPERATOR}>OPERADOR (Apenas Vendas)</option>
              </select>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowUserModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-lg shadow-indigo-100">Salvar</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );

  const renderCertificates = () => (
    <div className="space-y-8 animate-in slide-in-from-right-4 duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h3 className="text-2xl font-black text-slate-900">Certificados Digitais</h3>
          <p className="text-slate-500 text-sm">Configuração de emissão NFC-e por UF.</p>
        </div>
        <button 
          onClick={() => setShowCertModal(true)}
          className="px-6 py-3 bg-indigo-600 text-white rounded-2xl font-bold text-sm shadow-lg hover:scale-105 transition-all"
        >
          + Novo Certificado
        </button>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        {certificates.map(cert => (
          <div key={cert.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm hover:shadow-md transition-shadow">
            <span className="text-[10px] font-black text-indigo-500 uppercase mb-2 block">{cert.type} - {cert.state}</span>
            <h4 className="font-bold text-slate-800">{cert.alias}</h4>
            <div className="flex justify-between items-center mt-4">
              <p className="text-xs text-slate-400 font-medium">Vencimento: {new Date(cert.expirationDate).toLocaleDateString('pt-BR')}</p>
              <div className={`px-2 py-0.5 rounded text-[8px] font-black uppercase ${cert.status === 'Ativo' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>
                {cert.status}
              </div>
            </div>
          </div>
        ))}
      </div>

      {showCertModal && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-50 flex items-center justify-center p-6">
          <div className="bg-white p-10 rounded-[3rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-200">
            <h3 className="text-2xl font-black text-slate-900 mb-6 tracking-tight">Novo Certificado</h3>
            <form onSubmit={handleSaveCert} className="space-y-4">
              <input 
                type="text" placeholder="Nome/Apelido" required
                value={newCertData.alias} onChange={e => setNewCertData({...newCertData, alias: e.target.value})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium"
              />
              <div className="grid grid-cols-2 gap-4">
                <input 
                  type="date" required
                  value={newCertData.expirationDate} onChange={e => setNewCertData({...newCertData, expirationDate: e.target.value})}
                  className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium"
                />
                <select 
                  value={newCertData.state} onChange={e => setNewCertData({...newCertData, state: e.target.value})}
                  className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium"
                >
                  <option value="SP">São Paulo</option>
                  <option value="RJ">Rio de Janeiro</option>
                  <option value="MG">Minas Gerais</option>
                  <option value="BA">Bahia</option>
                </select>
              </div>
              <select 
                value={newCertData.type} onChange={e => setNewCertData({...newCertData, type: e.target.value as any})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium"
              >
                <option value="A1">Certificado A1 (Arquivo)</option>
                <option value="A3">Certificado A3 (Token/Cartão)</option>
              </select>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowCertModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-bold">Configurar</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} currentUser={currentUser} onLogout={handleLogout} />
      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-20 bg-white/70 backdrop-blur-md border-b border-slate-100 sticky top-0 z-40 flex items-center justify-between px-10">
          <div className="flex flex-col">
            <h2 className="text-xl font-black text-slate-900 leading-none">Nexus Hub</h2>
            <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-wider mt-1">{activeTab}</span>
          </div>
          <div className="flex items-center gap-4">
            <div className="text-right">
              <p className="text-xs font-black text-slate-900 leading-tight">{currentUser.name}</p>
              <p className="text-[9px] text-indigo-600 font-bold uppercase tracking-widest">{currentUser.role}</p>
            </div>
            <div className="w-10 h-10 bg-indigo-50 text-indigo-600 rounded-2xl flex items-center justify-center border border-indigo-100 shadow-inner font-bold">
              {currentUser.name.charAt(0)}
            </div>
          </div>
        </header>
        <main className="p-10 max-w-[1400px] w-full mx-auto">
          {activeTab === 'dashboard' && renderDashboard()}
          {activeTab === 'users' && renderUsers()}
          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}
          {activeTab === 'fiscal' && (
            <div className="space-y-6">
               <h3 className="text-2xl font-black text-slate-900">Monitor Fiscal NFC-e</h3>
               <TransactionTable transactions={transactions.filter(t => !!t.fiscalNoteId)} />
            </div>
          )}
          {activeTab === 'certificates' && renderCertificates()}
          {activeTab === 'simulator' && (
            <div className="max-w-xl mx-auto py-20 text-center">
              <div className="bg-white p-12 rounded-[3rem] shadow-2xl border border-slate-100">
                <div className="text-6xl mb-8">💳</div>
                <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Simulador de Transação</h3>
                <div className="flex gap-4">
                    <button onClick={simulateTransaction} disabled={isSimulating} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase hover:bg-indigo-700 shadow-xl transition-all">
                      {isSimulating ? '⌛' : 'Cartão'}
                    </button>
                    <button onClick={simulateTransaction} disabled={isSimulating} className="flex-1 py-5 bg-emerald-600 text-white rounded-2xl font-black uppercase hover:bg-emerald-700 shadow-xl transition-all">
                      {isSimulating ? '⌛' : 'PIX'}
                    </button>
                </div>
              </div>
            </div>
          )}
        </main>
      </div>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES, MOCK_TRANSACTIONS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginData, setLoginData] = useState({ username: '', password: '' });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [insights, setInsights] = useState<string>('Auditando registros fiscais...');
  const [isSimulating, setIsSimulating] = useState(false);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [setupRequired, setSetupRequired] = useState<boolean>(false);
  const [showLoginModal, setShowLoginModal] = useState(false);

  // Modal States
  const [showUserModal, setShowUserModal] = useState(false);
  const [showCertModal, setShowCertModal] = useState(false);
  const [newUserData, setNewUserData] = useState({ name: '', username: '', password: '', role: UserRole.MASTER });
  const [newCertData, setNewCertData] = useState({ id: '', alias: '', expirationDate: '', state: 'SP', status: 'Ativo' as any, type: 'A1' as any });

  // Persistence and Setup Check
  useEffect(() => {
    const checkSetup = async () => {
      try {
        const res = await fetch(`${API_URL}?action=check_setup`);
        const data = await res.json();
        setSetupRequired(data.setup_required);
      } catch (e) {
        console.error("Erro ao verificar banco de dados", e);
      }

      const saved = localStorage.getItem('nexus_user');
      if (saved) {
        setCurrentUser(JSON.parse(saved));
      }
      setLoading(false);
    };
    checkSetup();
  }, []);

  const loadData = async () => {
    try {
      const [txRes, certRes] = await Promise.all([
        fetch(`${API_URL}?action=get_transactions`),
        fetch(`${API_URL}?action=get_certificates`)
      ]);

      const txData = await txRes.json();
      const certData = await certRes.json();

      // Use mock if DB is empty for visual feedback, otherwise use real data
      setTransactions(Array.isArray(txData) && txData.length > 0 ? txData : MOCK_TRANSACTIONS);

      if (Array.isArray(certData)) {
        const mappedCerts = certData.map(c => ({
          ...c,
          expirationDate: c.expiration_date || c.expirationDate
        }));
        setCertificates(mappedCerts);
      }

      // Se for master ou se o sistema estiver em setup, carrega lista de usuários
      if (currentUser?.role === UserRole.MASTER || setupRequired) {
        const userRes = await fetch(`${API_URL}?action=get_users`);
        const userData = await userRes.json();
        if (Array.isArray(userData)) setUsersList(userData);
      }
    } catch (error) {
      console.error("API Error:", error);
    }
  };

  useEffect(() => {
    loadData();
  }, [currentUser, setupRequired]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    try {
      const res = await fetch(`${API_URL}?action=login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(loginData)
      });
      const data = await res.json();
      if (data.status === 'success') {
        setCurrentUser(data.user);
        localStorage.setItem('nexus_user', JSON.stringify(data.user));
        setShowLoginModal(false);
      } else {
        setError(data.message);
      }
    } catch (err) {
      setError('Erro de conexão com servidor.');
    }
  };

  const handleLogout = () => {
    setCurrentUser(null);
    localStorage.removeItem('nexus_user');
    setActiveTab('dashboard');
  };

  const handleSaveUser = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const res = await fetch(`${API_URL}?action=save_user`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newUserData)
      });
      const data = await res.json();
      if (data.status === 'success') {
        setShowUserModal(false);
        setNewUserData({ name: '', username: '', password: '', role: UserRole.OPERATOR });
        // Se for o primeiro usuário, atualiza o estado de setup
        const setupCheck = await fetch(`${API_URL}?action=check_setup`);
        const setupData = await setupCheck.json();
        setSetupRequired(setupData.setup_required);
        loadData();
      }
    } catch (e) {
      console.error(e);
    }
  };

  const handleSaveCert = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const certToSave = { ...newCertData, id: `CERT-${Math.floor(Math.random()*10000)}` };
      const res = await fetch(`${API_URL}?action=save_certificate`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(certToSave)
      });
      const data = await res.json();
      if (data.status === 'success') {
        setShowCertModal(false);
        setNewCertData({ id: '', alias: '', expirationDate: '', state: 'SP', status: 'Ativo', type: 'A1' });
        loadData();
      }
    } catch (e) {
      console.error(e);
    }
  };

  const stats = useMemo(() => {
    const successful = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const pixTotal = successful.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    const fiscalAuthorized = transactions.filter(t => t.fiscalStatus === FiscalStatus.AUTHORIZED).length;

    return { 
      total: successful.reduce((acc, curr) => acc + Number(curr.amount), 0),
      pixShare: ((pixTotal / (successful.reduce((a, b) => a + Number(b.amount), 0) || 1)) * 100).toFixed(1),
      fiscalHealth: ((fiscalAuthorized / (transactions.filter(t => t.fiscalNoteId).length || 1)) * 100).toFixed(1),
      count: transactions.length 
    };
  }, [transactions]);

  useEffect(() => {
    if (transactions.length > 0) {
      getSmartInsights(transactions).then(setInsights);
    }
  }, [transactions]);

  const simulateTransaction = async () => {
    setIsSimulating(true);
    const isPix = Math.random() > 0.5;
    const newTx: Transaction = {
      id: `TX-${Math.floor(1000 + Math.random() * 9000)}`,
      timestamp: new Date().toISOString().slice(0, 19).replace('T', ' '),
      amount: parseFloat((Math.random() * 200 + 10).toFixed(2)),
      method: isPix ? PaymentMethod.PIX : PaymentMethod.CREDIT,
      segment: 'Varejo Geral',
      status: PaymentStatus.SUCCESS,
      terminalId: 'PDV-01',
      fiscalNoteId: Math.random() > 0.1 ? String(Math.floor(6000 + Math.random() * 1000)) : undefined,
      fiscalStatus: Math.random() > 0.1 ? FiscalStatus.AUTHORIZED : FiscalStatus.CONTINGENCY
    };

    try {
      await fetch(`${API_URL}?action=save_transaction`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newTx)
      });
      loadData();
    } catch (e) {} finally { setIsSimulating(false); }
  };

  const renderDashboard = () => (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard label="Vendas Brutas" value={`R$ ${stats.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} icon="💰" color="bg-indigo-50 text-indigo-600" />
        <StatCard label="Penetração PIX" value={`${stats.pixShare}%`} icon="⚡" color="bg-emerald-50 text-emerald-600" />
        <StatCard label="Saúde Fiscal" value={`${stats.fiscalHealth}%`} icon="📑" color="bg-blue-50 text-blue-600" />
        <StatCard label="Total Transações" value={stats.count} icon="🔄" color="bg-slate-50 text-slate-600" />
      </div>
      <FiscalMonitor states={SEFAZ_STATES} />
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
