                    <button onClick={simulateTransaction} disabled={isSimulating} className="flex-1 py-5 bg-emerald-600 text-white rounded-2xl font-black uppercase tracking-widest hover:bg-emerald-700 shadow-xl transition-all">
                      {isSimulating ? '⌛' : 'PIX'}
                    </button>
                </div>
              </div>
            </div>
          )}
        </main>
      </div>

      {showLoginModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[3rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300">
            <div className="flex flex-col items-center mb-10">
              <div className="w-16 h-16 bg-indigo-600 rounded-3xl flex items-center justify-center text-3xl font-black text-white mb-4 shadow-xl">N</div>
              <h1 className="text-3xl font-black text-slate-900">Nexus Login</h1>
            </div>
            <form onSubmit={handleLogin} className="space-y-6">
              <input 
                type="text" placeholder="Usuário" required
                value={loginData.username} onChange={e => setLoginData({...loginData, username: e.target.value})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-4 px-6 font-medium"
              />
              <input 
                type="password" placeholder="Senha" required
                value={loginData.password} onChange={e => setLoginData({...loginData, password: e.target.value})}
                className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-4 px-6 font-medium"
              />
              {error && <div className="p-4 bg-rose-50 text-rose-600 rounded-2xl text-xs font-bold text-center">{error}</div>}
              <div className="flex gap-4">
                <button type="button" onClick={() => setShowLoginModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold">Voltar</button>
                <button type="submit" className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl">Entrar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showCertModal && (
        <div className="fixed inset-0 bg-slate-900/40 backdrop-blur-sm z-[60] flex items-center justify-center p-6">
          <div className="bg-white p-10 rounded-[3rem] w-full max-w-md shadow-2xl">
            <h3 className="text-2xl font-black text-slate-900 mb-6">Novo Certificado</h3>
            <form onSubmit={handleSaveCert} className="space-y-4">
              <input type="text" placeholder="Apelido" required className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" value={newCertData.alias} onChange={e => setNewCertData({...newCertData, alias: e.target.value})} />
              <input type="date" required className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" value={newCertData.expirationDate} onChange={e => setNewCertData({...newCertData, expirationDate: e.target.value})} />
              <select className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" value={newCertData.state} onChange={e => setNewCertData({...newCertData, state: e.target.value})}>
                <option value="SP">São Paulo</option>
                <option value="RJ">Rio de Janeiro</option>
                <option value="MG">Minas Gerais</option>
              </select>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowCertModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-bold">Salvar</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

