            <div className={`w-2 h-2 rounded-full animate-pulse ${currentUser ? 'bg-emerald-500' : 'bg-amber-500'}`}></div>
            <p className="text-xs font-bold text-slate-200">
              {currentUser ? `User: ${currentUser.username}` : 'Modo Visitante'}
