export const CHART_DATA = [
  { name: 'Seg', valor: 450, pix: 120 },
  { name: 'Ter', valor: 890, pix: 340 },
  { name: 'Qua', valor: 1200, pix: 560 },
  { name: 'Qui', valor: 1500, pix: 890 },
