                <p className="text-slate-500 font-medium mb-10">Simule o fluxo completo de pagamento TEF com integração fiscal automática.</p>
                <div className="grid grid-cols-2 gap-6">
                    <button onClick={() => simulateTransaction(PaymentMethod.CREDIT)} disabled={isSimulating} className="group relative py-6 bg-slate-900 text-white rounded-3xl font-black uppercase tracking-widest overflow-hidden transition-all hover:scale-[1.02]">
                      <span className="relative z-10">{isSimulating ? 'PROCESSANDO...' : '💳 Cartão'}</span>
                      <div className="absolute inset-0 bg-indigo-600 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
                    </button>
                    <button onClick={() => simulateTransaction(PaymentMethod.PIX)} disabled={isSimulating} className="group relative py-6 bg-emerald-600 text-white rounded-3xl font-black uppercase tracking-widest overflow-hidden transition-all hover:scale-[1.02]">
                      <span className="relative z-10">{isSimulating ? 'GERANDO...' : '⚡ Pix'}</span>
                      <div className="absolute inset-0 bg-emerald-700 translate-y-full group-hover:translate-y-0 transition-transform duration-300"></div>
                    </button>
                </div>
                <div className="mt-8 flex items-center justify-center gap-8 border-t border-slate-50 pt-8">
                   <div className="text-center">
                      <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Status SEFAZ</p>
                      <p className="text-xs font-bold text-emerald-500">AUTORIZANDO</p>
                   </div>
                   <div className="w-px h-8 bg-slate-100"></div>
                   <div className="text-center">
                      <p className="text-[10px] font-black text-slate-400 uppercase mb-1">Terminal</p>
                      <p className="text-xs font-bold text-slate-700">POS-NEXUS-01</p>
                   </div>
                </div>
              </div>
            </div>
          )}
        </main>
      </div>

      {/* PIX Modal Dinâmico */}
      {showPixModal && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[100] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300 text-center relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-2 bg-emerald-500"></div>
            <div className="flex justify-between items-center mb-8">
              <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">ID: {showPixModal.id}</span>
