            </div>
            <h3 className="text-2xl font-black text-slate-900 mb-2">Pagamento com Pix</h3>
            <p className="text-slate-500 font-bold text-sm mb-8">R$ {showPixModal.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>

            <div className="bg-slate-50 p-6 rounded-[2.5rem] mb-8 border border-slate-100">
               <img src={showPixModal.pixQrCode} alt="PIX QR Code" className="w-full h-auto rounded-3xl mix-blend-multiply" />
            </div>

            <div className="space-y-4">
              <button onClick={() => { navigator.clipboard.writeText(showPixModal.pixCopyPaste || ''); alert('Código copiado!'); }} className="w-full py-4 bg-emerald-50 text-emerald-700 rounded-2xl font-black text-xs uppercase tracking-widest border border-emerald-100 hover:bg-emerald-100 transition-all">
                Copiar Código Pix
              </button>
              <div className="flex items-center justify-center gap-3 text-emerald-600 font-bold animate-pulse text-xs">
                 <div className="w-2 h-2 bg-emerald-500 rounded-full"></div> Aguardando confirmação...
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Modal Certificado Simplificado */}
      {showCertModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[3rem] w-full max-w-md shadow-2xl">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Vincular Certificado Digital</h3>
            <form className="space-y-5" onSubmit={(e) => { e.preventDefault(); setShowCertModal(false); }}>
              <input type="text" placeholder="Nome do Certificado (Ex: Matriz RS)" required className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" />
              <div className="grid grid-cols-2 gap-4">
                <select className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium">
                  {ALL_UFS.map(uf => <option key={uf} value={uf}>{uf}</option>)}
                </select>
                <select className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium">
                  <option>A1 - Arquivo</option>
                  <option>A3 - Token</option>
                </select>
              </div>
              <div className="p-8 border-2 border-dashed border-slate-100 rounded-[2rem] text-center bg-slate-50/50">
                 <p className="text-[10px] font-black text-slate-400 uppercase mb-2">Arraste seu arquivo .pfx aqui</p>
                 <span className="text-xs text-indigo-600 font-bold underline">ou clique para selecionar</span>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowCertModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold uppercase text-[10px]">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl uppercase text-[10px]">Salvar e Ativar</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

