      if (currentUser?.role === UserRole.MASTER || setupRequired) {
        const userRes = await fetch(`${API_URL}?action=get_users`);
        const userData = await userRes.json();
        if (Array.isArray(userData)) setUsersList(userData);
      }
    } catch (error) { console.error(error); }
  };

  useEffect(() => { loadData(); }, [currentUser, setupRequired]);

