                        <span className="text-lg font-black text-slate-900">{uf}</span>
                        <div className={`w-2 h-2 rounded-full ${cert ? (cert.status === 'Ativo' ? 'bg-emerald-500' : 'bg-rose-500') : 'bg-slate-300'}`}></div>
                      </div>
                      <p className="text-[9px] font-black text-slate-400 uppercase truncate">{cert ? cert.alias : 'Vazio'}</p>
                    </div>
