                })}
              </div>
            </div>
          )}
          {activeTab === 'simulator' && (
            <div className="max-w-2xl mx-auto py-10 space-y-8">
              <div className="bg-white p-12 rounded-[3.5rem] shadow-2xl border border-slate-100 text-center">
                <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-[2rem] flex items-center justify-center text-4xl mx-auto mb-8">⚡</div>
                <h3 className="text-3xl font-black text-slate-900 mb-10 tracking-tight">Checkout Nexus</h3>
                <div className="grid grid-cols-2 gap-6">
                    <button onClick={() => simulateTransaction(PaymentMethod.CREDIT)} disabled={isSimulating} className="py-6 bg-slate-900 text-white rounded-3xl font-black uppercase tracking-widest hover:scale-105 transition-all shadow-xl">💳 Cartão</button>
                    <button onClick={() => simulateTransaction(PaymentMethod.PIX)} disabled={isSimulating} className="py-6 bg-emerald-600 text-white rounded-3xl font-black uppercase tracking-widest hover:scale-105 transition-all shadow-xl">⚡ Pix</button>
                </div>
              </div>
            </div>
          )}
        </main>
      </div>

      {showLoginModal && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300">
            <div className="flex flex-col items-center mb-10">
              <div className="w-20 h-20 bg-indigo-600 rounded-[2rem] flex items-center justify-center text-4xl font-black text-white mb-6 shadow-2xl shadow-indigo-200">N</div>
              <h1 className="text-3xl font-black text-slate-900 tracking-tight">Bem-vindo</h1>
              <p className="text-slate-400 font-bold text-xs uppercase tracking-widest mt-2">Acesso ao Hub NexusTEF</p>
            </div>
            <form onSubmit={handleLogin} className="space-y-6">
              <input type="text" placeholder="Usuário" required value={loginData.username} onChange={e => setLoginData({...loginData, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-5 px-6 font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all" />
              <input type="password" placeholder="Senha" required value={loginData.password} onChange={e => setLoginData({...loginData, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-5 px-6 font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all" />
