};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES, MOCK_TRANSACTIONS, ALL_UFS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginData, setLoginData] = useState({ username: '', password: '' });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [insights, setInsights] = useState<string>('Analizando métricas de Pix e Notas Fiscais...');
  const [isSimulating, setIsSimulating] = useState(false);
  const [setupRequired, setSetupRequired] = useState<boolean>(false);
  const [showPixModal, setShowPixModal] = useState<Transaction | null>(null);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [error, setError] = useState<string | null>(null);

  // User Management Modal States
  const [showUserModal, setShowUserModal] = useState(false);
  const [isConfirmingUser, setIsConfirmingUser] = useState(false);
  const [isSavingUser, setIsSavingUser] = useState(false);
  const [userModalError, setUserModalError] = useState<string | null>(null);
  const [newUserData, setNewUserData] = useState({ name: '', username: '', password: '', role: UserRole.OPERATOR });

  // Certificate Modal States
  const [showCertModal, setShowCertModal] = useState(false);
  const [newCertData, setNewCertData] = useState({ id: '', alias: '', expirationDate: '', state: 'SP', status: 'Ativo' as any, type: 'A1' as any });

  useEffect(() => {
    const init = async () => {
      try {
        const res = await fetch(`${API_URL}?action=check_setup`);
        const data = await res.json();
        setSetupRequired(data.setup_required);
      } catch (e) { console.error(e); }

      const saved = localStorage.getItem('nexus_user');
      if (saved) setCurrentUser(JSON.parse(saved));
    };
    init();
  }, []);

  const loadData = async () => {
    try {
      const [txRes, certRes] = await Promise.all([
        fetch(`${API_URL}?action=get_transactions`),
        fetch(`${API_URL}?action=get_certificates`)
      ]);
      const txData = await txRes.json();
      const certData = await certRes.json();

      setTransactions(Array.isArray(txData) && txData.length > 0 ? txData : MOCK_TRANSACTIONS);
      if (Array.isArray(certData)) setCertificates(certData);

      if (currentUser?.role === UserRole.MASTER || setupRequired) {
        const userRes = await fetch(`${API_URL}?action=get_users`);
        const userData = await userRes.json();
        if (Array.isArray(userData)) setUsersList(userData);
      }
    } catch (error) { console.error(error); }
  };

  useEffect(() => { loadData(); }, [currentUser, setupRequired]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    try {
      const res = await fetch(`${API_URL}?action=login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(loginData)
      });
      const data = await res.json();
      if (data.status === 'success') {
        setCurrentUser(data.user);
        localStorage.setItem('nexus_user', JSON.stringify(data.user));
        setShowLoginModal(false);
      } else {
        setError(data.message);
      }
    } catch (err) {
      setError('Erro de conexão com servidor.');
    }
  };

  const handleOpenUserModal = (role: UserRole) => {
    setNewUserData({ name: '', username: '', password: '', role });
    setIsConfirmingUser(false);
    setUserModalError(null);
    setShowUserModal(true);
  };

  const handleSaveUser = async () => {
    setIsSavingUser(true);
    setUserModalError(null);
    try {
      const res = await fetch(`${API_URL}?action=save_user`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newUserData)
      });
      const data = await res.json();
      if (data.status === 'success') {
        setShowUserModal(false);
        setIsConfirmingUser(false);
        setNewUserData({ name: '', username: '', password: '', role: UserRole.OPERATOR });
        const setupCheck = await fetch(`${API_URL}?action=check_setup`);
        const setupData = await setupCheck.json();
        setSetupRequired(setupData.setup_required);
        loadData();
      } else {
        setUserModalError(data.message || 'Erro ao cadastrar usuário.');
      }
    } catch (e) { 
      setUserModalError('Falha de rede ao tentar salvar.');
    } finally {
      setIsSavingUser(false);
    }
  };

  const stats = useMemo(() => {
    const success = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const pix = success.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    const authorized = transactions.filter(t => t.fiscalStatus === FiscalStatus.AUTHORIZED).length;
    return {
      total: success.reduce((a, b) => a + Number(b.amount), 0),
      pixPercent: ((pix / (success.reduce((a, b) => a + Number(b.amount), 0) || 1)) * 100).toFixed(1),
      fiscalHealth: ((authorized / (transactions.filter(t => t.fiscalNoteId).length || 1)) * 100).toFixed(1),
      txCount: transactions.length
    };
  }, [transactions]);

  useEffect(() => {
    if (transactions.length > 0) getSmartInsights(transactions).then(setInsights);
  }, [transactions]);

  const simulateTransaction = async (method: PaymentMethod) => {
    setIsSimulating(true);
    const txId = `TX-${Math.floor(10000 + Math.random() * 90000)}`;
    const newTx: Transaction = {
      id: txId,
      timestamp: new Date().toISOString(),
      amount: parseFloat((Math.random() * 500 + 5).toFixed(2)),
      method,
      segment: 'Varejo Digital',
      status: method === PaymentMethod.PIX ? PaymentStatus.PENDING : PaymentStatus.SUCCESS,
      terminalId: 'WEB-API',
      fiscalNoteId: method === PaymentMethod.PIX ? undefined : String(Math.floor(10000 + Math.random() * 9000)),
      fiscalStatus: method === PaymentMethod.PIX ? undefined : FiscalStatus.AUTHORIZED,
      pixQrCode: method === PaymentMethod.PIX ? 'https://api.qrserver.com/v1/create-qr-code/?size=300x300&data=NEXUSTEF-SIMULATED-PIX-KEY' : undefined,
      pixCopyPaste: method === PaymentMethod.PIX ? '00020126580014BR.GOV.BCB.PIX0136NEXUSTEF-PAYMENT-ID-' + txId : undefined
    };

    try {
      await fetch(`${API_URL}?action=save_transaction`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newTx)
      });
      loadData();
      if (method === PaymentMethod.PIX) setShowPixModal(newTx);
    } catch (e) { console.error(e); } finally { setIsSimulating(false); }
  };

  const renderDashboard = () => (
    <div className="space-y-8 animate-in fade-in duration-700">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard label="Volume Total" value={`R$ ${stats.total.toLocaleString('pt-BR')}`} icon="💰" color="bg-indigo-50 text-indigo-600" />
        <StatCard label="Mix de Pix" value={`${stats.pixPercent}%`} icon="⚡" color="bg-emerald-50 text-emerald-600" />
        <StatCard label="Sefaz Conectada" value={`${stats.fiscalHealth}%`} icon="📑" color="bg-blue-50 text-blue-600" />
        <StatCard label="Transações" value={stats.txCount} icon="🔄" color="bg-slate-50 text-slate-600" />
      </div>
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm">
          <h3 className="text-xl font-black text-slate-800 mb-8 tracking-tight">Crescimento Semanal</h3>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={CHART_DATA}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                <Tooltip />
                <Area type="monotone" dataKey="valor" stroke="#6366f1" strokeWidth={3} fillOpacity={0.1} fill="#6366f1" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>
        <div className="bg-slate-900 p-8 rounded-[3rem] text-white flex flex-col shadow-2xl">
          <h3 className="text-xl font-black mb-8">Nexus AI Insights</h3>
          <div className="flex-1 bg-white/5 rounded-[2rem] p-6 text-sm italic text-slate-300 overflow-auto">
            "{insights}"
          </div>
        </div>
      </div>
      <FiscalMonitor states={SEFAZ_STATES} />
    </div>
  );

  const renderUsers = () => (
    <div className="space-y-8 animate-in slide-in-from-bottom duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Usuários</h3>
          <p className="text-slate-500 font-medium">Controle de acessos e níveis de privilégio do sistema.</p>
        </div>
        <div className="flex gap-3">
          <button 
            onClick={() => handleOpenUserModal(UserRole.OPERATOR)}
            className="px-6 py-3 bg-indigo-600 text-white rounded-2xl font-bold text-sm shadow-lg hover:scale-105 transition-all flex items-center gap-2"
          >
            <span>👤</span> Cadastrar Usuário
          </button>
          <button 
            onClick={() => handleOpenUserModal(UserRole.MASTER)}
            className="px-6 py-3 bg-amber-500 text-white rounded-2xl font-bold text-sm shadow-lg hover:scale-105 transition-all flex items-center gap-2"
          >
            <span>👑</span> Cadastrar Master
          </button>
        </div>
      </div>

      {setupRequired && (
        <div className="p-6 bg-amber-50 border border-amber-100 rounded-[2.5rem] flex items-center gap-4">
          <div className="text-2xl">⚡</div>
          <div className="flex-1">
            <p className="text-amber-800 font-bold text-sm">Modo de Instalação Ativo</p>
            <p className="text-amber-600 text-xs font-medium">O primeiro usuário cadastrado será obrigatoriamente <b>MASTER</b>.</p>
          </div>
          <button onClick={() => handleOpenUserModal(UserRole.MASTER)} className="px-5 py-2 bg-amber-600 text-white rounded-xl text-xs font-black uppercase tracking-widest">Configurar Agora</button>
        </div>
      )}

      <div className="bg-white rounded-[3rem] border border-slate-100 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50/80 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nome</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Username</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nível de Acesso</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Membro Desde</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {usersList.length === 0 ? (
              <tr><td colSpan={4} className="px-8 py-10 text-center text-slate-400 italic">Nenhum usuário cadastrado no banco de dados.</td></tr>
            ) : (
              usersList.map(u => (
                <tr key={u.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-8 py-5">
                    <div className="flex items-center gap-3">
                      <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-bold ${u.role === UserRole.MASTER ? 'bg-amber-100 text-amber-700' : 'bg-indigo-50 text-indigo-600'}`}>{u.name.charAt(0)}</div>
                      <span className="font-bold text-slate-800">{u.name}</span>
                    </div>
                  </td>
                  <td className="px-8 py-5 text-sm font-mono text-slate-400">@{u.username}</td>
                  <td className="px-8 py-5">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${
                      u.role === UserRole.MASTER ? 'bg-amber-500 text-white' : 
                      u.role === UserRole.ADMIN ? 'bg-blue-100 text-blue-700' : 'bg-slate-100 text-slate-600'
                    }`}>
                      {u.role}
                    </span>
                  </td>
                  <td className="px-8 py-5 text-xs text-slate-400">{u.created_at ? new Date(u.created_at).toLocaleDateString('pt-BR') : 'Original'}</td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {showUserModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-200">
            {!isConfirmingUser ? (
              <>
                <div className="flex items-center gap-4 mb-8">
                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-2xl shadow-inner ${newUserData.role === UserRole.MASTER ? 'bg-amber-50 text-amber-600' : 'bg-indigo-50 text-indigo-600'}`}>
                    {newUserData.role === UserRole.MASTER ? '👑' : '👤'}
                  </div>
                  <div>
                    <h3 className="text-2xl font-black text-slate-900 tracking-tight">
                        {newUserData.role === UserRole.MASTER ? 'Dados do Master' : 'Dados do Usuário'}
                    </h3>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Etapa 1 de 2: Identificação</p>
                  </div>
                </div>
                <form onSubmit={(e) => { e.preventDefault(); setIsConfirmingUser(true); }} className="space-y-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nome Completo</label>
                    <input type="text" placeholder="Ex: João da Silva" required value={newUserData.name} onChange={e => setNewUserData({...newUserData, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none transition-all" />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Username (Login)</label>
                    <input type="text" placeholder="Ex: joao.tef" required value={newUserData.username} onChange={e => setNewUserData({...newUserData, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none transition-all" />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Senha de Acesso</label>
                    <input type="password" placeholder="••••••••" required value={newUserData.password} onChange={e => setNewUserData({...newUserData, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none transition-all" />
                  </div>
                  {newUserData.role !== UserRole.MASTER && !setupRequired && (
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nível de Acesso</label>
                      <select value={newUserData.role} onChange={e => setNewUserData({...newUserData, role: e.target.value as any})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none">
                        <option value={UserRole.ADMIN}>Administrador (Gestão + Fiscal)</option>
                        <option value={UserRole.OPERATOR}>Operador (Checkout + Vendas)</option>
                      </select>
                    </div>
                  )}
                  <div className="flex gap-4 pt-6">
                    <button type="button" onClick={() => setShowUserModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold text-xs uppercase tracking-widest hover:bg-slate-200 transition-all">Cancelar</button>
                    <button type="submit" className={`flex-1 py-4 text-white rounded-2xl font-bold text-xs uppercase tracking-widest shadow-xl transition-all ${newUserData.role === UserRole.MASTER ? 'bg-amber-500 shadow-amber-100' : 'bg-indigo-600 shadow-indigo-100'}`}>Revisar Dados</button>
                  </div>
                </form>
              </>
            ) : (
              <div className="animate-in fade-in zoom-in duration-300">
                <div className="text-center mb-8">
                  <div className={`w-20 h-20 rounded-full flex items-center justify-center text-4xl mx-auto mb-4 ${newUserData.role === UserRole.MASTER ? 'bg-amber-100' : 'bg-indigo-100'}`}>
                    {newUserData.role === UserRole.MASTER ? '👑' : '📋'}
                  </div>
                  <h3 className="text-2xl font-black text-slate-900 tracking-tight">Confirmar Registro?</h3>
                  <p className="text-slate-500 text-sm mt-2">Etapa 2 de 2: Validação de Permissões</p>
                </div>

                <div className={`p-6 rounded-[2.5rem] mb-6 border ${newUserData.role === UserRole.MASTER ? 'bg-amber-50 border-amber-100' : 'bg-slate-50 border-slate-100'}`}>
                  <div className="flex justify-between mb-4 border-b border-white pb-4 items-center">
                     <span className="text-[10px] font-black text-slate-400 uppercase">Acesso Selecionado</span>
                     <span className={`px-4 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-sm ${newUserData.role === UserRole.MASTER ? 'bg-amber-500 text-white' : 'bg-indigo-600 text-white'}`}>{newUserData.role}</span>
                  </div>

                  <div className="space-y-4">
                    <div className="flex justify-between items-center">
                      <span className="text-xs font-bold text-slate-500">Nome de Exibição</span>
                      <span className="text-xs font-black text-slate-800">{newUserData.name}</span>
                    </div>
                    <div className="flex justify-between items-center">
                      <span className="text-xs font-bold text-slate-500">Identificador (Login)</span>
                      <span className="text-xs font-black text-slate-800 italic">@{newUserData.username}</span>
                    </div>
                    <div className="h-px bg-white/50 w-full my-2"></div>
                    <div className="flex justify-between">
                      <span className="text-xs font-bold text-slate-500">Módulo Administrativo</span>
                      <span className="text-xs font-black text-emerald-600">ATIVO</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-xs font-bold text-slate-500">Gestão de TEF/Fiscal</span>
                      <span className={`text-xs font-black ${newUserData.role === UserRole.OPERATOR ? 'text-slate-300' : 'text-emerald-600'}`}>{newUserData.role === UserRole.OPERATOR ? 'INATIVO' : 'ATIVO'}</span>
                    </div>
                    <div className="flex justify-between">
                      <span className="text-xs font-bold text-slate-500">Controle de Usuários</span>
                      <span className={`text-xs font-black ${newUserData.role === UserRole.MASTER ? 'text-emerald-600' : 'text-slate-300'}`}>{newUserData.role === UserRole.MASTER ? 'ATIVO' : 'INATIVO'}</span>
                    </div>
                  </div>
                </div>

                {userModalError && (
                    <div className="mb-6 p-4 bg-rose-50 border border-rose-100 text-rose-600 rounded-2xl text-[10px] font-black uppercase tracking-widest text-center animate-bounce">
                        ⚠️ {userModalError}
                    </div>
                )}

                <div className="flex gap-4">
                  <button 
                    disabled={isSavingUser}
                    type="button" 
                    onClick={() => setIsConfirmingUser(false)} 
                    className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold text-xs uppercase tracking-widest hover:bg-slate-200 transition-all disabled:opacity-50"
                  >
                    Voltar e Editar
                  </button>
                  <button 
                    disabled={isSavingUser}
                    type="button" 
                    onClick={handleSaveUser} 
                    className={`flex-1 py-4 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl transition-all relative overflow-hidden ${newUserData.role === UserRole.MASTER ? 'bg-amber-600 shadow-amber-100' : 'bg-emerald-600 shadow-emerald-100'}`}
                  >
                    {isSavingUser ? (
                        <span className="flex items-center justify-center gap-2">
                            <span className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin"></span>
                            Salvando...
                        </span>
                    ) : 'Confirmar Registro'}
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        currentUser={currentUser || (setupRequired ? ({ id: 0, name: 'Instalador', username: 'setup', role: UserRole.MASTER } as User) : null)} 
        onLogout={() => { setCurrentUser(null); localStorage.removeItem('nexus_user'); setActiveTab('dashboard'); }} 
      />

      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-20 bg-white/70 backdrop-blur-md border-b border-slate-100 sticky top-0 z-40 flex items-center justify-between px-10">
          <div className="flex flex-col">
            <h2 className="text-xl font-black text-slate-900 leading-none">Nexus Hub</h2>
            <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-wider mt-1.5">{activeTab}</span>
          </div>

          <div className="flex items-center gap-6">
            {setupRequired ? (
              <div className="px-4 py-2 bg-amber-100 text-amber-700 rounded-xl text-[10px] font-black uppercase flex items-center gap-2">
                <span className="w-1.5 h-1.5 bg-amber-500 rounded-full animate-ping"></span> Setup Necessário
              </div>
            ) : currentUser ? (
              <div className="flex items-center gap-4">
                <div className="text-right hidden sm:block">
                  <p className="text-xs font-black text-slate-900 leading-tight">{currentUser.name}</p>
                  <p className="text-[9px] text-indigo-600 font-bold uppercase tracking-widest">{currentUser.role}</p>
                </div>
                <div className={`w-10 h-10 rounded-2xl flex items-center justify-center font-black shadow-lg ${currentUser.role === UserRole.MASTER ? 'bg-amber-500 text-white' : 'bg-indigo-600 text-white'}`}>
                  {currentUser.name.charAt(0)}
                </div>
              </div>
            ) : (
              <button onClick={() => setShowLoginModal(true)} className="px-6 py-2.5 bg-indigo-600 text-white rounded-xl font-bold text-xs uppercase tracking-widest shadow-lg shadow-indigo-100 hover:scale-105 transition-all">Entrar no Sistema</button>
            )}
          </div>
        </header>

        <main className="p-10 max-w-[1400px] w-full mx-auto">
          {activeTab === 'dashboard' && renderDashboard()}
          {activeTab === 'users' && renderUsers()}
          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}
          {activeTab === 'fiscal' && (
            <div className="space-y-6">
               <h3 className="text-3xl font-black text-slate-900 tracking-tight">Monitor Fiscal NFC-e</h3>
               <TransactionTable transactions={transactions.filter(t => !!t.fiscalNoteId)} />
            </div>
          )}
          {activeTab === 'certificates' && (
            <div className="space-y-8 animate-in slide-in-from-right duration-500">
              <div className="flex justify-between items-center">
                <div>
                  <h3 className="text-3xl font-black text-slate-900 tracking-tight">Certificados Digitais</h3>
                  <p className="text-slate-500 font-medium">Gestão global de cadeias A1/A3 para todos os estados.</p>
                </div>
                <button onClick={() => setShowCertModal(true)} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl hover:scale-105 transition-all text-sm">+ Adicionar</button>
              </div>
              <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
                {ALL_UFS.map(uf => {
                  const cert = certificates.find(c => c.state === uf);
                  return (
                    <div key={uf} className={`p-5 rounded-3xl border ${cert ? 'bg-white border-slate-100 shadow-sm' : 'bg-slate-50 border-dashed border-slate-200 opacity-60'}`}>
                      <div className="flex items-center justify-between mb-2">
                        <span className="text-lg font-black text-slate-900">{uf}</span>
                        <div className={`w-2 h-2 rounded-full ${cert ? (cert.status === 'Ativo' ? 'bg-emerald-500' : 'bg-rose-500') : 'bg-slate-300'}`}></div>
                      </div>
                      <p className="text-[9px] font-black text-slate-400 uppercase truncate">{cert ? cert.alias : 'Vazio'}</p>
                    </div>
                  );
                })}
              </div>
            </div>
          )}
          {activeTab === 'simulator' && (
            <div className="max-w-2xl mx-auto py-10 space-y-8">
              <div className="bg-white p-12 rounded-[3.5rem] shadow-2xl border border-slate-100 text-center">
                <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-[2rem] flex items-center justify-center text-4xl mx-auto mb-8">⚡</div>
                <h3 className="text-3xl font-black text-slate-900 mb-10 tracking-tight">Checkout Nexus</h3>
                <div className="grid grid-cols-2 gap-6">
                    <button onClick={() => simulateTransaction(PaymentMethod.CREDIT)} disabled={isSimulating} className="py-6 bg-slate-900 text-white rounded-3xl font-black uppercase tracking-widest hover:scale-105 transition-all shadow-xl">💳 Cartão</button>
                    <button onClick={() => simulateTransaction(PaymentMethod.PIX)} disabled={isSimulating} className="py-6 bg-emerald-600 text-white rounded-3xl font-black uppercase tracking-widest hover:scale-105 transition-all shadow-xl">⚡ Pix</button>
                </div>
              </div>
            </div>
          )}
        </main>
      </div>

      {showLoginModal && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300">
            <div className="flex flex-col items-center mb-10">
              <div className="w-20 h-20 bg-indigo-600 rounded-[2rem] flex items-center justify-center text-4xl font-black text-white mb-6 shadow-2xl shadow-indigo-200">N</div>
              <h1 className="text-3xl font-black text-slate-900 tracking-tight">Bem-vindo</h1>
              <p className="text-slate-400 font-bold text-xs uppercase tracking-widest mt-2">Acesso ao Hub NexusTEF</p>
            </div>
            <form onSubmit={handleLogin} className="space-y-6">
              <input type="text" placeholder="Usuário" required value={loginData.username} onChange={e => setLoginData({...loginData, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-5 px-6 font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all" />
              <input type="password" placeholder="Senha" required value={loginData.password} onChange={e => setLoginData({...loginData, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-5 px-6 font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all" />
              {error && <div className="p-4 bg-rose-50 text-rose-600 rounded-2xl text-[10px] font-black uppercase tracking-widest text-center">{error}</div>}
              <div className="flex gap-4 pt-2">
                <button type="button" onClick={() => setShowLoginModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs tracking-widest">Sair</button>
                <button type="submit" className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-indigo-100">Entrar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showPixModal && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-xl z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[4rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300 text-center relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-3 bg-emerald-500"></div>
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">QR Code Pix Dinâmico</h3>
            <div className="bg-slate-50 p-8 rounded-[3rem] mb-8 border border-slate-100 inline-block">
               <img src={showPixModal.pixQrCode} alt="PIX" className="w-48 h-48 mix-blend-multiply" />
            </div>
            <p className="text-3xl font-black text-slate-900 mb-2">R$ {showPixModal.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            <p className="text-[10px] text-emerald-600 font-black uppercase tracking-[0.2em] mb-8 animate-pulse">Aguardando Pagamento...</p>
            <button onClick={() => setShowPixModal(null)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest">Concluir</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES, MOCK_TRANSACTIONS, ALL_UFS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginData, setLoginData] = useState({ username: '', password: '' });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [insights, setInsights] = useState<string>('Analizando métricas de Pix e Notas Fiscais...');
  const [isSimulating, setIsSimulating] = useState(false);
  const [setupRequired, setSetupRequired] = useState<boolean>(false);
  const [showPixModal, setShowPixModal] = useState<Transaction | null>(null);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isMounted, setIsMounted] = useState(false);

  // User Management Modal States
  const [showUserModal, setShowUserModal] = useState(false);
  const [isConfirmingUser, setIsConfirmingUser] = useState(false);
  const [isSavingUser, setIsSavingUser] = useState(false);
  const [userModalError, setUserModalError] = useState<string | null>(null);
  const [newUserData, setNewUserData] = useState({ name: '', username: '', password: '', role: UserRole.OPERATOR });

  // Certificate Modal States
  const [showCertModal, setShowCertModal] = useState(false);

  useEffect(() => {
    setIsMounted(true);
    const init = async () => {
      try {
        const res = await fetch(`${API_URL}?action=check_setup`);
        if (!res.ok) throw new Error("API Offline");
        const data = await res.json();
        setSetupRequired(data.setup_required);
      } catch (e) { console.error("Setup Check Error:", e); }

      const saved = localStorage.getItem('nexus_user');
      if (saved) setCurrentUser(JSON.parse(saved));
    };
    init();
  }, []);

  const loadData = async () => {
    try {
      const [txRes, certRes] = await Promise.all([
        fetch(`${API_URL}?action=get_transactions`),
        fetch(`${API_URL}?action=get_certificates`)
      ]);

      const txData = txRes.ok ? await txRes.json() : [];
      const certData = certRes.ok ? await certRes.json() : [];

      setTransactions(Array.isArray(txData) && txData.length > 0 ? txData : MOCK_TRANSACTIONS);
      if (Array.isArray(certData)) setCertificates(certData);

      if (currentUser?.role === UserRole.MASTER || setupRequired) {
        const userRes = await fetch(`${API_URL}?action=get_users`);
        const userData = userRes.ok ? await userRes.json() : [];
        if (Array.isArray(userData)) setUsersList(userData);
      }
    } catch (error) { 
      console.error("Data Load Error:", error); 
      setTransactions(MOCK_TRANSACTIONS);
    }
  };

  useEffect(() => { 
    if (isMounted) loadData(); 
  }, [currentUser, setupRequired, isMounted]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    try {
      const res = await fetch(`${API_URL}?action=login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(loginData)
      });
      const data = await res.json();
      if (data.status === 'success') {
        setCurrentUser(data.user);
        localStorage.setItem('nexus_user', JSON.stringify(data.user));
        setShowLoginModal(false);
      } else {
        setError(data.message);
      }
    } catch (err) {
      setError('Erro de conexão com servidor.');
    }
  };

  const handleOpenUserModal = (role: UserRole) => {
    setNewUserData({ name: '', username: '', password: '', role });
    setIsConfirmingUser(false);
    setUserModalError(null);
    setShowUserModal(true);
  };

  const handleSaveUser = async () => {
    setIsSavingUser(true);
    setUserModalError(null);
    try {
      const res = await fetch(`${API_URL}?action=save_user`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newUserData)
      });
      const data = await res.json();
      if (data.status === 'success') {
        setShowUserModal(false);
        setIsConfirmingUser(false);
        setNewUserData({ name: '', username: '', password: '', role: UserRole.OPERATOR });
        const setupCheck = await fetch(`${API_URL}?action=check_setup`);
        const setupData = await setupCheck.json();
        setSetupRequired(setupData.setup_required);
        loadData();
      } else {
        setUserModalError(data.message || 'Erro ao cadastrar usuário.');
      }
    } catch (e) { 
      setUserModalError('Falha de rede ao tentar salvar.');
    } finally {
      setIsSavingUser(false);
    }
  };

  const stats = useMemo(() => {
    const success = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const pix = success.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    const authorized = transactions.filter(t => t.fiscalStatus === FiscalStatus.AUTHORIZED).length;
    const totalVal = success.reduce((a, b) => a + Number(b.amount), 0);
    return {
      total: totalVal,
      pixPercent: ((pix / (totalVal || 1)) * 100).toFixed(1),
      fiscalHealth: ((authorized / (transactions.filter(t => t.fiscalNoteId).length || 1)) * 100).toFixed(1),
      txCount: transactions.length
    };
  }, [transactions]);

  useEffect(() => {
    if (transactions.length > 0) getSmartInsights(transactions).then(setInsights);
  }, [transactions]);

  const simulateTransaction = async (method: PaymentMethod) => {
    setIsSimulating(true);
    const txId = `TX-${Math.floor(10000 + Math.random() * 90000)}`;
    const newTx: Transaction = {
      id: txId,
      timestamp: new Date().toISOString(),
      amount: parseFloat((Math.random() * 500 + 5).toFixed(2)),
      method,
      segment: 'Varejo Digital',
      status: method === PaymentMethod.PIX ? PaymentStatus.PENDING : PaymentStatus.SUCCESS,
      terminalId: 'WEB-API',
      fiscalNoteId: method === PaymentMethod.PIX ? undefined : String(Math.floor(10000 + Math.random() * 9000)),
      fiscalStatus: method === PaymentMethod.PIX ? undefined : FiscalStatus.AUTHORIZED,
      pixQrCode: method === PaymentMethod.PIX ? 'https://api.qrserver.com/v1/create-qr-code/?size=300x300&data=NEXUSTEF-SIMULATED-PIX-KEY' : undefined,
      pixCopyPaste: method === PaymentMethod.PIX ? '00020126580014BR.GOV.BCB.PIX0136NEXUSTEF-PAYMENT-ID-' + txId : undefined
    };

    try {
      await fetch(`${API_URL}?action=save_transaction`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(newTx)
      });
      loadData();
      if (method === PaymentMethod.PIX) setShowPixModal(newTx);
    } catch (e) { console.error(e); } finally { setIsSimulating(false); }
  };

  const renderDashboard = () => (
    <div className="space-y-8 animate-in fade-in duration-700">
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard label="Volume Total" value={`R$ ${stats.total.toLocaleString('pt-BR')}`} icon="💰" color="bg-indigo-50 text-indigo-600" />
        <StatCard label="Mix de Pix" value={`${stats.pixPercent}%`} icon="⚡" color="bg-emerald-50 text-emerald-600" />
        <StatCard label="Sefaz Conectada" value={`${stats.fiscalHealth}%`} icon="📑" color="bg-blue-50 text-blue-600" />
        <StatCard label="Transações" value={stats.txCount} icon="🔄" color="bg-slate-50 text-slate-600" />
      </div>
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-2 bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm min-h-[450px] flex flex-col">
          <h3 className="text-xl font-black text-slate-800 mb-8 tracking-tight">Crescimento Semanal</h3>
          <div className="flex-1 w-full min-h-[300px]">
            {isMounted && (
              <ResponsiveContainer width="100%" height="100%" minHeight={300}>
                <AreaChart data={CHART_DATA} margin={{ top: 10, right: 10, left: 0, bottom: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                  <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                  <Tooltip />
                  <Area type="monotone" dataKey="valor" stroke="#6366f1" strokeWidth={3} fillOpacity={0.1} fill="#6366f1" />
                </AreaChart>
              </ResponsiveContainer>
            )}
          </div>
        </div>
        <div className="bg-slate-900 p-8 rounded-[3rem] text-white flex flex-col shadow-2xl">
          <h3 className="text-xl font-black mb-8">Nexus AI Insights</h3>
          <div className="flex-1 bg-white/5 rounded-[2rem] p-6 text-sm italic text-slate-300 overflow-auto">
            "{insights}"
          </div>
        </div>
      </div>
      <FiscalMonitor states={SEFAZ_STATES} />
    </div>
  );

  const renderUsers = () => (
    <div className="space-y-8 animate-in slide-in-from-bottom duration-500">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Usuários</h3>
          <p className="text-slate-500 font-medium">Controle de acessos e níveis de privilégio do sistema.</p>
        </div>
        <div className="flex gap-3">
          <button 
            onClick={() => handleOpenUserModal(UserRole.OPERATOR)}
            className="px-6 py-3 bg-indigo-600 text-white rounded-2xl font-bold text-sm shadow-lg hover:scale-105 transition-all flex items-center gap-2"
          >
            <span>👤</span> Cadastrar Usuário
          </button>
          <button 
            onClick={() => handleOpenUserModal(UserRole.MASTER)}
            className="px-6 py-3 bg-amber-500 text-white rounded-2xl font-bold text-sm shadow-lg hover:scale-105 transition-all flex items-center gap-2"
          >
            <span>👑</span> Cadastrar Master
          </button>
        </div>
      </div>

      {setupRequired && (
        <div className="p-6 bg-amber-50 border border-amber-100 rounded-[2.5rem] flex items-center gap-4">
          <div className="text-2xl">⚡</div>
          <div className="flex-1">
            <p className="text-amber-800 font-bold text-sm">Modo de Instalação Ativo</p>
            <p className="text-amber-600 text-xs font-medium">O primeiro usuário cadastrado será obrigatoriamente <b>MASTER</b>.</p>
          </div>
          <button onClick={() => handleOpenUserModal(UserRole.MASTER)} className="px-5 py-2 bg-amber-600 text-white rounded-xl text-xs font-black uppercase tracking-widest">Configurar Agora</button>
        </div>
      )}

      <div className="bg-white rounded-[3rem] border border-slate-100 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50/80 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nome</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Username</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nível de Acesso</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Membro Desde</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {usersList.length === 0 ? (
              <tr><td colSpan={4} className="px-8 py-10 text-center text-slate-400 italic">Nenhum usuário cadastrado no banco de dados.</td></tr>
            ) : (
              usersList.map(u => (
                <tr key={u.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-8 py-5">
                    <div className="flex items-center gap-3">
                      <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-bold ${u.role === UserRole.MASTER ? 'bg-amber-100 text-amber-700' : 'bg-indigo-50 text-indigo-600'}`}>{u.name.charAt(0)}</div>
                      <span className="font-bold text-slate-800">{u.name}</span>
                    </div>
                  </td>
                  <td className="px-8 py-5 text-sm font-mono text-slate-400">@{u.username}</td>
                  <td className="px-8 py-5">
                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${
                      u.role === UserRole.MASTER ? 'bg-amber-500 text-white' : 
                      u.role === UserRole.ADMIN ? 'bg-blue-100 text-blue-700' : 'bg-slate-100 text-slate-600'
                    }`}>
                      {u.role}
                    </span>
                  </td>
                  <td className="px-8 py-5 text-xs text-slate-400">{u.created_at ? new Date(u.created_at).toLocaleDateString('pt-BR') : 'Original'}</td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>

      {showUserModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[100] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-200">
            {!isConfirmingUser ? (
              <>
                <div className="flex items-center gap-4 mb-8">
                  <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-2xl shadow-inner ${newUserData.role === UserRole.MASTER ? 'bg-amber-50 text-amber-600' : 'bg-indigo-50 text-indigo-600'}`}>
                    {newUserData.role === UserRole.MASTER ? '👑' : '👤'}
                  </div>
                  <div>
                    <h3 className="text-2xl font-black text-slate-900 tracking-tight">
                        {newUserData.role === UserRole.MASTER ? 'Dados do Master' : 'Dados do Usuário'}
                    </h3>
                    <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">Etapa 1 de 2: Identificação</p>
                  </div>
                </div>
                <form onSubmit={(e) => { e.preventDefault(); setIsConfirmingUser(true); }} className="space-y-4">
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nome Completo</label>
                    <input type="text" placeholder="Ex: João da Silva" required value={newUserData.name} onChange={e => setNewUserData({...newUserData, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none transition-all" />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Username (Login)</label>
                    <input type="text" placeholder="Ex: joao.tef" required value={newUserData.username} onChange={e => setNewUserData({...newUserData, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none transition-all" />
                  </div>
                  <div className="space-y-1">
                    <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Senha de Acesso</label>
                    <input type="password" placeholder="••••••••" required value={newUserData.password} onChange={e => setNewUserData({...newUserData, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium focus:ring-2 focus:ring-indigo-500 outline-none transition-all" />
                  </div>
                  {newUserData.role !== UserRole.MASTER && !setupRequired && (
                    <div className="space-y-1">
                      <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nível de Acesso</label>
                      <select value={newUserData.role} onChange={e => setNewUserData({...newUserData, role: e.target.value as any})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none">
                        <option value={UserRole.ADMIN}>Administrador (Gestão + Fiscal)</option>
                        <option value={UserRole.OPERATOR}>Operador (Checkout + Vendas)</option>
                      </select>
                    </div>
                  )}
                  <div className="flex gap-4 pt-6">
                    <button type="button" onClick={() => setShowUserModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold text-xs uppercase tracking-widest hover:bg-slate-200 transition-all">Cancelar</button>
                    <button type="submit" className={`flex-1 py-4 text-white rounded-2xl font-bold text-xs uppercase tracking-widest shadow-xl transition-all ${newUserData.role === UserRole.MASTER ? 'bg-amber-500 shadow-amber-100' : 'bg-indigo-600 shadow-indigo-100'}`}>Revisar Dados</button>
                  </div>
                </form>
              </>
            ) : (
              <div className="animate-in fade-in zoom-in duration-300">
                <div className="text-center mb-8">
                  <div className={`w-20 h-20 rounded-full flex items-center justify-center text-4xl mx-auto mb-4 ${newUserData.role === UserRole.MASTER ? 'bg-amber-100' : 'bg-indigo-100'}`}>
                    {newUserData.role === UserRole.MASTER ? '👑' : '📋'}
                  </div>
                  <h3 className="text-2xl font-black text-slate-900 tracking-tight">Confirmar Registro?</h3>
                  <p className="text-slate-500 text-sm mt-2">Etapa 2 de 2: Validação de Permissões</p>
                </div>

                <div className={`p-6 rounded-[2.5rem] mb-6 border ${newUserData.role === UserRole.MASTER ? 'bg-amber-50 border-amber-100' : 'bg-slate-50 border-slate-100'}`}>
                  <div className="flex justify-between mb-4 border-b border-white pb-4 items-center">
                     <span className="text-[10px] font-black text-slate-400 uppercase">Acesso Selecionado</span>
                     <span className={`px-4 py-1.5 rounded-xl text-[10px] font-black uppercase tracking-widest shadow-sm ${newUserData.role === UserRole.MASTER ? 'bg-amber-500 text-white' : 'bg-indigo-600 text-white'}`}>{newUserData.role}</span>
                  </div>

                  <div className="space-y-4">
                    <div className="flex justify-between items-center">
                      <span className="text-xs font-bold text-slate-500">Nome de Exibição</span>
                      <span className="text-xs font-black text-slate-800">{newUserData.name}</span>
                    </div>
                    <div className="flex justify-between items-center">
                      <span className="text-xs font-bold text-slate-500">Identificador (Login)</span>
                      <span className="text-xs font-black text-slate-800 italic">@{newUserData.username}</span>
                    </div>
                  </div>
                </div>

                {userModalError && (
                    <div className="mb-6 p-4 bg-rose-50 border border-rose-100 text-rose-600 rounded-2xl text-[10px] font-black uppercase tracking-widest text-center">
                        ⚠️ {userModalError}
                    </div>
                )}

                <div className="flex gap-4">
                  <button 
                    disabled={isSavingUser}
                    type="button" 
                    onClick={() => setIsConfirmingUser(false)} 
                    className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold text-xs uppercase tracking-widest hover:bg-slate-200 transition-all disabled:opacity-50"
                  >
                    Voltar
                  </button>
                  <button 
                    disabled={isSavingUser}
                    type="button" 
                    onClick={handleSaveUser} 
                    className={`flex-1 py-4 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl transition-all ${newUserData.role === UserRole.MASTER ? 'bg-amber-600 shadow-amber-100' : 'bg-emerald-600 shadow-emerald-100'}`}
                  >
                    {isSavingUser ? 'Salvando...' : 'Confirmar'}
                  </button>
                </div>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        currentUser={currentUser || (setupRequired ? ({ id: 0, name: 'Instalador', username: 'setup', role: UserRole.MASTER } as User) : null)} 
        onLogout={() => { setCurrentUser(null); localStorage.removeItem('nexus_user'); setActiveTab('dashboard'); }} 
      />

      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-20 bg-white/70 backdrop-blur-md border-b border-slate-100 sticky top-0 z-40 flex items-center justify-between px-10">
          <div className="flex flex-col">
            <h2 className="text-xl font-black text-slate-900 leading-none">Nexus Hub</h2>
            <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-wider mt-1.5">{activeTab}</span>
          </div>

          <div className="flex items-center gap-6">
            {setupRequired ? (
              <div className="px-4 py-2 bg-amber-100 text-amber-700 rounded-xl text-[10px] font-black uppercase flex items-center gap-2">
                <span className="w-1.5 h-1.5 bg-amber-500 rounded-full animate-ping"></span> Setup Necessário
              </div>
            ) : currentUser ? (
              <div className="flex items-center gap-4">
                <div className="text-right hidden sm:block">
                  <p className="text-xs font-black text-slate-900 leading-tight">{currentUser.name}</p>
                  <p className="text-[9px] text-indigo-600 font-bold uppercase tracking-widest">{currentUser.role}</p>
                </div>
                <div className={`w-10 h-10 rounded-2xl flex items-center justify-center font-black shadow-lg ${currentUser.role === UserRole.MASTER ? 'bg-amber-500 text-white' : 'bg-indigo-600 text-white'}`}>
                  {currentUser.name.charAt(0)}
                </div>
              </div>
            ) : (
              <button onClick={() => setShowLoginModal(true)} className="px-6 py-2.5 bg-indigo-600 text-white rounded-xl font-bold text-xs uppercase tracking-widest shadow-lg shadow-indigo-100 hover:scale-105 transition-all">Entrar no Sistema</button>
            )}
          </div>
        </header>

        <main className="p-10 max-w-[1400px] w-full mx-auto">
          {activeTab === 'dashboard' && renderDashboard()}
          {activeTab === 'users' && renderUsers()}
          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}
          {activeTab === 'fiscal' && (
            <div className="space-y-6">
               <h3 className="text-3xl font-black text-slate-900 tracking-tight">Monitor Fiscal NFC-e</h3>
               <TransactionTable transactions={transactions.filter(t => !!t.fiscalNoteId)} />
            </div>
          )}
          {activeTab === 'certificates' && (
            <div className="space-y-8 animate-in slide-in-from-right duration-500">
              <div className="flex justify-between items-center">
                <div>
                  <h3 className="text-3xl font-black text-slate-900 tracking-tight">Certificados Digitais</h3>
                  <p className="text-slate-500 font-medium">Gestão global de cadeias A1/A3 para todos os estados.</p>
                </div>
                <button onClick={() => setShowCertModal(true)} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl hover:scale-105 transition-all text-sm">+ Adicionar</button>
              </div>
              <div className="grid grid-cols-2 md:grid-cols-4 lg:grid-cols-6 gap-4">
                {ALL_UFS.map(uf => {
                  const cert = certificates.find(c => c.state === uf);
                  return (
                    <div key={uf} className={`p-5 rounded-3xl border ${cert ? 'bg-white border-slate-100 shadow-sm' : 'bg-slate-50 border-dashed border-slate-200 opacity-60'}`}>
                      <div className="flex items-center justify-between mb-2">
                        <span className="text-lg font-black text-slate-900">{uf}</span>
                        <div className={`w-2 h-2 rounded-full ${cert ? (cert.status === 'Ativo' ? 'bg-emerald-500' : 'bg-rose-500') : 'bg-slate-300'}`}></div>
                      </div>
                      <p className="text-[9px] font-black text-slate-400 uppercase truncate">{cert ? cert.alias : 'Vazio'}</p>
                    </div>
                  );
                })}
              </div>
            </div>
          )}
          {activeTab === 'simulator' && (
            <div className="max-w-2xl mx-auto py-10 space-y-8">
              <div className="bg-white p-12 rounded-[3.5rem] shadow-2xl border border-slate-100 text-center">
                <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-[2rem] flex items-center justify-center text-4xl mx-auto mb-8">⚡</div>
                <h3 className="text-3xl font-black text-slate-900 mb-10 tracking-tight">Checkout Nexus</h3>
                <div className="grid grid-cols-2 gap-6">
                    <button onClick={() => simulateTransaction(PaymentMethod.CREDIT)} disabled={isSimulating} className="py-6 bg-slate-900 text-white rounded-3xl font-black uppercase tracking-widest hover:scale-105 transition-all shadow-xl">💳 Cartão</button>
                    <button onClick={() => simulateTransaction(PaymentMethod.PIX)} disabled={isSimulating} className="py-6 bg-emerald-600 text-white rounded-3xl font-black uppercase tracking-widest hover:scale-105 transition-all shadow-xl">⚡ Pix</button>
                </div>
              </div>
            </div>
          )}
        </main>
      </div>

      {showLoginModal && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300">
            <div className="flex flex-col items-center mb-10">
              <div className="w-20 h-20 bg-indigo-600 rounded-[2rem] flex items-center justify-center text-4xl font-black text-white mb-6 shadow-2xl shadow-indigo-200">N</div>
              <h1 className="text-3xl font-black text-slate-900 tracking-tight">Bem-vindo</h1>
              <p className="text-slate-400 font-bold text-xs uppercase tracking-widest mt-2">Acesso ao Hub NexusTEF</p>
            </div>
            <form onSubmit={handleLogin} className="space-y-6">
              <input type="text" placeholder="Usuário" required value={loginData.username} onChange={e => setLoginData({...loginData, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-5 px-6 font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all" />
              <input type="password" placeholder="Senha" required value={loginData.password} onChange={e => setLoginData({...loginData, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-5 px-6 font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all" />
              {error && <div className="p-4 bg-rose-50 text-rose-600 rounded-2xl text-[10px] font-black uppercase tracking-widest text-center">{error}</div>}
              <div className="flex gap-4 pt-2">
                <button type="button" onClick={() => setShowLoginModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs tracking-widest">Sair</button>
                <button type="submit" className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-indigo-100">Entrar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showPixModal && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-xl z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[4rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300 text-center relative overflow-hidden">
            <div className="absolute top-0 left-0 w-full h-3 bg-emerald-500"></div>
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">QR Code Pix Dinâmico</h3>
            <div className="bg-slate-50 p-8 rounded-[3rem] mb-8 border border-slate-100 inline-block">
               <img src={showPixModal.pixQrCode} alt="PIX" className="w-48 h-48 mix-blend-multiply" />
            </div>
            <p className="text-3xl font-black text-slate-900 mb-2">R$ {showPixModal.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            <p className="text-[10px] text-emerald-600 font-black uppercase tracking-[0.2em] mb-8 animate-pulse">Aguardando Pagamento...</p>
            <button onClick={() => setShowPixModal(null)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest">Concluir</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES, MOCK_TRANSACTIONS, ALL_UFS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginData, setLoginData] = useState({ username: '', password: '' });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [insights, setInsights] = useState<string>('Analizando métricas em tempo real...');
  const [isSimulating, setIsSimulating] = useState(false);
  const [setupRequired, setSetupRequired] = useState<boolean>(false);
  const [showPixModal, setShowPixModal] = useState<Transaction | null>(null);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isMounted, setIsMounted] = useState(false);

  // User Management
  const [showUserModal, setShowUserModal] = useState(false);
  const [isConfirmingUser, setIsConfirmingUser] = useState(false);
  const [isSavingUser, setIsSavingUser] = useState(false);
  const [userModalError, setUserModalError] = useState<string | null>(null);
  const [newUserData, setNewUserData] = useState({ name: '', username: '', password: '', role: UserRole.OPERATOR });

  // Safe JSON Fetch Helper to avoid stream errors
  const safeFetch = async (url: string, options?: RequestInit) => {
    try {
      const response = await fetch(url, options);
      const text = await response.text();
      try {
        return JSON.parse(text);
      } catch (e) {
        console.error("JSON Parse Error. Server outputted:", text);
        return { status: 'error', message: 'Resposta inválida do servidor.' };
      }
    } catch (e) {
      console.error("Fetch Error:", e);
      return { status: 'error', message: 'Falha na conexão com a API.' };
    }
  };

  useEffect(() => {
    setIsMounted(true);
    const init = async () => {
      const data = await safeFetch(`${API_URL}?action=check_setup`);
      if (data && typeof data.setup_required !== 'undefined') {
        setSetupRequired(data.setup_required);
      }
      const saved = localStorage.getItem('nexus_user');
      if (saved) setCurrentUser(JSON.parse(saved));
    };
    init();
  }, []);

  const loadData = async () => {
    const txData = await safeFetch(`${API_URL}?action=get_transactions`);
    const certData = await safeFetch(`${API_URL}?action=get_certificates`);

    setTransactions(Array.isArray(txData) ? txData : MOCK_TRANSACTIONS);
    if (Array.isArray(certData)) setCertificates(certData);

    if (currentUser?.role === UserRole.MASTER || setupRequired) {
      const userData = await safeFetch(`${API_URL}?action=get_users`);
      if (Array.isArray(userData)) setUsersList(userData);
    }
  };

  useEffect(() => { 
    if (isMounted) loadData(); 
  }, [currentUser, setupRequired, isMounted]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    const data = await safeFetch(`${API_URL}?action=login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(loginData)
    });
    if (data.status === 'success') {
      setCurrentUser(data.user);
      localStorage.setItem('nexus_user', JSON.stringify(data.user));
      setShowLoginModal(false);
    } else {
      setError(data.message || 'Erro ao realizar login.');
    }
  };

  const handleOpenUserModal = (role: UserRole) => {
    setNewUserData({ name: '', username: '', password: '', role });
    setIsConfirmingUser(false);
    setUserModalError(null);
    setShowUserModal(true);
  };

  const handleSaveUser = async () => {
    setIsSavingUser(true);
    setUserModalError(null);
    const data = await safeFetch(`${API_URL}?action=save_user`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(newUserData)
    });

    if (data.status === 'success') {
      setShowUserModal(false);
      setIsConfirmingUser(false);
      const setupCheck = await safeFetch(`${API_URL}?action=check_setup`);
      setSetupRequired(setupCheck.setup_required);
      loadData();
    } else {
      setUserModalError(data.message || 'Erro ao salvar usuário.');
    }
    setIsSavingUser(false);
  };

  const stats = useMemo(() => {
    const success = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const pix = success.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    const authorized = transactions.filter(t => t.fiscalStatus === FiscalStatus.AUTHORIZED).length;
    const totalVal = success.reduce((a, b) => a + Number(b.amount), 0);
    return {
      total: totalVal,
      pixPercent: ((pix / (totalVal || 1)) * 100).toFixed(1),
      fiscalHealth: ((authorized / (transactions.filter(t => t.fiscalNoteId).length || 1)) * 100).toFixed(1),
      txCount: transactions.length
    };
  }, [transactions]);

  useEffect(() => {
    if (transactions.length > 0) getSmartInsights(transactions).then(setInsights);
  }, [transactions]);

  const simulateTransaction = async (method: PaymentMethod) => {
    setIsSimulating(true);
    const txId = `TX-${Math.floor(10000 + Math.random() * 90000)}`;
    const newTx: Transaction = {
      id: txId,
      timestamp: new Date().toISOString(),
      amount: parseFloat((Math.random() * 500 + 5).toFixed(2)),
      method,
      segment: 'Varejo Digital',
      status: method === PaymentMethod.PIX ? PaymentStatus.PENDING : PaymentStatus.SUCCESS,
      terminalId: 'WEB-API',
      fiscalNoteId: method === PaymentMethod.PIX ? undefined : String(Math.floor(10000 + Math.random() * 9000)),
      fiscalStatus: method === PaymentMethod.PIX ? undefined : FiscalStatus.AUTHORIZED,
      pixQrCode: method === PaymentMethod.PIX ? 'https://api.qrserver.com/v1/create-qr-code/?size=300x300&data=NEXUSTEF-PIX-' + txId : undefined,
    };

    await safeFetch(`${API_URL}?action=save_transaction`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(newTx)
    });
    loadData();
    setIsSimulating(false);
    if (method === PaymentMethod.PIX) setShowPixModal(newTx);
  };

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        currentUser={currentUser || (setupRequired ? ({ id: 0, name: 'Instalador', username: 'setup', role: UserRole.MASTER } as User) : null)} 
        onLogout={() => { setCurrentUser(null); localStorage.removeItem('nexus_user'); setActiveTab('dashboard'); }} 
      />

      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-20 bg-white/80 backdrop-blur-md border-b border-slate-100 sticky top-0 z-40 flex items-center justify-between px-10">
          <div className="flex flex-col">
            <h2 className="text-xl font-black text-slate-900 leading-none">Nexus Engine</h2>
            <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest mt-1.5">{activeTab}</span>
          </div>
          <div className="flex items-center gap-6">
            {setupRequired ? (
              <div className="px-4 py-2 bg-amber-100 text-amber-700 rounded-xl text-[10px] font-black uppercase flex items-center gap-2">
                <span className="w-1.5 h-1.5 bg-amber-500 rounded-full animate-ping"></span> Setup Necessário
              </div>
            ) : currentUser ? (
              <div className="flex items-center gap-4">
                <div className="text-right hidden sm:block">
                  <p className="text-xs font-black text-slate-900 leading-tight">{currentUser.name}</p>
                  <p className="text-[9px] text-indigo-600 font-bold uppercase tracking-widest">{currentUser.role}</p>
                </div>
                <div className={`w-10 h-10 rounded-2xl flex items-center justify-center font-black shadow-lg ${currentUser.role === UserRole.MASTER ? 'bg-amber-500 text-white' : 'bg-indigo-600 text-white'}`}>
                  {currentUser.name.charAt(0)}
                </div>
              </div>
            ) : (
              <button onClick={() => setShowLoginModal(true)} className="px-6 py-2.5 bg-indigo-600 text-white rounded-xl font-bold text-xs uppercase tracking-widest shadow-lg hover:scale-105 transition-all">Entrar</button>
            )}
          </div>
        </header>

        <main className="p-10 max-w-[1400px] w-full mx-auto">
          {activeTab === 'dashboard' && (
            <div className="space-y-8 animate-in fade-in duration-700">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <StatCard label="Volume Total" value={`R$ ${stats.total.toLocaleString('pt-BR')}`} icon="💰" color="bg-indigo-50 text-indigo-600" />
                <StatCard label="Mix de Pix" value={`${stats.pixPercent}%`} icon="⚡" color="bg-emerald-50 text-emerald-600" />
                <StatCard label="Saúde Fiscal" value={`${stats.fiscalHealth}%`} icon="📑" color="bg-blue-50 text-blue-600" />
                <StatCard label="Registros" value={stats.txCount} icon="🔄" color="bg-slate-50 text-slate-600" />
              </div>
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm flex flex-col min-h-[400px]">
                  <h3 className="text-xl font-black text-slate-800 mb-8">Fluxo de Vendas</h3>
                  <div className="flex-1 min-h-[300px] relative">
                    {/* Fixed Height Parent to avoid Recharts width(-1) error */}
                    <div style={{ width: '100%', height: 300 }}>
                      <ResponsiveContainer>
                        <AreaChart data={CHART_DATA}>
                          <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                          <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                          <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                          <Tooltip />
                          <Area type="monotone" dataKey="valor" stroke="#6366f1" strokeWidth={3} fillOpacity={0.1} fill="#6366f1" />
                        </AreaChart>
                      </ResponsiveContainer>
                    </div>
                  </div>
                </div>
                <div className="bg-slate-900 p-8 rounded-[3rem] text-white flex flex-col shadow-2xl">
                  <h3 className="text-xl font-black mb-8 flex items-center gap-2">Nexus AI <span className="text-[10px] bg-indigo-500 px-2 py-1 rounded">BETA</span></h3>
                  <div className="flex-1 bg-white/5 rounded-[2rem] p-6 text-sm italic text-slate-300 overflow-auto border border-white/5">
                    "{insights}"
                  </div>
                </div>
              </div>
              <FiscalMonitor states={SEFAZ_STATES} />
            </div>
          )}

          {activeTab === 'users' && (
            <div className="space-y-8 animate-in slide-in-from-bottom duration-500">
               <div className="flex justify-between items-center">
                  <h3 className="text-3xl font-black text-slate-900 tracking-tight">Usuários do Sistema</h3>
                  <div className="flex gap-4">
                     <button onClick={() => handleOpenUserModal(UserRole.OPERATOR)} className="px-6 py-3 bg-indigo-600 text-white rounded-2xl font-bold text-sm shadow-lg hover:scale-105 transition-all">+ Novo Usuário</button>
                     <button onClick={() => handleOpenUserModal(UserRole.MASTER)} className="px-6 py-3 bg-amber-500 text-white rounded-2xl font-bold text-sm shadow-lg hover:scale-105 transition-all">👑 Novo Master</button>
                  </div>
               </div>
               <div className="bg-white rounded-[3rem] border border-slate-100 overflow-hidden shadow-sm">
                  <table className="w-full text-left">
                     <thead>
                        <tr className="bg-slate-50 border-b border-slate-100">
                           <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Identidade</th>
                           <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Username</th>
                           <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Cargo</th>
                        </tr>
                     </thead>
                     <tbody className="divide-y divide-slate-50">
                        {usersList.length === 0 ? (
                           <tr><td colSpan={3} className="px-8 py-10 text-center text-slate-400 italic">Carregando lista de acessos...</td></tr>
                        ) : (
                           usersList.map(u => (
                              <tr key={u.id} className="hover:bg-slate-50/50 transition-colors">
                                 <td className="px-8 py-5">
                                    <div className="flex items-center gap-3">
                                       <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-bold ${u.role === UserRole.MASTER ? 'bg-amber-100 text-amber-700' : 'bg-indigo-50 text-indigo-600'}`}>{u.name.charAt(0)}</div>
                                       <span className="font-bold text-slate-800">{u.name}</span>
                                    </div>
                                 </td>
                                 <td className="px-8 py-5 text-sm font-mono text-slate-400">@{u.username}</td>
                                 <td className="px-8 py-5">
                                    <span className={`px-3 py-1 rounded-full text-[10px] font-black uppercase tracking-widest ${u.role === UserRole.MASTER ? 'bg-amber-500 text-white' : 'bg-indigo-100 text-indigo-700'}`}>{u.role}</span>
                                 </td>
                              </tr>
                           ))
                        )}
                     </tbody>
                  </table>
               </div>
            </div>
          )}

          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}

          {activeTab === 'simulator' && (
            <div className="max-w-2xl mx-auto py-10">
               <div className="bg-white p-12 rounded-[3.5rem] shadow-2xl border border-slate-100 text-center">
                  <div className="w-20 h-20 bg-emerald-50 text-emerald-600 rounded-[2rem] flex items-center justify-center text-4xl mx-auto mb-8 shadow-inner">⚡</div>
                  <h3 className="text-3xl font-black text-slate-900 mb-10 tracking-tight">Checkout Simulado</h3>
                  <div className="grid grid-cols-2 gap-6">
                     <button onClick={() => simulateTransaction(PaymentMethod.CREDIT)} disabled={isSimulating} className="py-6 bg-slate-900 text-white rounded-3xl font-black uppercase tracking-widest hover:scale-105 transition-all shadow-xl disabled:opacity-50">Cartão de Crédito</button>
                     <button onClick={() => simulateTransaction(PaymentMethod.PIX)} disabled={isSimulating} className="py-6 bg-emerald-600 text-white rounded-3xl font-black uppercase tracking-widest hover:scale-105 transition-all shadow-xl disabled:opacity-50">Pagamento via PIX</button>
                  </div>
               </div>
            </div>
          )}
        </main>
      </div>

      {showUserModal && (
        <div className="fixed inset-0 bg-slate-900/70 backdrop-blur-md z-[100] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-200">
            {!isConfirmingUser ? (
              <form onSubmit={(e) => { e.preventDefault(); setIsConfirmingUser(true); }} className="space-y-4">
                <h3 className="text-2xl font-black text-slate-900 mb-6">Novo Cadastro</h3>
                <div className="space-y-4">
                   <input type="text" placeholder="Nome Completo" required value={newUserData.name} onChange={e => setNewUserData({...newUserData, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
                   <input type="text" placeholder="Username" required value={newUserData.username} onChange={e => setNewUserData({...newUserData, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
                   <input type="password" placeholder="Senha" required value={newUserData.password} onChange={e => setNewUserData({...newUserData, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
                   {newUserData.role !== UserRole.MASTER && (
                      <select value={newUserData.role} onChange={e => setNewUserData({...newUserData, role: e.target.value as any})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none">
                         <option value={UserRole.ADMIN}>Administrador</option>
                         <option value={UserRole.OPERATOR}>Operador</option>
                      </select>
                   )}
                </div>
                <div className="flex gap-4 pt-6">
                   <button type="button" onClick={() => setShowUserModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold uppercase text-xs tracking-widest">Sair</button>
                   <button type="submit" className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-bold uppercase text-xs tracking-widest shadow-xl">Prosseguir</button>
                </div>
              </form>
            ) : (
              <div className="animate-in fade-in zoom-in duration-300 text-center">
