                  <div className="flex-1 bg-white/5 rounded-[2.5rem] p-6 text-sm italic text-slate-300 overflow-auto border border-white/5 relative z-10 scrollbar-hide">
                    "{insights}"
                  </div>
                </div>
              </div>
              <FiscalMonitor states={SEFAZ_STATES} />
            </div>
          )}

          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}
          {activeTab === 'simulator' && (
            <div className="max-w-xl mx-auto py-10">
               <div className="bg-white p-12 rounded-[3.5rem] shadow-2xl border border-slate-100 text-center relative overflow-hidden">
                  <div className="absolute top-0 left-0 w-full h-2 bg-indigo-500"></div>
                  <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-[2rem] flex items-center justify-center text-4xl mx-auto mb-8 shadow-inner">💳</div>
                  <h3 className="text-3xl font-black text-slate-900 mb-4 tracking-tight">Checkout Nexus</h3>
                  <p className="text-slate-500 text-sm mb-10">Simule transações em tempo real para testar a integração fiscal e financeira.</p>
                  <div className="grid grid-cols-1 gap-4">
                     <button onClick={() => simulateTransaction(PaymentMethod.CREDIT)} disabled={isSimulating} className="py-6 bg-slate-900 text-white rounded-3xl font-black uppercase tracking-widest hover:bg-slate-800 transition-all shadow-xl disabled:opacity-50">Cartão (Crédito/Débito)</button>
                     <button onClick={() => simulateTransaction(PaymentMethod.PIX)} disabled={isSimulating} className="py-6 bg-emerald-600 text-white rounded-3xl font-black uppercase tracking-widest hover:bg-emerald-700 transition-all shadow-xl disabled:opacity-50">Gerar PIX QR Code</button>
                  </div>
