import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES, MOCK_TRANSACTIONS, ALL_UFS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginData, setLoginData] = useState({ username: '', password: '' });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [insights, setInsights] = useState<string>('Analizando métricas em tempo real...');
  const [isSimulating, setIsSimulating] = useState(false);
  const [setupRequired, setSetupRequired] = useState<boolean>(false);
  const [showPixModal, setShowPixModal] = useState<Transaction | null>(null);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isMounted, setIsMounted] = useState(false);

  // Certificate Modal State
  const [showCertModal, setShowCertModal] = useState(false);
  const [isSavingCert, setIsSavingCert] = useState(false);
  const [editingCert, setEditingCert] = useState<Partial<DigitalCertificate> | null>(null);

  const safeFetch = async (url: string, options?: RequestInit) => {
    try {
      const response = await fetch(url, options);
      if (!response.ok) throw new Error(`Server returned ${response.status}`);
      const text = await response.text();
      try { return JSON.parse(text); } catch (e) { throw new Error("Invalid JSON response"); }
    } catch (e) {
      console.warn("API Fallback triggered:", e);
      const action = new URL(url, window.location.origin).searchParams.get('action');
      if (action === 'check_setup') return { setup_required: localStorage.getItem('nexus_users') === null };
      if (action === 'get_transactions') return MOCK_TRANSACTIONS;
      if (action === 'get_certificates') return certificates.length ? certificates : [];
      return { status: 'error', message: 'Offline Mode' };
    }
  };

  useEffect(() => {
    setIsMounted(true);
    const init = async () => {
      const data = await safeFetch(`${API_URL}?action=check_setup`);
      if (data && typeof data.setup_required !== 'undefined') setSetupRequired(data.setup_required);
      const saved = localStorage.getItem('nexus_user');
      if (saved) setCurrentUser(JSON.parse(saved));
    };
    init();
  }, []);

  const loadData = async () => {
    const [txData, certData] = await Promise.all([
      safeFetch(`${API_URL}?action=get_transactions`),
      safeFetch(`${API_URL}?action=get_certificates`)
    ]);
    setTransactions(Array.isArray(txData) ? txData : MOCK_TRANSACTIONS);
    if (Array.isArray(certData)) setCertificates(certData);
    if (currentUser?.role === UserRole.MASTER || setupRequired) {
      const userData = await safeFetch(`${API_URL}?action=get_users`);
      if (Array.isArray(userData)) setUsersList(userData);
    }
  };

  useEffect(() => { if (isMounted) loadData(); }, [currentUser, setupRequired, isMounted]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    const data = await safeFetch(`${API_URL}?action=login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(loginData)
    });
    if (data.status === 'success') {
      setCurrentUser(data.user);
      localStorage.setItem('nexus_user', JSON.stringify(data.user));
      setShowLoginModal(false);
    } else { setError(data.message || 'Credenciais inválidas.'); }
  };

  const stats = useMemo(() => {
    const success = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const totalVal = success.reduce((a, b) => a + Number(b.amount), 0);
    const pix = success.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    return {
      total: totalVal,
      pixPercent: ((pix / (totalVal || 1)) * 100).toFixed(1),
      txCount: transactions.length
    };
  }, [transactions]);

  const certStats = useMemo(() => {
    const now = new Date();
    const thirtyDays = new Date();
    thirtyDays.setDate(now.getDate() + 30);

    return {
      total: certificates.length,
      expired: certificates.filter(c => new Date(c.expirationDate) < now).length,
      alert: certificates.filter(c => {
        const d = new Date(c.expirationDate);
        return d >= now && d <= thirtyDays;
      }).length,
      active: certificates.filter(c => new Date(c.expirationDate) > thirtyDays).length
    };
  }, [certificates]);

  const handleSaveCert = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingCert(true);
    const data = await safeFetch(`${API_URL}?action=save_certificate`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingCert)
    });
    if (data.status === 'success') {
      setShowCertModal(false);
      setEditingCert(null);
      loadData();
    }
    setIsSavingCert(false);
  };

  const handleDeleteCert = async (id: string) => {
    if (!confirm('Deseja realmente remover este certificado?')) return;
    const data = await safeFetch(`${API_URL}?action=delete_certificate&id=${id}`);
    if (data.status === 'success') loadData();
  };

  const renderCertificates = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Certificados Digitais</h3>
          <p className="text-slate-500 font-medium">Controle centralizado de cadeias A1/A3 para NFC-e.</p>
        </div>
        <button 
          onClick={() => { setEditingCert({ alias: '', state: 'SP', expirationDate: '', type: 'A1', status: 'Ativo' }); setShowCertModal(true); }}
          className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl hover:scale-105 transition-all text-sm"
        >
          + Novo Certificado
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <StatCard label="Total" value={certStats.total} icon="🔐" color="bg-indigo-50 text-indigo-600" />
        <StatCard label="Ativos" value={certStats.active} icon="✅" color="bg-emerald-50 text-emerald-600" />
        <StatCard label="Em Alerta" value={certStats.alert} icon="⚠️" color="bg-amber-50 text-amber-600" />
        <StatCard label="Expirados" value={certStats.expired} icon="❌" color="bg-rose-50 text-rose-600" />
      </div>

      <div className="bg-white rounded-[3rem] border border-slate-100 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Apelido / Estado</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Tipo</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Vencimento</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {certificates.length === 0 ? (
              <tr><td colSpan={5} className="px-8 py-10 text-center text-slate-400 italic">Nenhum certificado cadastrado.</td></tr>
            ) : (
              certificates.map(c => {
                const expDate = new Date(c.expirationDate);
                const now = new Date();
                const diffDays = Math.ceil((expDate.getTime() - now.getTime()) / (1000 * 3600 * 24));
                const statusColor = diffDays < 0 ? 'bg-rose-100 text-rose-700' : diffDays <= 30 ? 'bg-amber-100 text-amber-700' : 'bg-emerald-100 text-emerald-700';

                return (
                  <tr key={c.id} className="hover:bg-slate-50/50 transition-colors">
                    <td className="px-8 py-5">
                      <p className="font-bold text-slate-800">{c.alias}</p>
                      <p className="text-[10px] font-black text-indigo-500 uppercase">{c.state}</p>
                    </td>
                    <td className="px-8 py-5">
                      <span className="text-xs font-bold text-slate-500">{c.type}</span>
                    </td>
                    <td className="px-8 py-5">
                      <p className="text-sm font-medium text-slate-600">{expDate.toLocaleDateString('pt-BR')}</p>
                      <p className={`text-[9px] font-black uppercase mt-1 ${diffDays < 0 ? 'text-rose-500' : 'text-slate-400'}`}>
                        {diffDays < 0 ? 'Expirado' : `Faltam ${diffDays} dias`}
                      </p>
                    </td>
                    <td className="px-8 py-5">
                      <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${statusColor}`}>
                        {diffDays < 0 ? 'Inativo' : 'Ativo'}
                      </span>
                    </td>
                    <td className="px-8 py-5 text-right">
                      <div className="flex justify-end gap-2">
                        <button onClick={() => { setEditingCert(c); setShowCertModal(true); }} className="w-8 h-8 bg-indigo-50 text-indigo-600 rounded-lg flex items-center justify-center hover:bg-indigo-600 hover:text-white transition-all">✏️</button>
                        <button onClick={() => handleDeleteCert(c.id)} className="w-8 h-8 bg-rose-50 text-rose-600 rounded-lg flex items-center justify-center hover:bg-rose-600 hover:text-white transition-all">🗑️</button>
                      </div>
                    </td>
                  </tr>
                );
              })
            )}
          </tbody>
        </table>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        currentUser={currentUser || (setupRequired ? ({ id: 0, name: 'Instalador', username: 'setup', role: UserRole.MASTER } as User) : null)} 
        onLogout={() => { setCurrentUser(null); localStorage.removeItem('nexus_user'); setActiveTab('dashboard'); }} 
      />

      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-20 bg-white/70 backdrop-blur-md border-b border-slate-100 sticky top-0 z-40 flex items-center justify-between px-10">
          <div className="flex flex-col">
            <h2 className="text-xl font-black text-slate-900 leading-none">NexusTEF</h2>
            <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest mt-1.5">{activeTab}</span>
          </div>
          <div className="flex items-center gap-6">
            {setupRequired ? (
              <div className="px-4 py-2 bg-amber-100 text-amber-700 rounded-xl text-[10px] font-black uppercase flex items-center gap-2">
                <span className="w-1.5 h-1.5 bg-amber-500 rounded-full animate-ping"></span> Setup Necessário
              </div>
            ) : currentUser ? (
              <div className="flex items-center gap-4">
                <div className="text-right hidden sm:block">
                  <p className="text-xs font-black text-slate-900 leading-tight">{currentUser.name}</p>
                  <p className="text-[9px] text-indigo-600 font-bold uppercase tracking-widest">{currentUser.role}</p>
                </div>
                <div className={`w-10 h-10 rounded-2xl flex items-center justify-center font-black shadow-lg ${currentUser.role === UserRole.MASTER ? 'bg-amber-500 text-white' : 'bg-indigo-600 text-white'}`}>
                  {currentUser.name.charAt(0)}
                </div>
              </div>
            ) : (
              <button onClick={() => setShowLoginModal(true)} className="px-6 py-2.5 bg-indigo-600 text-white rounded-xl font-bold text-xs uppercase tracking-widest shadow-lg hover:scale-105 transition-all">Entrar</button>
            )}
          </div>
        </header>

        <main className="p-10 max-w-[1400px] w-full mx-auto">
          {activeTab === 'dashboard' && (
            <div className="space-y-8 animate-in fade-in duration-700">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <StatCard label="Volume Total" value={`R$ ${stats.total.toLocaleString('pt-BR')}`} icon="💰" color="bg-indigo-50 text-indigo-600" />
                <StatCard label="Mix de Pix" value={`${stats.pixPercent}%`} icon="⚡" color="bg-emerald-50 text-emerald-600" />
                <StatCard label="Certificados" value={certStats.total} icon="🔐" color="bg-blue-50 text-blue-600" />
                <StatCard label="Transações" value={stats.txCount} icon="🔄" color="bg-slate-50 text-slate-600" />
              </div>
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm flex flex-col min-h-[450px]">
                  <h3 className="text-xl font-black text-slate-800 mb-8 tracking-tight">Performance Semanal</h3>
                  <div className="flex-1 w-full h-full min-h-[300px]">
                    <ResponsiveContainer width="100%" height={300}>
                      <AreaChart data={CHART_DATA}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                        <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} dy={10} />
                        <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} dx={-10} />
                        <Tooltip contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }} />
                        <Area type="monotone" dataKey="valor" stroke="#6366f1" strokeWidth={3} fillOpacity={0.1} fill="#6366f1" />
                      </AreaChart>
                    </ResponsiveContainer>
                  </div>
                </div>
                <div className="bg-slate-900 p-8 rounded-[3rem] text-white flex flex-col shadow-2xl overflow-hidden relative">
                  <div className="absolute top-0 right-0 p-8 opacity-10 text-6xl">🤖</div>
                  <h3 className="text-xl font-black mb-8">Insights Nexus</h3>
                  <div className="flex-1 bg-white/5 rounded-[2.5rem] p-6 text-sm italic text-slate-300 overflow-auto border border-white/5 relative z-10">
                    "{insights}"
                  </div>
                </div>
              </div>
              <FiscalMonitor states={SEFAZ_STATES} />
            </div>
          )}

          {activeTab === 'certificates' && renderCertificates()}
          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}
          {activeTab === 'simulator' && (
            <div className="max-w-xl mx-auto py-10">
               <div className="bg-white p-12 rounded-[3.5rem] shadow-2xl border border-slate-100 text-center relative overflow-hidden">
                  <div className="absolute top-0 left-0 w-full h-2 bg-indigo-500"></div>
                  <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-[2rem] flex items-center justify-center text-4xl mx-auto mb-8 shadow-inner">💳</div>
                  <h3 className="text-3xl font-black text-slate-900 mb-4 tracking-tight">Checkout Nexus</h3>
                  <div className="grid grid-cols-1 gap-4">
                     <button onClick={() => simulateTransaction(PaymentMethod.CREDIT)} disabled={isSimulating} className="py-6 bg-slate-900 text-white rounded-3xl font-black uppercase tracking-widest hover:bg-slate-800 shadow-xl transition-all">Cartão (Crédito/Débito)</button>
                     <button onClick={() => simulateTransaction(PaymentMethod.PIX)} disabled={isSimulating} className="py-6 bg-emerald-600 text-white rounded-3xl font-black uppercase tracking-widest hover:bg-emerald-700 shadow-xl transition-all">Gerar PIX QR Code</button>
                  </div>
               </div>
            </div>
          )}
        </main>
      </div>

      {showCertModal && editingCert && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-10 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Configurar Certificado</h3>
            <form onSubmit={handleSaveCert} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Apelido (Identificação)</label>
                <input type="text" placeholder="Ex: Filial Curitiba" required value={editingCert.alias} onChange={e => setEditingCert({...editingCert, alias: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Estado (UF)</label>
                  <select value={editingCert.state} onChange={e => setEditingCert({...editingCert, state: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none">
                    {ALL_UFS.map(uf => <option key={uf} value={uf}>{uf}</option>)}
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Tipo</label>
                  <select value={editingCert.type} onChange={e => setEditingCert({...editingCert, type: e.target.value as any})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none">
                    <option value="A1">A1 (Arquivo)</option>
                    <option value="A3">A3 (Cartão/Token)</option>
                  </select>
                </div>
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Data de Expiração</label>
                <input type="date" required value={editingCert.expirationDate} onChange={e => setEditingCert({...editingCert, expirationDate: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none" />
              </div>
              <div className="flex gap-4 pt-6">
                <button type="button" onClick={() => setShowCertModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold uppercase text-xs tracking-widest">Cancelar</button>
                <button type="submit" disabled={isSavingCert} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-indigo-100 disabled:opacity-50">
                  {isSavingCert ? 'Salvando...' : 'Gravar Dados'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showLoginModal && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300 text-center">
            <h1 className="text-3xl font-black text-slate-900 mb-8 tracking-tight">Login Nexus</h1>
            <form onSubmit={handleLogin} className="space-y-6">
              <input type="text" placeholder="Usuário" required value={loginData.username} onChange={e => setLoginData({...loginData, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-5 px-6 font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              <input type="password" placeholder="Senha" required value={loginData.password} onChange={e => setLoginData({...loginData, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-5 px-6 font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              {error && <div className="p-4 bg-rose-50 text-rose-600 rounded-2xl text-[10px] font-black uppercase text-center animate-shake">{error}</div>}
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowLoginModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs tracking-widest">Sair</button>
                <button type="submit" className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs shadow-xl shadow-indigo-100">Acessar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showPixModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-xl z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[4rem] w-full max-w-md shadow-2xl text-center animate-in zoom-in">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">QR Code PIX</h3>
            <div className="bg-slate-50 p-8 rounded-[3rem] mb-8 inline-block border border-slate-100">
               <img src={showPixModal.pixQrCode} alt="PIX QR" className="w-56 h-56 mx-auto" />
            </div>
            <p className="text-3xl font-black text-slate-900 mb-2">R$ {showPixModal.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            <button onClick={() => setShowPixModal(null)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest">Fechar</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES, MOCK_TRANSACTIONS, ALL_UFS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginData, setLoginData] = useState({ username: '', password: '' });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [insights, setInsights] = useState<string>('Analizando métricas em tempo real...');
  const [isSimulating, setIsSimulating] = useState(false);
  const [setupRequired, setSetupRequired] = useState<boolean>(false);
  const [showPixModal, setShowPixModal] = useState<Transaction | null>(null);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isMounted, setIsMounted] = useState(false);

  // Certificate Modal State
  const [showCertModal, setShowCertModal] = useState(false);
  const [isSavingCert, setIsSavingCert] = useState(false);
  const [editingCert, setEditingCert] = useState<Partial<DigitalCertificate> | null>(null);

  const safeFetch = async (url: string, options?: RequestInit) => {
    try {
      const response = await fetch(url, options);
      if (!response.ok) throw new Error(`Server returned ${response.status}`);
      const text = await response.text();
      try { return JSON.parse(text); } catch (e) { throw new Error("Invalid JSON response"); }
    } catch (e) {
      console.warn("API Fallback triggered:", e);
      const action = new URL(url, window.location.origin).searchParams.get('action');
      if (action === 'check_setup') return { setup_required: localStorage.getItem('nexus_users') === null };
      if (action === 'get_transactions') return MOCK_TRANSACTIONS;
      if (action === 'get_certificates') return certificates.length ? certificates : [];
      return { status: 'error', message: 'Offline Mode' };
    }
  };

  useEffect(() => {
    setIsMounted(true);
    const init = async () => {
      const data = await safeFetch(`${API_URL}?action=check_setup`);
      if (data && typeof data.setup_required !== 'undefined') setSetupRequired(data.setup_required);
      const saved = localStorage.getItem('nexus_user');
      if (saved) setCurrentUser(JSON.parse(saved));
    };
    init();
  }, []);

  const loadData = async () => {
    const [txData, certData] = await Promise.all([
      safeFetch(`${API_URL}?action=get_transactions`),
      safeFetch(`${API_URL}?action=get_certificates`)
    ]);
    setTransactions(Array.isArray(txData) ? txData : MOCK_TRANSACTIONS);
    if (Array.isArray(certData)) setCertificates(certData);
    if (currentUser?.role === UserRole.MASTER || setupRequired) {
      const userData = await safeFetch(`${API_URL}?action=get_users`);
      if (Array.isArray(userData)) setUsersList(userData);
    }
  };

  useEffect(() => { if (isMounted) loadData(); }, [currentUser, setupRequired, isMounted]);

  // Fix: Call Gemini API to get smart insights whenever transactions change
  useEffect(() => {
    if (transactions.length > 0 && activeTab === 'dashboard') {
      const fetchInsights = async () => {
        const result = await getSmartInsights(transactions);
        setInsights(result);
      };
      const timer = setTimeout(fetchInsights, 2000);
      return () => clearTimeout(timer);
    }
  }, [transactions, activeTab]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    const data = await safeFetch(`${API_URL}?action=login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(loginData)
    });
    if (data.status === 'success') {
      setCurrentUser(data.user);
      localStorage.setItem('nexus_user', JSON.stringify(data.user));
      setShowLoginModal(false);
    } else { setError(data.message || 'Credenciais inválidas.'); }
  };

  const stats = useMemo(() => {
    const success = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const totalVal = success.reduce((a, b) => a + Number(b.amount), 0);
    const pix = success.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    return {
      total: totalVal,
      pixPercent: ((pix / (totalVal || 1)) * 100).toFixed(1),
      txCount: transactions.length
    };
  }, [transactions]);

  const certStats = useMemo(() => {
    const now = new Date();
    const thirtyDays = new Date();
    thirtyDays.setDate(now.getDate() + 30);

    return {
      total: certificates.length,
      expired: certificates.filter(c => new Date(c.expirationDate) < now).length,
      alert: certificates.filter(c => {
        const d = new Date(c.expirationDate);
        return d >= now && d <= thirtyDays;
      }).length,
      active: certificates.filter(c => new Date(c.expirationDate) > thirtyDays).length
    };
  }, [certificates]);

  const handleSaveCert = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingCert(true);
    const data = await safeFetch(`${API_URL}?action=save_certificate`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingCert)
    });
    if (data.status === 'success') {
      setShowCertModal(false);
      setEditingCert(null);
      loadData();
    }
    setIsSavingCert(false);
  };

  const handleDeleteCert = async (id: string) => {
    if (!confirm('Deseja realmente remover este certificado?')) return;
    const data = await safeFetch(`${API_URL}?action=delete_certificate&id=${id}`);
    if (data.status === 'success') loadData();
  };

  // Fix: Added missing simulateTransaction function to handle TEF simulator buttons
  const simulateTransaction = async (method: PaymentMethod) => {
    setIsSimulating(true);
    const amount = Math.floor(Math.random() * 500) + 10.5;

    try {
      const data = await safeFetch(`${API_URL}?action=simulate_transaction`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ method, amount })
      });

      if (data.status === 'success' && data.transaction) {
        setTransactions(prev => [data.transaction, ...prev]);
        if (method === PaymentMethod.PIX) setShowPixModal(data.transaction);
      } else {
        // Mock fallback for simulation UI
        const mockTx: Transaction = {
          id: `TX-${Math.floor(Math.random() * 90000 + 10000)}`,
          timestamp: new Date().toISOString(),
          amount: amount,
          method: method,
          status: PaymentStatus.SUCCESS,
          terminalId: 'TERM-SIM',
          segment: 'Simulação',
          fiscalNoteId: Math.floor(Math.random() * 9000 + 1000).toString(),
          fiscalStatus: FiscalStatus.AUTHORIZED,
          pixQrCode: method === PaymentMethod.PIX ? 'https://api.qrserver.com/v1/create-qr-code/?size=250x250&data=00020101021226870014BR.GOV.BCB.PIX0125' : undefined
        };
        setTransactions(prev => [mockTx, ...prev]);
        if (method === PaymentMethod.PIX) setShowPixModal(mockTx);
      }
    } catch (e) {
      console.error("Simulation failed:", e);
    } finally {
      setIsSimulating(false);
      setActiveTab('dashboard');
    }
  };

  const renderCertificates = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Certificados Digitais</h3>
          <p className="text-slate-500 font-medium">Controle centralizado de cadeias A1/A3 para NFC-e.</p>
        </div>
        <button 
          onClick={() => { setEditingCert({ alias: '', state: 'SP', expirationDate: '', type: 'A1', status: 'Ativo' }); setShowCertModal(true); }}
          className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl hover:scale-105 transition-all text-sm"
        >
          + Novo Certificado
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <StatCard label="Total" value={certStats.total} icon="🔐" color="bg-indigo-50 text-indigo-600" />
        <StatCard label="Ativos" value={certStats.active} icon="✅" color="bg-emerald-50 text-emerald-600" />
        <StatCard label="Em Alerta" value={certStats.alert} icon="⚠️" color="bg-amber-50 text-amber-600" />
        <StatCard label="Expirados" value={certStats.expired} icon="❌" color="bg-rose-50 text-rose-600" />
      </div>

      <div className="bg-white rounded-[3rem] border border-slate-100 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Apelido / Estado</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Tipo</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Vencimento</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {certificates.length === 0 ? (
              <tr><td colSpan={5} className="px-8 py-10 text-center text-slate-400 italic">Nenhum certificado cadastrado.</td></tr>
            ) : (
              certificates.map(c => {
                const expDate = new Date(c.expirationDate);
                const now = new Date();
                const diffDays = Math.ceil((expDate.getTime() - now.getTime()) / (1000 * 3600 * 24));
                const statusColor = diffDays < 0 ? 'bg-rose-100 text-rose-700' : diffDays <= 30 ? 'bg-amber-100 text-amber-700' : 'bg-emerald-100 text-emerald-700';

                return (
                  <tr key={c.id} className="hover:bg-slate-50/50 transition-colors">
                    <td className="px-8 py-5">
                      <p className="font-bold text-slate-800">{c.alias}</p>
                      <p className="text-[10px] font-black text-indigo-500 uppercase">{c.state}</p>
                    </td>
                    <td className="px-8 py-5">
                      <span className="text-xs font-bold text-slate-500">{c.type}</span>
                    </td>
                    <td className="px-8 py-5">
                      <p className="text-sm font-medium text-slate-600">{expDate.toLocaleDateString('pt-BR')}</p>
                      <p className={`text-[9px] font-black uppercase mt-1 ${diffDays < 0 ? 'text-rose-500' : 'text-slate-400'}`}>
                        {diffDays < 0 ? 'Expirado' : `Faltam ${diffDays} dias`}
                      </p>
                    </td>
                    <td className="px-8 py-5">
                      <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${statusColor}`}>
                        {diffDays < 0 ? 'Inativo' : 'Ativo'}
                      </span>
                    </td>
                    <td className="px-8 py-5 text-right">
                      <div className="flex justify-end gap-2">
                        <button onClick={() => { setEditingCert(c); setShowCertModal(true); }} className="w-8 h-8 bg-indigo-50 text-indigo-600 rounded-lg flex items-center justify-center hover:bg-indigo-600 hover:text-white transition-all">✏️</button>
                        <button onClick={() => handleDeleteCert(c.id)} className="w-8 h-8 bg-rose-50 text-rose-600 rounded-lg flex items-center justify-center hover:bg-rose-600 hover:text-white transition-all">🗑️</button>
                      </div>
                    </td>
                  </tr>
                );
              })
            )}
          </tbody>
        </table>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        currentUser={currentUser || (setupRequired ? ({ id: 0, name: 'Instalador', username: 'setup', role: UserRole.MASTER } as User) : null)} 
        onLogout={() => { setCurrentUser(null); localStorage.removeItem('nexus_user'); setActiveTab('dashboard'); }} 
      />

      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-20 bg-white/70 backdrop-blur-md border-b border-slate-100 sticky top-0 z-40 flex items-center justify-between px-10">
          <div className="flex flex-col">
            <h2 className="text-xl font-black text-slate-900 leading-none">NexusTEF</h2>
            <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest mt-1.5">{activeTab}</span>
          </div>
          <div className="flex items-center gap-6">
            {setupRequired ? (
              <div className="px-4 py-2 bg-amber-100 text-amber-700 rounded-xl text-[10px] font-black uppercase flex items-center gap-2">
                <span className="w-1.5 h-1.5 bg-amber-500 rounded-full animate-ping"></span> Setup Necessário
              </div>
            ) : currentUser ? (
              <div className="flex items-center gap-4">
                <div className="text-right hidden sm:block">
                  <p className="text-xs font-black text-slate-900 leading-tight">{currentUser.name}</p>
                  <p className="text-[9px] text-indigo-600 font-bold uppercase tracking-widest">{currentUser.role}</p>
                </div>
                <div className={`w-10 h-10 rounded-2xl flex items-center justify-center font-black shadow-lg ${currentUser.role === UserRole.MASTER ? 'bg-amber-500 text-white' : 'bg-indigo-600 text-white'}`}>
                  {currentUser.name.charAt(0)}
                </div>
              </div>
            ) : (
              <button onClick={() => setShowLoginModal(true)} className="px-6 py-2.5 bg-indigo-600 text-white rounded-xl font-bold text-xs uppercase tracking-widest shadow-lg hover:scale-105 transition-all">Entrar</button>
            )}
          </div>
        </header>

        <main className="p-10 max-w-[1400px] w-full mx-auto">
          {activeTab === 'dashboard' && (
            <div className="space-y-8 animate-in fade-in duration-700">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <StatCard label="Volume Total" value={`R$ ${stats.total.toLocaleString('pt-BR')}`} icon="💰" color="bg-indigo-50 text-indigo-600" />
                <StatCard label="Mix de Pix" value={`${stats.pixPercent}%`} icon="⚡" color="bg-emerald-50 text-emerald-600" />
                <StatCard label="Certificados" value={certStats.total} icon="🔐" color="bg-blue-50 text-blue-600" />
                <StatCard label="Transações" value={stats.txCount} icon="🔄" color="bg-slate-50 text-slate-600" />
              </div>
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm flex flex-col min-h-[450px]">
                  <h3 className="text-xl font-black text-slate-800 mb-8 tracking-tight">Performance Semanal</h3>
                  <div className="flex-1 w-full h-full min-h-[300px]">
                    <ResponsiveContainer width="100%" height={300}>
                      <AreaChart data={CHART_DATA}>
                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                        <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} dy={10} />
                        <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} dx={-10} />
                        <Tooltip contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }} />
                        <Area type="monotone" dataKey="valor" stroke="#6366f1" strokeWidth={3} fillOpacity={0.1} fill="#6366f1" />
                      </AreaChart>
                    </ResponsiveContainer>
                  </div>
                </div>
                <div className="bg-slate-900 p-8 rounded-[3rem] text-white flex flex-col shadow-2xl overflow-hidden relative">
                  <div className="absolute top-0 right-0 p-8 opacity-10 text-6xl">🤖</div>
                  <h3 className="text-xl font-black mb-8">Insights Nexus</h3>
                  <div className="flex-1 bg-white/5 rounded-[2.5rem] p-6 text-sm italic text-slate-300 overflow-auto border border-white/5 relative z-10">
                    "{insights}"
                  </div>
                </div>
              </div>
              <FiscalMonitor states={SEFAZ_STATES} />
            </div>
          )}

          {activeTab === 'certificates' && renderCertificates()}
          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}
          {activeTab === 'simulator' && (
            <div className="max-w-xl mx-auto py-10">
               <div className="bg-white p-12 rounded-[3.5rem] shadow-2xl border border-slate-100 text-center relative overflow-hidden">
                  <div className="absolute top-0 left-0 w-full h-2 bg-indigo-500"></div>
                  <div className="w-20 h-20 bg-indigo-50 text-indigo-600 rounded-[2rem] flex items-center justify-center text-4xl mx-auto mb-8 shadow-inner">💳</div>
                  <h3 className="text-3xl font-black text-slate-900 mb-4 tracking-tight">Checkout Nexus</h3>
                  <div className="grid grid-cols-1 gap-4">
                     <button onClick={() => simulateTransaction(PaymentMethod.CREDIT)} disabled={isSimulating} className="py-6 bg-slate-900 text-white rounded-3xl font-black uppercase tracking-widest hover:bg-slate-800 shadow-xl transition-all">Cartão (Crédito/Débito)</button>
                     <button onClick={() => simulateTransaction(PaymentMethod.PIX)} disabled={isSimulating} className="py-6 bg-emerald-600 text-white rounded-3xl font-black uppercase tracking-widest hover:bg-emerald-700 shadow-xl transition-all">Gerar PIX QR Code</button>
                  </div>
               </div>
            </div>
          )}
        </main>
      </div>

      {showCertModal && editingCert && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-10 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Configurar Certificado</h3>
            <form onSubmit={handleSaveCert} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Apelido (Identificação)</label>
                <input type="text" placeholder="Ex: Filial Curitiba" required value={editingCert.alias} onChange={e => setEditingCert({...editingCert, alias: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Estado (UF)</label>
                  <select value={editingCert.state} onChange={e => setEditingCert({...editingCert, state: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none">
                    {ALL_UFS.map(uf => <option key={uf} value={uf}>{uf}</option>)}
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Tipo</label>
                  <select value={editingCert.type} onChange={e => setEditingCert({...editingCert, type: e.target.value as any})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none">
                    <option value="A1">A1 (Arquivo)</option>
                    <option value="A3">A3 (Cartão/Token)</option>
                  </select>
                </div>
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Data de Expiração</label>
                <input type="date" required value={editingCert.expirationDate} onChange={e => setEditingCert({...editingCert, expirationDate: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none" />
              </div>
              <div className="flex gap-4 pt-6">
                <button type="button" onClick={() => setShowCertModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold uppercase text-xs tracking-widest">Cancelar</button>
                <button type="submit" disabled={isSavingCert} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl shadow-indigo-100 disabled:opacity-50">
                  {isSavingCert ? 'Salvando...' : 'Gravar Dados'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showLoginModal && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300 text-center">
            <h1 className="text-3xl font-black text-slate-900 mb-8 tracking-tight">Login Nexus</h1>
            <form onSubmit={handleLogin} className="space-y-6">
              <input type="text" placeholder="Usuário" required value={loginData.username} onChange={e => setLoginData({...loginData, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-5 px-6 font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              <input type="password" placeholder="Senha" required value={loginData.password} onChange={e => setLoginData({...loginData, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-5 px-6 font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              {error && <div className="p-4 bg-rose-50 text-rose-600 rounded-2xl text-[10px] font-black uppercase text-center animate-shake">{error}</div>}
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowLoginModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs tracking-widest">Sair</button>
                <button type="submit" className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs shadow-xl shadow-indigo-100">Acessar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showPixModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-xl z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[4rem] w-full max-w-md shadow-2xl text-center animate-in zoom-in">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">QR Code PIX</h3>
            <div className="bg-slate-50 p-8 rounded-[3rem] mb-8 inline-block border border-slate-100">
               <img src={showPixModal.pixQrCode} alt="PIX QR" className="w-56 h-56 mx-auto" />
            </div>
            <p className="text-3xl font-black text-slate-900 mb-2">R$ {showPixModal.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            <button onClick={() => setShowPixModal(null)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest">Fechar</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES, MOCK_TRANSACTIONS, ALL_UFS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginData, setLoginData] = useState({ username: '', password: '' });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [insights, setInsights] = useState<string>('Analizando métricas em tempo real...');
  const [isSimulating, setIsSimulating] = useState(false);
  const [setupRequired, setSetupRequired] = useState<boolean>(false);
  const [showPixModal, setShowPixModal] = useState<Transaction | null>(null);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isMounted, setIsMounted] = useState(false);

  // Certificate Modal State
  const [showCertModal, setShowCertModal] = useState(false);
  const [isSavingCert, setIsSavingCert] = useState(false);
  const [editingCert, setEditingCert] = useState<Partial<DigitalCertificate> | null>(null);

  // User Management State
  const [showUserModal, setShowUserModal] = useState(false);
  const [isSavingUser, setIsSavingUser] = useState(false);
  const [editingUser, setEditingUser] = useState<Partial<User> & { password?: string } | null>(null);

  const safeFetch = async (url: string, options?: RequestInit) => {
    try {
      const response = await fetch(url, options);
      if (!response.ok) throw new Error(`Server returned ${response.status}`);
      const text = await response.text();
      try { return JSON.parse(text); } catch (e) { throw new Error("Invalid JSON response"); }
    } catch (e) {
      console.warn("API Fallback triggered:", e);
      const action = new URL(url, window.location.origin).searchParams.get('action');
      if (action === 'check_setup') return { setup_required: localStorage.getItem('nexus_users') === null };
      if (action === 'get_transactions') return MOCK_TRANSACTIONS;
      if (action === 'get_certificates') return certificates.length ? certificates : [];
      if (action === 'get_users') return usersList.length ? usersList : [];
      return { status: 'error', message: 'Offline Mode' };
    }
  };

  useEffect(() => {
    setIsMounted(true);
    const init = async () => {
      const data = await safeFetch(`${API_URL}?action=check_setup`);
      if (data && typeof data.setup_required !== 'undefined') setSetupRequired(data.setup_required);
      const saved = localStorage.getItem('nexus_user');
      if (saved) setCurrentUser(JSON.parse(saved));
    };
    init();
  }, []);

  const loadData = async () => {
    const [txData, certData, userData] = await Promise.all([
      safeFetch(`${API_URL}?action=get_transactions`),
      safeFetch(`${API_URL}?action=get_certificates`),
      safeFetch(`${API_URL}?action=get_users`)
    ]);
    setTransactions(Array.isArray(txData) ? txData : MOCK_TRANSACTIONS);
    if (Array.isArray(certData)) setCertificates(certData);
    if (Array.isArray(userData)) setUsersList(userData);

    if (currentUser?.role === UserRole.MASTER || setupRequired) {
      // Refresh users specifically if master
      const freshUsers = await safeFetch(`${API_URL}?action=get_users`);
      if (Array.isArray(freshUsers)) setUsersList(freshUsers);
    }
  };

  useEffect(() => { if (isMounted) loadData(); }, [currentUser, setupRequired, isMounted]);

  useEffect(() => {
    if (transactions.length > 0 && activeTab === 'dashboard') {
      const fetchInsights = async () => {
        const result = await getSmartInsights(transactions);
        setInsights(result);
      };
      const timer = setTimeout(fetchInsights, 2000);
      return () => clearTimeout(timer);
    }
  }, [transactions, activeTab]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    const data = await safeFetch(`${API_URL}?action=login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(loginData)
    });
    if (data.status === 'success') {
      setCurrentUser(data.user);
      localStorage.setItem('nexus_user', JSON.stringify(data.user));
      setShowLoginModal(false);
    } else { setError(data.message || 'Credenciais inválidas.'); }
  };

  const handleSaveUser = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingUser(true);
    const data = await safeFetch(`${API_URL}?action=save_user`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingUser)
    });
    if (data.status === 'success') {
      setShowUserModal(false);
      setEditingUser(null);
      loadData();
    }
    setIsSavingUser(false);
  };

  const handleDeleteUser = async (id: number) => {
    if (!confirm('Deseja realmente remover este acesso?')) return;
    const data = await safeFetch(`${API_URL}?action=delete_user&id=${id}`);
    if (data.status === 'success') loadData();
  };

  const stats = useMemo(() => {
    const success = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const totalVal = success.reduce((a, b) => a + Number(b.amount), 0);
    const pix = success.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    return {
      total: totalVal,
      pixPercent: ((pix / (totalVal || 1)) * 100).toFixed(1),
      txCount: transactions.length
    };
  }, [transactions]);

  const simulateTransaction = async (method: PaymentMethod) => {
    setIsSimulating(true);
    const amount = Math.floor(Math.random() * 500) + 10.5;
    const mockTx: Transaction = {
      id: `TX-${Math.floor(Math.random() * 90000 + 10000)}`,
      timestamp: new Date().toISOString(),
      amount: amount,
      method: method,
      status: PaymentStatus.SUCCESS,
      terminalId: 'TERM-SIM',
      segment: 'Simulação',
      fiscalNoteId: Math.floor(Math.random() * 9000 + 1000).toString(),
      fiscalStatus: FiscalStatus.AUTHORIZED,
      pixQrCode: method === PaymentMethod.PIX ? 'https://api.qrserver.com/v1/create-qr-code/?size=250x250&data=00020101021226870014BR.GOV.BCB.PIX0125' : undefined
    };
    setTransactions(prev => [mockTx, ...prev]);
    if (method === PaymentMethod.PIX) setShowPixModal(mockTx);
    setIsSimulating(false);
    setActiveTab('dashboard');
  };

  const renderUsers = () => (
    <div className="space-y-8 animate-in slide-in-from-bottom duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Acessos</h3>
          <p className="text-slate-500 font-medium">Controle de quem pode operar e administrar o NexusTEF.</p>
        </div>
        <button 
          onClick={() => { setEditingUser({ name: '', username: '', role: UserRole.OPERATOR, password: '' }); setShowUserModal(true); }}
          className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl hover:scale-105 transition-all text-sm"
        >
          + Novo Usuário
        </button>
      </div>

      <div className="bg-white rounded-[3rem] border border-slate-100 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Identidade</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Username</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nível de Acesso</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {usersList.length === 0 ? (
              <tr><td colSpan={4} className="px-8 py-10 text-center text-slate-400 italic">Nenhum usuário encontrado.</td></tr>
            ) : (
              usersList.map(u => (
                <tr key={u.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-8 py-5">
                    <div className="flex items-center gap-3">
                      <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-bold text-sm ${
                        u.role === UserRole.MASTER ? 'bg-amber-100 text-amber-700' : 
                        u.role === UserRole.ADMIN ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-100 text-slate-700'
                      }`}>
                        {u.name.charAt(0)}
                      </div>
                      <span className="font-bold text-slate-800">{u.name}</span>
                    </div>
                  </td>
                  <td className="px-8 py-5 text-sm font-mono text-slate-500">@{u.username}</td>
                  <td className="px-8 py-5">
                    <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${
                      u.role === UserRole.MASTER ? 'bg-amber-500 text-white' : 
                      u.role === UserRole.ADMIN ? 'bg-indigo-600 text-white' : 'bg-slate-500 text-white'
                    }`}>
                      {u.role}
                    </span>
                  </td>
                  <td className="px-8 py-5 text-right">
                    <div className="flex justify-end gap-2">
                      <button onClick={() => { setEditingUser({...u, password: ''}); setShowUserModal(true); }} className="w-8 h-8 bg-indigo-50 text-indigo-600 rounded-lg flex items-center justify-center hover:bg-indigo-600 hover:text-white transition-all">✏️</button>
                      {u.username !== 'master' && (
                        <button onClick={() => handleDeleteUser(u.id)} className="w-8 h-8 bg-rose-50 text-rose-600 rounded-lg flex items-center justify-center hover:bg-rose-600 hover:text-white transition-all">🗑️</button>
                      )}
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );

  const renderCertificates = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Certificados Digitais</h3>
          <p className="text-slate-500 font-medium">Controle centralizado de cadeias A1/A3 para NFC-e.</p>
        </div>
        <button 
          onClick={() => { setEditingCert({ alias: '', state: 'SP', expirationDate: '', type: 'A1', status: 'Ativo' }); setShowCertModal(true); }}
          className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl hover:scale-105 transition-all text-sm"
        >
          + Novo Certificado
        </button>
      </div>
      {/* Rest of certificates UI stays the same as per previous turn */}
      <div className="bg-white rounded-[3rem] border border-slate-100 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Apelido</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Estado</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {certificates.map(c => (
              <tr key={c.id}>
                <td className="px-8 py-5 font-bold">{c.alias}</td>
                <td className="px-8 py-5">{c.state}</td>
                <td className="px-8 py-5 text-right">
                  <button onClick={() => handleDeleteCert(c.id)} className="text-rose-500">Remover</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        currentUser={currentUser || (setupRequired ? ({ id: 0, name: 'Instalador', username: 'setup', role: UserRole.MASTER } as User) : null)} 
        onLogout={() => { setCurrentUser(null); localStorage.removeItem('nexus_user'); setActiveTab('dashboard'); }} 
      />

      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-20 bg-white/80 backdrop-blur-md border-b border-slate-100 sticky top-0 z-40 flex items-center justify-between px-10">
          <div className="flex flex-col">
            <h2 className="text-xl font-black text-slate-900 leading-none">NexusTEF</h2>
            <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest mt-1.5">{activeTab}</span>
          </div>
          <div className="flex items-center gap-6">
            {currentUser ? (
              <div className="flex items-center gap-4">
                <div className="text-right hidden sm:block">
                  <p className="text-xs font-black text-slate-900 leading-tight">{currentUser.name}</p>
                  <p className="text-[9px] text-indigo-600 font-bold uppercase tracking-widest">{currentUser.role}</p>
                </div>
                <div className={`w-10 h-10 rounded-2xl flex items-center justify-center font-black shadow-lg ${currentUser.role === UserRole.MASTER ? 'bg-amber-500 text-white' : 'bg-indigo-600 text-white'}`}>
                  {currentUser.name.charAt(0)}
                </div>
              </div>
            ) : (
              <button onClick={() => setShowLoginModal(true)} className="px-6 py-2.5 bg-indigo-600 text-white rounded-xl font-bold text-xs uppercase tracking-widest shadow-lg">Entrar</button>
            )}
          </div>
        </header>

        <main className="p-10 max-w-[1400px] w-full mx-auto">
          {activeTab === 'dashboard' && (
            <div className="space-y-8 animate-in fade-in duration-700">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <StatCard label="Volume Total" value={`R$ ${stats.total.toLocaleString('pt-BR')}`} icon="💰" color="bg-indigo-50 text-indigo-600" />
                <StatCard label="Mix de Pix" value={`${stats.pixPercent}%`} icon="⚡" color="bg-emerald-50 text-emerald-600" />
                <StatCard label="Usuários" value={usersList.length} icon="👥" color="bg-amber-50 text-amber-600" />
                <StatCard label="Transações" value={stats.txCount} icon="🔄" color="bg-slate-50 text-slate-600" />
              </div>
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm min-h-[400px]">
                  <h3 className="text-xl font-black text-slate-800 mb-8 tracking-tight">Fluxo Financeiro</h3>
                  <ResponsiveContainer width="100%" height={300}>
                    <AreaChart data={CHART_DATA}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                      <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                      <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                      <Tooltip contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }} />
                      <Area type="monotone" dataKey="valor" stroke="#6366f1" strokeWidth={3} fillOpacity={0.1} fill="#6366f1" />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>
                <div className="bg-slate-900 p-8 rounded-[3rem] text-white flex flex-col shadow-2xl relative overflow-hidden">
                  <div className="absolute top-0 right-0 p-8 opacity-10 text-6xl">🤖</div>
                  <h3 className="text-xl font-black mb-8">Nexus AI</h3>
                  <div className="flex-1 bg-white/5 rounded-[2.5rem] p-6 text-sm italic text-slate-300 overflow-auto border border-white/5 relative z-10">
                    "{insights}"
                  </div>
                </div>
              </div>
              <FiscalMonitor states={SEFAZ_STATES} />
            </div>
          )}

          {activeTab === 'users' && renderUsers()}
          {activeTab === 'certificates' && renderCertificates()}
          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}
          {activeTab === 'simulator' && (
            <div className="max-w-xl mx-auto py-10">
               <div className="bg-white p-12 rounded-[3.5rem] shadow-2xl border border-slate-100 text-center relative overflow-hidden">
                  <h3 className="text-3xl font-black text-slate-900 mb-8 tracking-tight">Checkout Nexus</h3>
                  <div className="grid grid-cols-1 gap-4">
                     <button onClick={() => simulateTransaction(PaymentMethod.CREDIT)} disabled={isSimulating} className="py-6 bg-slate-900 text-white rounded-3xl font-black uppercase tracking-widest hover:bg-slate-800 shadow-xl">Cartão Crédito</button>
                     <button onClick={() => simulateTransaction(PaymentMethod.PIX)} disabled={isSimulating} className="py-6 bg-emerald-600 text-white rounded-3xl font-black uppercase tracking-widest hover:bg-emerald-700 shadow-xl">Gerar PIX QR</button>
                  </div>
               </div>
            </div>
          )}
        </main>
      </div>

      {showUserModal && editingUser && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-10 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Configurar Acesso</h3>
            <form onSubmit={handleSaveUser} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nome Completo</label>
                <input type="text" required value={editingUser.name} onChange={e => setEditingUser({...editingUser, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Username (Login)</label>
                <input type="text" required value={editingUser.username} onChange={e => setEditingUser({...editingUser, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Senha {editingUser.id ? '(Deixe vazio para manter)' : ''}</label>
                <input type="password" value={editingUser.password} onChange={e => setEditingUser({...editingUser, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nível de Permissão</label>
                <select value={editingUser.role} onChange={e => setEditingUser({...editingUser, role: e.target.value as any})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none">
                  <option value={UserRole.OPERATOR}>Operador (Básico)</option>
                  <option value={UserRole.ADMIN}>Administrador (Médio)</option>
                  <option value={UserRole.MASTER}>Master (Total)</option>
                </select>
              </div>
              <div className="flex gap-4 pt-6">
                <button type="button" onClick={() => setShowUserModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold uppercase text-xs tracking-widest">Cancelar</button>
                <button type="submit" disabled={isSavingUser} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl disabled:opacity-50">
                  {isSavingUser ? 'Salvando...' : 'Gravar Acesso'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Login and Pix Modals stay consistent with previous Turn */}
      {showLoginModal && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[3.5rem] w-full max-w-md shadow-2xl text-center">
            <h1 className="text-3xl font-black text-slate-900 mb-8 tracking-tight">Acesso Restrito</h1>
            <form onSubmit={handleLogin} className="space-y-6">
              <input type="text" placeholder="Usuário" required value={loginData.username} onChange={e => setLoginData({...loginData, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-5 px-6 font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              <input type="password" placeholder="Senha" required value={loginData.password} onChange={e => setLoginData({...loginData, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-5 px-6 font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              {error && <div className="p-4 bg-rose-50 text-rose-600 rounded-2xl text-[10px] font-black uppercase text-center">{error}</div>}
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowLoginModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs tracking-widest">Sair</button>
                <button type="submit" className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs shadow-xl">Entrar</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES, MOCK_TRANSACTIONS, ALL_UFS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginData, setLoginData] = useState({ username: '', password: '' });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [insights, setInsights] = useState<string>('Analizando métricas em tempo real...');
  const [isSimulating, setIsSimulating] = useState(false);
  const [setupRequired, setSetupRequired] = useState<boolean>(false);
  const [showPixModal, setShowPixModal] = useState<Transaction | null>(null);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isMounted, setIsMounted] = useState(false);

  // Certificate Modal State
  const [showCertModal, setShowCertModal] = useState(false);
  const [isSavingCert, setIsSavingCert] = useState(false);
  const [editingCert, setEditingCert] = useState<Partial<DigitalCertificate> | null>(null);

  // User Management State
  const [showUserModal, setShowUserModal] = useState(false);
  const [isSavingUser, setIsSavingUser] = useState(false);
  const [editingUser, setEditingUser] = useState<Partial<User> & { password?: string } | null>(null);

  const safeFetch = async (url: string, options?: RequestInit) => {
    try {
      const response = await fetch(url, options);
      if (!response.ok) throw new Error(`Server returned ${response.status}`);
      const text = await response.text();
      try { return JSON.parse(text); } catch (e) { throw new Error("Invalid JSON response"); }
    } catch (e) {
      console.warn("API Fallback triggered:", e);
      const action = new URL(url, window.location.origin).searchParams.get('action');
      if (action === 'check_setup') return { setup_required: localStorage.getItem('nexus_users') === null };
      if (action === 'get_transactions') return MOCK_TRANSACTIONS;
      if (action === 'get_certificates') return certificates.length ? certificates : [];
      if (action === 'get_users') return usersList.length ? usersList : [];
      return { status: 'error', message: 'Offline Mode' };
    }
  };

  useEffect(() => {
    setIsMounted(true);
    const init = async () => {
      const data = await safeFetch(`${API_URL}?action=check_setup`);
      if (data && typeof data.setup_required !== 'undefined') setSetupRequired(data.setup_required);
      const saved = localStorage.getItem('nexus_user');
      if (saved) setCurrentUser(JSON.parse(saved));
    };
    init();
  }, []);

  const loadData = async () => {
    const [txData, certData, userData] = await Promise.all([
      safeFetch(`${API_URL}?action=get_transactions`),
      safeFetch(`${API_URL}?action=get_certificates`),
      safeFetch(`${API_URL}?action=get_users`)
    ]);
    setTransactions(Array.isArray(txData) ? txData : MOCK_TRANSACTIONS);
    if (Array.isArray(certData)) setCertificates(certData);
    if (Array.isArray(userData)) setUsersList(userData);

    if (currentUser?.role === UserRole.MASTER || setupRequired) {
      // Refresh users specifically if master
      const freshUsers = await safeFetch(`${API_URL}?action=get_users`);
      if (Array.isArray(freshUsers)) setUsersList(freshUsers);
    }
  };

  useEffect(() => { if (isMounted) loadData(); }, [currentUser, setupRequired, isMounted]);

  useEffect(() => {
    if (transactions.length > 0 && activeTab === 'dashboard') {
      const fetchInsights = async () => {
        const result = await getSmartInsights(transactions);
        setInsights(result);
      };
      const timer = setTimeout(fetchInsights, 2000);
      return () => clearTimeout(timer);
    }
  }, [transactions, activeTab]);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    const data = await safeFetch(`${API_URL}?action=login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(loginData)
    });
    if (data.status === 'success') {
      setCurrentUser(data.user);
      localStorage.setItem('nexus_user', JSON.stringify(data.user));
      setShowLoginModal(false);
    } else { setError(data.message || 'Credenciais inválidas.'); }
  };

  const handleSaveUser = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingUser(true);
    const data = await safeFetch(`${API_URL}?action=save_user`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingUser)
    });
    if (data.status === 'success') {
      setShowUserModal(false);
      setEditingUser(null);
      loadData();
    }
    setIsSavingUser(false);
  };

  const handleDeleteUser = async (id: number) => {
    if (!confirm('Deseja realmente remover este acesso?')) return;
    const data = await safeFetch(`${API_URL}?action=delete_user&id=${id}`);
    if (data.status === 'success') loadData();
  };

  // Fix: Added missing handleDeleteCert function to handle certificate deletion via the API
  const handleDeleteCert = async (id: string) => {
    if (!confirm('Deseja realmente remover este certificado?')) return;
    const data = await safeFetch(`${API_URL}?action=delete_certificate&id=${id}`);
    if (data.status === 'success') loadData();
  };

  const stats = useMemo(() => {
    const success = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const totalVal = success.reduce((a, b) => a + Number(b.amount), 0);
    const pix = success.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    return {
      total: totalVal,
      pixPercent: ((pix / (totalVal || 1)) * 100).toFixed(1),
      txCount: transactions.length
    };
  }, [transactions]);

  const simulateTransaction = async (method: PaymentMethod) => {
    setIsSimulating(true);
    const amount = Math.floor(Math.random() * 500) + 10.5;
    const mockTx: Transaction = {
      id: `TX-${Math.floor(Math.random() * 90000 + 10000)}`,
      timestamp: new Date().toISOString(),
      amount: amount,
      method: method,
      status: PaymentStatus.SUCCESS,
      terminalId: 'TERM-SIM',
      segment: 'Simulação',
      fiscalNoteId: Math.floor(Math.random() * 9000 + 1000).toString(),
      fiscalStatus: FiscalStatus.AUTHORIZED,
      pixQrCode: method === PaymentMethod.PIX ? 'https://api.qrserver.com/v1/create-qr-code/?size=250x250&data=00020101021226870014BR.GOV.BCB.PIX0125' : undefined
    };
    setTransactions(prev => [mockTx, ...prev]);
    if (method === PaymentMethod.PIX) setShowPixModal(mockTx);
    setIsSimulating(false);
    setActiveTab('dashboard');
  };

  const renderUsers = () => (
    <div className="space-y-8 animate-in slide-in-from-bottom duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Acessos</h3>
          <p className="text-slate-500 font-medium">Controle de quem pode operar e administrar o NexusTEF.</p>
        </div>
        <button 
          onClick={() => { setEditingUser({ name: '', username: '', role: UserRole.OPERATOR, password: '' }); setShowUserModal(true); }}
          className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl hover:scale-105 transition-all text-sm"
        >
          + Novo Usuário
        </button>
      </div>

      <div className="bg-white rounded-[3rem] border border-slate-100 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Identidade</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Username</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nível de Acesso</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {usersList.length === 0 ? (
              <tr><td colSpan={4} className="px-8 py-10 text-center text-slate-400 italic">Nenhum usuário encontrado.</td></tr>
            ) : (
              usersList.map(u => (
                <tr key={u.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-8 py-5">
                    <div className="flex items-center gap-3">
                      <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-bold text-sm ${
                        u.role === UserRole.MASTER ? 'bg-amber-100 text-amber-700' : 
                        u.role === UserRole.ADMIN ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-100 text-slate-700'
                      }`}>
                        {u.name.charAt(0)}
                      </div>
                      <span className="font-bold text-slate-800">{u.name}</span>
                    </div>
                  </td>
                  <td className="px-8 py-5 text-sm font-mono text-slate-500">@{u.username}</td>
                  <td className="px-8 py-5">
                    <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${
                      u.role === UserRole.MASTER ? 'bg-amber-500 text-white' : 
                      u.role === UserRole.ADMIN ? 'bg-indigo-600 text-white' : 'bg-slate-500 text-white'
                    }`}>
                      {u.role}
                    </span>
                  </td>
                  <td className="px-8 py-5 text-right">
                    <div className="flex justify-end gap-2">
                      <button onClick={() => { setEditingUser({...u, password: ''}); setShowUserModal(true); }} className="w-8 h-8 bg-indigo-50 text-indigo-600 rounded-lg flex items-center justify-center hover:bg-indigo-600 hover:text-white transition-all">✏️</button>
                      {u.username !== 'master' && (
                        <button onClick={() => handleDeleteUser(u.id)} className="w-8 h-8 bg-rose-50 text-rose-600 rounded-lg flex items-center justify-center hover:bg-rose-600 hover:text-white transition-all">🗑️</button>
                      )}
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );

  const renderCertificates = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Certificados Digitais</h3>
          <p className="text-slate-500 font-medium">Controle centralizado de cadeias A1/A3 para NFC-e.</p>
        </div>
        <button 
          onClick={() => { setEditingCert({ alias: '', state: 'SP', expirationDate: '', type: 'A1', status: 'Ativo' }); setShowCertModal(true); }}
          className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl hover:scale-105 transition-all text-sm"
        >
          + Novo Certificado
        </button>
      </div>

      <div className="bg-white rounded-[3rem] border border-slate-100 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Apelido</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Estado</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {certificates.map(c => (
              <tr key={c.id}>
                <td className="px-8 py-5 font-bold">{c.alias}</td>
                <td className="px-8 py-5">{c.state}</td>
                <td className="px-8 py-5 text-right">
                  <button onClick={() => handleDeleteCert(c.id)} className="text-rose-500">Remover</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        currentUser={currentUser || (setupRequired ? ({ id: 0, name: 'Instalador', username: 'setup', role: UserRole.MASTER } as User) : null)} 
        onLogout={() => { setCurrentUser(null); localStorage.removeItem('nexus_user'); setActiveTab('dashboard'); }} 
      />

      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-20 bg-white/80 backdrop-blur-md border-b border-slate-100 sticky top-0 z-40 flex items-center justify-between px-10">
          <div className="flex flex-col">
            <h2 className="text-xl font-black text-slate-900 leading-none">NexusTEF</h2>
            <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest mt-1.5">{activeTab}</span>
          </div>
          <div className="flex items-center gap-6">
            {currentUser ? (
              <div className="flex items-center gap-4">
                <div className="text-right hidden sm:block">
                  <p className="text-xs font-black text-slate-900 leading-tight">{currentUser.name}</p>
                  <p className="text-[9px] text-indigo-600 font-bold uppercase tracking-widest">{currentUser.role}</p>
                </div>
                <div className={`w-10 h-10 rounded-2xl flex items-center justify-center font-black shadow-lg ${currentUser.role === UserRole.MASTER ? 'bg-amber-500 text-white' : 'bg-indigo-600 text-white'}`}>
                  {currentUser.name.charAt(0)}
                </div>
              </div>
            ) : (
              <button onClick={() => setShowLoginModal(true)} className="px-6 py-2.5 bg-indigo-600 text-white rounded-xl font-bold text-xs uppercase tracking-widest shadow-lg">Entrar</button>
            )}
          </div>
        </header>

        <main className="p-10 max-w-[1400px] w-full mx-auto">
          {activeTab === 'dashboard' && (
            <div className="space-y-8 animate-in fade-in duration-700">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <StatCard label="Volume Total" value={`R$ ${stats.total.toLocaleString('pt-BR')}`} icon="💰" color="bg-indigo-50 text-indigo-600" />
                <StatCard label="Mix de Pix" value={`${stats.pixPercent}%`} icon="⚡" color="bg-emerald-50 text-emerald-600" />
                <StatCard label="Usuários" value={usersList.length} icon="👥" color="bg-amber-50 text-amber-600" />
                <StatCard label="Transações" value={stats.txCount} icon="🔄" color="bg-slate-50 text-slate-600" />
              </div>
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm min-h-[400px]">
                  <h3 className="text-xl font-black text-slate-800 mb-8 tracking-tight">Fluxo Financeiro</h3>
                  <ResponsiveContainer width="100%" height={300}>
                    <AreaChart data={CHART_DATA}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                      <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                      <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                      <Tooltip contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }} />
                      <Area type="monotone" dataKey="valor" stroke="#6366f1" strokeWidth={3} fillOpacity={0.1} fill="#6366f1" />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>
                <div className="bg-slate-900 p-8 rounded-[3rem] text-white flex flex-col shadow-2xl relative overflow-hidden">
                  <div className="absolute top-0 right-0 p-8 opacity-10 text-6xl">🤖</div>
                  <h3 className="text-xl font-black mb-8">Nexus AI</h3>
                  <div className="flex-1 bg-white/5 rounded-[2.5rem] p-6 text-sm italic text-slate-300 overflow-auto border border-white/5 relative z-10">
                    "{insights}"
                  </div>
                </div>
              </div>
              <FiscalMonitor states={SEFAZ_STATES} />
            </div>
          )}

          {activeTab === 'users' && renderUsers()}
          {activeTab === 'certificates' && renderCertificates()}
          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}
          {activeTab === 'simulator' && (
            <div className="max-w-xl mx-auto py-10">
               <div className="bg-white p-12 rounded-[3.5rem] shadow-2xl border border-slate-100 text-center relative overflow-hidden">
                  <h3 className="text-3xl font-black text-slate-900 mb-8 tracking-tight">Checkout Nexus</h3>
                  <div className="grid grid-cols-1 gap-4">
                     <button onClick={() => simulateTransaction(PaymentMethod.CREDIT)} disabled={isSimulating} className="py-6 bg-slate-900 text-white rounded-3xl font-black uppercase tracking-widest hover:bg-slate-800 shadow-xl">Cartão Crédito</button>
                     <button onClick={() => simulateTransaction(PaymentMethod.PIX)} disabled={isSimulating} className="py-6 bg-emerald-600 text-white rounded-3xl font-black uppercase tracking-widest hover:bg-emerald-700 shadow-xl">Gerar PIX QR</button>
                  </div>
               </div>
            </div>
          )}
        </main>
      </div>

      {showUserModal && editingUser && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-10 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Configurar Acesso</h3>
            <form onSubmit={handleSaveUser} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nome Completo</label>
                <input type="text" required value={editingUser.name} onChange={e => setEditingUser({...editingUser, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Username (Login)</label>
                <input type="text" required value={editingUser.username} onChange={e => setEditingUser({...editingUser, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Senha {editingUser.id ? '(Deixe vazio para manter)' : ''}</label>
                <input type="password" value={editingUser.password} onChange={e => setEditingUser({...editingUser, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nível de Permissão</label>
                <select value={editingUser.role} onChange={e => setEditingUser({...editingUser, role: e.target.value as any})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none">
                  <option value={UserRole.OPERATOR}>Operador (Básico)</option>
                  <option value={UserRole.ADMIN}>Administrador (Médio)</option>
                  <option value={UserRole.MASTER}>Master (Total)</option>
                </select>
              </div>
              <div className="flex gap-4 pt-6">
                <button type="button" onClick={() => setShowUserModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold uppercase text-xs tracking-widest">Cancelar</button>
                <button type="submit" disabled={isSavingUser} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl disabled:opacity-50">
                  {isSavingUser ? 'Salvando...' : 'Gravar Acesso'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showLoginModal && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[3.5rem] w-full max-w-md shadow-2xl text-center">
            <h1 className="text-3xl font-black text-slate-900 mb-8 tracking-tight">Acesso Restrito</h1>
            <form onSubmit={handleLogin} className="space-y-6">
              <input type="text" placeholder="Usuário" required value={loginData.username} onChange={e => setLoginData({...loginData, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-5 px-6 font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              <input type="password" placeholder="Senha" required value={loginData.password} onChange={e => setLoginData({...loginData, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-5 px-6 font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              {error && <div className="p-4 bg-rose-50 text-rose-600 rounded-2xl text-[10px] font-black uppercase text-center">{error}</div>}
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowLoginModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs tracking-widest">Sair</button>
                <button type="submit" className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs shadow-xl">Entrar</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export enum PaymentStatus {
  SUCCESS = 'SUCCESS',
  PENDING = 'PENDING',
  FAILED = 'FAILED',
  REFUNDED = 'REFUNDED'
}

export enum PaymentMethod {
  CREDIT = 'Crédito',
  DEBIT = 'Débito',
  PIX = 'PIX',
  VOUCHER = 'Voucher'
}

export enum FiscalStatus {
  AUTHORIZED = 'Autorizada',
  REJECTED = 'Rejeitada',
  CONTINGENCY = 'Contingência',
  CANCELED = 'Cancelada'
}

export enum UserRole {
  MASTER = 'MASTER',
  ADMIN = 'ADMIN',
  OPERATOR = 'OPERATOR'
}

export interface User {
  id: number;
  name: string;
  username: string;
  role: UserRole;
  created_at?: string;
}

export interface Transaction {
  id: string;
  timestamp: string;
  amount: number;
  method: PaymentMethod;
  status: PaymentStatus;
  terminalId: string;
  segment: string;
  fiscalNoteId?: string;
  fiscalStatus?: FiscalStatus;
  pixQrCode?: string;
  pixCopyPaste?: string;
}

export interface DigitalCertificate {
  id: string;
  alias: string;
  expirationDate: string;
  state: string;
  status: 'Ativo' | 'Expirado' | 'Alerta';
  type: 'A1' | 'A3';
  uf: string;
}

export interface SefazStatus {
  state: string;
  status: 'Online' | 'Offline' | 'Instável';
}

export interface FiscalConfig {
  cnpj: string;
  ie: string;
  razaoSocial: string;
  cscToken: string;
  cscId: string;
  ambiente: 'Produção' | 'Homologação';
  serie: string;
  ultimoNumero: number;
  contingencia: boolean;
}

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES, MOCK_TRANSACTIONS, ALL_UFS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole, FiscalConfig } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginData, setLoginData] = useState({ username: '', password: '' });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [fiscalConfig, setFiscalConfig] = useState<FiscalConfig>({
    cnpj: '', ie: '', razaoSocial: '', cscToken: '', cscId: '',
    ambiente: 'Homologação', serie: '1', ultimoNumero: 0, contingencia: false
  });
  const [insights, setInsights] = useState<string>('Analizando métricas em tempo real...');
  const [isSimulating, setIsSimulating] = useState(false);
  const [isSavingFiscal, setIsSavingFiscal] = useState(false);
  const [setupRequired, setSetupRequired] = useState<boolean>(false);
  const [showPixModal, setShowPixModal] = useState<Transaction | null>(null);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isMounted, setIsMounted] = useState(false);

  // Certificate Modal State
  const [showCertModal, setShowCertModal] = useState(false);
  const [isSavingCert, setIsSavingCert] = useState(false);
  const [editingCert, setEditingCert] = useState<Partial<DigitalCertificate> | null>(null);

  // User Management State
  const [showUserModal, setShowUserModal] = useState(false);
  const [isSavingUser, setIsSavingUser] = useState(false);
  const [editingUser, setEditingUser] = useState<Partial<User> & { password?: string } | null>(null);

  const safeFetch = async (url: string, options?: RequestInit) => {
    try {
      const response = await fetch(url, options);
      if (!response.ok) throw new Error(`Server returned ${response.status}`);
      const text = await response.text();
      try { return JSON.parse(text); } catch (e) { throw new Error("Invalid JSON response"); }
    } catch (e) {
      console.warn("API Fallback triggered:", e);
      const action = new URL(url, window.location.origin).searchParams.get('action');
      if (action === 'check_setup') return { setup_required: localStorage.getItem('nexus_users') === null };
      if (action === 'get_transactions') return MOCK_TRANSACTIONS;
      if (action === 'get_certificates') return certificates.length ? certificates : [];
      if (action === 'get_users') return usersList.length ? usersList : [];
      if (action === 'get_fiscal_config') return fiscalConfig;
      return { status: 'error', message: 'Offline Mode' };
    }
  };

  useEffect(() => {
    setIsMounted(true);
    const init = async () => {
      const data = await safeFetch(`${API_URL}?action=check_setup`);
      if (data && typeof data.setup_required !== 'undefined') setSetupRequired(data.setup_required);
      const saved = localStorage.getItem('nexus_user');
      if (saved) setCurrentUser(JSON.parse(saved));
    };
    init();
  }, []);

  const loadData = async () => {
    const [txData, certData, userData, fiscalData] = await Promise.all([
      safeFetch(`${API_URL}?action=get_transactions`),
      safeFetch(`${API_URL}?action=get_certificates`),
      safeFetch(`${API_URL}?action=get_users`),
      safeFetch(`${API_URL}?action=get_fiscal_config`)
    ]);
    setTransactions(Array.isArray(txData) ? txData : MOCK_TRANSACTIONS);
    if (Array.isArray(certData)) setCertificates(certData);
    if (Array.isArray(userData)) setUsersList(userData);
    if (fiscalData && !fiscalData.status) setFiscalConfig(fiscalData);
  };

  useEffect(() => { if (isMounted) loadData(); }, [currentUser, setupRequired, isMounted]);

  useEffect(() => {
    if (transactions.length > 0 && activeTab === 'dashboard') {
      const fetchInsights = async () => {
        const result = await getSmartInsights(transactions);
        setInsights(result);
      };
      const timer = setTimeout(fetchInsights, 2000);
      return () => clearTimeout(timer);
    }
  }, [transactions, activeTab]);

  const handleSaveFiscal = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingFiscal(true);
    await safeFetch(`${API_URL}?action=save_fiscal_config`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(fiscalConfig)
    });
    setIsSavingFiscal(false);
    alert('Configurações fiscais salvas com sucesso!');
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    const data = await safeFetch(`${API_URL}?action=login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(loginData)
    });
    if (data.status === 'success') {
      setCurrentUser(data.user);
      localStorage.setItem('nexus_user', JSON.stringify(data.user));
      setShowLoginModal(false);
    } else { setError(data.message || 'Credenciais inválidas.'); }
  };

  const handleSaveUser = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingUser(true);
    const data = await safeFetch(`${API_URL}?action=save_user`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingUser)
    });
    if (data.status === 'success') {
      setShowUserModal(false);
      setEditingUser(null);
      loadData();
    }
    setIsSavingUser(false);
  };

  const handleDeleteCert = async (id: string) => {
    if (!confirm('Deseja realmente remover este certificado?')) return;
    const data = await safeFetch(`${API_URL}?action=delete_certificate&id=${id}`);
    if (data.status === 'success') loadData();
  };

  const stats = useMemo(() => {
    const success = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const totalVal = success.reduce((a, b) => a + Number(b.amount), 0);
    const pix = success.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    return {
      total: totalVal,
      pixPercent: ((pix / (totalVal || 1)) * 100).toFixed(1),
      txCount: transactions.length
    };
  }, [transactions]);

  const simulateTransaction = async (method: PaymentMethod) => {
    setIsSimulating(true);
    const amount = Math.floor(Math.random() * 500) + 10.5;
    const mockTx: Transaction = {
      id: `TX-${Math.floor(Math.random() * 90000 + 10000)}`,
      timestamp: new Date().toISOString(),
      amount: amount,
      method: method,
      status: PaymentStatus.SUCCESS,
      terminalId: 'TERM-SIM',
      segment: 'Simulação',
      fiscalNoteId: Math.floor(Math.random() * 9000 + 1000).toString(),
      fiscalStatus: FiscalStatus.AUTHORIZED,
      pixQrCode: method === PaymentMethod.PIX ? 'https://api.qrserver.com/v1/create-qr-code/?size=250x250&data=00020101021226870014BR.GOV.BCB.PIX0125' : undefined
    };
    setTransactions(prev => [mockTx, ...prev]);
    if (method === PaymentMethod.PIX) setShowPixModal(mockTx);
    setIsSimulating(false);
    setActiveTab('dashboard');
  };

  const renderFiscalConfig = () => (
    <div className="space-y-8 animate-in slide-in-from-top duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Módulo Fiscal NFC-e</h3>
          <p className="text-slate-500 font-medium">Configure as regras de emissão de notas fiscais do consumidor.</p>
        </div>
        <div className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase flex items-center gap-2 border ${
          fiscalConfig.ambiente === 'Produção' ? 'bg-rose-50 border-rose-100 text-rose-600' : 'bg-amber-50 border-amber-100 text-amber-600'
        }`}>
           <span className={`w-2 h-2 rounded-full ${fiscalConfig.ambiente === 'Produção' ? 'bg-rose-500' : 'bg-amber-500'} animate-pulse`}></span>
           Ambiente: {fiscalConfig.ambiente}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <form onSubmit={handleSaveFiscal} className="lg:col-span-2 space-y-6">
          <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-6">
            <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 pb-4">Dados da Empresa</h4>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">CNPJ</label>
                <input type="text" placeholder="00.000.000/0000-00" value={fiscalConfig.cnpj} onChange={e => setFiscalConfig({...fiscalConfig, cnpj: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Inscrição Estadual</label>
                <input type="text" placeholder="000.000.000.000" value={fiscalConfig.ie} onChange={e => setFiscalConfig({...fiscalConfig, ie: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all" />
              </div>
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Razão Social</label>
              <input type="text" placeholder="Nome Fantasia LTDA" value={fiscalConfig.razaoSocial} onChange={e => setFiscalConfig({...fiscalConfig, razaoSocial: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all" />
            </div>
          </div>

          <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-6">
            <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 pb-4">Configurações de Emissão (CSC)</h4>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">ID do Token CSC</label>
                <input type="text" placeholder="000001" value={fiscalConfig.cscId} onChange={e => setFiscalConfig({...fiscalConfig, cscId: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Ambiente</label>
                <select value={fiscalConfig.ambiente} onChange={e => setFiscalConfig({...fiscalConfig, ambiente: e.target.value as any})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-bold text-slate-700 outline-none">
                  <option value="Homologação">Homologação (Testes)</option>
                  <option value="Produção">Produção (Real)</option>
                </select>
              </div>
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Token CSC (Hash)</label>
              <input type="password" placeholder="EX: A1B2C3D4E5F6..." value={fiscalConfig.cscToken} onChange={e => setFiscalConfig({...fiscalConfig, cscToken: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all" />
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Série</label>
                <input type="text" value={fiscalConfig.serie} onChange={e => setFiscalConfig({...fiscalConfig, serie: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Próximo Nº</label>
                <input type="number" value={fiscalConfig.ultimoNumero} onChange={e => setFiscalConfig({...fiscalConfig, ultimoNumero: parseInt(e.target.value) || 0})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none" />
              </div>
            </div>
          </div>

          <div className="flex gap-4">
            <button type="submit" disabled={isSavingFiscal} className="flex-1 py-5 bg-indigo-600 text-white rounded-[2rem] font-black uppercase text-xs tracking-widest shadow-2xl shadow-indigo-100 hover:scale-[1.02] active:scale-95 transition-all disabled:opacity-50">
              {isSavingFiscal ? 'Sincronizando...' : 'Salvar Configurações Fiscais'}
            </button>
          </div>
        </form>

        <div className="space-y-8">
           <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-xl relative overflow-hidden group">
              <div className="absolute -right-4 -top-4 w-24 h-24 bg-rose-500/20 rounded-full blur-3xl group-hover:bg-rose-500/40 transition-all"></div>
              <h4 className="text-xl font-black mb-4 flex items-center gap-2">
                📡 Contingência
              </h4>
              <p className="text-slate-400 text-xs mb-8 leading-relaxed">
                Ative este modo caso a SEFAZ do seu estado esteja offline. As notas serão emitidas localmente e enviadas assim que o serviço retornar.
              </p>
              <button 
                onClick={() => setFiscalConfig({...fiscalConfig, contingencia: !fiscalConfig.contingencia})}
                className={`w-full py-4 rounded-2xl font-black text-[10px] uppercase tracking-widest transition-all ${
                  fiscalConfig.contingencia ? 'bg-rose-600 text-white animate-pulse' : 'bg-white/10 text-white hover:bg-white/20'
                }`}
              >
                {fiscalConfig.contingencia ? 'MODO CONTINGÊNCIA ATIVO' : 'ATIVAR CONTINGÊNCIA'}
              </button>
           </div>

           <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
              <h4 className="text-sm font-black text-slate-800 mb-6">Últimas Notas</h4>
              <div className="space-y-4">
                 {[1,2,3].map(n => (
                   <div key={n} className="flex items-center justify-between p-3 bg-slate-50 rounded-xl border border-slate-100">
                      <div>
                        <p className="text-[10px] font-black text-slate-400 uppercase">Nota {100 + n}</p>
                        <p className="text-xs font-bold text-slate-700">R$ {(Math.random() * 100).toFixed(2)}</p>
                      </div>
                      <span className="text-[9px] font-black text-emerald-500 uppercase">Autorizada</span>
                   </div>
                 ))}
              </div>
              <button className="w-full mt-6 py-3 bg-slate-100 text-slate-500 rounded-xl font-bold text-[10px] uppercase tracking-widest">Ver Histórico Completo</button>
           </div>
        </div>
      </div>
    </div>
  );

  const renderUsers = () => (
    <div className="space-y-8 animate-in slide-in-from-bottom duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Gestão de Acessos</h3>
          <p className="text-slate-500 font-medium">Controle de quem pode operar e administrar o NexusTEF.</p>
        </div>
        <button 
          onClick={() => { setEditingUser({ name: '', username: '', role: UserRole.OPERATOR, password: '' }); setShowUserModal(true); }}
          className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl hover:scale-105 transition-all text-sm"
        >
          + Novo Usuário
        </button>
      </div>

      <div className="bg-white rounded-[3rem] border border-slate-100 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Identidade</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Username</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nível de Acesso</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {usersList.length === 0 ? (
              <tr><td colSpan={4} className="px-8 py-10 text-center text-slate-400 italic">Nenhum usuário encontrado.</td></tr>
            ) : (
              usersList.map(u => (
                <tr key={u.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-8 py-5">
                    <div className="flex items-center gap-3">
                      <div className={`w-10 h-10 rounded-xl flex items-center justify-center font-bold text-sm ${
                        u.role === UserRole.MASTER ? 'bg-amber-100 text-amber-700' : 
                        u.role === UserRole.ADMIN ? 'bg-indigo-100 text-indigo-700' : 'bg-slate-100 text-slate-700'
                      }`}>
                        {u.name.charAt(0)}
                      </div>
                      <span className="font-bold text-slate-800">{u.name}</span>
                    </div>
                  </td>
                  <td className="px-8 py-5 text-sm font-mono text-slate-500">@{u.username}</td>
                  <td className="px-8 py-5">
                    <span className={`px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${
                      u.role === UserRole.MASTER ? 'bg-amber-500 text-white' : 
                      u.role === UserRole.ADMIN ? 'bg-indigo-600 text-white' : 'bg-slate-500 text-white'
                    }`}>
                      {u.role}
                    </span>
                  </td>
                  <td className="px-8 py-5 text-right">
                    <div className="flex justify-end gap-2">
                      <button onClick={() => { setEditingUser({...u, password: ''}); setShowUserModal(true); }} className="w-8 h-8 bg-indigo-50 text-indigo-600 rounded-lg flex items-center justify-center hover:bg-indigo-600 hover:text-white transition-all">✏️</button>
                      {u.username !== 'master' && (
                        <button onClick={() => handleDeleteCert(u.id.toString())} className="w-8 h-8 bg-rose-50 text-rose-600 rounded-lg flex items-center justify-center hover:bg-rose-600 hover:text-white transition-all">🗑️</button>
                      )}
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );

  const renderCertificates = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Certificados Digitais</h3>
          <p className="text-slate-500 font-medium">Controle centralizado de cadeias A1/A3 para NFC-e.</p>
        </div>
        <button 
          onClick={() => { setEditingCert({ alias: '', state: 'SP', expirationDate: '', type: 'A1', status: 'Ativo' }); setShowCertModal(true); }}
          className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl hover:scale-105 transition-all text-sm"
        >
          + Novo Certificado
        </button>
      </div>

      <div className="bg-white rounded-[3rem] border border-slate-100 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Apelido</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Estado</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {certificates.map(c => (
              <tr key={c.id}>
                <td className="px-8 py-5 font-bold">{c.alias}</td>
                <td className="px-8 py-5">{c.state}</td>
                <td className="px-8 py-5 text-right">
                  <button onClick={() => handleDeleteCert(c.id)} className="text-rose-500 font-black text-[10px] uppercase">Remover</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        currentUser={currentUser || (setupRequired ? ({ id: 0, name: 'Instalador', username: 'setup', role: UserRole.MASTER } as User) : null)} 
        onLogout={() => { setCurrentUser(null); localStorage.removeItem('nexus_user'); setActiveTab('dashboard'); }} 
      />

      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-20 bg-white/70 backdrop-blur-md border-b border-slate-100 sticky top-0 z-40 flex items-center justify-between px-10">
          <div className="flex flex-col">
            <h2 className="text-xl font-black text-slate-900 leading-none">NexusTEF</h2>
            <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest mt-1.5">{activeTab}</span>
          </div>
          <div className="flex items-center gap-6">
            {currentUser ? (
              <div className="flex items-center gap-4">
                <div className="text-right hidden sm:block">
                  <p className="text-xs font-black text-slate-900 leading-tight">{currentUser.name}</p>
                  <p className="text-[9px] text-indigo-600 font-bold uppercase tracking-widest">{currentUser.role}</p>
                </div>
                <div className={`w-10 h-10 rounded-2xl flex items-center justify-center font-black shadow-lg ${currentUser.role === UserRole.MASTER ? 'bg-amber-500 text-white' : 'bg-indigo-600 text-white'}`}>
                  {currentUser.name.charAt(0)}
                </div>
              </div>
            ) : (
              <button onClick={() => setShowLoginModal(true)} className="px-6 py-2.5 bg-indigo-600 text-white rounded-xl font-bold text-xs uppercase tracking-widest shadow-lg">Entrar</button>
            )}
          </div>
        </header>

        <main className="p-10 max-w-[1400px] w-full mx-auto">
          {activeTab === 'dashboard' && (
            <div className="space-y-8 animate-in fade-in duration-700">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <StatCard label="Volume Total" value={`R$ ${stats.total.toLocaleString('pt-BR')}`} icon="💰" color="bg-indigo-50 text-indigo-600" />
                <StatCard label="Mix de Pix" value={`${stats.pixPercent}%`} icon="⚡" color="bg-emerald-50 text-emerald-600" />
                <StatCard label="Usuários" value={usersList.length} icon="👥" color="bg-amber-50 text-amber-600" />
                <StatCard label="Transações" value={stats.txCount} icon="🔄" color="bg-slate-50 text-slate-600" />
              </div>
              <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                <div className="lg:col-span-2 bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm min-h-[400px]">
                  <h3 className="text-xl font-black text-slate-800 mb-8 tracking-tight">Fluxo Financeiro</h3>
                  <ResponsiveContainer width="100%" height={300}>
                    <AreaChart data={CHART_DATA}>
                      <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                      <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                      <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 11}} />
                      <Tooltip contentStyle={{ borderRadius: '20px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)' }} />
                      <Area type="monotone" dataKey="valor" stroke="#6366f1" strokeWidth={3} fillOpacity={0.1} fill="#6366f1" />
                    </AreaChart>
                  </ResponsiveContainer>
                </div>
                <div className="bg-slate-900 p-8 rounded-[3rem] text-white flex flex-col shadow-2xl relative overflow-hidden">
                  <div className="absolute top-0 right-0 p-8 opacity-10 text-6xl">🤖</div>
                  <h3 className="text-xl font-black mb-8 text-indigo-400">Nexus Insight</h3>
                  <div className="flex-1 bg-white/5 rounded-[2.5rem] p-6 text-sm italic text-slate-300 overflow-auto border border-white/5 relative z-10">
                    "{insights}"
                  </div>
                </div>
              </div>
              <FiscalMonitor states={SEFAZ_STATES} />
            </div>
          )}

          {activeTab === 'users' && renderUsers()}
          {activeTab === 'certificates' && renderCertificates()}
          {activeTab === 'fiscal' && renderFiscalConfig()}
          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}
          {activeTab === 'simulator' && (
            <div className="max-w-xl mx-auto py-10">
               <div className="bg-white p-12 rounded-[3.5rem] shadow-2xl border border-slate-100 text-center relative overflow-hidden">
                  <h3 className="text-3xl font-black text-slate-900 mb-8 tracking-tight">Simulador Checkout</h3>
                  <div className="grid grid-cols-1 gap-4">
                     <button onClick={() => simulateTransaction(PaymentMethod.CREDIT)} disabled={isSimulating} className="py-6 bg-slate-900 text-white rounded-3xl font-black uppercase tracking-widest hover:bg-slate-800 shadow-xl transition-all">Cartão Crédito</button>
                     <button onClick={() => simulateTransaction(PaymentMethod.PIX)} disabled={isSimulating} className="py-6 bg-emerald-600 text-white rounded-3xl font-black uppercase tracking-widest hover:bg-emerald-700 shadow-xl transition-all">Gerar PIX QR</button>
                  </div>
               </div>
            </div>
          )}
        </main>
      </div>

      {showUserModal && editingUser && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-10 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Configurar Acesso</h3>
            <form onSubmit={handleSaveUser} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nome Completo</label>
                <input type="text" required value={editingUser.name} onChange={e => setEditingUser({...editingUser, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Username (Login)</label>
                <input type="text" required value={editingUser.username} onChange={e => setEditingUser({...editingUser, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Senha</label>
                <input type="password" value={editingUser.password} onChange={e => setEditingUser({...editingUser, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nível de Permissão</label>
                <select value={editingUser.role} onChange={e => setEditingUser({...editingUser, role: e.target.value as any})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none">
                  <option value={UserRole.OPERATOR}>Operador</option>
                  <option value={UserRole.ADMIN}>Admin</option>
                  <option value={UserRole.MASTER}>Master</option>
                </select>
              </div>
              <div className="flex gap-4 pt-6">
                <button type="button" onClick={() => setShowUserModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold uppercase text-xs tracking-widest">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl">Gravar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showLoginModal && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[3.5rem] w-full max-w-md shadow-2xl text-center">
            <h1 className="text-3xl font-black text-slate-900 mb-8 tracking-tight">Acesso Restrito</h1>
            <form onSubmit={handleLogin} className="space-y-6">
              <input type="text" placeholder="Usuário" required value={loginData.username} onChange={e => setLoginData({...loginData, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-5 px-6 font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              <input type="password" placeholder="Senha" required value={loginData.password} onChange={e => setLoginData({...loginData, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-5 px-6 font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              {error && <div className="p-4 bg-rose-50 text-rose-600 rounded-2xl text-[10px] font-black uppercase text-center">{error}</div>}
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowLoginModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs tracking-widest">Sair</button>
                <button type="submit" className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs shadow-xl">Entrar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showPixModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-xl z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[4rem] w-full max-w-md shadow-2xl text-center">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">QR Code PIX</h3>
            <div className="bg-slate-50 p-8 rounded-[3rem] mb-8 inline-block border border-slate-100">
               <img src={showPixModal.pixQrCode} alt="PIX QR" className="w-56 h-56 mx-auto" />
            </div>
            <p className="text-3xl font-black text-slate-900 mb-2">R$ {showPixModal.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            <button onClick={() => setShowPixModal(null)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest">Fechar</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export enum PaymentStatus {
  SUCCESS = 'SUCCESS',
  PENDING = 'PENDING',
  FAILED = 'FAILED',
  REFUNDED = 'REFUNDED'
}

export enum PaymentMethod {
  CREDIT = 'Crédito',
  DEBIT = 'Débito',
  PIX = 'PIX',
  VOUCHER = 'Voucher'
}

export enum FiscalStatus {
  AUTHORIZED = 'Autorizada',
  REJECTED = 'Rejeitada',
  CONTINGENCY = 'Contingência',
  CANCELED = 'Cancelada'
}

export enum UserRole {
  MASTER = 'MASTER',
  ADMIN = 'ADMIN',
  OPERATOR = 'OPERATOR'
}

export interface User {
  id: number;
  name: string;
  username: string;
  role: UserRole;
  created_at?: string;
