  id: number;
  name: string;
  sku: string;
  price: number;
  category: string;
  stock: number;
  created_at?: string;
}

export interface Transaction {
  id: string;
  timestamp: string;
  amount: number;
  method: PaymentMethod;
  status: PaymentStatus;
  terminalId: string;
  segment: string;
  fiscalNoteId?: string;
  fiscalStatus?: FiscalStatus;
  pixQrCode?: string;
  pixCopyPaste?: string;
}

export interface DigitalCertificate {
  id: string;
  alias: string;
  expirationDate: string;
  state: string;
  status: 'Ativo' | 'Expirado' | 'Alerta';
  type: 'A1' | 'A3';
  uf: string;
}

export interface SefazStatus {
