}

import React from 'react';
import { User, UserRole } from '../types';

interface SidebarProps {
  activeTab: string;
  setActiveTab: (tab: string) => void;
  currentUser: User | null;
  onLogout: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ activeTab, setActiveTab, currentUser, onLogout }) => {
  const menuItems = [
    { id: 'dashboard', label: 'Dashboard', icon: '📊', roles: [UserRole.MASTER, UserRole.ADMIN, UserRole.OPERATOR] },
    { id: 'products', label: 'Produtos', icon: '📦', roles: [UserRole.MASTER, UserRole.ADMIN, UserRole.OPERATOR] },
    { id: 'transactions', label: 'Transações', icon: '💸', roles: [UserRole.MASTER, UserRole.ADMIN, UserRole.OPERATOR] },
    { id: 'fiscal', label: 'Fiscal NFC-e', icon: '📝', roles: [UserRole.MASTER, UserRole.ADMIN] },
    { id: 'certificates', label: 'Certificados', icon: '🔐', roles: [UserRole.MASTER, UserRole.ADMIN] },
    { id: 'users', label: 'Usuários', icon: '👥', roles: [UserRole.MASTER] },
    { id: 'simulator', label: 'Simulador TEF', icon: '⚙️', roles: [UserRole.MASTER, UserRole.ADMIN] },
  ];

  const filteredItems = currentUser 
    ? menuItems.filter(item => item.roles.includes(currentUser.role))
    : menuItems.filter(item => ['dashboard', 'transactions', 'products'].includes(item.id));

  return (
    <div className="w-64 bg-slate-900 h-screen fixed left-0 top-0 text-white p-6 hidden md:flex flex-col border-r border-slate-800">
      <div className="mb-12 flex items-center gap-3">
        <div className="w-10 h-10 bg-indigo-500 rounded-xl flex items-center justify-center font-black text-2xl shadow-lg shadow-indigo-500/20">
          N
        </div>
        <div>
          <h1 className="text-xl font-bold tracking-tight">NexusTEF</h1>
          <p className="text-[10px] text-slate-400 font-medium uppercase tracking-[0.2em]">V6 Direct Access</p>
        </div>
      </div>

      <nav className="flex-1 space-y-2">
        {filteredItems.map((item) => (
          <button
            key={item.id}
            onClick={() => setActiveTab(item.id)}
            className={`w-full text-left px-4 py-3 rounded-xl transition-all duration-200 flex items-center gap-4 ${
              activeTab === item.id 
                ? 'bg-indigo-600 text-white shadow-xl shadow-indigo-600/30' 
                : 'text-slate-400 hover:bg-slate-800 hover:text-white'
            }`}
          >
            <span className="text-xl opacity-80">{item.icon}</span>
            <span className="font-semibold text-sm">{item.label}</span>
          </button>
        ))}
      </nav>

      <div className="pt-8 mt-8 border-t border-slate-800/50">
        {currentUser && currentUser.username !== 'setup' && (
          <button 
            onClick={onLogout}
            className="w-full text-left px-4 py-3 rounded-xl text-slate-500 hover:bg-rose-500/10 hover:text-rose-400 transition-all flex items-center gap-4 mb-4"
          >
            <span className="text-xl">🚪</span>
            <span className="font-semibold text-sm">Sair do Sistema</span>
          </button>
        )}

        <div className="bg-slate-800/40 rounded-2xl p-4 border border-slate-700/30">
          <div className="flex items-center gap-3 mb-2">
            <div className={`w-2 h-2 rounded-full animate-pulse ${currentUser ? 'bg-emerald-500' : 'bg-amber-500'}`}></div>
            <p className="text-xs font-bold text-slate-200">
              {currentUser ? `User: ${currentUser.username}` : 'Modo Visitante'}
            </p>
          </div>
          <p className="text-[10px] text-slate-500 uppercase tracking-wider">
            {currentUser?.role || 'Visitante'}
          </p>
        </div>
      </div>
    </div>
  );
};

export default Sidebar;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES, MOCK_TRANSACTIONS, ALL_UFS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole, FiscalConfig, Product } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginData, setLoginData] = useState({ username: '', password: '' });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [productsList, setProductsList] = useState<Product[]>([]);
  const [fiscalConfig, setFiscalConfig] = useState<FiscalConfig>({
    cnpj: '', ie: '', razaoSocial: '', cscToken: '', cscId: '',
    ambiente: 'Homologação', serie: '1', ultimoNumero: 0, contingencia: false
  });
  const [insights, setInsights] = useState<string>('Analizando métricas em tempo real...');
  const [isSimulating, setIsSimulating] = useState(false);
  const [isSavingFiscal, setIsSavingFiscal] = useState(false);
  const [setupRequired, setSetupRequired] = useState<boolean>(false);
  const [showPixModal, setShowPixModal] = useState<Transaction | null>(null);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isMounted, setIsMounted] = useState(false);

  // Certificate Modal State
  const [showCertModal, setShowCertModal] = useState(false);
  const [isSavingCert, setIsSavingCert] = useState(false);
  const [editingCert, setEditingCert] = useState<Partial<DigitalCertificate> | null>(null);

  // User Management State
  const [showUserModal, setShowUserModal] = useState(false);
  const [isSavingUser, setIsSavingUser] = useState(false);
  const [editingUser, setEditingUser] = useState<Partial<User> & { password?: string } | null>(null);

  // Product Management State
  const [showProductModal, setShowProductModal] = useState(false);
  const [isSavingProduct, setIsSavingProduct] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Partial<Product> | null>(null);

  const safeFetch = async (url: string, options?: RequestInit) => {
    try {
      const response = await fetch(url, options);
      if (!response.ok) throw new Error(`Server returned ${response.status}`);
      const text = await response.text();
      try { return JSON.parse(text); } catch (e) { throw new Error("Invalid JSON response"); }
    } catch (e) {
      console.warn("API Fallback triggered:", e);
      const action = new URL(url, window.location.origin).searchParams.get('action');
      if (action === 'check_setup') return { setup_required: localStorage.getItem('nexus_users') === null };
      if (action === 'get_transactions') return MOCK_TRANSACTIONS;
      if (action === 'get_products') return productsList;
      return { status: 'error', message: 'Offline Mode' };
    }
  };

  useEffect(() => {
    setIsMounted(true);
    const init = async () => {
      const data = await safeFetch(`${API_URL}?action=check_setup`);
      if (data && typeof data.setup_required !== 'undefined') setSetupRequired(data.setup_required);
      const saved = localStorage.getItem('nexus_user');
      if (saved) setCurrentUser(JSON.parse(saved));
    };
    init();
  }, []);

  const loadData = async () => {
    const [txData, certData, userData, fiscalData, prodData] = await Promise.all([
      safeFetch(`${API_URL}?action=get_transactions`),
      safeFetch(`${API_URL}?action=get_certificates`),
      safeFetch(`${API_URL}?action=get_users`),
      safeFetch(`${API_URL}?action=get_fiscal_config`),
      safeFetch(`${API_URL}?action=get_products`)
    ]);
    setTransactions(Array.isArray(txData) ? txData : MOCK_TRANSACTIONS);
    if (Array.isArray(certData)) setCertificates(certData);
    if (Array.isArray(userData)) setUsersList(userData);
    if (fiscalData && !fiscalData.status) setFiscalConfig(fiscalData);
    if (Array.isArray(prodData)) setProductsList(prodData);
  };

  useEffect(() => { if (isMounted) loadData(); }, [currentUser, setupRequired, isMounted]);

  useEffect(() => {
    if (transactions.length > 0 && activeTab === 'dashboard') {
      const fetchInsights = async () => {
        const result = await getSmartInsights(transactions);
        setInsights(result);
      };
      const timer = setTimeout(fetchInsights, 2000);
      return () => clearTimeout(timer);
    }
  }, [transactions, activeTab]);

  const handleSaveProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingProduct(true);
    const data = await safeFetch(`${API_URL}?action=save_product`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingProduct)
    });
    if (data.status === 'success') {
      setShowProductModal(false);
      setEditingProduct(null);
      loadData();
    }
    setIsSavingProduct(false);
  };

  const handleDeleteProduct = async (id: number) => {
    if (!confirm('Deseja remover este produto do catálogo?')) return;
    const data = await safeFetch(`${API_URL}?action=delete_product&id=${id}`);
    if (data.status === 'success') loadData();
  };

  const handleSaveFiscal = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingFiscal(true);
    await safeFetch(`${API_URL}?action=save_fiscal_config`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(fiscalConfig)
    });
    setIsSavingFiscal(false);
    alert('Configurações fiscais salvas com sucesso!');
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    const data = await safeFetch(`${API_URL}?action=login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(loginData)
    });
    if (data.status === 'success') {
      setCurrentUser(data.user);
      localStorage.setItem('nexus_user', JSON.stringify(data.user));
      setShowLoginModal(false);
    } else { setError(data.message || 'Credenciais inválidas.'); }
  };

  const handleSaveUser = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingUser(true);
    const data = await safeFetch(`${API_URL}?action=save_user`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingUser)
    });
    if (data.status === 'success') {
      setShowUserModal(false);
      setEditingUser(null);
      loadData();
    }
    setIsSavingUser(false);
  };

  const handleDeleteCert = async (id: string) => {
    if (!confirm('Deseja realmente remover este certificado?')) return;
    const data = await safeFetch(`${API_URL}?action=delete_certificate&id=${id}`);
    if (data.status === 'success') loadData();
  };

  const stats = useMemo(() => {
    const success = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const totalVal = success.reduce((a, b) => a + Number(b.amount), 0);
    const pix = success.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    return {
      total: totalVal,
      pixPercent: ((pix / (totalVal || 1)) * 100).toFixed(1),
      txCount: transactions.length
    };
  }, [transactions]);

  const simulateTransaction = async (method: PaymentMethod) => {
    setIsSimulating(true);
    const amount = Math.floor(Math.random() * 500) + 10.5;
    const mockTx: Transaction = {
      id: `TX-${Math.floor(Math.random() * 90000 + 10000)}`,
      timestamp: new Date().toISOString(),
      amount: amount,
      method: method,
      status: PaymentStatus.SUCCESS,
      terminalId: 'TERM-SIM',
      segment: 'Simulação',
      fiscalNoteId: Math.floor(Math.random() * 9000 + 1000).toString(),
      fiscalStatus: FiscalStatus.AUTHORIZED,
      pixQrCode: method === PaymentMethod.PIX ? 'https://api.qrserver.com/v1/create-qr-code/?size=250x250&data=00020101021226870014BR.GOV.BCB.PIX0125' : undefined
    };
    setTransactions(prev => [mockTx, ...prev]);
    if (method === PaymentMethod.PIX) setShowPixModal(mockTx);
    setIsSimulating(false);
    setActiveTab('dashboard');
  };

  const renderProducts = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Catálogo de Produtos</h3>
          <p className="text-slate-500 font-medium">Gestão centralizada de itens, preços e estoque.</p>
        </div>
        <button 
          onClick={() => { setEditingProduct({ name: '', sku: '', price: 0, category: 'Geral', stock: 0 }); setShowProductModal(true); }}
          className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl hover:scale-105 transition-all text-sm"
        >
          + Novo Produto
        </button>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <StatCard label="Total de Itens" value={productsList.length} icon="📦" color="bg-indigo-50 text-indigo-600" />
        <StatCard label="Estoque Baixo" value={productsList.filter(p => p.stock < 10).length} icon="⚠️" color="bg-amber-50 text-amber-600" />
        <StatCard label="Categorias" value={new Set(productsList.map(p => p.category)).size} icon="🏷️" color="bg-blue-50 text-blue-600" />
        <StatCard label="Valor em Estoque" value={`R$ ${productsList.reduce((acc, p) => acc + (p.price * p.stock), 0).toLocaleString('pt-BR')}`} icon="💰" color="bg-emerald-50 text-emerald-600" />
      </div>

      <div className="bg-white rounded-[3rem] border border-slate-100 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Produto / SKU</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Categoria</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Preço Unit.</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Estoque</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {productsList.length === 0 ? (
              <tr><td colSpan={5} className="px-8 py-10 text-center text-slate-400 italic">Nenhum produto cadastrado.</td></tr>
            ) : (
              productsList.map(p => (
                <tr key={p.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-8 py-5">
                    <p className="font-bold text-slate-800">{p.name}</p>
                    <p className="text-[10px] font-mono text-indigo-500 uppercase">{p.sku}</p>
                  </td>
                  <td className="px-8 py-5">
                    <span className="px-3 py-1 bg-slate-100 rounded-full text-[9px] font-black uppercase tracking-widest text-slate-600">
                      {p.category}
                    </span>
                  </td>
                  <td className="px-8 py-5 text-sm font-bold text-slate-900">
                    R$ {Number(p.price).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                  </td>
                  <td className="px-8 py-5">
                    <div className="flex items-center gap-2">
                       <span className={`w-2 h-2 rounded-full ${p.stock < 10 ? 'bg-rose-500 animate-pulse' : 'bg-emerald-500'}`}></span>
                       <span className={`text-sm font-black ${p.stock < 10 ? 'text-rose-600' : 'text-slate-600'}`}>
                         {p.stock} un
                       </span>
                    </div>
                  </td>
                  <td className="px-8 py-5 text-right">
                    <div className="flex justify-end gap-2">
                      <button onClick={() => { setEditingProduct(p); setShowProductModal(true); }} className="w-8 h-8 bg-indigo-50 text-indigo-600 rounded-lg flex items-center justify-center hover:bg-indigo-600 hover:text-white transition-all">✏️</button>
                      <button onClick={() => handleDeleteProduct(p.id)} className="w-8 h-8 bg-rose-50 text-rose-600 rounded-lg flex items-center justify-center hover:bg-rose-600 hover:text-white transition-all">🗑️</button>
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );

  const renderFiscalConfig = () => (
    <div className="space-y-8 animate-in slide-in-from-top duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Módulo Fiscal NFC-e</h3>
          <p className="text-slate-500 font-medium">Configure as regras de emissão de notas fiscais do consumidor.</p>
        </div>
        <div className={`px-4 py-2 rounded-xl text-[10px] font-black uppercase flex items-center gap-2 border ${
          fiscalConfig.ambiente === 'Produção' ? 'bg-rose-50 border-rose-100 text-rose-600' : 'bg-amber-50 border-amber-100 text-amber-600'
        }`}>
           <span className={`w-2 h-2 rounded-full ${fiscalConfig.ambiente === 'Produção' ? 'bg-rose-500' : 'bg-amber-500'} animate-pulse`}></span>
           Ambiente: {fiscalConfig.ambiente}
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <form onSubmit={handleSaveFiscal} className="lg:col-span-2 space-y-6">
          <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-6">
            <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 pb-4">Dados da Empresa</h4>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">CNPJ</label>
                <input type="text" placeholder="00.000.000/0000-00" value={fiscalConfig.cnpj} onChange={e => setFiscalConfig({...fiscalConfig, cnpj: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Inscrição Estadual</label>
                <input type="text" placeholder="000.000.000.000" value={fiscalConfig.ie} onChange={e => setFiscalConfig({...fiscalConfig, ie: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all" />
              </div>
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Razão Social</label>
              <input type="text" placeholder="Nome Fantasia LTDA" value={fiscalConfig.razaoSocial} onChange={e => setFiscalConfig({...fiscalConfig, razaoSocial: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all" />
            </div>
          </div>

          <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-6">
            <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 pb-4">Configurações de Emissão (CSC)</h4>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">ID do Token CSC</label>
                <input type="text" placeholder="000001" value={fiscalConfig.cscId} onChange={e => setFiscalConfig({...fiscalConfig, cscId: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Ambiente</label>
                <select value={fiscalConfig.ambiente} onChange={e => setFiscalConfig({...fiscalConfig, ambiente: e.target.value as any})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-bold text-slate-700 outline-none">
                  <option value="Homologação">Homologação (Testes)</option>
                  <option value="Produção">Produção (Real)</option>
                </select>
              </div>
            </div>
            <div className="space-y-1">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Token CSC (Hash)</label>
              <input type="password" placeholder="EX: A1B2C3D4E5F6..." value={fiscalConfig.cscToken} onChange={e => setFiscalConfig({...fiscalConfig, cscToken: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all" />
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Série</label>
                <input type="text" value={fiscalConfig.serie} onChange={e => setFiscalConfig({...fiscalConfig, serie: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none" />
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Próximo Nº</label>
                <input type="number" value={fiscalConfig.ultimoNumero} onChange={e => setFiscalConfig({...fiscalConfig, ultimoNumero: parseInt(e.target.value) || 0})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none" />
              </div>
            </div>
          </div>

          <div className="flex gap-4">
            <button type="submit" disabled={isSavingFiscal} className="flex-1 py-5 bg-indigo-600 text-white rounded-[2rem] font-black uppercase text-xs tracking-widest shadow-2xl shadow-indigo-100 hover:scale-[1.02] active:scale-95 transition-all disabled:opacity-50">
              {isSavingFiscal ? 'Sincronizando...' : 'Salvar Configurações Fiscais'}
