              <div className="flex gap-4 pt-6">
                <button type="button" onClick={() => setShowUserModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold uppercase text-xs tracking-widest">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl">Gravar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showLoginModal && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[3.5rem] w-full max-w-md shadow-2xl text-center">
            <h1 className="text-3xl font-black text-slate-900 mb-8 tracking-tight">Acesso Restrito</h1>
            <form onSubmit={handleLogin} className="space-y-6">
              <input type="text" placeholder="Usuário" required value={loginData.username} onChange={e => setLoginData({...loginData, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-5 px-6 font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              <input type="password" placeholder="Senha" required value={loginData.password} onChange={e => setLoginData({...loginData, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl py-5 px-6 font-medium outline-none focus:ring-2 focus:ring-indigo-500" />
              {error && <div className="p-4 bg-rose-50 text-rose-600 rounded-2xl text-[10px] font-black uppercase text-center">{error}</div>}
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowLoginModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs tracking-widest">Sair</button>
                <button type="submit" className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs shadow-xl">Entrar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showPixModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-xl z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[4rem] w-full max-w-md shadow-2xl text-center">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">QR Code PIX</h3>
            <div className="bg-slate-50 p-8 rounded-[3rem] mb-8 inline-block border border-slate-100">
               <img src={showPixModal.pixQrCode} alt="PIX QR" className="w-56 h-56 mx-auto" />
            </div>
            <p className="text-3xl font-black text-slate-900 mb-2">R$ {showPixModal.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            <button onClick={() => setShowPixModal(null)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest">Fechar</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

export enum PaymentStatus {
  SUCCESS = 'SUCCESS',
  PENDING = 'PENDING',
  FAILED = 'FAILED',
  REFUNDED = 'REFUNDED'
}

export enum PaymentMethod {
  CREDIT = 'Crédito',
  DEBIT = 'Débito',
  PIX = 'PIX',
  VOUCHER = 'Voucher'
}

export enum FiscalStatus {
  AUTHORIZED = 'Autorizada',
  REJECTED = 'Rejeitada',
  CONTINGENCY = 'Contingência',
  CANCELED = 'Cancelada'
}

export enum UserRole {
  MASTER = 'MASTER',
  ADMIN = 'ADMIN',
  OPERATOR = 'OPERATOR'
}

export interface User {
  id: number;
  name: string;
  username: string;
  role: UserRole;
  created_at?: string;
}

export interface Product {
  id: number;
  name: string;
  sku: string;
  price: number;
  category: string;
  stock: number;
  created_at?: string;
}

export interface Transaction {
  id: string;
  timestamp: string;
  amount: number;
  method: PaymentMethod;
  status: PaymentStatus;
  terminalId: string;
  segment: string;
  fiscalNoteId?: string;
  fiscalStatus?: FiscalStatus;
  pixQrCode?: string;
  pixCopyPaste?: string;
  cardBrand?: string;
  installments?: number;
}

export interface DigitalCertificate {
  id: string;
  alias: string;
  expirationDate: string;
  state: string;
  status: 'Ativo' | 'Expirado' | 'Alerta';
  type: 'A1' | 'A3';
  uf: string;
}

export interface SefazStatus {
  state: string;
  status: 'Online' | 'Offline' | 'Instável';
}

export interface FiscalConfig {
  cnpj: string;
  ie: string;
  razaoSocial: string;
  cscToken: string;
  cscId: string;
  ambiente: 'Produção' | 'Homologação';
  serie: string;
  ultimoNumero: number;
  contingencia: boolean;
}

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES, MOCK_TRANSACTIONS, ALL_UFS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole, FiscalConfig, Product } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginData, setLoginData] = useState({ username: '', password: '' });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [productsList, setProductsList] = useState<Product[]>([]);
  const [fiscalConfig, setFiscalConfig] = useState<FiscalConfig>({
    cnpj: '', ie: '', razaoSocial: '', cscToken: '', cscId: '',
    ambiente: 'Homologação', serie: '1', ultimoNumero: 0, contingencia: false
  });
  const [insights, setInsights] = useState<string>('Analizando métricas em tempo real...');
  const [isSimulating, setIsSimulating] = useState(false);
  const [isSavingFiscal, setIsSavingFiscal] = useState(false);
  const [setupRequired, setSetupRequired] = useState<boolean>(false);
  const [showPixModal, setShowPixModal] = useState<Transaction | null>(null);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isMounted, setIsMounted] = useState(false);

  // Advanced Simulator State
  const [showCardSimModal, setShowCardSimModal] = useState(false);
  const [simStep, setSimStep] = useState<'brand' | 'method' | 'installments' | 'processing'>('brand');
  const [simData, setSimData] = useState({ brand: '', method: PaymentMethod.CREDIT, installments: 1 });

  // Certificate Modal State
  const [showCertModal, setShowCertModal] = useState(false);
  const [isSavingCert, setIsSavingCert] = useState(false);
  const [editingCert, setEditingCert] = useState<Partial<DigitalCertificate> | null>(null);

  // User Management State
  const [showUserModal, setShowUserModal] = useState(false);
  const [isSavingUser, setIsSavingUser] = useState(false);
  const [editingUser, setEditingUser] = useState<Partial<User> & { password?: string } | null>(null);

  // Product Management State
  const [showProductModal, setShowProductModal] = useState(false);
  const [isSavingProduct, setIsSavingProduct] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Partial<Product> | null>(null);

  const safeFetch = async (url: string, options?: RequestInit) => {
    try {
      const response = await fetch(url, options);
      if (!response.ok) throw new Error(`Server returned ${response.status}`);
      const text = await response.text();
      try { return JSON.parse(text); } catch (e) { throw new Error("Invalid JSON response"); }
    } catch (e) {
      console.warn("API Fallback triggered:", e);
      const action = new URL(url, window.location.origin).searchParams.get('action');
      if (action === 'check_setup') return { setup_required: localStorage.getItem('nexus_users') === null };
      if (action === 'get_transactions') return MOCK_TRANSACTIONS;
      if (action === 'get_products') return productsList;
      return { status: 'error', message: 'Offline Mode' };
    }
  };

  useEffect(() => {
    setIsMounted(true);
    const init = async () => {
      const data = await safeFetch(`${API_URL}?action=check_setup`);
      if (data && typeof data.setup_required !== 'undefined') setSetupRequired(data.setup_required);
      const saved = localStorage.getItem('nexus_user');
      if (saved) setCurrentUser(JSON.parse(saved));
    };
    init();
  }, []);

  const loadData = async () => {
    const [txData, certData, userData, fiscalData, prodData] = await Promise.all([
      safeFetch(`${API_URL}?action=get_transactions`),
      safeFetch(`${API_URL}?action=get_certificates`),
      safeFetch(`${API_URL}?action=get_users`),
      safeFetch(`${API_URL}?action=get_fiscal_config`),
      safeFetch(`${API_URL}?action=get_products`)
    ]);
    setTransactions(Array.isArray(txData) ? txData : MOCK_TRANSACTIONS);
    if (Array.isArray(certData)) setCertificates(certData);
    if (Array.isArray(userData)) setUsersList(userData);
    if (fiscalData && !fiscalData.status) setFiscalConfig(fiscalData);
    if (Array.isArray(prodData)) setProductsList(prodData);
  };

  useEffect(() => { if (isMounted) loadData(); }, [currentUser, setupRequired, isMounted]);

  const handleSaveProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingProduct(true);
    const data = await safeFetch(`${API_URL}?action=save_product`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingProduct)
    });
    if (data.status === 'success') {
      setShowProductModal(false);
      setEditingProduct(null);
      loadData();
    }
    setIsSavingProduct(false);
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    const data = await safeFetch(`${API_URL}?action=login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(loginData)
    });
    if (data.status === 'success') {
      setCurrentUser(data.user);
      localStorage.setItem('nexus_user', JSON.stringify(data.user));
      setShowLoginModal(false);
    } else { setError(data.message || 'Credenciais inválidas.'); }
  };

  const handleSaveUser = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingUser(true);
    const data = await safeFetch(`${API_URL}?action=save_user`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingUser)
    });
    if (data.status === 'success') {
      setShowUserModal(false);
      setEditingUser(null);
      loadData();
    }
    setIsSavingUser(false);
  };

  const handleDeleteCert = async (id: string) => {
    if (!confirm('Deseja realmente remover este certificado?')) return;
    const data = await safeFetch(`${API_URL}?action=delete_certificate&id=${id}`);
    if (data.status === 'success') loadData();
  };

  const stats = useMemo(() => {
    const success = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const totalVal = success.reduce((a, b) => a + Number(b.amount), 0);
    const pix = success.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    return {
      total: totalVal,
      pixPercent: ((pix / (totalVal || 1)) * 100).toFixed(1),
      txCount: transactions.length
    };
  }, [transactions]);

  const simulateTransaction = async (method: PaymentMethod, details?: { brand: string, installments: number }) => {
    setIsSimulating(true);
    const amount = Math.floor(Math.random() * 500) + 10.5;
    const mockTx: Transaction = {
      id: `TX-${Math.floor(Math.random() * 90000 + 10000)}`,
      timestamp: new Date().toISOString(),
      amount: amount,
      method: method,
      status: PaymentStatus.SUCCESS,
      terminalId: 'TERM-SIM',
      segment: 'Simulação',
      fiscalNoteId: Math.floor(Math.random() * 9000 + 1000).toString(),
      fiscalStatus: FiscalStatus.AUTHORIZED,
      cardBrand: details?.brand,
      installments: details?.installments,
      pixQrCode: method === PaymentMethod.PIX ? 'https://api.qrserver.com/v1/create-qr-code/?size=250x250&data=00020101021226870014BR.GOV.BCB.PIX0125' : undefined
    };

    // Simulate API Delay
    await new Promise(r => setTimeout(r, 1500));

    setTransactions(prev => [mockTx, ...prev]);
    if (method === PaymentMethod.PIX) setShowPixModal(mockTx);
    setIsSimulating(false);
    setShowCardSimModal(false);
    setSimStep('brand');
    setActiveTab('dashboard');
  };

  const renderSimulator = () => (
    <div className="max-w-xl mx-auto py-10 animate-in slide-in-from-bottom duration-500">
      <div className="bg-white p-12 rounded-[4rem] shadow-2xl border border-slate-100 text-center relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-2 bg-indigo-500"></div>
        <h3 className="text-4xl font-black text-slate-900 mb-2 tracking-tight">Pinpad Virtual</h3>
        <p className="text-slate-500 font-medium mb-12">Simule transações em tempo real para testes de fluxo.</p>

        <div className="grid grid-cols-1 gap-6">
          <button 
            onClick={() => { setShowCardSimModal(true); setSimStep('brand'); }}
            className="group relative py-8 bg-slate-900 text-white rounded-[2.5rem] font-black uppercase tracking-widest hover:bg-indigo-600 transition-all shadow-2xl shadow-slate-200 overflow-hidden"
          >
            <div className="absolute inset-0 bg-white/5 opacity-0 group-hover:opacity-100 transition-opacity"></div>
            <span className="relative z-10 flex items-center justify-center gap-3">
               💳 Inserir Cartão
            </span>
          </button>

          <button 
            onClick={() => simulateTransaction(PaymentMethod.PIX)}
            className="group relative py-8 bg-emerald-600 text-white rounded-[2.5rem] font-black uppercase tracking-widest hover:bg-emerald-700 transition-all shadow-2xl shadow-emerald-100"
          >
            <span className="relative z-10 flex items-center justify-center gap-3">
               ⚡ Gerar Pix QR
            </span>
          </button>
        </div>

        <div className="mt-12 pt-8 border-t border-slate-50 flex justify-center gap-8">
           <div className="text-center">
             <p className="text-[10px] font-black text-slate-400 uppercase">Terminal</p>
             <p className="text-xs font-bold text-slate-700">POS-NEXUS-01</p>
           </div>
           <div className="text-center">
             <p className="text-[10px] font-black text-slate-400 uppercase">Status</p>
             <p className="text-xs font-bold text-emerald-500 flex items-center gap-1.5 justify-center">
               <span className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></span>
               Pronto
             </p>
           </div>
        </div>
      </div>
    </div>
  );

  const renderProducts = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Catálogo de Produtos</h3>
          <p className="text-slate-500 font-medium">Gestão centralizada de itens, preços e estoque.</p>
        </div>
        <button 
          onClick={() => { setEditingProduct({ name: '', sku: '', price: 0, category: 'Geral', stock: 0 }); setShowProductModal(true); }}
          className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl hover:scale-105 transition-all text-sm"
        >
          + Novo Produto
        </button>
      </div>
      {/* ... render products list (already implemented) ... */}
      <div className="bg-white rounded-[3rem] border border-slate-100 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Produto / SKU</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Preço Unit.</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Estoque</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {productsList.map(p => (
              <tr key={p.id}>
                <td className="px-8 py-5 font-bold">{p.name}</td>
                <td className="px-8 py-5 font-bold">R$ {Number(p.price).toFixed(2)}</td>
                <td className="px-8 py-5">{p.stock} un</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar 
        activeTab={activeTab} 
        setActiveTab={setActiveTab} 
        currentUser={currentUser || (setupRequired ? ({ id: 0, name: 'Instalador', username: 'setup', role: UserRole.MASTER } as User) : null)} 
        onLogout={() => { setCurrentUser(null); localStorage.removeItem('nexus_user'); setActiveTab('dashboard'); }} 
      />

      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-20 bg-white/70 backdrop-blur-md border-b border-slate-100 sticky top-0 z-40 flex items-center justify-between px-10">
          <div className="flex flex-col">
            <h2 className="text-xl font-black text-slate-900 leading-none">NexusTEF</h2>
            <span className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest mt-1.5">{activeTab}</span>
          </div>
          {/* Header User Info consistent with other turns */}
          <div className="flex items-center gap-4">
             {currentUser && <span className="text-xs font-bold text-slate-600">Olá, {currentUser.name}</span>}
          </div>
        </header>

        <main className="p-10 max-w-[1400px] w-full mx-auto">
          {activeTab === 'dashboard' && (
            <div className="space-y-8 animate-in fade-in duration-700">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
                <StatCard label="Volume Total" value={`R$ ${stats.total.toLocaleString('pt-BR')}`} icon="💰" color="bg-indigo-50 text-indigo-600" />
                <StatCard label="Mix de Pix" value={`${stats.pixPercent}%`} icon="⚡" color="bg-emerald-50 text-emerald-600" />
                <StatCard label="Produtos" value={productsList.length} icon="📦" color="bg-amber-50 text-amber-600" />
                <StatCard label="Transações" value={stats.txCount} icon="🔄" color="bg-slate-50 text-slate-600" />
              </div>
              <FiscalMonitor states={SEFAZ_STATES} />
            </div>
          )}

          {activeTab === 'simulator' && renderSimulator()}
          {activeTab === 'products' && renderProducts()}
          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}
          {/* ... other tabs ... */}
        </main>
      </div>

      {/* Advanced Card Simulator Modal */}
      {showCardSimModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-xl z-[300] flex items-center justify-center p-6">
           <div className="bg-white w-full max-w-sm rounded-[3rem] shadow-2xl overflow-hidden border border-slate-100 animate-in zoom-in duration-300">
              <div className="bg-slate-900 p-8 text-center">
                 <div className="w-16 h-1 bg-slate-800 mx-auto rounded-full mb-6"></div>
                 <h4 className="text-white text-xl font-black tracking-tight">
                    {simStep === 'brand' && 'Selecione a Bandeira'}
                    {simStep === 'method' && 'Tipo de Operação'}
                    {simStep === 'installments' && 'Parcelamento'}
                    {simStep === 'processing' && 'Processando...'}
                 </h4>
              </div>

              <div className="p-10">
                 {simStep === 'brand' && (
                    <div className="grid grid-cols-2 gap-4">
                       {['Visa', 'Mastercard', 'Elo', 'Amex'].map(brand => (
                          <button 
                            key={brand}
                            onClick={() => { setSimData({...simData, brand}); setSimStep('method'); }}
                            className="p-6 bg-slate-50 border border-slate-100 rounded-3xl font-black text-slate-800 hover:bg-indigo-50 hover:border-indigo-200 transition-all flex flex-col items-center gap-3"
                          >
                             <span className="text-2xl">{brand === 'Visa' ? '💳' : brand === 'Mastercard' ? '🃏' : brand === 'Elo' ? '🔗' : '💎'}</span>
                             <span className="text-[10px] uppercase tracking-widest">{brand}</span>
                          </button>
                       ))}
                    </div>
                 )}

                 {simStep === 'method' && (
                    <div className="space-y-4">
                       <button 
                         onClick={() => { setSimData({...simData, method: PaymentMethod.DEBIT, installments: 1}); setSimStep('processing'); simulateTransaction(PaymentMethod.DEBIT, { brand: simData.brand, installments: 1 }); }}
                         className="w-full p-6 bg-indigo-600 text-white rounded-3xl font-black uppercase text-xs tracking-widest shadow-xl shadow-indigo-100"
                       >
                         💳 Débito à Vista
                       </button>
                       <button 
                         onClick={() => setSimStep('installments')}
                         className="w-full p-6 bg-slate-900 text-white rounded-3xl font-black uppercase text-xs tracking-widest shadow-xl shadow-slate-100"
                       >
                         🧾 Crédito (Parcelas)
                       </button>
                    </div>
                 )}

                 {simStep === 'installments' && (
                    <div className="grid grid-cols-3 gap-3">
                       {[1, 2, 3, 4, 6, 12].map(n => (
                          <button 
                            key={n}
                            onClick={() => { setSimData({...simData, installments: n}); setSimStep('processing'); simulateTransaction(PaymentMethod.CREDIT, { brand: simData.brand, installments: n }); }}
                            className="p-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-slate-700 hover:bg-indigo-600 hover:text-white transition-all"
                          >
                             {n}x
                          </button>
                       ))}
                    </div>
                 )}

                 {simStep === 'processing' && (
                    <div className="text-center py-10">
                       <div className="w-16 h-16 border-4 border-indigo-600 border-t-transparent rounded-full mx-auto animate-spin mb-6"></div>
                       <p className="text-slate-500 font-bold animate-pulse">Comunicando com Adquirente...</p>
                    </div>
                 )}

                 {simStep !== 'processing' && (
                    <button 
                      onClick={() => setShowCardSimModal(false)}
                      className="w-full mt-8 py-3 text-slate-400 font-black text-[10px] uppercase tracking-widest hover:text-slate-600"
                    >
                       Cancelar Operação
                    </button>
                 )}
              </div>
           </div>
        </div>
      )}

      {/* Pix Modal Consistent with previous logic */}
      {showPixModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-xl z-[400] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[4rem] w-full max-w-md shadow-2xl text-center">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">QR Code PIX</h3>
            <div className="bg-slate-50 p-8 rounded-[3rem] mb-8 inline-block border border-slate-100">
               <img src={showPixModal.pixQrCode} alt="PIX QR" className="w-56 h-56 mx-auto" />
            </div>
            <p className="text-3xl font-black text-slate-900 mb-2">R$ {showPixModal.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            <button onClick={() => setShowPixModal(null)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest">Fechar</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { Transaction, PaymentStatus, FiscalStatus } from '../types';

interface TransactionTableProps {
  transactions: Transaction[];
}

const TransactionTable: React.FC<TransactionTableProps> = ({ transactions }) => {
  const getStatusStyle = (status: PaymentStatus) => {
    switch (status) {
      case PaymentStatus.SUCCESS: return 'bg-emerald-50 text-emerald-700 ring-1 ring-emerald-200';
      case PaymentStatus.FAILED: return 'bg-rose-50 text-rose-700 ring-1 ring-rose-200';
      default: return 'bg-slate-100 text-slate-600';
    }
  };

  const getFiscalStyle = (status?: FiscalStatus) => {
    switch (status) {
      case FiscalStatus.AUTHORIZED: return 'text-emerald-500 bg-emerald-50';
      case FiscalStatus.CONTINGENCY: return 'text-amber-500 bg-amber-50';
      case FiscalStatus.REJECTED: return 'text-rose-500 bg-rose-50';
      default: return 'text-slate-300 bg-slate-50';
    }
  };

  return (
    <div className="bg-white rounded-[3rem] border border-slate-200 overflow-hidden shadow-sm animate-in slide-in-from-bottom duration-500">
      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50/80 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">ID / Fiscal</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Data</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Valor</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Método / Bandeira</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Pagamento</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Sefaz NFC-e</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {transactions.map((tx) => (
              <tr key={tx.id} className="hover:bg-slate-50/40 transition-colors">
                <td className="px-8 py-5">
                  <div className="font-mono text-[11px] font-bold text-slate-500">{tx.id}</div>
                  <div className="text-[10px] text-indigo-400 font-bold">Nota: {tx.fiscalNoteId || 'N/A'}</div>
                </td>
                <td className="px-8 py-5 text-xs font-medium text-slate-600">
                  {new Date(tx.timestamp).toLocaleString('pt-BR', { dateStyle: 'short', timeStyle: 'short' })}
                </td>
                <td className="px-8 py-5">
                  <p className="text-sm font-black text-slate-900">R$ {tx.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
                  {tx.installments && tx.installments > 1 && (
                    <p className="text-[9px] font-bold text-slate-400 uppercase">{tx.installments}x de R$ {(tx.amount / tx.installments).toFixed(2)}</p>
                  )}
                </td>
                <td className="px-8 py-5">
                  <div className="flex flex-col gap-1">
                    <span className={`w-fit px-2 py-0.5 rounded text-[9px] font-black uppercase ${tx.method === 'PIX' ? 'bg-emerald-100 text-emerald-700' : 'bg-indigo-50 text-indigo-600'}`}>
                      {tx.method}
                    </span>
                    {tx.cardBrand && (
                      <span className="text-[10px] font-bold text-slate-500 flex items-center gap-1">
                         🔹 {tx.cardBrand}
                      </span>
                    )}
                  </div>
                </td>
                <td className="px-8 py-5">
                  <span className={`px-2.5 py-1 text-[10px] font-bold rounded-full ${getStatusStyle(tx.status)}`}>
                    {tx.status}
                  </span>
                </td>
                <td className="px-8 py-5 text-right">
                  <span className={`px-2.5 py-1 text-[10px] font-black rounded-lg ${getFiscalStyle(tx.fiscalStatus)}`}>
                    {tx.fiscalStatus || 'Sem Nota'}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default TransactionTable;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES, MOCK_TRANSACTIONS, ALL_UFS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole, FiscalConfig, Product } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginData, setLoginData] = useState({ username: '', password: '' });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [productsList, setProductsList] = useState<Product[]>([]);
  const [fiscalConfig, setFiscalConfig] = useState<FiscalConfig>({
    cnpj: '', ie: '', razaoSocial: '', cscToken: '', cscId: '',
    ambiente: 'Homologação', serie: '1', ultimoNumero: 0, contingencia: false
  });
  const [insights, setInsights] = useState<string>('Analizando métricas em tempo real...');
  const [isSimulating, setIsSimulating] = useState(false);
  const [isSavingFiscal, setIsSavingFiscal] = useState(false);
  const [setupRequired, setSetupRequired] = useState<boolean>(false);
  const [showPixModal, setShowPixModal] = useState<Transaction | null>(null);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isMounted, setIsMounted] = useState(false);

  // Advanced Simulator State
  const [showCardSimModal, setShowCardSimModal] = useState(false);
  const [simStep, setSimStep] = useState<'brand' | 'method' | 'installments' | 'processing'>('brand');
  const [simData, setSimData] = useState({ brand: '', method: PaymentMethod.CREDIT, installments: 1 });

  // Certificate Modal State
  const [showCertModal, setShowCertModal] = useState(false);
  const [isSavingCert, setIsSavingCert] = useState(false);
  const [editingCert, setEditingCert] = useState<Partial<DigitalCertificate> | null>(null);

  // User Management State
  const [showUserModal, setShowUserModal] = useState(false);
  const [isSavingUser, setIsSavingUser] = useState(false);
  const [editingUser, setEditingUser] = useState<Partial<User> & { password?: string } | null>(null);

  // Product Management State
  const [showProductModal, setShowProductModal] = useState(false);
  const [isSavingProduct, setIsSavingProduct] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Partial<Product> | null>(null);

  const safeFetch = async (url: string, options?: RequestInit) => {
    try {
      const response = await fetch(url, options);
      if (!response.ok) throw new Error(`Server returned ${response.status}`);
      const text = await response.text();
      try { return JSON.parse(text); } catch (e) { throw new Error("Invalid JSON response"); }
    } catch (e) {
      console.warn("API Fallback triggered:", e);
      const action = new URL(url, window.location.origin).searchParams.get('action');
      if (action === 'check_setup') return { setup_required: localStorage.getItem('nexus_users') === null };
      if (action === 'get_transactions') return MOCK_TRANSACTIONS;
      if (action === 'get_products') return productsList;
      if (action === 'get_certificates') return certificates;
      return { status: 'error', message: 'Offline Mode' };
    }
  };

  useEffect(() => {
    setIsMounted(true);
    const init = async () => {
      const data = await safeFetch(`${API_URL}?action=check_setup`);
      if (data && typeof data.setup_required !== 'undefined') setSetupRequired(data.setup_required);
      const saved = localStorage.getItem('nexus_user');
      if (saved) setCurrentUser(JSON.parse(saved));
    };
    init();
  }, []);

  const loadData = async () => {
    const [txData, certData, userData, fiscalData, prodData] = await Promise.all([
      safeFetch(`${API_URL}?action=get_transactions`),
      safeFetch(`${API_URL}?action=get_certificates`),
      safeFetch(`${API_URL}?action=get_users`),
      safeFetch(`${API_URL}?action=get_fiscal_config`),
      safeFetch(`${API_URL}?action=get_products`)
    ]);
    setTransactions(Array.isArray(txData) ? txData : MOCK_TRANSACTIONS);
    if (Array.isArray(certData)) {
      // Normalização de campos do banco
      const mappedCerts = certData.map(c => ({
        ...c,
        expirationDate: c.expiration_date || c.expirationDate
      }));
      setCertificates(mappedCerts);
    }
    if (Array.isArray(userData)) setUsersList(userData);
    if (fiscalData && !fiscalData.status) setFiscalConfig(fiscalData);
    if (Array.isArray(prodData)) setProductsList(prodData);
  };

  useEffect(() => { if (isMounted) loadData(); }, [currentUser, setupRequired, isMounted]);

  const handleSaveProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingProduct(true);
    const data = await safeFetch(`${API_URL}?action=save_product`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingProduct)
    });
    if (data.status === 'success') {
      setShowProductModal(false);
      setEditingProduct(null);
      loadData();
    }
    setIsSavingProduct(false);
  };

  const handleSaveCert = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingCert(true);
    const data = await safeFetch(`${API_URL}?action=save_certificate`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingCert)
    });
    if (data.status === 'success') {
      setShowCertModal(false);
      setEditingCert(null);
      loadData();
    }
    setIsSavingCert(false);
  };

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    const data = await safeFetch(`${API_URL}?action=login`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(loginData)
    });
    if (data.status === 'success') {
      setCurrentUser(data.user);
      localStorage.setItem('nexus_user', JSON.stringify(data.user));
      setShowLoginModal(false);
    } else { setError(data.message || 'Credenciais inválidas.'); }
  };

  const handleSaveUser = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingUser(true);
    const data = await safeFetch(`${API_URL}?action=save_user`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingUser)
    });
    if (data.status === 'success') {
      setShowUserModal(false);
      setEditingUser(null);
      loadData();
    }
    setIsSavingUser(false);
  };

  const handleDeleteCert = async (id: string) => {
    if (!confirm('Deseja realmente remover este certificado?')) return;
    const data = await safeFetch(`${API_URL}?action=delete_certificate&id=${id}`);
    if (data.status === 'success') loadData();
  };

  const stats = useMemo(() => {
    const success = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const totalVal = success.reduce((a, b) => a + Number(b.amount), 0);
    const pix = success.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    return {
      total: totalVal,
      pixPercent: ((pix / (totalVal || 1)) * 100).toFixed(1),
      txCount: transactions.length
    };
  }, [transactions]);

  const simulateTransaction = async (method: PaymentMethod, details?: { brand: string, installments: number }) => {
    setIsSimulating(true);
    const amount = Math.floor(Math.random() * 500) + 10.5;
    const mockTx: Transaction = {
      id: `TX-${Math.floor(Math.random() * 90000 + 10000)}`,
      timestamp: new Date().toISOString(),
      amount: amount,
      method: method,
      status: PaymentStatus.SUCCESS,
      terminalId: 'TERM-SIM',
      segment: 'Simulação',
      fiscalNoteId: Math.floor(Math.random() * 9000 + 1000).toString(),
      fiscalStatus: FiscalStatus.AUTHORIZED,
      cardBrand: details?.brand,
      installments: details?.installments,
      pixQrCode: method === PaymentMethod.PIX ? 'https://api.qrserver.com/v1/create-qr-code/?size=250x250&data=00020101021226870014BR.GOV.BCB.PIX0125' : undefined
    };
    await new Promise(r => setTimeout(r, 1500));
    setTransactions(prev => [mockTx, ...prev]);
    if (method === PaymentMethod.PIX) setShowPixModal(mockTx);
    setIsSimulating(false);
    setShowCardSimModal(false);
    setSimStep('brand');
    setActiveTab('dashboard');
  };

  const renderSimulator = () => (
    <div className="max-w-xl mx-auto py-10 animate-in slide-in-from-bottom duration-500">
      <div className="bg-white p-12 rounded-[4rem] shadow-2xl border border-slate-100 text-center relative overflow-hidden">
        <div className="absolute top-0 left-0 w-full h-2 bg-indigo-500"></div>
        <h3 className="text-4xl font-black text-slate-900 mb-2 tracking-tight">Pinpad Virtual</h3>
        <p className="text-slate-500 font-medium mb-12">Simule transações em tempo real para testes de fluxo.</p>
        <div className="grid grid-cols-1 gap-6">
          <button onClick={() => { setShowCardSimModal(true); setSimStep('brand'); }} className="group relative py-8 bg-slate-900 text-white rounded-[2.5rem] font-black uppercase tracking-widest hover:bg-indigo-600 transition-all shadow-2xl shadow-slate-200">
            <span className="relative z-10 flex items-center justify-center gap-3">💳 Inserir Cartão</span>
          </button>
          <button onClick={() => simulateTransaction(PaymentMethod.PIX)} className="group relative py-8 bg-emerald-600 text-white rounded-[2.5rem] font-black uppercase tracking-widest hover:bg-emerald-700 transition-all shadow-2xl shadow-emerald-100">
            <span className="relative z-10 flex items-center justify-center gap-3">⚡ Gerar Pix QR</span>
          </button>
        </div>
      </div>
    </div>
  );

  const renderProducts = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Catálogo de Produtos</h3>
          <p className="text-slate-500 font-medium">Gestão centralizada de itens, preços e estoque.</p>
        </div>
        <button onClick={() => { setEditingProduct({ name: '', sku: '', price: 0, category: 'Geral', stock: 0 }); setShowProductModal(true); }} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl hover:scale-105 transition-all text-sm">
          + Novo Produto
        </button>
      </div>
      <div className="bg-white rounded-[3rem] border border-slate-100 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Produto / SKU</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Preço Unit.</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Estoque</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {productsList.map(p => (
              <tr key={p.id}>
                <td className="px-8 py-5 font-bold">{p.name}</td>
                <td className="px-8 py-5 font-bold">R$ {Number(p.price).toFixed(2)}</td>
                <td className="px-8 py-5">{p.stock} un</td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );

  const renderCertificates = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Certificados Digitais</h3>
          <p className="text-slate-500 font-medium">Controle centralizado de cadeias A1/A3 para NFC-e.</p>
        </div>
        <button 
          onClick={() => { setEditingCert({ alias: '', state: 'SP', expirationDate: '', type: 'A1', status: 'Ativo' }); setShowCertModal(true); }}
          className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-xl hover:scale-105 transition-all text-sm"
        >
          + Novo Certificado
        </button>
      </div>

      <div className="bg-white rounded-[3rem] border border-slate-100 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Apelido</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">UF / Tipo</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Expiração</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Status</th>
              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {certificates.length === 0 ? (
              <tr><td colSpan={5} className="px-8 py-10 text-center text-slate-400 italic">Nenhum certificado configurado.</td></tr>
            ) : (
              certificates.map(c => (
                <tr key={c.id} className="hover:bg-slate-50/50 transition-colors">
                  <td className="px-8 py-5">
                    <p className="font-bold text-slate-800">{c.alias}</p>
                    <p className="text-[10px] font-mono text-slate-400 uppercase">{c.id}</p>
                  </td>
                  <td className="px-8 py-5">
                    <span className="font-bold text-slate-700">{c.state}</span>
                    <span className="ml-2 px-2 py-0.5 bg-slate-100 rounded text-[9px] font-black text-slate-500">{c.type}</span>
                  </td>
                  <td className="px-8 py-5 text-sm font-medium text-slate-600">
                    {c.expirationDate ? new Date(c.expirationDate).toLocaleDateString('pt-BR') : 'N/D'}
                  </td>
                  <td className="px-8 py-5">
                    <span className={`px-2.5 py-1 rounded-full text-[9px] font-black uppercase tracking-widest ${
                      c.status === 'Ativo' ? 'bg-emerald-50 text-emerald-600 ring-1 ring-emerald-200' : 
                      c.status === 'Alerta' ? 'bg-amber-50 text-amber-600 ring-1 ring-amber-200' : 'bg-rose-50 text-rose-600 ring-1 ring-rose-200'
                    }`}>
                      {c.status}
                    </span>
                  </td>
                  <td className="px-8 py-5 text-right">
                    <div className="flex justify-end gap-2">
                      <button onClick={() => { setEditingCert(c); setShowCertModal(true); }} className="w-8 h-8 bg-indigo-50 text-indigo-600 rounded-lg flex items-center justify-center hover:bg-indigo-600 hover:text-white transition-all">✏️</button>
                      <button onClick={() => handleDeleteCert(c.id)} className="w-8 h-8 bg-rose-50 text-rose-600 rounded-lg flex items-center justify-center hover:bg-rose-600 hover:text-white transition-all">🗑️</button>
                    </div>
                  </td>
                </tr>
              ))
            )}
          </tbody>
        </table>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} currentUser={currentUser || (setupRequired ? ({ id: 0, name: 'Instalador', username: 'setup', role: UserRole.MASTER } as User) : null)} onLogout={() => { setCurrentUser(null); localStorage.removeItem('nexus_user'); setActiveTab('dashboard'); }} />
      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-20 bg-white/70 backdrop-blur-md border-b border-slate-100 sticky top-0 z-40 flex items-center justify-between px-10">
          <div className="flex flex-col"><h2 className="text-xl font-black text-slate-900">NexusTEF</h2><span className="text-[10px] font-bold text-indigo-500 uppercase">{activeTab}</span></div>
          <div className="flex items-center gap-4">{currentUser && <span className="text-xs font-bold text-slate-600">Olá, {currentUser.name}</span>}</div>
        </header>

        <main className="p-10 max-w-[1400px] w-full mx-auto">
          {activeTab === 'dashboard' && <div className="space-y-8"><div className="grid grid-cols-4 gap-6"><StatCard label="Volume" value={`R$ ${stats.total.toLocaleString('pt-BR')}`} icon="💰" color="bg-indigo-50" /><StatCard label="Pix" value={`${stats.pixPercent}%`} icon="⚡" color="bg-emerald-50" /><StatCard label="Produtos" value={productsList.length} icon="📦" color="bg-amber-50" /><StatCard label="Transações" value={stats.txCount} icon="🔄" color="bg-slate-50" /></div><FiscalMonitor states={SEFAZ_STATES} /></div>}
          {activeTab === 'simulator' && renderSimulator()}
          {activeTab === 'products' && renderProducts()}
          {activeTab === 'certificates' && renderCertificates()}
          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}
        </main>
      </div>

      {showCertModal && editingCert && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-10 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Configurar Certificado</h3>
            <form onSubmit={handleSaveCert} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Apelido (Identificação)</label>
                <input type="text" required value={editingCert.alias} onChange={e => setEditingCert({...editingCert, alias: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none" placeholder="Ex: Matriz São Paulo" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Estado (UF)</label>
                  <select value={editingCert.state} onChange={e => setEditingCert({...editingCert, state: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none">
                    {ALL_UFS.map(uf => <option key={uf} value={uf}>{uf}</option>)}
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Tipo</label>
                  <select value={editingCert.type} onChange={e => setEditingCert({...editingCert, type: e.target.value as any})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none">
                    <option value="A1">Arquivo (A1)</option>
                    <option value="A3">Cartão/Token (A3)</option>
                  </select>
                </div>
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Data de Expiração</label>
                <input type="date" required value={editingCert.expirationDate} onChange={e => setEditingCert({...editingCert, expirationDate: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none" />
              </div>
              <div className="flex gap-4 pt-6">
                <button type="button" onClick={() => setShowCertModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold uppercase text-xs tracking-widest">Cancelar</button>
                <button type="submit" disabled={isSavingCert} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl">
                  {isSavingCert ? 'Gravando...' : 'Gravar'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Re-implementing other existing modals for consistency */}
      {showProductModal && editingProduct && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-10 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Configurar Item</h3>
            <form onSubmit={handleSaveProduct} className="space-y-4">
              <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nome</label><input type="text" required value={editingProduct.name} onChange={e => setEditingProduct({...editingProduct, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" /></div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Preço</label><input type="number" step="0.01" required value={editingProduct.price} onChange={e => setEditingProduct({...editingProduct, price: parseFloat(e.target.value)})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" /></div>
                <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Estoque</label><input type="number" required value={editingProduct.stock} onChange={e => setEditingProduct({...editingProduct, stock: parseInt(e.target.value)})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" /></div>
              </div>
              <div className="flex gap-4 pt-6"><button type="button" onClick={() => setShowProductModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold uppercase text-xs">Cancelar</button><button type="submit" className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs">Salvar</button></div>
            </form>
          </div>
        </div>
      )}

      {showCardSimModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-xl z-[300] flex items-center justify-center p-6">
           <div className="bg-white w-full max-w-sm rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in duration-300">
              <div className="bg-slate-900 p-8 text-center text-white"><h4>Pinpad</h4></div>
              <div className="p-10">
                 {simStep === 'brand' && <div className="grid grid-cols-2 gap-4">{['Visa', 'Mastercard', 'Elo', 'Amex'].map(brand => <button key={brand} onClick={() => { setSimData({...simData, brand}); setSimStep('method'); }} className="p-6 bg-slate-50 border border-slate-100 rounded-3xl font-black text-slate-800 uppercase text-[10px]">{brand}</button>)}</div>}
                 {simStep === 'method' && <div className="space-y-4"><button onClick={() => simulateTransaction(PaymentMethod.DEBIT, { brand: simData.brand, installments: 1 })} className="w-full p-6 bg-indigo-600 text-white rounded-3xl font-black uppercase text-xs">Débito</button><button onClick={() => setSimStep('installments')} className="w-full p-6 bg-slate-900 text-white rounded-3xl font-black uppercase text-xs">Crédito</button></div>}
                 {simStep === 'installments' && <div className="grid grid-cols-3 gap-3">{[1, 2, 3, 6, 12].map(n => <button key={n} onClick={() => simulateTransaction(PaymentMethod.CREDIT, { brand: simData.brand, installments: n })} className="p-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-slate-700">{n}x</button>)}</div>}
                 {simStep === 'processing' && <div className="text-center py-10"><div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full mx-auto animate-spin mb-6"></div><p>Processando...</p></div>}
                 {simStep !== 'processing' && <button onClick={() => setShowCardSimModal(false)} className="w-full mt-8 py-3 text-slate-400 font-black text-[10px] uppercase tracking-widest">Cancelar</button>}
              </div>
           </div>
        </div>
      )}

      {showPixModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-xl z-[400] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[4rem] w-full max-w-md shadow-2xl text-center">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">QR Code PIX</h3>
            <div className="bg-slate-50 p-8 rounded-[3rem] mb-8 inline-block"><img src={showPixModal.pixQrCode} alt="PIX QR" className="w-56 h-56 mx-auto" /></div>
            <p className="text-3xl font-black text-slate-900 mb-2">R$ {showPixModal.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            <button onClick={() => setShowPixModal(null)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs">Fechar</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES, MOCK_TRANSACTIONS, ALL_UFS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole, FiscalConfig, Product } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginData, setLoginData] = useState({ username: '', password: '' });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [productsList, setProductsList] = useState<Product[]>([]);
  const [fiscalConfig, setFiscalConfig] = useState<FiscalConfig>({
    cnpj: '', ie: '', razaoSocial: '', cscToken: '', cscId: '',
    ambiente: 'Homologação', serie: '1', ultimoNumero: 0, contingencia: false
  });
  const [insights, setInsights] = useState<string>('Analizando métricas em tempo real...');
  const [isSimulating, setIsSimulating] = useState(false);
  const [isSavingFiscal, setIsSavingFiscal] = useState(false);
  const [setupRequired, setSetupRequired] = useState<boolean>(false);
  const [showPixModal, setShowPixModal] = useState<Transaction | null>(null);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isMounted, setIsMounted] = useState(false);

  // Advanced Simulator State
  const [showCardSimModal, setShowCardSimModal] = useState(false);
  const [simStep, setSimStep] = useState<'brand' | 'method' | 'installments' | 'processing'>('brand');
  const [simData, setSimData] = useState({ brand: '', method: PaymentMethod.CREDIT, installments: 1 });

  // Certificate Modal State
  const [showCertModal, setShowCertModal] = useState(false);
  const [isSavingCert, setIsSavingCert] = useState(false);
  const [editingCert, setEditingCert] = useState<Partial<DigitalCertificate> | null>(null);

  // Certification Center State
  const [isCertifying, setIsCertifying] = useState(false);
  const [certPhase, setCertPhase] = useState<number>(0); // 0: Idle, 1: XML, 2: Sign, 3: Transmission, 4: Done
  const [selectedCertForFiscal, setSelectedCertForFiscal] = useState<string>('');
  const [pendingTxToCertify, setPendingTxToCertify] = useState<string | null>(null);

  // User Management State
  const [showUserModal, setShowUserModal] = useState(false);
  const [isSavingUser, setIsSavingUser] = useState(false);
  const [editingUser, setEditingUser] = useState<Partial<User> & { password?: string } | null>(null);

  // Product Management State
  const [showProductModal, setShowProductModal] = useState(false);
  const [isSavingProduct, setIsSavingProduct] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Partial<Product> | null>(null);

  const safeFetch = async (url: string, options?: RequestInit) => {
    try {
      const response = await fetch(url, options);
      if (!response.ok) throw new Error(`Server returned ${response.status}`);
      const text = await response.text();
      try { return JSON.parse(text); } catch (e) { throw new Error("Invalid JSON response"); }
    } catch (e) {
      console.warn("API Fallback triggered:", e);
      const action = new URL(url, window.location.origin).searchParams.get('action');
      if (action === 'check_setup') return { setup_required: localStorage.getItem('nexus_users') === null };
      if (action === 'get_transactions') return MOCK_TRANSACTIONS;
      if (action === 'get_products') return productsList;
      if (action === 'get_certificates') return certificates;
      return { status: 'error', message: 'Offline Mode' };
    }
  };

  useEffect(() => {
    setIsMounted(true);
    const init = async () => {
      const data = await safeFetch(`${API_URL}?action=check_setup`);
      if (data && typeof data.setup_required !== 'undefined') setSetupRequired(data.setup_required);
      const saved = localStorage.getItem('nexus_user');
      if (saved) setCurrentUser(JSON.parse(saved));
    };
    init();
  }, []);

  const loadData = async () => {
    const [txData, certData, userData, fiscalData, prodData] = await Promise.all([
      safeFetch(`${API_URL}?action=get_transactions`),
      safeFetch(`${API_URL}?action=get_certificates`),
      safeFetch(`${API_URL}?action=get_users`),
      safeFetch(`${API_URL}?action=get_fiscal_config`),
      safeFetch(`${API_URL}?action=get_products`)
    ]);

    setTransactions(Array.isArray(txData) ? txData : MOCK_TRANSACTIONS);

    if (Array.isArray(certData)) {
      const mappedCerts = certData.map(c => ({
        ...c,
        expirationDate: c.expiration_date || c.expirationDate
      }));
      setCertificates(mappedCerts);
      if (mappedCerts.length > 0 && !selectedCertForFiscal) setSelectedCertForFiscal(mappedCerts[0].id);
    }

    if (Array.isArray(userData)) setUsersList(userData);
    if (fiscalData && !fiscalData.status) setFiscalConfig(fiscalData);
    if (Array.isArray(prodData)) setProductsList(prodData);
  };

  useEffect(() => { if (isMounted) loadData(); }, [currentUser, setupRequired, isMounted]);

  const handleSaveProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingProduct(true);
    const data = await safeFetch(`${API_URL}?action=save_product`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingProduct)
    });
    if (data.status === 'success') {
      setShowProductModal(false);
      setEditingProduct(null);
      loadData();
    }
    setIsSavingProduct(false);
  };

  const handleSaveCert = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingCert(true);
    const data = await safeFetch(`${API_URL}?action=save_certificate`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingCert)
    });
    if (data.status === 'success') {
      setShowCertModal(false);
      setEditingCert(null);
      loadData();
    }
    setIsSavingCert(false);
  };

  const handleCertify = async (txId: string) => {
    if (!selectedCertForFiscal) {
      alert('Selecione um certificado para prosseguir.');
      return;
    }
    setPendingTxToCertify(txId);
    setIsCertifying(true);

    // Simulate phases
    setCertPhase(1); // XML Generation
    await new Promise(r => setTimeout(r, 1200));
    setCertPhase(2); // Signing with selected certificate
    await new Promise(r => setTimeout(r, 1500));
    setCertPhase(3); // Transmission to SEFAZ
    await new Promise(r => setTimeout(r, 2000));

    const data = await safeFetch(`${API_URL}?action=certify_transaction`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ txId, certId: selectedCertForFiscal })
    });

    if (data.status === 'success') {
      setCertPhase(4); // Success
      await new Promise(r => setTimeout(r, 1500));
      loadData();
    } else {
      alert('Erro na certificação: ' + data.message);
    }

    setIsCertifying(false);
    setCertPhase(0);
    setPendingTxToCertify(null);
  };

  const stats = useMemo(() => {
    const success = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const totalVal = success.reduce((a, b) => a + Number(b.amount), 0);
    const pix = success.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    return {
      total: totalVal,
      pixPercent: ((pix / (totalVal || 1)) * 100).toFixed(1),
      txCount: transactions.length
    };
  }, [transactions]);

  const simulateTransaction = async (method: PaymentMethod, details?: { brand: string, installments: number }) => {
    setIsSimulating(true);
    const amount = Math.floor(Math.random() * 500) + 10.5;
    const mockTx: Transaction = {
      id: `TX-${Math.floor(Math.random() * 90000 + 10000)}`,
      timestamp: new Date().toISOString(),
      amount: amount,
      method: method,
      status: PaymentStatus.SUCCESS,
      terminalId: 'TERM-SIM',
      segment: 'Simulação',
      fiscalNoteId: '', // Empty to show in generator
      fiscalStatus: undefined, 
      cardBrand: details?.brand,
      installments: details?.installments,
      pixQrCode: method === PaymentMethod.PIX ? 'https://api.qrserver.com/v1/create-qr-code/?size=250x250&data=00020101021226870014BR.GOV.BCB.PIX0125' : undefined
    };
    await new Promise(r => setTimeout(r, 1500));
    setTransactions(prev => [mockTx, ...prev]);
    if (method === PaymentMethod.PIX) setShowPixModal(mockTx);
    setIsSimulating(false);
    setShowCardSimModal(false);
    setSimStep('brand');
    setActiveTab('dashboard');
  };

  const renderFiscalGenerator = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Gerador NFC-e</h3>
          <p className="text-slate-500 font-medium">Transmissão e certificação digital de vendas pendentes.</p>
        </div>
        <div className="flex items-center gap-4">
           <div className="space-y-1">
             <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Certificado Ativo</label>
             <select 
               value={selectedCertForFiscal} 
               onChange={(e) => setSelectedCertForFiscal(e.target.value)}
               className="bg-white border border-slate-100 rounded-xl p-3 text-xs font-bold text-slate-700 shadow-sm outline-none focus:ring-2 focus:ring-indigo-500"
             >
               {certificates.map(c => (
                 <option key={c.id} value={c.id}>{c.alias} ({c.type})</option>
               ))}
               {certificates.length === 0 && <option value="">Nenhum Certificado</option>}
             </select>
           </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left: Configuration (Existing logic preserved) */}
        <div className="lg:col-span-1 space-y-6">
           <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm space-y-4">
              <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest border-b border-slate-50 pb-4">Configuração Fiscal</h4>
              <div className="space-y-4">
                <div className="flex justify-between text-xs">
                   <span className="text-slate-400 font-bold uppercase">CNPJ</span>
                   <span className="text-slate-800 font-black">{fiscalConfig.cnpj || 'Não definido'}</span>
                </div>
                <div className="flex justify-between text-xs">
                   <span className="text-slate-400 font-bold uppercase">Ambiente</span>
                   <span className={`px-2 py-0.5 rounded-full font-black ${fiscalConfig.ambiente === 'Produção' ? 'bg-rose-50 text-rose-600' : 'bg-amber-50 text-amber-600'}`}>{fiscalConfig.ambiente}</span>
                </div>
              </div>
              <button onClick={() => setActiveTab('fiscal_config')} className="w-full py-3 bg-slate-50 text-slate-500 rounded-xl font-bold text-[10px] uppercase tracking-widest hover:bg-slate-100 transition-all mt-4">
                Alterar Configurações
              </button>
           </div>

           {isCertifying && (
             <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white shadow-2xl animate-pulse">
                <h4 className="text-sm font-black mb-6 uppercase tracking-widest text-indigo-400">Certificação em Curso</h4>
                <div className="space-y-6">
                   <div className="flex items-center gap-4">
                      <div className={`w-3 h-3 rounded-full ${certPhase >= 1 ? 'bg-emerald-500' : 'bg-slate-700'}`}></div>
                      <span className={`text-[10px] font-bold ${certPhase >= 1 ? 'text-white' : 'text-slate-500'}`}>GERAÇÃO XML NFC-e</span>
                   </div>
                   <div className="flex items-center gap-4">
                      <div className={`w-3 h-3 rounded-full ${certPhase >= 2 ? 'bg-emerald-500' : 'bg-slate-700'}`}></div>
                      <span className={`text-[10px] font-bold ${certPhase >= 2 ? 'text-white' : 'text-slate-500'}`}>ASSINATURA DIGITAL (SHA256)</span>
                   </div>
                   <div className="flex items-center gap-4">
                      <div className={`w-3 h-3 rounded-full ${certPhase >= 3 ? 'bg-emerald-500' : 'bg-slate-700'}`}></div>
                      <span className={`text-[10px] font-bold ${certPhase >= 3 ? 'text-white' : 'text-slate-500'}`}>TRANSMISSÃO SEFAZ</span>
                   </div>
                   <div className="flex items-center gap-4">
                      <div className={`w-3 h-3 rounded-full ${certPhase >= 4 ? 'bg-emerald-500' : 'bg-slate-700'}`}></div>
                      <span className={`text-[10px] font-bold ${certPhase >= 4 ? 'text-white' : 'text-slate-500'}`}>AUTORIZAÇÃO DE USO</span>
                   </div>
                </div>
             </div>
           )}
        </div>

        {/* Right: Generator List */}
        <div className="lg:col-span-2 space-y-6">
          <div className="bg-white rounded-[3rem] border border-slate-100 overflow-hidden shadow-sm">
            <div className="p-8 border-b border-slate-50 flex justify-between items-center">
              <h4 className="text-sm font-black text-slate-800 uppercase tracking-widest">Vendas sem Nota Emitida</h4>
              <span className="bg-indigo-50 text-indigo-600 px-3 py-1 rounded-full text-[10px] font-black">
                {transactions.filter(tx => !tx.fiscalNoteId).length} Pendentes
              </span>
            </div>
            <div className="divide-y divide-slate-50 max-h-[600px] overflow-auto">
               {transactions.filter(tx => !tx.fiscalNoteId).length === 0 ? (
                 <div className="p-20 text-center space-y-4">
                    <div className="text-4xl">✅</div>
                    <p className="text-slate-400 font-bold">Todas as vendas foram certificadas.</p>
                 </div>
               ) : (
                 transactions.filter(tx => !tx.fiscalNoteId).map(tx => (
                   <div key={tx.id} className="p-6 flex items-center justify-between hover:bg-slate-50/50 transition-all">
                      <div className="flex gap-4 items-center">
                         <div className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center font-black text-slate-400">
                           {tx.method.charAt(0)}
                         </div>
                         <div>
                            <p className="text-sm font-black text-slate-800">R$ {tx.amount.toLocaleString('pt-BR')}</p>
                            <p className="text-[10px] font-mono text-slate-400">{tx.id} • {new Date(tx.timestamp).toLocaleTimeString()}</p>
                         </div>
                      </div>
                      <button 
                        disabled={isCertifying}
                        onClick={() => handleCertify(tx.id)}
                        className={`px-6 py-3 rounded-xl font-black text-[10px] uppercase tracking-widest transition-all ${
                          isCertifying && pendingTxToCertify === tx.id ? 'bg-indigo-600 text-white animate-pulse' : 'bg-indigo-50 text-indigo-600 hover:bg-indigo-600 hover:text-white'
                        }`}
                      >
                         {isCertifying && pendingTxToCertify === tx.id ? 'Transmitindo...' : 'Transmitir e Certificar'}
                      </button>
                   </div>
                 ))
               )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} currentUser={currentUser || (setupRequired ? ({ id: 0, name: 'Instalador', username: 'setup', role: UserRole.MASTER } as User) : null)} onLogout={() => { setCurrentUser(null); localStorage.removeItem('nexus_user'); setActiveTab('dashboard'); }} />
      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-20 bg-white/70 backdrop-blur-md border-b border-slate-100 sticky top-0 z-40 flex items-center justify-between px-10">
          <div className="flex flex-col"><h2 className="text-xl font-black text-slate-900">NexusTEF</h2><span className="text-[10px] font-bold text-indigo-500 uppercase">{activeTab}</span></div>
          <div className="flex items-center gap-4">{currentUser && <span className="text-xs font-bold text-slate-600">Olá, {currentUser.name}</span>}</div>
        </header>

        <main className="p-10 max-w-[1400px] w-full mx-auto">
          {activeTab === 'dashboard' && <div className="space-y-8"><div className="grid grid-cols-4 gap-6"><StatCard label="Volume" value={`R$ ${stats.total.toLocaleString('pt-BR')}`} icon="💰" color="bg-indigo-50" /><StatCard label="Pix" value={`${stats.pixPercent}%`} icon="⚡" color="bg-emerald-50" /><StatCard label="Produtos" value={productsList.length} icon="📦" color="bg-amber-50" /><StatCard label="Transações" value={stats.txCount} icon="🔄" color="bg-slate-50" /></div><FiscalMonitor states={SEFAZ_STATES} /></div>}
          {activeTab === 'simulator' && renderSimulator()}
          {activeTab === 'products' && renderProducts()}
          {activeTab === 'certificates' && renderCertificates()}
          {activeTab === 'fiscal' && renderFiscalGenerator()}
          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}
        </main>
      </div>

      {showCertModal && editingCert && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-10 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Configurar Certificado</h3>
            <form onSubmit={handleSaveCert} className="space-y-4">
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Apelido (Identificação)</label>
                <input type="text" required value={editingCert.alias} onChange={e => setEditingCert({...editingCert, alias: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none" placeholder="Ex: Matriz São Paulo" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Estado (UF)</label>
                  <select value={editingCert.state} onChange={e => setEditingCert({...editingCert, state: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none">
                    {ALL_UFS.map(uf => <option key={uf} value={uf}>{uf}</option>)}
                  </select>
                </div>
                <div className="space-y-1">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Tipo</label>
                  <select value={editingCert.type} onChange={e => setEditingCert({...editingCert, type: e.target.value as any})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none">
                    <option value="A1">Arquivo (A1)</option>
                    <option value="A3">Cartão/Token (A3)</option>
                  </select>
                </div>
              </div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Data de Expiração</label>
                <input type="date" required value={editingCert.expirationDate} onChange={e => setEditingCert({...editingCert, expirationDate: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none" />
              </div>
              <div className="flex gap-4 pt-6">
                <button type="button" onClick={() => setShowCertModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold uppercase text-xs tracking-widest">Cancelar</button>
                <button type="submit" disabled={isSavingCert} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl">
                  {isSavingCert ? 'Gravando...' : 'Gravar'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showProductModal && editingProduct && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-10 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Configurar Item</h3>
            <form onSubmit={handleSaveProduct} className="space-y-4">
              <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nome</label><input type="text" required value={editingProduct.name} onChange={e => setEditingProduct({...editingProduct, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" /></div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Preço</label><input type="number" step="0.01" required value={editingProduct.price} onChange={e => setEditingProduct({...editingProduct, price: parseFloat(e.target.value)})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" /></div>
                <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Estoque</label><input type="number" required value={editingProduct.stock} onChange={e => setEditingProduct({...editingProduct, stock: parseInt(e.target.value)})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" /></div>
              </div>
              <div className="flex gap-4 pt-6"><button type="button" onClick={() => setShowProductModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold uppercase text-xs">Cancelar</button><button type="submit" className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs">Salvar</button></div>
            </form>
          </div>
        </div>
      )}

      {showCardSimModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-xl z-[300] flex items-center justify-center p-6">
           <div className="bg-white w-full max-w-sm rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in duration-300">
              <div className="bg-slate-900 p-8 text-center text-white"><h4>Pinpad</h4></div>
              <div className="p-10">
                 {simStep === 'brand' && <div className="grid grid-cols-2 gap-4">{['Visa', 'Mastercard', 'Elo', 'Amex'].map(brand => <button key={brand} onClick={() => { setSimData({...simData, brand}); setSimStep('method'); }} className="p-6 bg-slate-50 border border-slate-100 rounded-3xl font-black text-slate-800 uppercase text-[10px]">{brand}</button>)}</div>}
                 {simStep === 'method' && <div className="space-y-4"><button onClick={() => simulateTransaction(PaymentMethod.DEBIT, { brand: simData.brand, installments: 1 })} className="w-full p-6 bg-indigo-600 text-white rounded-3xl font-black uppercase text-xs">Débito</button><button onClick={() => setSimStep('installments')} className="w-full p-6 bg-slate-900 text-white rounded-3xl font-black uppercase text-xs">Crédito</button></div>}
                 {simStep === 'installments' && <div className="grid grid-cols-3 gap-3">{[1, 2, 3, 6, 12].map(n => <button key={n} onClick={() => simulateTransaction(PaymentMethod.CREDIT, { brand: simData.brand, installments: n })} className="p-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-slate-700">{n}x</button>)}</div>}
                 {simStep === 'processing' && <div className="text-center py-10"><div className="w-12 h-12 border-4 border-indigo-600 border-t-transparent rounded-full mx-auto animate-spin mb-6"></div><p>Processando...</p></div>}
                 {simStep !== 'processing' && <button onClick={() => setShowCardSimModal(false)} className="w-full mt-8 py-3 text-slate-400 font-black text-[10px] uppercase tracking-widest">Cancelar</button>}
              </div>
           </div>
        </div>
      )}

      {showPixModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-xl z-[400] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[4rem] w-full max-w-md shadow-2xl text-center">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">QR Code PIX</h3>
            <div className="bg-slate-50 p-8 rounded-[3rem] mb-8 inline-block"><img src={showPixModal.pixQrCode} alt="PIX QR" className="w-56 h-56 mx-auto" /></div>
            <p className="text-3xl font-black text-slate-900 mb-2">R$ {showPixModal.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            <button onClick={() => setShowPixModal(null)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs">Fechar</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES, MOCK_TRANSACTIONS, ALL_UFS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole, FiscalConfig, Product } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginData, setLoginData] = useState({ username: '', password: '' });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [productsList, setProductsList] = useState<Product[]>([]);
  const [fiscalConfig, setFiscalConfig] = useState<FiscalConfig>({
    cnpj: '', ie: '', razaoSocial: '', cscToken: '', cscId: '',
    ambiente: 'Homologação', serie: '1', ultimoNumero: 0, contingencia: false
  });
  const [insights, setInsights] = useState<string>('Analizando métricas em tempo real...');
  const [isSimulating, setIsSimulating] = useState(false);
  const [isSavingFiscal, setIsSavingFiscal] = useState(false);
  const [setupRequired, setSetupRequired] = useState<boolean>(false);
  const [showPixModal, setShowPixModal] = useState<Transaction | null>(null);
  const [showLoginModal, setShowLoginModal] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [isMounted, setIsMounted] = useState(false);

  // Advanced Simulator State
  const [showCardSimModal, setShowCardSimModal] = useState(false);
  const [simStep, setSimStep] = useState<'brand' | 'method' | 'installments' | 'processing'>('brand');
  const [simData, setSimData] = useState({ brand: '', method: PaymentMethod.CREDIT, installments: 1 });

  // Certificate Modal State
  const [showCertModal, setShowCertModal] = useState(false);
  const [isSavingCert, setIsSavingCert] = useState(false);
  const [editingCert, setEditingCert] = useState<Partial<DigitalCertificate> | null>(null);

  // Certification Center State
  const [isCertifying, setIsCertifying] = useState(false);
  const [certPhase, setCertPhase] = useState<number>(0); // 0: Idle, 1: XML, 2: Sign, 3: Transmission, 4: Done
  const [selectedCertForFiscal, setSelectedCertForFiscal] = useState<string>('');
  const [pendingTxToCertify, setPendingTxToCertify] = useState<string | null>(null);

  // User Management State
  const [showUserModal, setShowUserModal] = useState(false);
  const [isSavingUser, setIsSavingUser] = useState(false);
  const [editingUser, setEditingUser] = useState<Partial<User> & { password?: string } | null>(null);

  // Product Management State
  const [showProductModal, setShowProductModal] = useState(false);
  const [isSavingProduct, setIsSavingProduct] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Partial<Product> | null>(null);

  const safeFetch = async (url: string, options?: RequestInit) => {
    try {
      const response = await fetch(url, options);
      if (!response.ok) throw new Error(`Server returned ${response.status}`);
      const text = await response.text();
      try { return JSON.parse(text); } catch (e) { throw new Error("Invalid JSON response"); }
    } catch (e) {
      console.warn("API Fallback triggered:", e);
      const action = new URL(url, window.location.origin).searchParams.get('action');
      if (action === 'check_setup') return { setup_required: localStorage.getItem('nexus_users') === null };
      if (action === 'get_transactions') return MOCK_TRANSACTIONS;
      if (action === 'get_products') return productsList;
      if (action === 'get_certificates') return certificates;
      return { status: 'error', message: 'Offline Mode' };
    }
  };

  useEffect(() => {
    setIsMounted(true);
    const init = async () => {
      const data = await safeFetch(`${API_URL}?action=check_setup`);
      if (data && typeof data.setup_required !== 'undefined') setSetupRequired(data.setup_required);
      const saved = localStorage.getItem('nexus_user');
      if (saved) setCurrentUser(JSON.parse(saved));
    };
    init();
  }, []);

  const loadData = async () => {
    const [txData, certData, userData, fiscalData, prodData] = await Promise.all([
      safeFetch(`${API_URL}?action=get_transactions`),
      safeFetch(`${API_URL}?action=get_certificates`),
      safeFetch(`${API_URL}?action=get_users`),
      safeFetch(`${API_URL}?action=get_fiscal_config`),
      safeFetch(`${API_URL}?action=get_products`)
    ]);

    setTransactions(Array.isArray(txData) ? txData : MOCK_TRANSACTIONS);

    if (Array.isArray(certData)) {
      const mappedCerts = certData.map(c => ({
        ...c,
        expirationDate: c.expiration_date || c.expirationDate
      }));
      setCertificates(mappedCerts);
      if (mappedCerts.length > 0 && !selectedCertForFiscal) setSelectedCertForFiscal(mappedCerts[0].id);
    }

    if (Array.isArray(userData)) setUsersList(userData);
    if (fiscalData && !fiscalData.status) setFiscalConfig(fiscalData);
    if (Array.isArray(prodData)) setProductsList(prodData);
  };

  useEffect(() => { if (isMounted) loadData(); }, [currentUser, setupRequired, isMounted]);

  const handleSaveProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingProduct(true);
    const data = await safeFetch(`${API_URL}?action=save_product`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingProduct)
    });
    if (data.status === 'success') {
      setShowProductModal(false);
      setEditingProduct(null);
      loadData();
    }
    setIsSavingProduct(false);
  };

  const handleSaveCert = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingCert(true);
    const data = await safeFetch(`${API_URL}?action=save_certificate`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingCert)
    });
    if (data.status === 'success') {
      setShowCertModal(false);
      setEditingCert(null);
      loadData();
    }
    setIsSavingCert(false);
  };

  const handleCertify = async (txId: string) => {
    if (!selectedCertForFiscal) {
      alert('Selecione um certificado para prosseguir.');
      return;
    }
    setPendingTxToCertify(txId);
    setIsCertifying(true);

    // Simulate phases
    setCertPhase(1); // XML Generation
    await new Promise(r => setTimeout(r, 1200));
    setCertPhase(2); // Signing with selected certificate
    await new Promise(r => setTimeout(r, 1500));
    setCertPhase(3); // Transmission to SEFAZ
    await new Promise(r => setTimeout(r, 2000));

    const data = await safeFetch(`${API_URL}?action=certify_transaction`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ txId, certId: selectedCertForFiscal })
    });

    if (data.status === 'success') {
      setCertPhase(4); // Success
      await new Promise(r => setTimeout(r, 1500));
      loadData();
    } else {
      alert('Erro na certificação: ' + data.message);
    }

    setIsCertifying(false);
    setCertPhase(0);
    setPendingTxToCertify(null);
  };

  const stats = useMemo(() => {
    const success = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const totalVal = success.reduce((a, b) => a + Number(b.amount), 0);
    const pix = success.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    return {
      total: totalVal,
      pixPercent: ((pix / (totalVal || 1)) * 100).toFixed(1),
      txCount: transactions.length
    };
  }, [transactions]);

  const simulateTransaction = async (method: PaymentMethod, details?: { brand: string, installments: number }) => {
    setIsSimulating(true);
    const amount = Math.floor(Math.random() * 500) + 10.5;
    const mockTx: Transaction = {
      id: `TX-${Math.floor(Math.random() * 90000 + 10000)}`,
      timestamp: new Date().toISOString(),
      amount: amount,
      method: method,
      status: PaymentStatus.SUCCESS,
      terminalId: 'TERM-SIM',
      segment: 'Simulação',
      fiscalNoteId: '', // Empty to show in generator
      fiscalStatus: undefined, 
      cardBrand: details?.brand,
      installments: details?.installments,
      pixQrCode: method === PaymentMethod.PIX ? 'https://api.qrserver.com/v1/create-qr-code/?size=250x250&data=00020101021226870014BR.GOV.BCB.PIX0125' : undefined
    };
    await new Promise(r => setTimeout(r, 1500));
    setTransactions(prev => [mockTx, ...prev]);
    if (method === PaymentMethod.PIX) setShowPixModal(mockTx);
    setIsSimulating(false);
    setShowCardSimModal(false);
    setSimStep('brand');
    setActiveTab('dashboard');
  };

  // Fix: Added missing renderSimulator function
  const renderSimulator = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div>
        <h3 className="text-3xl font-black text-slate-900 tracking-tight">Simulador de Vendas</h3>
        <p className="text-slate-500 font-medium">Teste o fluxo de pagamento e integração fiscal em tempo real.</p>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <button 
          onClick={() => simulateTransaction(PaymentMethod.PIX)}
          disabled={isSimulating}
          className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm hover:shadow-xl transition-all group text-left"
        >
          <div className="w-16 h-16 bg-emerald-50 rounded-3xl flex items-center justify-center text-3xl mb-6 group-hover:scale-110 transition-transform">⚡</div>
          <h4 className="text-xl font-black text-slate-900 mb-2">Simular PIX</h4>
          <p className="text-sm text-slate-500 font-medium leading-relaxed">Gera um QR Code dinâmico e simula a confirmação instantânea do Banco Central via Webhook.</p>
        </button>
        <button 
          onClick={() => setShowCardSimModal(true)}
          disabled={isSimulating}
          className="bg-white p-10 rounded-[3rem] border border-slate-100 shadow-sm hover:shadow-xl transition-all group text-left"
        >
          <div className="w-16 h-16 bg-indigo-50 rounded-3xl flex items-center justify-center text-3xl mb-6 group-hover:scale-110 transition-transform">💳</div>
          <h4 className="text-xl font-black text-slate-900 mb-2">Simular Cartão</h4>
          <p className="text-sm text-slate-500 font-medium leading-relaxed">Simula a interação com o Pinpad (TEF), seleção de bandeira e processamento de parcelas autorizadas.</p>
        </button>
      </div>
    </div>
  );

  // Fix: Added missing renderProducts function
  const renderProducts = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
