              <th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {productsList.length === 0 ? (
              <tr><td colSpan={4} className="p-20 text-center text-slate-400 font-bold">Nenhum produto cadastrado</td></tr>
            ) : (
              productsList.map((product) => (
                <tr key={product.id} className="hover:bg-slate-50/40 transition-colors">
                  <td className="px-8 py-5">
                    <p className="text-sm font-black text-slate-900">{product.name}</p>
                    <p className="text-[10px] font-bold text-slate-400 uppercase">{product.category}</p>
                  </td>
                  <td className="px-8 py-5 font-black text-slate-900">R$ {product.price.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</td>
                  <td className="px-8 py-5"><span className={`px-2 py-1 rounded-lg text-[10px] font-black ${product.stock > 10 ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>{product.stock} un</span></td>
                  <td className="px-8 py-5 text-right"><button onClick={() => { setEditingProduct(product); setShowProductModal(true); }} className="text-indigo-600 font-black text-[10px] uppercase">Editar</button></td>
