                 {simStep !== 'processing' && <button onClick={() => setShowCardSimModal(false)} className="w-full mt-8 py-3 text-slate-400 font-black text-[10px] uppercase tracking-widest">Cancelar</button>}
              </div>
           </div>
        </div>
      )}

      {showPixModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-xl z-[400] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[4rem] w-full max-w-md shadow-2xl text-center">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">QR Code PIX</h3>
            <div className="bg-slate-50 p-8 rounded-[3rem] mb-8 inline-block"><img src={showPixModal.pixQrCode} alt="PIX QR" className="w-56 h-56 mx-auto" /></div>
            <p className="text-3xl font-black text-slate-900 mb-2">R$ {showPixModal.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            <button onClick={() => setShowPixModal(null)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs">Fechar</button>
          </div>
        </div>
      )}
    </div>
  );
};

