  const renderProducts = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-end">
        <h3 className="text-3xl font-black text-slate-900 tracking-tight">Produtos</h3>
        <button onClick={() => { setEditingProduct({ name: '', price: 0, stock: 0, category: 'Geral', sku: '' }); setShowProductModal(true); }} className="px-6 py-3 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg shadow-indigo-600/20">+ Novo Item</button>
      </div>
      <div className="bg-white rounded-[3rem] border border-slate-200 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead className="bg-slate-50/80 border-b border-slate-100">
            <tr><th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Produto</th><th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Preço</th><th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Estoque</th><th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th></tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {productsList.map((product) => (
              <tr key={product.id} className="hover:bg-slate-50/40 transition-colors">
                <td className="px-8 py-5 font-black text-slate-900">{product.name}</td>
                <td className="px-8 py-5 font-black text-slate-900">R$ {product.price.toLocaleString('pt-BR')}</td>
                <td className="px-8 py-5 font-black text-slate-900">{product.stock} un</td>
                <td className="px-8 py-5 text-right"><button onClick={() => { setEditingProduct(product); setShowProductModal(true); }} className="text-indigo-600 font-black text-[10px] uppercase">Editar</button></td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );

  const renderUsers = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-end">
        <h3 className="text-3xl font-black text-slate-900 tracking-tight">Usuários</h3>
        <button onClick={() => { setEditingUser({ name: '', username: '', role: UserRole.OPERATOR, password: '' }); setShowUserModal(true); }} className="px-6 py-3 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg shadow-indigo-600/20">+ Novo Usuário</button>
      </div>
      <div className="bg-white rounded-[3rem] border border-slate-200 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead className="bg-slate-50/80 border-b border-slate-100">
            <tr><th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nome / Username</th><th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nível de Acesso</th><th className="px-8 py-5 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th></tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {usersList.map((u) => (
              <tr key={u.id} className="hover:bg-slate-50/40 transition-colors">
                <td className="px-8 py-5 font-black text-slate-900">{u.name} <span className="text-slate-400 font-normal">(@{u.username})</span></td>
