          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nome Fantasia</label>
            <input type="text" required value={establishment.nomeFantasia} onChange={e => setEstablishment({...establishment, nomeFantasia: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all" />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase ml-1">CNPJ</label>
            <input type="text" required value={establishment.cnpj} onChange={e => setEstablishment({...establishment, cnpj: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all" placeholder="00.000.000/0000-00" />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Telefone</label>
            <input type="text" required value={establishment.telefone} onChange={e => setEstablishment({...establishment, telefone: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all" placeholder="(00) 00000-0000" />
          </div>
          <div className="md:col-span-2 space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Endereço Completo</label>
            <input type="text" required value={establishment.endereco} onChange={e => setEstablishment({...establishment, endereco: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none focus:ring-2 focus:ring-indigo-500 transition-all" />
          </div>
        </div>
        <button type="submit" disabled={isSavingEstablishment} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl">{isSavingEstablishment ? 'Salvando...' : 'Gravar Dados Cadastrais'}</button>
      </form>
    </div>
  );

  const renderFiscalGenerator = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-end">
        <h3 className="text-3xl font-black text-slate-900 tracking-tight">Gerador NFC-e</h3>
        <select value={selectedCertForFiscal} onChange={(e) => setSelectedCertForFiscal(e.target.value)} className="bg-white border border-slate-100 rounded-xl p-3 text-xs font-bold text-slate-700 shadow-sm">
          {certificates.map(c => <option key={c.id} value={c.id}>{c.alias} ({c.type})</option>)}
          {certificates.length === 0 && <option value="">Nenhum Certificado</option>}
        </select>
      </div>
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-1 space-y-6">
           <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
              <h4 className="text-xs font-black text-slate-400 uppercase tracking-widest mb-4">Configuração Fiscal</h4>
              <div className="space-y-3">
                <div className="flex justify-between text-xs font-bold"><span>CNPJ:</span><span className="text-slate-800">{fiscalConfig.cnpj}</span></div>
                <div className="flex justify-between text-xs font-bold"><span>Ambiente:</span><span className="text-amber-600">{fiscalConfig.ambiente}</span></div>
              </div>
              <button onClick={() => setActiveTab('fiscal_config')} className="w-full py-3 bg-slate-50 text-slate-500 rounded-xl font-bold text-[10px] uppercase mt-4">Alterar Configuração</button>
           </div>
           {isCertifying && <div className="bg-slate-900 p-8 rounded-[2.5rem] text-white animate-pulse">
              <h4 className="text-[10px] font-black uppercase mb-4 text-indigo-400">Transmissão em curso...</h4>
              <div className="space-y-2 text-[10px] font-bold">
                <p className={certPhase >= 1 ? 'text-emerald-400' : 'text-slate-600'}>- Geração XML NFC-e</p>
                <p className={certPhase >= 2 ? 'text-emerald-400' : 'text-slate-600'}>- Assinatura com Certificado Digital</p>
                <p className={certPhase >= 3 ? 'text-emerald-400' : 'text-slate-600'}>- Transmissão SEFAZ Autorizada</p>
              </div>
           </div>}
        </div>
        <div className="lg:col-span-2 bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
           <div className="divide-y divide-slate-50 max-h-[600px] overflow-auto">
              {transactions.filter(tx => !tx.fiscalNoteId).map(tx => (
                <div key={tx.id} className="p-6 flex items-center justify-between hover:bg-slate-50/50">
                  <div>
                    <p className="text-sm font-black text-slate-800">R$ {tx.amount.toLocaleString('pt-BR')}</p>
                    <p className="text-[10px] font-mono text-slate-400">{tx.id} • {tx.method}</p>
                  </div>
                  <button onClick={() => handleCertify(tx.id)} disabled={isCertifying} className="px-6 py-3 bg-indigo-50 text-indigo-600 rounded-xl font-black text-[10px] uppercase tracking-widest">Emitir NFC-e</button>
                </div>
              ))}
           </div>
        </div>
      </div>
    </div>
  );

  const renderFiscalConfig = () => (
    <div className="max-w-4xl mx-auto space-y-8 animate-in slide-in-from-right duration-500">
      <h3 className="text-3xl font-black text-slate-900 tracking-tight">Parâmetros NFC-e</h3>
      <form onSubmit={handleSaveFiscalConfig} className="bg-white p-12 rounded-[3.5rem] border border-slate-100 shadow-sm space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">CNPJ do Emissor</label><input type="text" required value={fiscalConfig.cnpj} onChange={e => setFiscalConfig({...fiscalConfig, cnpj: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none" /></div>
          <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">CSC Token</label><input type="text" required value={fiscalConfig.cscToken} onChange={e => setFiscalConfig({...fiscalConfig, cscToken: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none" /></div>
          <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">CSC ID</label><input type="text" required value={fiscalConfig.cscId} onChange={e => setFiscalConfig({...fiscalConfig, cscId: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none" /></div>
          <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Ambiente</label><select value={fiscalConfig.ambiente} onChange={e => setFiscalConfig({...fiscalConfig, ambiente: e.target.value as any})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none"><option value="Homologação">Homologação</option><option value="Produção">Produção</option></select></div>
          <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Série</label><input type="text" required value={fiscalConfig.serie} onChange={e => setFiscalConfig({...fiscalConfig, serie: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none" /></div>
          <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Última Nota</label><input type="number" required value={fiscalConfig.ultimoNumero} onChange={e => setFiscalConfig({...fiscalConfig, ultimoNumero: parseInt(e.target.value)})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none" /></div>
        </div>
        <button type="submit" disabled={isSavingFiscal} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl">Salvar Parâmetros</button>
      </form>
    </div>
  );

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} currentUser={currentUser} onLogout={() => { setCurrentUser(null); localStorage.removeItem('nexus_user'); }} />
      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-20 bg-white border-b border-slate-100 flex items-center justify-between px-10 sticky top-0 z-40">
          <div className="flex flex-col"><h2 className="text-xl font-black text-slate-900 leading-none">NexusTEF</h2><span className="text-[10px] font-bold text-indigo-500 uppercase tracking-widest mt-1">{activeTab}</span></div>
          {currentUser && <span className="text-xs font-bold text-slate-600">Usuário: {currentUser.name}</span>}
        </header>
        <main className="p-10 max-w-[1400px] w-full mx-auto">
          {activeTab === 'dashboard' && <div className="space-y-8"><div className="grid grid-cols-4 gap-6"><StatCard label="Volume" value={`R$ ${stats.total.toLocaleString('pt-BR')}`} icon="💰" color="bg-indigo-50" /><StatCard label="Pix" value={`${stats.pixPercent}%`} icon="⚡" color="bg-emerald-50" /><StatCard label="Produtos" value={productsList.length} icon="📦" color="bg-amber-50" /><StatCard label="Transações" value={stats.txCount} icon="🔄" color="bg-slate-50" /></div><FiscalMonitor states={SEFAZ_STATES} /></div>}
          {activeTab === 'simulator' && renderSimulator()}
          {activeTab === 'products' && renderProducts()}
          {activeTab === 'users' && renderUsers()}
          {activeTab === 'establishment' && renderEstablishment()}
          {activeTab === 'fiscal' && renderFiscalGenerator()}
          {activeTab === 'fiscal_config' && renderFiscalConfig()}
          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}
        </main>
      </div>

      {showUserModal && editingUser && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-10 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Configurar Usuário</h3>
            <form onSubmit={handleSaveUser} className="space-y-4">
              <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nome Completo</label><input type="text" required value={editingUser.name} onChange={e => setEditingUser({...editingUser, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" /></div>
              <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Username</label><input type="text" required value={editingUser.username} onChange={e => setEditingUser({...editingUser, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" /></div>
              <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Senha (vazio para manter)</label><input type="password" value={editingUser.password} onChange={e => setEditingUser({...editingUser, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" /></div>
              <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Acesso</label><select value={editingUser.role} onChange={e => setEditingUser({...editingUser, role: e.target.value as any})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none"><option value={UserRole.OPERATOR}>Operador</option><option value={UserRole.ADMIN}>Administrador</option><option value={UserRole.MASTER}>Master</option></select></div>
              <div className="flex gap-4 pt-4"><button type="button" onClick={() => setShowUserModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold uppercase text-xs">Cancelar</button><button type="submit" className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs">Gravar</button></div>
            </form>
          </div>
        </div>
      )}

      {showProductModal && editingProduct && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-10 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Produto</h3>
            <form onSubmit={handleSaveProduct} className="space-y-4">
              <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nome</label><input type="text" required value={editingProduct.name} onChange={e => setEditingProduct({...editingProduct, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" /></div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Preço</label><input type="number" step="0.01" required value={editingProduct.price} onChange={e => setEditingProduct({...editingProduct, price: parseFloat(e.target.value)})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" /></div>
                <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Estoque</label><input type="number" required value={editingProduct.stock} onChange={e => setEditingProduct({...editingProduct, stock: parseInt(e.target.value)})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" /></div>
              </div>
              <div className="flex gap-4 pt-4"><button type="button" onClick={() => setShowProductModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold uppercase text-xs">Cancelar</button><button type="submit" className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs">Gravar</button></div>
            </form>
          </div>
        </div>
      )}

      {showPixModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-xl z-[400] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[4rem] w-full max-w-md shadow-2xl text-center">
            <h3 className="text-2xl font-black text-slate-900 mb-8">Pagamento PIX</h3>
            <div className="bg-slate-50 p-8 rounded-[3rem] mb-8 inline-block"><img src={showPixModal.pixQrCode} alt="PIX QR" className="w-48 h-48 mx-auto" /></div>
            <p className="text-2xl font-black text-slate-900 mb-6">R$ {showPixModal.amount.toLocaleString('pt-BR')}</p>
            <button onClick={() => setShowPixModal(null)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs">Fechar</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES, MOCK_TRANSACTIONS, ALL_UFS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole, FiscalConfig, Product, Establishment } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [loginData, setLoginData] = useState({ username: '', password: '' });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [productsList, setProductsList] = useState<Product[]>([]);
  const [fiscalConfig, setFiscalConfig] = useState<FiscalConfig>({
    cnpj: '', ie: '', razaoSocial: '', cscToken: '', cscId: '',
    ambiente: 'Homologação', serie: '1', ultimoNumero: 0, contingencia: false
  });
  const [establishment, setEstablishment] = useState<Establishment>({
    razaoSocial: '', nomeFantasia: '', cnpj: '', endereco: '', telefone: '', email: ''
  });

  const [isSimulating, setIsSimulating] = useState(false);
  const [isSavingFiscal, setIsSavingFiscal] = useState(false);
  const [isSavingEstablishment, setIsSavingEstablishment] = useState(false);
  const [setupRequired, setSetupRequired] = useState<boolean>(false);
  const [showPixModal, setShowPixModal] = useState<Transaction | null>(null);
  const [showNoteModal, setShowNoteModal] = useState<Transaction | null>(null);
  const [isMounted, setIsMounted] = useState(false);

  // Advanced Simulator State
  const [showCardSimModal, setShowCardSimModal] = useState(false);
  const [simStep, setSimStep] = useState<'brand' | 'method' | 'installments' | 'processing'>('brand');
  const [simData, setSimData] = useState({ brand: '', method: PaymentMethod.CREDIT, installments: 1 });

  // Certificate Modal State
  const [showCertModal, setShowCertModal] = useState(false);
  const [isSavingCert, setIsSavingCert] = useState(false);
  const [editingCert, setEditingCert] = useState<Partial<DigitalCertificate> | null>(null);

  // Certification Center State
  const [isCertifying, setIsCertifying] = useState(false);
  const [certPhase, setCertPhase] = useState<number>(0); 
  const [selectedCertForFiscal, setSelectedCertForFiscal] = useState<string>('');
  const [pendingTxToCertify, setPendingTxToCertify] = useState<string | null>(null);

  // User Management State
  const [showUserModal, setShowUserModal] = useState(false);
  const [isSavingUser, setIsSavingUser] = useState(false);
  const [editingUser, setEditingUser] = useState<Partial<User> & { password?: string } | null>(null);

  // Product Management State
  const [showProductModal, setShowProductModal] = useState(false);
  const [isSavingProduct, setIsSavingProduct] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Partial<Product> | null>(null);

  const safeFetch = async (url: string, options?: RequestInit) => {
    try {
      const response = await fetch(url, options);
      if (!response.ok) throw new Error(`Server returned ${response.status}`);
      const text = await response.text();
      try { return JSON.parse(text); } catch (e) { throw new Error("Invalid JSON response"); }
    } catch (e) {
      console.warn("API Fallback triggered:", e);
      return { status: 'error', message: 'Offline Mode' };
    }
  };

  useEffect(() => {
    setIsMounted(true);
    const init = async () => {
      const data = await safeFetch(`${API_URL}?action=check_setup`);
      if (data && typeof data.setup_required !== 'undefined') setSetupRequired(data.setup_required);
      const saved = localStorage.getItem('nexus_user');
      if (saved) setCurrentUser(JSON.parse(saved));
    };
    init();
  }, []);

  const loadData = async () => {
    const [txData, certData, userData, fiscalData, prodData, estData] = await Promise.all([
      safeFetch(`${API_URL}?action=get_transactions`),
      safeFetch(`${API_URL}?action=get_certificates`),
      safeFetch(`${API_URL}?action=get_users`),
      safeFetch(`${API_URL}?action=get_fiscal_config`),
      safeFetch(`${API_URL}?action=get_products`),
      safeFetch(`${API_URL}?action=get_establishment`)
    ]);

    if (Array.isArray(txData)) setTransactions(txData);
    if (Array.isArray(certData)) setCertificates(certData);
    if (Array.isArray(userData)) setUsersList(userData);
    if (fiscalData && !fiscalData.status) setFiscalConfig(fiscalData);
    if (Array.isArray(prodData)) setProductsList(prodData);
    if (estData && !estData.status) setEstablishment(estData);
  };

  useEffect(() => { if (isMounted) loadData(); }, [currentUser, setupRequired, isMounted]);

  const handleSaveProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingProduct(true);
    const data = await safeFetch(`${API_URL}?action=save_product`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingProduct)
    });
    if (data.status === 'success') {
      setShowProductModal(false);
      setEditingProduct(null);
      loadData();
    }
    setIsSavingProduct(false);
  };

  const handleSaveCert = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingCert(true);
    const data = await safeFetch(`${API_URL}?action=save_certificate`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingCert)
    });
    if (data.status === 'success') {
      setShowCertModal(false);
      setEditingCert(null);
      loadData();
    }
    setIsSavingCert(false);
  };

  const handleSaveUser = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingUser(true);
    const data = await safeFetch(`${API_URL}?action=save_user`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingUser)
    });
    if (data.status === 'success') {
      setShowUserModal(false);
      setEditingUser(null);
      loadData();
    }
    setIsSavingUser(false);
  };

  const handleDeleteUser = async (id: number) => {
    if (!confirm('Excluir este usuário?')) return;
    const data = await safeFetch(`${API_URL}?action=delete_user&id=${id}`);
    if (data.status === 'success') loadData();
  };

  const handleSaveFiscalConfig = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingFiscal(true);
    const data = await safeFetch(`${API_URL}?action=save_fiscal_config`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(fiscalConfig)
    });
    if (data.status === 'success') {
      alert('Configuração fiscal salva!');
      setActiveTab('fiscal');
    }
    setIsSavingFiscal(false);
  };

  const handleSaveEstablishment = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingEstablishment(true);
    const data = await safeFetch(`${API_URL}?action=save_establishment`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(establishment)
    });
    if (data.status === 'success') {
      alert('Dados do estabelecimento salvos!');
      // Atualiza também o CNPJ da config fiscal para facilitar
      setFiscalConfig(prev => ({ ...prev, cnpj: establishment.cnpj, razaoSocial: establishment.razaoSocial }));
    }
    setIsSavingEstablishment(false);
  };

  const handleCertify = async (txId: string) => {
    if (!selectedCertForFiscal && certificates.length > 0) {
      setSelectedCertForFiscal(certificates[0].id);
    }
    if (certificates.length === 0) {
      alert('Cadastre um certificado antes de emitir notas.');
      return;
    }

    setPendingTxToCertify(txId);
    setIsCertifying(true);
    setCertPhase(1);
    await new Promise(r => setTimeout(r, 800));
    setCertPhase(2);
    await new Promise(r => setTimeout(r, 800));
    setCertPhase(3);
    await new Promise(r => setTimeout(r, 800));

    const data = await safeFetch(`${API_URL}?action=certify_transaction`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ txId })
    });

    if (data.status === 'success') {
      setCertPhase(4);
      await new Promise(r => setTimeout(r, 800));
      loadData();
    }
    setIsCertifying(false);
