      method: method,
      status: PaymentStatus.SUCCESS,
      terminalId: 'TERM-SIM',
      segment: establishment.nomeFantasia || 'Venda Nexus',
      fiscalNoteId: '',
      pixQrCode: method === PaymentMethod.PIX ? 'https://api.qrserver.com/v1/create-qr-code/?size=250x250&data=00020101021226870014BR.GOV.BCB.PIX0125' : undefined
    };
    await new Promise(r => setTimeout(r, 1500));
    setTransactions(prev => [mockTx, ...prev]);
    if (method === PaymentMethod.PIX) setShowPixModal(mockTx);
    setIsSimulating(false);
    setShowCardSimModal(false);
