              <FiscalMonitor states={SEFAZ_STATES} />
            </div>
          )}
          {activeTab === 'simulator' && renderSimulator()}
          {activeTab === 'products' && renderProducts()}
          {activeTab === 'users' && renderUsers()}
          {activeTab === 'establishment' && renderEstablishment()}
          {activeTab === 'fiscal' && renderFiscalGenerator()}
          {activeTab === 'fiscal_config' && renderFiscalConfig()}
          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}
        </main>
      </div>

      {/* Note Modal (DANFE) */}
      {showNoteModal && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-md z-[500] flex items-center justify-center p-6 animate-in fade-in duration-300">
           <div className="bg-white w-full max-w-sm rounded-3xl shadow-2xl overflow-hidden animate-in zoom-in duration-300">
              <div className="bg-slate-50 p-6 border-b border-slate-100 flex justify-between items-center">
                 <h4 className="font-black text-slate-800 uppercase text-[10px] tracking-widest">Visualização NFC-e</h4>
                 <button onClick={() => setShowNoteModal(null)} className="text-slate-400 hover:text-slate-900 font-bold">FECHAR</button>
              </div>
              <div className="p-8 space-y-6 font-mono text-[10px] text-slate-700 bg-[#fff] max-h-[70vh] overflow-y-auto receipt">
                 <div className="text-center border-b border-dashed border-slate-200 pb-4 space-y-1">
                    <p className="font-black text-sm uppercase">{establishment.nomeFantasia || 'NEXUS ESTABLISHMENT'}</p>
                    <p>{establishment.razaoSocial}</p>
                    <p>CNPJ: {establishment.cnpj || '00.000.000/0000-00'}</p>
                    <p>{establishment.endereco || 'Endereço não cadastrado'}</p>
                    <p>TEL: {establishment.telefone || '(00) 0000-0000'}</p>
                 </div>
                 <div className="space-y-1">
                    <p className="font-bold text-center mb-2">DANFE NFC-e - Documento Auxiliar</p>
                    <div className="flex justify-between font-black border-b border-slate-100 pb-1 mb-2">
                       <span>DESCRIÇÃO</span>
                       <span>VALOR</span>
                    </div>
                    <div className="flex justify-between">
                       <span>VENDA NEXUSTEF {showNoteModal.id}</span>
                       <span>{Number(showNoteModal.amount).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                    </div>
                 </div>
                 <div className="border-t border-dashed border-slate-200 pt-4 space-y-1">
                    <div className="flex justify-between font-black text-sm">
                       <span>TOTAL R$</span>
                       <span>{Number(showNoteModal.amount).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</span>
                    </div>
                    <p>FORMA PAGTO: {showNoteModal.method}</p>
                 </div>
                 <div className="text-center space-y-2 pt-6">
                    <p className="font-bold">NÚMERO: {showNoteModal.fiscalNoteId} SÉRIE: {fiscalConfig.serie}</p>
                    <p>EMISSÃO: {new Date(showNoteModal.timestamp).toLocaleString()}</p>
                    <p className="text-[8px] break-all px-4">CHAVE DE ACESSO:<br/>3524 0100 0000 0000 0000 0000 0000 0000 0000 0000 0000</p>
                    <div className="flex justify-center py-4">
                       <img src={`https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=CHAVE35240100000000000000000000000000000000000000000`} className="w-32 h-32 grayscale" alt="SEFAZ QR" />
                    </div>
                    <p className="font-black uppercase">Consulte via QR Code ou Chave de Acesso</p>
                 </div>
              </div>
              <div className="p-6 bg-slate-50 border-t border-slate-100">
                 <button onClick={() => window.print()} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl">Imprimir Cupom</button>
              </div>
           </div>
        </div>
      )}

      {/* User Modal */}
      {showUserModal && editingUser && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-10 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Configurar Usuário</h3>
            <form onSubmit={handleSaveUser} className="space-y-4">
              <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nome Completo</label><input type="text" required value={editingUser.name} onChange={e => setEditingUser({...editingUser, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" /></div>
              <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Username</label><input type="text" required value={editingUser.username} onChange={e => setEditingUser({...editingUser, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" /></div>
              <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Senha (Vazio para manter)</label><input type="password" value={editingUser.password} onChange={e => setEditingUser({...editingUser, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" /></div>
              <div className="space-y-1">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nível de Acesso</label>
                <select value={editingUser.role} onChange={e => setEditingUser({...editingUser, role: e.target.value as any})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium outline-none">
                  <option value={UserRole.OPERATOR}>Operador (Padrão)</option>
                  <option value={UserRole.ADMIN}>Administrador (Fiscal)</option>
                  <option value={UserRole.MASTER}>Master (Total)</option>
                </select>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowUserModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold uppercase text-xs">Cancelar</button>
                <button type="submit" disabled={isSavingUser} className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs">
                  {isSavingUser ? 'Gravando...' : 'Gravar'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Product Modal */}
      {showProductModal && editingProduct && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6">
          <div className="bg-white p-10 rounded-[3.5rem] w-full max-w-md shadow-2xl animate-in zoom-in duration-300">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Dados do Produto</h3>
            <form onSubmit={handleSaveProduct} className="space-y-4">
              <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nome</label><input type="text" required value={editingProduct.name} onChange={e => setEditingProduct({...editingProduct, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" /></div>
              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Preço (R$)</label><input type="number" step="0.01" required value={editingProduct.price} onChange={e => setEditingProduct({...editingProduct, price: parseFloat(e.target.value)})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" /></div>
                <div className="space-y-1"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Estoque Inicial</label><input type="number" required value={editingProduct.stock} onChange={e => setEditingProduct({...editingProduct, stock: parseInt(e.target.value)})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-4 text-sm font-medium" /></div>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowProductModal(false)} className="flex-1 py-4 bg-slate-100 text-slate-500 rounded-2xl font-bold uppercase text-xs">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs">Salvar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Simulator Modal */}
      {showCardSimModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-xl z-[400] flex items-center justify-center p-6">
           <div className="bg-white w-full max-w-sm rounded-[3rem] shadow-2xl overflow-hidden animate-in zoom-in duration-300">
              <div className="bg-slate-900 p-8 text-center text-white">
                <h4 className="font-black text-xs uppercase tracking-[0.2em] text-indigo-400">Pinpad Virtual Nexus</h4>
              </div>
              <div className="p-10">
                 {simStep === 'brand' && (
                    <div className="space-y-4">
                       <p className="text-center font-black text-slate-400 uppercase text-[10px] mb-6">Selecione a Bandeira</p>
                       <div className="grid grid-cols-2 gap-4">
                          {['Visa', 'Mastercard', 'Elo', 'Amex'].map(brand => (
                             <button key={brand} onClick={() => { setSimData({...simData, brand}); setSimStep('method'); }} className="p-6 bg-slate-50 border border-slate-100 rounded-3xl font-black text-slate-800 uppercase text-[10px] hover:bg-indigo-50 transition-all">{brand}</button>
                          ))}
                       </div>
                    </div>
                 )}
                 {simStep === 'method' && (
                    <div className="space-y-4 text-center">
                       <p className="font-black text-slate-400 uppercase text-[10px] mb-6">Método para {simData.brand}</p>
                       <button onClick={() => simulateTransaction(PaymentMethod.DEBIT, { brand: simData.brand, installments: 1 })} className="w-full p-6 bg-indigo-600 text-white rounded-3xl font-black uppercase text-xs shadow-xl">Débito à Vista</button>
                       <button onClick={() => setSimStep('installments')} className="w-full p-6 bg-slate-900 text-white rounded-3xl font-black uppercase text-xs shadow-xl">Crédito</button>
                    </div>
                 )}
                 {simStep === 'installments' && (
                    <div className="space-y-4">
                       <p className="text-center font-black text-slate-400 uppercase text-[10px] mb-6">Parcelamento (Crédito {simData.brand})</p>
                       <div className="grid grid-cols-3 gap-3">
                          {[1, 2, 3, 4, 5, 6, 10, 12].map(n => (
                             <button key={n} onClick={() => simulateTransaction(PaymentMethod.CREDIT, { brand: simData.brand, installments: n })} className="p-4 bg-slate-50 border border-slate-100 rounded-2xl font-black text-slate-700 hover:bg-indigo-600 hover:text-white transition-all">{n}x</button>
                          ))}
                       </div>
                    </div>
                 )}
                 <button onClick={() => {setShowCardSimModal(false); setSimStep('brand');}} className="w-full mt-8 py-3 text-slate-400 font-black text-[10px] uppercase tracking-widest hover:text-rose-500 transition-colors">Cancelar Operação</button>
              </div>
           </div>
        </div>
      )}

      {/* Pix Modal */}
      {showPixModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-xl z-[400] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[4rem] w-full max-w-md shadow-2xl text-center animate-in zoom-in duration-300">
            <h3 className="text-2xl font-black text-slate-900 mb-2">Pagamento Dinâmico PIX</h3>
            <p className="text-slate-400 text-xs font-bold uppercase tracking-widest mb-8">Aguardando confirmação do Bacen...</p>
            <div className="bg-slate-50 p-8 rounded-[3rem] mb-8 inline-block shadow-inner">
               <img src={showPixModal.pixQrCode} alt="PIX QR" className="w-48 h-48 mx-auto" />
            </div>
            <p className="text-3xl font-black text-slate-900 mb-8">R$ {Number(showPixModal.amount).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            <button onClick={() => setShowPixModal(null)} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-rose-600 transition-all">Cancelar Pagamento</button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES, MOCK_TRANSACTIONS, ALL_UFS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole, FiscalConfig, Product, Establishment } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [productsList, setProductsList] = useState<Product[]>([]);
  const [fiscalConfig, setFiscalConfig] = useState<FiscalConfig>({
    cnpj: '', ie: '', razaoSocial: '', cscToken: '', cscId: '',
    ambiente: 'Homologação', serie: '1', ultimoNumero: 0, contingencia: false
  });
  const [establishment, setEstablishment] = useState<Establishment>({
    razaoSocial: '', nomeFantasia: '', cnpj: '', endereco: '', telefone: '', email: ''
  });

  const [isSimulating, setIsSimulating] = useState(false);
  const [isSavingFiscal, setIsSavingFiscal] = useState(false);
  const [isSavingEstablishment, setIsSavingEstablishment] = useState(false);
  const [setupRequired, setSetupRequired] = useState<boolean>(false);
  const [showPixModal, setShowPixModal] = useState<Transaction | null>(null);
  const [showNoteModal, setShowNoteModal] = useState<Transaction | null>(null);
  const [showSuccessModal, setShowSuccessModal] = useState<Transaction | null>(null);
  const [isMounted, setIsMounted] = useState(false);

  // Advanced Simulator State
  const [showCardSimModal, setShowCardSimModal] = useState(false);
  const [simStep, setSimStep] = useState<'brand' | 'method' | 'installments' | 'processing'>('brand');
  const [simData, setSimData] = useState({ brand: '', method: PaymentMethod.CREDIT, installments: 1 });

  // Certificate Modal State
  const [showCertModal, setShowCertModal] = useState(false);
  const [isSavingCert, setIsSavingCert] = useState(false);
  const [editingCert, setEditingCert] = useState<Partial<DigitalCertificate> | null>(null);

  // Certification Center State
  const [isCertifying, setIsCertifying] = useState(false);
  const [certPhase, setCertPhase] = useState<number>(0); 
  const [selectedCertForFiscal, setSelectedCertForFiscal] = useState<string>('');
  const [pendingTxToCertify, setPendingTxToCertify] = useState<string | null>(null);

  // User Management State
  const [showUserModal, setShowUserModal] = useState(false);
  const [isSavingUser, setIsSavingUser] = useState(false);
  const [editingUser, setEditingUser] = useState<Partial<User> & { password?: string } | null>(null);

  // Product Management State
  const [showProductModal, setShowProductModal] = useState(false);
  const [isSavingProduct, setIsSavingProduct] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Partial<Product> | null>(null);

  const safeFetch = async (url: string, options?: RequestInit) => {
    try {
      const response = await fetch(url, options);
      if (!response.ok) throw new Error(`Server returned ${response.status}`);
      const text = await response.text();
      try { return JSON.parse(text); } catch (e) { throw new Error("Invalid JSON response"); }
    } catch (e) {
      console.warn("API Fallback triggered:", e);
      return { status: 'error', message: 'Offline Mode' };
    }
  };

  useEffect(() => {
    setIsMounted(true);
    const init = async () => {
      const data = await safeFetch(`${API_URL}?action=check_setup`);
      if (data && typeof data.setup_required !== 'undefined') setSetupRequired(data.setup_required);
      const saved = localStorage.getItem('nexus_user');
      if (saved) setCurrentUser(JSON.parse(saved));
    };
    init();
  }, []);

  const loadData = async () => {
    const [txData, certData, userData, fiscalData, prodData, estData] = await Promise.all([
      safeFetch(`${API_URL}?action=get_transactions`),
      safeFetch(`${API_URL}?action=get_certificates`),
      safeFetch(`${API_URL}?action=get_users`),
      safeFetch(`${API_URL}?action=get_fiscal_config`),
      safeFetch(`${API_URL}?action=get_products`),
      safeFetch(`${API_URL}?action=get_establishment`)
    ]);

    if (Array.isArray(txData)) setTransactions(txData);
    if (Array.isArray(certData)) setCertificates(certData);
    if (Array.isArray(userData)) setUsersList(userData);
    if (fiscalData && !fiscalData.status) setFiscalConfig(fiscalData);
    if (Array.isArray(prodData)) setProductsList(prodData);
    if (estData && !estData.status) setEstablishment(estData);
  };

  useEffect(() => { if (isMounted) loadData(); }, [currentUser, setupRequired, isMounted]);

  const handleSaveProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingProduct(true);
    const data = await safeFetch(`${API_URL}?action=save_product`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingProduct)
    });
    if (data.status === 'success') {
      setShowProductModal(false);
      setEditingProduct(null);
      loadData();
    }
    setIsSavingProduct(false);
  };

  const handleSaveCert = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingCert(true);
    const data = await safeFetch(`${API_URL}?action=save_certificate`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingCert)
    });
    if (data.status === 'success') {
      setShowCertModal(false);
      setEditingCert(null);
      loadData();
    }
    setIsSavingCert(false);
  };

  const handleSaveUser = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingUser(true);
    const data = await safeFetch(`${API_URL}?action=save_user`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingUser)
    });
    if (data.status === 'success') {
      setShowUserModal(false);
      setEditingUser(null);
      loadData();
    }
    setIsSavingUser(false);
  };

  const handleDeleteUser = async (id: number) => {
    if (!confirm('Excluir este usuário?')) return;
    const data = await safeFetch(`${API_URL}?action=delete_user&id=${id}`);
    if (data.status === 'success') loadData();
  };

  const handleSaveFiscalConfig = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingFiscal(true);
    const data = await safeFetch(`${API_URL}?action=save_fiscal_config`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(fiscalConfig)
    });
    if (data.status === 'success') {
      alert('Configuração fiscal salva!');
      setActiveTab('fiscal');
    }
    setIsSavingFiscal(false);
  };

  const handleSaveEstablishment = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingEstablishment(true);
    const data = await safeFetch(`${API_URL}?action=save_establishment`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(establishment)
    });
    if (data.status === 'success') {
      alert('Dados do estabelecimento salvos!');
      setFiscalConfig(prev => ({ ...prev, cnpj: establishment.cnpj, razaoSocial: establishment.razaoSocial }));
    }
    setIsSavingEstablishment(false);
  };

  const handleCertify = async (txId: string) => {
    if (!selectedCertForFiscal && certificates.length > 0) {
      setSelectedCertForFiscal(certificates[0].id);
    }
    if (certificates.length === 0) {
      alert('Configure um certificado digital para o estado do estabelecimento antes de emitir notas.');
      return;
    }

    setPendingTxToCertify(txId);
    setIsCertifying(true);
    setCertPhase(1); // Geração XML
    await new Promise(r => setTimeout(r, 600));
    setCertPhase(2); // Assinatura Digital
    await new Promise(r => setTimeout(r, 600));
    setCertPhase(3); // Transmissão SEFAZ
    await new Promise(r => setTimeout(r, 600));

    const data = await safeFetch(`${API_URL}?action=certify_transaction`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ txId })
    });

    if (data.status === 'success') {
      setCertPhase(4); // Autorizada
      await new Promise(r => setTimeout(r, 600));
      loadData();
    }
    setIsCertifying(false);
    setCertPhase(0);
    setPendingTxToCertify(null);
  };

  const simulateTransaction = async (method: PaymentMethod, details?: { brand: string, installments: number }) => {
    setIsSimulating(true);
    const amount = Math.floor(Math.random() * 500) + 10.5;
    const txId = `TX-${Math.floor(Math.random() * 90000 + 10000)}`;

    if (method === PaymentMethod.PIX) {
      const pixTx: Transaction = {
        id: txId,
        timestamp: new Date().toISOString(),
        amount: amount,
        method: PaymentMethod.PIX,
        status: PaymentStatus.PENDING,
        terminalId: 'TERM-PIX',
        segment: establishment.nomeFantasia || 'Venda Nexus',
        pixQrCode: `https://api.qrserver.com/v1/create-qr-code/?size=250x250&data=00020101021226870014BR.GOV.BCB.PIX0125-${txId}`
      };
      setShowPixModal(pixTx);
      setIsSimulating(false);
      // Simulação de confirmação automática após 5 segundos
      setTimeout(() => {
        setTransactions(prev => [{...pixTx, status: PaymentStatus.SUCCESS}, ...prev]);
        setShowPixModal(null);
        setShowSuccessModal({...pixTx, status: PaymentStatus.SUCCESS});
      }, 5000);
    } else {
      await new Promise(r => setTimeout(r, 2000));
      const cardTx: Transaction = {
        id: txId,
        timestamp: new Date().toISOString(),
        amount: amount,
        method: method,
        status: PaymentStatus.SUCCESS,
        terminalId: 'TERM-CARD',
        segment: establishment.nomeFantasia || 'Venda Nexus',
        cardBrand: details?.brand,
        installments: details?.installments
      };
      setTransactions(prev => [cardTx, ...prev]);
      setIsSimulating(false);
      setShowCardSimModal(false);
      setShowSuccessModal(cardTx);
    }
  };

  const stats = useMemo(() => {
    const success = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const totalVal = success.reduce((a, b) => a + Number(b.amount), 0);
    const pix = success.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    return {
      total: totalVal,
      pixPercent: ((pix / (totalVal || 1)) * 100).toFixed(1),
      txCount: transactions.length
    };
  }, [transactions]);

  const renderSimulator = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Venda Balcão (TEF)</h3>
          <p className="text-slate-500 font-medium">Inicie uma venda rápida integrada ao PIX e Cartões de todas as bandeiras.</p>
        </div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
