              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Expiração</label><input type="date" required value={editingCert.expirationDate} onChange={e => setEditingCert({...editingCert, expirationDate: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" /></div>
              <div className="flex gap-4 pt-6"><button type="button" onClick={() => setShowCertModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs">Cancelar</button><button type="submit" disabled={isSavingCert} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl">Sincronizar Chave</button></div>
            </form>
          </div>
        </div>
      )}

      {/* USER MODAL */}
      {showUserModal && editingUser && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6 animate-in zoom-in duration-300">
          <div className="bg-white p-12 rounded-[3.5rem] w-full max-w-md shadow-2xl">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Dados de Acesso</h3>
            <form onSubmit={handleSaveUser} className="space-y-6">
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nome Completo</label><input type="text" required value={editingUser.name} onChange={e => setEditingUser({...editingUser, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" /></div>
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Login</label><input type="text" required value={editingUser.username} onChange={e => setEditingUser({...editingUser, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" /></div>
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Acesso</label><select value={editingUser.role} onChange={e => setEditingUser({...editingUser, role: e.target.value as any})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none"><option value={UserRole.OPERATOR}>Operador</option><option value={UserRole.ADMIN}>Administrador</option><option value={UserRole.MASTER}>Master</option></select></div>
              <div className="flex gap-4 pt-4"><button type="button" onClick={() => setShowUserModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs">Cancelar</button><button type="submit" className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs">Gravar</button></div>
            </form>
          </div>
        </div>
      )}

      {/* CARD SIMULATOR */}
      {showCardSimModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-2xl z-[700] flex items-center justify-center p-6 animate-in zoom-in duration-300">
           <div className="bg-white w-full max-w-sm rounded-[4rem] shadow-2xl overflow-hidden">
              <div className="bg-slate-900 p-8 text-center text-white">
                <h4 className="font-black text-xs uppercase tracking-[0.3em] text-indigo-400">Pinpad Nexus V6</h4>
              </div>
              <div className="p-12">
                 {simStep === 'brand' && (
                    <div className="space-y-6">
                       <p className="text-center font-black text-slate-400 uppercase text-[10px] tracking-widest mb-4">Insira ou Aproximar Cartão</p>
                       <div className="grid grid-cols-2 gap-4">
                          {['Visa', 'Mastercard', 'Elo', 'Amex'].map(brand => (
                             <button key={brand} onClick={() => { setSimData({...simData, brand}); setSimStep('method'); }} className="p-8 bg-slate-50 border border-slate-100 rounded-3xl font-black text-slate-800 uppercase text-[10px] hover:bg-indigo-600 hover:text-white transition-all shadow-sm">{brand}</button>
                          ))}
                       </div>
                    </div>
                 )}
                 {simStep === 'method' && (
                    <div className="space-y-6 text-center">
                       <p className="font-black text-slate-400 uppercase text-[10px] mb-8">Cartão {simData.brand} Detectado</p>
                       <button onClick={() => simulateTransaction(PaymentMethod.DEBIT, { brand: simData.brand, installments: 1 })} className="w-full p-8 bg-indigo-600 text-white rounded-[2rem] font-black uppercase text-xs shadow-xl hover:bg-slate-900 transition-all">Débito</button>
                       <button onClick={() => setSimStep('installments')} className="w-full p-8 bg-slate-50 text-slate-900 rounded-[2rem] font-black uppercase text-xs shadow-sm hover:bg-slate-100 transition-all">Crédito</button>
                    </div>
                 )}
                 {simStep === 'installments' && (
                    <div className="space-y-6">
                       <p className="text-center font-black text-slate-400 uppercase text-[10px] mb-8">Parcelamento {simData.brand}</p>
                       <div className="grid grid-cols-3 gap-3">
                          {[1, 2, 3, 4, 6, 12].map(n => (
                             <button key={n} onClick={() => simulateTransaction(PaymentMethod.CREDIT, { brand: simData.brand, installments: n })} className="p-5 bg-slate-50 border border-slate-100 rounded-2xl font-black text-slate-700 hover:bg-indigo-600 hover:text-white transition-all">{n}x</button>
                          ))}
                       </div>
                    </div>
                 )}
                 <button onClick={() => {setShowCardSimModal(false); setSimStep('brand');}} className="w-full mt-12 py-3 text-slate-400 font-black text-[10px] uppercase tracking-widest hover:text-rose-500 transition-colors">Abortar</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES, MOCK_TRANSACTIONS, ALL_UFS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole, FiscalConfig, Product, Establishment } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [productsList, setProductsList] = useState<Product[]>([]);
  const [fiscalConfig, setFiscalConfig] = useState<FiscalConfig>({
    cnpj: '', ie: '', razaoSocial: '', cscToken: '', cscId: '',
    ambiente: 'Homologação', serie: '1', ultimoNumero: 0, contingencia: false
  });
  const [establishment, setEstablishment] = useState<Establishment>({
    razaoSocial: '', nomeFantasia: '', cnpj: '', endereco: '', telefone: '', email: ''
  });

  const [isSimulating, setIsSimulating] = useState(false);
  const [isSavingFiscal, setIsSavingFiscal] = useState(false);
  const [isSavingEstablishment, setIsSavingEstablishment] = useState(false);
  const [setupRequired, setSetupRequired] = useState<boolean>(false);
  const [showPixModal, setShowPixModal] = useState<Transaction | null>(null);
  const [showNoteModal, setShowNoteModal] = useState<Transaction | null>(null);
  const [showSuccessModal, setShowSuccessModal] = useState<Transaction | null>(null);
  const [isMounted, setIsMounted] = useState(false);

  // Advanced Simulator State
  const [showCardSimModal, setShowCardSimModal] = useState(false);
  const [simStep, setSimStep] = useState<'brand' | 'method' | 'installments' | 'processing'>('brand');
  const [simData, setSimData] = useState({ brand: '', method: PaymentMethod.CREDIT, installments: 1 });

  // Certificate Modal State
  const [showCertModal, setShowCertModal] = useState(false);
  const [isSavingCert, setIsSavingCert] = useState(false);
  const [editingCert, setEditingCert] = useState<Partial<DigitalCertificate> | null>(null);

  // Certification Center State
  const [isCertifying, setIsCertifying] = useState(false);
  const [certPhase, setCertPhase] = useState<number>(0); 
  const [selectedCertForFiscal, setSelectedCertForFiscal] = useState<string>('');
  const [pendingTxToCertify, setPendingTxToCertify] = useState<string | null>(null);

  // User Management State
  const [showUserModal, setShowUserModal] = useState(false);
  const [isSavingUser, setIsSavingUser] = useState(false);
  const [editingUser, setEditingUser] = useState<Partial<User> & { password?: string } | null>(null);

  // Product Management State
  const [showProductModal, setShowProductModal] = useState(false);
  const [isSavingProduct, setIsSavingProduct] = useState(false);
  const [editingProduct, setEditingProduct] = useState<Partial<Product> | null>(null);

  const safeFetch = async (url: string, options?: RequestInit) => {
    try {
      const response = await fetch(url, options);
      if (!response.ok) throw new Error(`Server returned ${response.status}`);
      const text = await response.text();
      try { return JSON.parse(text); } catch (e) { throw new Error("Invalid JSON response"); }
    } catch (e) {
      console.warn("API Fallback triggered:", e);
      return { status: 'error', message: 'Offline Mode' };
    }
  };

  useEffect(() => {
    setIsMounted(true);
    const init = async () => {
      const data = await safeFetch(`${API_URL}?action=check_setup`);
      if (data && typeof data.setup_required !== 'undefined') setSetupRequired(data.setup_required);
      const saved = localStorage.getItem('nexus_user');
      if (saved) setCurrentUser(JSON.parse(saved));
    };
    init();
  }, []);

  const loadData = async () => {
    const [txData, certData, userData, fiscalData, prodData, estData] = await Promise.all([
      safeFetch(`${API_URL}?action=get_transactions`),
      safeFetch(`${API_URL}?action=get_certificates`),
      safeFetch(`${API_URL}?action=get_users`),
      safeFetch(`${API_URL}?action=get_fiscal_config`),
      safeFetch(`${API_URL}?action=get_products`),
      safeFetch(`${API_URL}?action=get_establishment`)
    ]);

    if (Array.isArray(txData)) setTransactions(txData);
    if (Array.isArray(certData)) setCertificates(certData);
    if (Array.isArray(userData)) setUsersList(userData);
    if (fiscalData && !fiscalData.status) setFiscalConfig(fiscalData);
    if (Array.isArray(prodData)) setProductsList(prodData);
    if (estData && !estData.status) setEstablishment(estData);
  };

  useEffect(() => { if (isMounted) loadData(); }, [currentUser, setupRequired, isMounted]);

  const handleSaveProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingProduct(true);
    const data = await safeFetch(`${API_URL}?action=save_product`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingProduct)
    });
    if (data.status === 'success') {
      setShowProductModal(false);
      setEditingProduct(null);
      loadData();
    }
    setIsSavingProduct(false);
  };

  const handleSaveCert = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingCert(true);
    const data = await safeFetch(`${API_URL}?action=save_certificate`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingCert)
    });
    if (data.status === 'success') {
      setShowCertModal(false);
      setEditingCert(null);
      loadData();
    }
    setIsSavingCert(false);
  };

  const handleSaveUser = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingUser(true);
    const data = await safeFetch(`${API_URL}?action=save_user`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingUser)
    });
    if (data.status === 'success') {
      setShowUserModal(false);
      setEditingUser(null);
      loadData();
    }
    setIsSavingUser(false);
  };

  const handleDeleteUser = async (id: number) => {
    if (!confirm('Excluir este usuário?')) return;
    const data = await safeFetch(`${API_URL}?action=delete_user&id=${id}`);
    if (data.status === 'success') loadData();
  };

  const handleSaveFiscalConfig = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingFiscal(true);
    const data = await safeFetch(`${API_URL}?action=save_fiscal_config`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(fiscalConfig)
    });
    if (data.status === 'success') {
      alert('Configuração fiscal salva!');
      setActiveTab('fiscal');
    }
    setIsSavingFiscal(false);
  };

  const handleSaveEstablishment = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingEstablishment(true);
    const data = await safeFetch(`${API_URL}?action=save_establishment`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(establishment)
    });
    if (data.status === 'success') {
      alert('Dados do estabelecimento salvos!');
      setFiscalConfig(prev => ({ ...prev, cnpj: establishment.cnpj, razaoSocial: establishment.razaoSocial }));
    }
    setIsSavingEstablishment(false);
  };

  const handleCertify = async (txId: string) => {
    if (!selectedCertForFiscal && certificates.length > 0) {
      setSelectedCertForFiscal(certificates[0].id);
    }
    if (certificates.length === 0) {
      alert('Configure um certificado digital para o estado do estabelecimento antes de emitir notas.');
      return;
    }

    setPendingTxToCertify(txId);
    setIsCertifying(true);
    setCertPhase(1); // Geração XML
    await new Promise(r => setTimeout(r, 600));
    setCertPhase(2); // Assinatura Digital
    await new Promise(r => setTimeout(r, 600));
    setCertPhase(3); // Transmissão SEFAZ
    await new Promise(r => setTimeout(r, 600));

    const data = await safeFetch(`${API_URL}?action=certify_transaction`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ txId })
    });

    if (data.status === 'success') {
      setCertPhase(4); // Autorizada
      await new Promise(r => setTimeout(r, 600));
      loadData();
    }
    setIsCertifying(false);
    setCertPhase(0);
    setPendingTxToCertify(null);
  };

  const simulateTransaction = async (method: PaymentMethod, details?: { brand: string, installments: number }) => {
    setIsSimulating(true);
    const amount = Math.floor(Math.random() * 500) + 10.5;
    const txId = `TX-${Math.floor(Math.random() * 90000 + 10000)}`;

    if (method === PaymentMethod.PIX) {
      const pixTx: Transaction = {
        id: txId,
        timestamp: new Date().toISOString(),
        amount: amount,
        method: PaymentMethod.PIX,
        status: PaymentStatus.PENDING,
        terminalId: 'TERM-PIX',
        segment: establishment.nomeFantasia || 'Venda Nexus',
        pixQrCode: `https://api.qrserver.com/v1/create-qr-code/?size=250x250&data=00020101021226870014BR.GOV.BCB.PIX0125-${txId}`
      };
      setShowPixModal(pixTx);
      setIsSimulating(false);
      // Simulação de confirmação automática após 5 segundos
      setTimeout(() => {
        setTransactions(prev => [{...pixTx, status: PaymentStatus.SUCCESS}, ...prev]);
        setShowPixModal(null);
        setShowSuccessModal({...pixTx, status: PaymentStatus.SUCCESS});
      }, 5000);
    } else {
      await new Promise(r => setTimeout(r, 2000));
      const cardTx: Transaction = {
        id: txId,
        timestamp: new Date().toISOString(),
        amount: amount,
        method: method,
        status: PaymentStatus.SUCCESS,
        terminalId: 'TERM-CARD',
        segment: establishment.nomeFantasia || 'Venda Nexus',
        cardBrand: details?.brand,
        installments: details?.installments
      };
      setTransactions(prev => [cardTx, ...prev]);
      setIsSimulating(false);
      setShowCardSimModal(false);
      setShowSuccessModal(cardTx);
    }
  };

  const stats = useMemo(() => {
    const success = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const totalVal = success.reduce((a, b) => a + Number(b.amount), 0);
    const pix = success.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    return {
      total: totalVal,
      pixPercent: ((pix / (totalVal || 1)) * 100).toFixed(1),
      txCount: transactions.length
    };
  }, [transactions]);

  const renderSimulator = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-center">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Venda Balcão (TEF)</h3>
          <p className="text-slate-500 font-medium">Inicie uma venda rápida integrada ao PIX e Cartões de todas as bandeiras.</p>
        </div>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <button onClick={() => simulateTransaction(PaymentMethod.PIX)} disabled={isSimulating} className="bg-white p-12 rounded-[3.5rem] border border-slate-100 shadow-sm hover:shadow-2xl transition-all text-left group overflow-hidden relative">
          <div className="absolute top-0 right-0 w-32 h-32 bg-emerald-500/5 -mr-12 -mt-12 rounded-full group-hover:scale-150 transition-transform"></div>
          <div className="text-4xl mb-8 bg-emerald-50 w-20 h-20 flex items-center justify-center rounded-[2rem] group-hover:rotate-12 transition-transform shadow-inner">⚡</div>
          <h4 className="text-2xl font-black text-slate-900 mb-2 tracking-tight">Simular PIX</h4>
          <p className="text-sm text-slate-500 font-medium leading-relaxed">Confirmação instantânea e emissão de QR Code dinâmico Bacen.</p>
        </button>
        <button onClick={() => setShowCardSimModal(true)} disabled={isSimulating} className="bg-white p-12 rounded-[3.5rem] border border-slate-100 shadow-sm hover:shadow-2xl transition-all text-left group overflow-hidden relative">
          <div className="absolute top-0 right-0 w-32 h-32 bg-indigo-500/5 -mr-12 -mt-12 rounded-full group-hover:scale-150 transition-transform"></div>
          <div className="text-4xl mb-8 bg-indigo-50 w-20 h-20 flex items-center justify-center rounded-[2rem] group-hover:-rotate-12 transition-transform shadow-inner">💳</div>
          <h4 className="text-2xl font-black text-slate-900 mb-2 tracking-tight">Cartão (Pinpad)</h4>
          <p className="text-sm text-slate-500 font-medium leading-relaxed">Processamento multi-bandeira com parcelamento e autorização bancária.</p>
        </button>
      </div>
    </div>
  );

  const renderCertificates = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Certificados Digitais</h3>
          <p className="text-slate-500 font-medium">Gerencie chaves e-CNPJ (A1 e A3) para autorização fiscal em todos os estados.</p>
        </div>
        <button onClick={() => { setEditingCert({ alias: '', state: 'SP', type: 'A1', expirationDate: '' }); setShowCertModal(true); }} className="px-6 py-3 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg shadow-indigo-600/20">+ Novo Certificado</button>
      </div>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {certificates.length === 0 ? (
          <div className="col-span-full bg-white/50 border-2 border-dashed border-slate-200 rounded-[3rem] p-20 text-center">
            <p className="text-slate-400 font-bold">Nenhum certificado digital cadastrado.</p>
            <p className="text-xs text-slate-400 mt-2">O sistema requer um certificado para emissão de NFC-e.</p>
          </div>
        ) : certificates.map((cert) => (
          <div key={cert.id} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm hover:shadow-md transition-all relative overflow-hidden group">
            <div className={`absolute top-0 right-0 w-20 h-20 -mr-10 -mt-10 rounded-full opacity-10 ${cert.status === 'Ativo' ? 'bg-emerald-500' : 'bg-rose-500'}`}></div>
            <div className="flex items-center gap-4 mb-6">
              <div className="w-12 h-12 bg-slate-50 rounded-2xl flex items-center justify-center text-xl shadow-inner">🔐</div>
              <div>
                <h4 className="font-black text-slate-900 leading-none">{cert.alias}</h4>
                <p className="text-[10px] font-bold text-slate-400 uppercase tracking-widest mt-1">{cert.type} • {cert.state}</p>
              </div>
            </div>
            <div className="space-y-4">
              <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest">
                <span className="text-slate-400">Expiração</span>
                <span className="text-slate-800">{new Date(cert.expirationDate).toLocaleDateString()}</span>
              </div>
              <div className="flex justify-between items-center text-[10px] font-black uppercase tracking-widest">
                <span className="text-slate-400">Sefaz/UF</span>
                <span className="px-2 py-0.5 bg-slate-100 rounded text-slate-600">{cert.state}</span>
              </div>
            </div>
            <div className="mt-8 flex gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
              <button onClick={() => { setEditingCert(cert); setShowCertModal(true); }} className="flex-1 py-3 bg-slate-50 text-slate-400 rounded-xl font-bold text-[10px] uppercase hover:bg-indigo-600 hover:text-white transition-all">Editar</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const renderFiscalGenerator = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Emissão NFC-e</h3>
          <p className="text-slate-500 font-medium">Controle centralizado de autorização e consulta SEFAZ.</p>
        </div>
      </div>
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-1 space-y-6">
           <div className="bg-white p-8 rounded-[2.5rem] border border-slate-100 shadow-sm">
              <div className="flex justify-between items-center mb-6">
                <h4 className="text-xs font-black text-slate-900 uppercase tracking-widest">Configuração Ativa</h4>
                <span className={`w-3 h-3 rounded-full ${certificates.length > 0 ? 'bg-emerald-500 animate-pulse' : 'bg-rose-500'}`}></span>
              </div>
              <div className="space-y-4">
                <div className="flex justify-between text-[10px] font-bold uppercase tracking-widest">
                  <span className="text-slate-400">CNPJ Emissor:</span>
                  <span className="text-slate-800">{establishment.cnpj || 'PENDENTE'}</span>
                </div>
                <div className="flex justify-between text-[10px] font-bold uppercase tracking-widest">
                  <span className="text-slate-400">Ambiente:</span>
                  <span className={`px-2 py-0.5 rounded ${fiscalConfig.ambiente === 'Produção' ? 'bg-rose-50 text-rose-600' : 'bg-amber-50 text-amber-600'}`}>{fiscalConfig.ambiente}</span>
                </div>
                <div className="flex justify-between text-[10px] font-bold uppercase tracking-widest">
                  <span className="text-slate-400">Certificado:</span>
                  <span className="text-indigo-600 underline cursor-pointer" onClick={() => setActiveTab('certificates')}>{certificates[0]?.alias || 'Configurar'}</span>
                </div>
              </div>
              <button onClick={() => setActiveTab('fiscal_config')} className="w-full py-4 bg-slate-50 text-slate-500 rounded-2xl font-black text-[10px] uppercase tracking-widest mt-8 hover:bg-slate-100 transition-all">Parâmetros Técnicos</button>
