            <form onSubmit={handleSaveCert} className="space-y-6">
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Apelido (Identificação)</label><input type="text" required value={editingCert.alias} onChange={e => setEditingCert({...editingCert, alias: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" placeholder="Ex: Matriz SP e-CNPJ" /></div>
              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Estado (Sefaz/UF)</label>
                  <select value={editingCert.state} onChange={e => setEditingCert({...editingCert, state: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none">
                    {ALL_UFS.map(uf => <option key={uf} value={uf}>{uf}</option>)}
                  </select>
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Tipo</label>
                  <select value={editingCert.type} onChange={e => setEditingCert({...editingCert, type: e.target.value as any})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none"><option value="A1">Arquivo (A1)</option><option value="A3">Cartão/Token (A3)</option></select>
                </div>
              </div>
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Expiração</label><input type="date" required value={editingCert.expirationDate} onChange={e => setEditingCert({...editingCert, expirationDate: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" /></div>
              <div className="flex gap-4 pt-6"><button type="button" onClick={() => setShowCertModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs">Cancelar</button><button type="submit" disabled={isSavingCert} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl">Sincronizar Chave</button></div>
            </form>
          </div>
        </div>
      )}

      {/* USER MODAL */}
      {showUserModal && editingUser && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6 animate-in zoom-in duration-300">
          <div className="bg-white p-12 rounded-[3.5rem] w-full max-w-md shadow-2xl">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Dados de Acesso</h3>
            <form onSubmit={handleSaveUser} className="space-y-6">
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nome Completo</label><input type="text" required value={editingUser.name} onChange={e => setEditingUser({...editingUser, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" /></div>
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Login</label><input type="text" required value={editingUser.username} onChange={e => setEditingUser({...editingUser, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" /></div>
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Acesso</label><select value={editingUser.role} onChange={e => setEditingUser({...editingUser, role: e.target.value as any})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none"><option value={UserRole.OPERATOR}>Operador</option><option value={UserRole.ADMIN}>Administrador</option><option value={UserRole.MASTER}>Master</option></select></div>
              <div className="flex gap-4 pt-4"><button type="button" onClick={() => setShowUserModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs">Cancelar</button><button type="submit" className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs">Gravar</button></div>
            </form>
          </div>
        </div>
      )}

      {/* Fix: Adding PRODUCT MODAL */}
      {showProductModal && editingProduct && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6 animate-in zoom-in duration-300">
          <div className="bg-white p-12 rounded-[3.5rem] w-full max-w-md shadow-2xl">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight">Cadastro de Produto</h3>
            <form onSubmit={handleSaveProduct} className="space-y-6">
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nome do Produto</label><input type="text" required value={editingProduct.name} onChange={e => setEditingProduct({...editingProduct, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" /></div>
              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">SKU / Cód.</label><input type="text" required value={editingProduct.sku} onChange={e => setEditingProduct({...editingProduct, sku: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" /></div>
                <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Preço (R$)</label><input type="number" step="0.01" required value={editingProduct.price} onChange={e => setEditingProduct({...editingProduct, price: parseFloat(e.target.value) || 0})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" /></div>
              </div>
              <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Categoria</label><input type="text" required value={editingProduct.category} onChange={e => setEditingProduct({...editingProduct, category: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" /></div>
              <div className="flex gap-4 pt-4"><button type="button" onClick={() => setShowProductModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs">Cancelar</button><button type="submit" disabled={isSavingProduct} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs">Salvar</button></div>
            </form>
          </div>
        </div>
      )}

      {/* CARD SIMULATOR */}
      {showCardSimModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-2xl z-[700] flex items-center justify-center p-6 animate-in zoom-in duration-300">
           <div className="bg-white w-full max-w-sm rounded-[4rem] shadow-2xl overflow-hidden">
              <div className="bg-slate-900 p-8 text-center text-white">
                <h4 className="font-black text-xs uppercase tracking-[0.3em] text-indigo-400">Pinpad Nexus V6</h4>
              </div>
              <div className="p-12">
                 {simStep === 'brand' && (
                    <div className="space-y-6">
                       <p className="text-center font-black text-slate-400 uppercase text-[10px] tracking-widest mb-4">Insira ou Aproximar Cartão</p>
                       <div className="grid grid-cols-2 gap-4">
                          {['Visa', 'Mastercard', 'Elo', 'Amex'].map(brand => (
                             <button key={brand} onClick={() => { setSimData({...simData, brand}); setSimStep('method'); }} className="p-8 bg-slate-50 border border-slate-100 rounded-3xl font-black text-slate-800 uppercase text-[10px] hover:bg-indigo-600 hover:text-white transition-all shadow-sm">{brand}</button>
                          ))}
                       </div>
                    </div>
                 )}
                 {simStep === 'method' && (
                    <div className="space-y-6 text-center">
                       <p className="font-black text-slate-400 uppercase text-[10px] mb-8">Cartão {simData.brand} Detectado</p>
                       <button onClick={() => simulateTransaction(PaymentMethod.DEBIT, { brand: simData.brand, installments: 1 })} className="w-full p-8 bg-indigo-600 text-white rounded-[2rem] font-black uppercase text-xs shadow-xl hover:bg-slate-900 transition-all">Débito</button>
                       <button onClick={() => setSimStep('installments')} className="w-full p-8 bg-slate-50 text-slate-900 rounded-[2rem] font-black uppercase text-xs shadow-sm hover:bg-slate-100 transition-all">Crédito</button>
                    </div>
                 )}
                 {simStep === 'installments' && (
                    <div className="space-y-6">
                       <p className="text-center font-black text-slate-400 uppercase text-[10px] mb-8">Parcelamento {simData.brand}</p>
                       <div className="grid grid-cols-3 gap-3">
                          {[1, 2, 3, 4, 6, 12].map(n => (
                             <button key={n} onClick={() => simulateTransaction(PaymentMethod.CREDIT, { brand: simData.brand, installments: n })} className="p-5 bg-slate-50 border border-slate-100 rounded-2xl font-black text-slate-700 hover:bg-indigo-600 hover:text-white transition-all">{n}x</button>
                          ))}
                       </div>
                    </div>
                 )}
                 <button onClick={() => {setShowCardSimModal(false); setSimStep('brand');}} className="w-full mt-12 py-3 text-slate-400 font-black text-[10px] uppercase tracking-widest hover:text-rose-500 transition-colors">Abortar</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES, MOCK_TRANSACTIONS, ALL_UFS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole, FiscalConfig, Product, Establishment } from './types';
import { getSmartInsights } from './services/geminiService';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [productsList, setProductsList] = useState<Product[]>([]);
  const [fiscalConfig, setFiscalConfig] = useState<FiscalConfig>({
    cnpj: '', ie: '', razaoSocial: '', cscToken: '', cscId: '',
    ambiente: 'Homologação', serie: '1', ultimoNumero: 0, contingencia: false
  });
  const [establishment, setEstablishment] = useState<Establishment>({
    razaoSocial: '', nomeFantasia: '', cnpj: '', endereco: '', telefone: '', email: ''
  });

  const [isSimulating, setIsSimulating] = useState(false);
  const [isSavingFiscal, setIsSavingFiscal] = useState(false);
  const [isSavingEstablishment, setIsSavingEstablishment] = useState(false);
  const [setupRequired, setSetupRequired] = useState<boolean>(false);
  const [showPixModal, setShowPixModal] = useState<Transaction | null>(null);
  const [showNoteModal, setShowNoteModal] = useState<Transaction | null>(null);
  const [showSuccessModal, setShowSuccessModal] = useState<Transaction | null>(null);
  const [isMounted, setIsMounted] = useState(false);

  // User Management State
  const [showUserModal, setShowUserModal] = useState(false);
  const [isSavingUser, setIsSavingUser] = useState(false);
  const [editingUser, setEditingUser] = useState<Partial<User> & { password?: string } | null>(null);

  // Setup State
  const [setupData, setSetupData] = useState({ name: '', username: '', password: '' });

  const safeFetch = async (url: string, options?: RequestInit) => {
    try {
      const response = await fetch(url, options);
      if (!response.ok) throw new Error(`Server returned ${response.status}`);
      const text = await response.text();
      try { return JSON.parse(text); } catch (e) { throw new Error("Invalid JSON response"); }
    } catch (e) {
      console.warn("API Fallback triggered:", e);
      return { status: 'error', message: 'Offline Mode' };
    }
  };

  useEffect(() => {
    setIsMounted(true);
    const init = async () => {
      // Verificar se existem usuários no banco
      const data = await safeFetch(`${API_URL}?action=get_users`);
      if (Array.isArray(data) && data.length === 0) {
        setSetupRequired(true);
      } else {
        setSetupRequired(false);
        const saved = localStorage.getItem('nexus_user');
        if (saved) setCurrentUser(JSON.parse(saved));
      }
    };
    init();
  }, []);

  const loadData = async () => {
    if (!currentUser && !setupRequired) return;

    const [txData, certData, userData, fiscalData, prodData, estData] = await Promise.all([
      safeFetch(`${API_URL}?action=get_transactions`),
      safeFetch(`${API_URL}?action=get_certificates`),
      safeFetch(`${API_URL}?action=get_users`),
      safeFetch(`${API_URL}?action=get_fiscal_config`),
      safeFetch(`${API_URL}?action=get_products`),
      safeFetch(`${API_URL}?action=get_establishment`)
    ]);

    if (Array.isArray(txData)) setTransactions(txData);
    if (Array.isArray(certData)) setCertificates(certData);
    if (Array.isArray(userData)) setUsersList(userData);
    if (fiscalData && !fiscalData.status) setFiscalConfig(fiscalData);
    if (Array.isArray(prodData)) setProductsList(prodData);
    if (estData && !estData.status) setEstablishment(estData);
  };

  useEffect(() => { if (isMounted) loadData(); }, [currentUser, setupRequired, isMounted]);

  const handleCreateMaster = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingUser(true);
    const data = await safeFetch(`${API_URL}?action=save_user`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ ...setupData, role: UserRole.MASTER })
    });
    if (data.status === 'success') {
      alert('Usuário MASTER criado com sucesso! Faça login para continuar.');
      setSetupRequired(false);
      window.location.reload();
    }
    setIsSavingUser(false);
  };

  const handleSaveUser = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingUser(true);
    const data = await safeFetch(`${API_URL}?action=save_user`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingUser)
    });
    if (data.status === 'success') {
      setShowUserModal(false);
      setEditingUser(null);
      loadData();
    }
    setIsSavingUser(false);
  };

  const handleDeleteUser = async (id: number) => {
    const userToDelete = usersList.find(u => u.id === id);
    if (userToDelete?.role === UserRole.MASTER && usersList.filter(u => u.role === UserRole.MASTER).length <= 1) {
      alert('Segurança: Não é possível remover o único usuário MASTER do sistema.');
      return;
    }
    if (!confirm('Tem certeza que deseja remover este usuário?')) return;
    const data = await safeFetch(`${API_URL}?action=delete_user&id=${id}`);
    if (data.status === 'success') loadData();
  };

  const renderSetup = () => (
    <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6">
      <div className="bg-white w-full max-w-lg rounded-[3rem] p-12 shadow-2xl animate-in zoom-in duration-500">
        <div className="text-center mb-10">
          <div className="w-20 h-20 bg-indigo-600 rounded-[2rem] flex items-center justify-center text-3xl mx-auto mb-6 text-white font-black shadow-xl shadow-indigo-500/20">N</div>
          <h2 className="text-3xl font-black text-slate-900 tracking-tight">Primeiro Acesso</h2>
          <p className="text-slate-500 font-medium mt-2">Crie a conta MASTER para gerenciar seu estabelecimento.</p>
        </div>
        <form onSubmit={handleCreateMaster} className="space-y-6">
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase ml-1 tracking-widest">Nome do Proprietário</label>
            <input type="text" required value={setupData.name} onChange={e => setSetupData({...setupData, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none focus:ring-4 focus:ring-indigo-500/10 transition-all" placeholder="Seu Nome Completo" />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase ml-1 tracking-widest">Login de Acesso</label>
            <input type="text" required value={setupData.username} onChange={e => setSetupData({...setupData, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none focus:ring-4 focus:ring-indigo-500/10 transition-all" placeholder="Ex: master" />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase ml-1 tracking-widest">Senha de Segurança</label>
            <input type="password" required value={setupData.password} onChange={e => setSetupData({...setupData, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none focus:ring-4 focus:ring-indigo-500/10 transition-all" placeholder="Mínimo 8 caracteres" />
          </div>
          <button type="submit" disabled={isSavingUser} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-indigo-600 transition-all active:scale-[0.98]">
            {isSavingUser ? 'Configurando...' : 'Finalizar Instalação Pro'}
          </button>
        </form>
      </div>
    </div>
  );

  const renderUsers = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Segurança e Usuários</h3>
          <p className="text-slate-500 font-medium">Controle quem pode realizar vendas, emitir notas e alterar configurações.</p>
        </div>
        <button onClick={() => { setEditingUser({ name: '', username: '', role: UserRole.OPERATOR, password: '' }); setShowUserModal(true); }} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg shadow-indigo-600/20 hover:scale-[1.02] active:scale-95 transition-all">
          + Novo Usuário
        </button>
      </div>
      <div className="grid grid-cols-1 gap-6">
        <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
          <table className="w-full text-left border-collapse">
            <thead>
              <tr className="bg-slate-50/80 border-b border-slate-100">
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Usuário</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Login</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nível de Acesso</th>
                <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-50">
              {usersList.map((u) => (
                <tr key={u.id} className="group hover:bg-slate-50/50 transition-all">
                  <td className="px-8 py-6">
                    <div className="flex items-center gap-4">
                      <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-black text-lg ${u.role === UserRole.MASTER ? 'bg-indigo-50 text-indigo-600' : 'bg-slate-100 text-slate-400'}`}>
                        {u.name.charAt(0)}
                      </div>
                      <span className="font-black text-slate-900 text-sm">{u.name}</span>
                    </div>
                  </td>
                  <td className="px-8 py-6">
                    <span className="font-mono text-xs text-slate-500">@{u.username}</span>
                  </td>
                  <td className="px-8 py-6">
                    <span className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest ${
                      u.role === UserRole.MASTER ? 'bg-slate-900 text-white' : 
                      u.role === UserRole.ADMIN ? 'bg-amber-100 text-amber-700' : 'bg-slate-100 text-slate-500'
                    }`}>
                      {u.role}
                    </span>
                  </td>
                  <td className="px-8 py-6 text-right">
                    <div className="flex justify-end gap-3 opacity-0 group-hover:opacity-100 transition-all">
                      <button onClick={() => { setEditingUser(u); setShowUserModal(true); }} className="w-10 h-10 bg-white border border-slate-100 rounded-xl flex items-center justify-center text-slate-400 hover:text-indigo-600 hover:shadow-lg transition-all">✏️</button>
                      <button onClick={() => handleDeleteUser(u.id)} className="w-10 h-10 bg-white border border-slate-100 rounded-xl flex items-center justify-center text-slate-400 hover:text-rose-600 hover:shadow-lg transition-all">🗑️</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );

  const stats = useMemo(() => {
    const success = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const totalVal = success.reduce((a, b) => a + Number(b.amount), 0);
    const pix = success.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    return {
      total: totalVal,
      pixPercent: ((pix / (totalVal || 1)) * 100).toFixed(1),
      txCount: transactions.length
    };
  }, [transactions]);

  if (setupRequired) return renderSetup();

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} currentUser={currentUser} onLogout={() => { setCurrentUser(null); localStorage.removeItem('nexus_user'); window.location.reload(); }} />
      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-24 bg-white/70 backdrop-blur-xl border-b border-slate-100 flex items-center justify-between px-12 sticky top-0 z-40">
          <div className="flex flex-col">
            <h2 className="text-2xl font-black text-slate-900 tracking-tight leading-none uppercase">NexusTEF <span className="text-indigo-600">Pro</span></h2>
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.3em] mt-2">{activeTab}</span>
          </div>
          {currentUser && (
            <div className="flex items-center gap-4 bg-slate-50 p-2 pr-5 rounded-2xl border border-slate-100">
              <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center text-xl shadow-sm">👤</div>
              <div className="text-left">
                <p className="text-xs font-black text-slate-900 leading-none uppercase tracking-tight">{currentUser.name}</p>
                <p className="text-[9px] font-bold text-indigo-500 uppercase tracking-widest mt-1">{currentUser.role}</p>
              </div>
            </div>
          )}
        </header>

        <main className="p-12 max-w-[1500px] w-full mx-auto">
          {activeTab === 'dashboard' && (
            <div className="space-y-12">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
                <StatCard label="Faturamento" value={`R$ ${stats.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} icon="💰" color="bg-indigo-50" />
                <StatCard label="Taxa PIX" value={`${stats.pixPercent}%`} icon="⚡" color="bg-emerald-50" trend="12%" trendUp />
                <StatCard label="Operadores" value={usersList.length} icon="👥" color="bg-amber-50" />
                <StatCard label="Vendas/Mês" value={stats.txCount} icon="🔄" color="bg-slate-50" />
              </div>
              <FiscalMonitor states={SEFAZ_STATES} />
            </div>
          )}
          {activeTab === 'users' && renderUsers()}
          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}
        </main>
      </div>

      {showUserModal && editingUser && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6 animate-in zoom-in duration-300">
          <div className="bg-white p-12 rounded-[3.5rem] w-full max-w-md shadow-2xl">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight uppercase">Configurar Usuário</h3>
            <form onSubmit={handleSaveUser} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nome Completo</label>
                <input type="text" required value={editingUser.name} onChange={e => setEditingUser({...editingUser, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Login</label>
                <input type="text" required value={editingUser.username} onChange={e => setEditingUser({...editingUser, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Senha {editingUser.id ? '(Vazio para não alterar)' : ''}</label>
                <input type="password" required={!editingUser.id} value={editingUser.password} onChange={e => setEditingUser({...editingUser, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nível de Acesso</label>
                <select value={editingUser.role} onChange={e => setEditingUser({...editingUser, role: e.target.value as any})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none">
                  <option value={UserRole.OPERATOR}>Operador (Vendas)</option>
                  <option value={UserRole.ADMIN}>Administrador (Fiscal)</option>
                  <option value={UserRole.MASTER}>Master (Dono do Estabelecimento)</option>
                </select>
              </div>
              {editingUser.role === UserRole.MASTER && (
                <div className="bg-amber-50 p-4 rounded-2xl border border-amber-100">
                  <p className="text-[10px] font-bold text-amber-700 leading-relaxed uppercase">⚠️ Atenção: Usuários MASTER possuem controle total sobre o sistema, incluindo exclusão de dados e alteração de taxas.</p>
                </div>
              )}
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowUserModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs">Cancelar</button>
                <button type="submit" className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl">Gravar Acesso</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES, ALL_UFS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole, FiscalConfig, Product, Establishment } from './types';
import { getSmartInsights } from './services/geminiService';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [usersList, setUsersList] = useState<User[]>([]);
  const [productsList, setProductsList] = useState<Product[]>([]);
  const [fiscalConfig, setFiscalConfig] = useState<FiscalConfig>({
    cnpj: '', ie: '', razaoSocial: '', cscToken: '', cscId: '',
    ambiente: 'Homologação', serie: '1', ultimoNumero: 0, contingencia: false
  });
  const [establishment, setEstablishment] = useState<Establishment>({
    razaoSocial: '', nomeFantasia: '', cnpj: '', endereco: '', telefone: '', email: ''
  });

  const [isSavingFiscal, setIsSavingFiscal] = useState(false);
  const [isSavingEstablishment, setIsSavingEstablishment] = useState(false);
  const [setupRequired, setSetupRequired] = useState<boolean>(false);
  const [isMounted, setIsMounted] = useState(false);

  // Modals
  const [showUserModal, setShowUserModal] = useState(false);
  const [showProductModal, setShowProductModal] = useState(false);
  const [isSavingUser, setIsSavingUser] = useState(false);
  const [isSavingProduct, setIsSavingProduct] = useState(false);

  // Editing states
  const [editingUser, setEditingUser] = useState<Partial<User> & { password?: string } | null>(null);
  const [editingProduct, setEditingProduct] = useState<Partial<Product> | null>(null);
  const [setupData, setSetupData] = useState({ name: '', username: '', password: '' });

  const safeFetch = async (url: string, options?: RequestInit) => {
    try {
      const response = await fetch(url, options);
      if (!response.ok) throw new Error(`Server returned ${response.status}`);
      const text = await response.text();
      try { return JSON.parse(text); } catch (e) { throw new Error("Invalid JSON response"); }
    } catch (e) {
      console.warn("API Fallback triggered:", e);
      return { status: 'error', message: 'Offline Mode' };
    }
  };

  useEffect(() => {
    setIsMounted(true);
    const init = async () => {
      const data = await safeFetch(`${API_URL}?action=get_users`);
      if (Array.isArray(data) && data.length === 0) {
        setSetupRequired(true);
      } else {
        setSetupRequired(false);
        const saved = localStorage.getItem('nexus_user');
        if (saved) setCurrentUser(JSON.parse(saved));
      }
    };
    init();
  }, []);

  const loadData = async () => {
    if (!currentUser && !setupRequired) return;

    const [txData, certData, userData, fiscalData, prodData, estData] = await Promise.all([
      safeFetch(`${API_URL}?action=get_transactions`),
      safeFetch(`${API_URL}?action=get_certificates`),
      safeFetch(`${API_URL}?action=get_users`),
      safeFetch(`${API_URL}?action=get_fiscal_config`),
      safeFetch(`${API_URL}?action=get_products`),
      safeFetch(`${API_URL}?action=get_establishment`)
    ]);

    if (Array.isArray(txData)) setTransactions(txData);
    if (Array.isArray(certData)) setCertificates(certData);
    if (Array.isArray(userData)) setUsersList(userData);
    if (fiscalData && !fiscalData.status) setFiscalConfig(fiscalData);
    if (Array.isArray(prodData)) setProductsList(prodData);
    if (estData && !estData.status) setEstablishment(estData);
  };

  useEffect(() => { if (isMounted) loadData(); }, [currentUser, setupRequired, isMounted]);

  const handleCreateMaster = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingUser(true);
    const data = await safeFetch(`${API_URL}?action=save_user`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ ...setupData, role: UserRole.MASTER })
    });
    if (data.status === 'success') {
      alert('Usuário MASTER criado com sucesso! Faça login para continuar.');
      setSetupRequired(false);
      window.location.reload();
    }
    setIsSavingUser(false);
  };

  const handleSaveUser = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingUser(true);
    const data = await safeFetch(`${API_URL}?action=save_user`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingUser)
    });
    if (data.status === 'success') {
      setShowUserModal(false);
      setEditingUser(null);
      loadData();
    }
    setIsSavingUser(false);
  };

  const handleSaveProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingProduct(true);
    const data = await safeFetch(`${API_URL}?action=save_product`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingProduct)
    });
    if (data.status === 'success') {
      setShowProductModal(false);
      setEditingProduct(null);
      loadData();
    }
    setIsSavingProduct(false);
  };

  const handleDeleteProduct = async (id: number) => {
    if (!confirm('Deseja realmente excluir este produto do catálogo?')) return;
    const data = await safeFetch(`${API_URL}?action=delete_product&id=${id}`);
    if (data.status === 'success') loadData();
  };

  const handleDeleteUser = async (id: number) => {
    const userToDelete = usersList.find(u => u.id === id);
    if (userToDelete?.role === UserRole.MASTER && usersList.filter(u => u.role === UserRole.MASTER).length <= 1) {
      alert('Segurança: Não é possível remover o único usuário MASTER.');
      return;
    }
    if (!confirm('Tem certeza que deseja remover este usuário?')) return;
    const data = await safeFetch(`${API_URL}?action=delete_user&id=${id}`);
    if (data.status === 'success') loadData();
  };

  const handleSaveEstablishment = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingEstablishment(true);
    const data = await safeFetch(`${API_URL}?action=save_establishment`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(establishment)
    });
    if (data.status === 'success') {
      alert('Dados da empresa salvos!');
    }
    setIsSavingEstablishment(false);
  };

  const renderProducts = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Catálogo de Produtos</h3>
          <p className="text-slate-500 font-medium">Gerencie o estoque, preços e categorias dos itens da sua loja.</p>
        </div>
        <button 
          onClick={() => { setEditingProduct({ name: '', sku: '', price: 0, category: '', stock: 0 }); setShowProductModal(true); }} 
          className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg shadow-indigo-600/20 hover:scale-[1.02] active:scale-95 transition-all"
        >
          + Novo Produto
        </button>
      </div>

      <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50/80 border-b border-slate-100">
              <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Produto / SKU</th>
              <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Categoria</th>
              <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Estoque</th>
              <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Preço</th>
              <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {productsList.length === 0 ? (
              <tr><td colSpan={5} className="p-20 text-center text-slate-400 font-bold italic uppercase tracking-widest text-xs">Nenhum produto cadastrado</td></tr>
            ) : productsList.map((prod) => (
              <tr key={prod.id} className="group hover:bg-slate-50/50 transition-all">
                <td className="px-8 py-6">
                  <p className="font-black text-slate-900 text-sm">{prod.name}</p>
                  <p className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">{prod.sku}</p>
                </td>
                <td className="px-8 py-6">
                  <span className="px-3 py-1 bg-slate-100 text-slate-500 rounded-lg text-[10px] font-black uppercase tracking-widest">
                    {prod.category || 'Geral'}
                  </span>
                </td>
                <td className="px-8 py-6 text-center">
                  <span className={`font-mono text-sm font-bold ${prod.stock < 10 ? 'text-rose-500' : 'text-slate-600'}`}>
                    {prod.stock}
                  </span>
                </td>
                <td className="px-8 py-6 font-black text-slate-900 text-sm">
                  R$ {Number(prod.price).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                </td>
                <td className="px-8 py-6 text-right">
                  <div className="flex justify-end gap-3 opacity-0 group-hover:opacity-100 transition-all">
                    <button onClick={() => { setEditingProduct(prod); setShowProductModal(true); }} className="w-10 h-10 bg-white border border-slate-100 rounded-xl flex items-center justify-center text-slate-400 hover:text-indigo-600 hover:shadow-lg transition-all">✏️</button>
                    <button onClick={() => handleDeleteProduct(prod.id)} className="w-10 h-10 bg-white border border-slate-100 rounded-xl flex items-center justify-center text-slate-400 hover:text-rose-600 hover:shadow-lg transition-all">🗑️</button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );

  const renderEstablishment = () => (
    <div className="max-w-4xl mx-auto space-y-8 animate-in slide-in-from-right duration-500">
      <div>
        <h3 className="text-3xl font-black text-slate-900 tracking-tight">Dados da Empresa</h3>
        <p className="text-slate-500 font-medium">Informações básicas do estabelecimento para cabeçalhos e documentos fiscais.</p>
      </div>
      <form onSubmit={handleSaveEstablishment} className="bg-white p-12 rounded-[3.5rem] border border-slate-100 shadow-sm space-y-8">
        <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
          <div className="space-y-2 col-span-full">
            <label className="text-[10px] font-black text-slate-400 uppercase ml-1 tracking-widest">Razão Social</label>
            <input type="text" required value={establishment.razaoSocial} onChange={e => setEstablishment({...establishment, razaoSocial: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none focus:ring-4 focus:ring-indigo-500/10" />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase ml-1 tracking-widest">Nome Fantasia</label>
            <input type="text" required value={establishment.nomeFantasia} onChange={e => setEstablishment({...establishment, nomeFantasia: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none focus:ring-4 focus:ring-indigo-500/10" />
          </div>
          <div className="space-y-2">
            <label className="text-[10px] font-black text-slate-400 uppercase ml-1 tracking-widest">CNPJ</label>
            <input type="text" required value={establishment.cnpj} onChange={e => setEstablishment({...establishment, cnpj: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none focus:ring-4 focus:ring-indigo-500/10" placeholder="00.000.000/0000-00" />
          </div>
        </div>
        <button type="submit" disabled={isSavingEstablishment} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-indigo-600 transition-all">
          {isSavingEstablishment ? 'Salvando...' : 'Gravar Dados Empresariais'}
        </button>
      </form>
    </div>
  );

  const renderUsers = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Segurança e Usuários</h3>
          <p className="text-slate-500 font-medium">Controle quem pode realizar vendas, emitir notas e alterar configurações.</p>
        </div>
        <button onClick={() => { setEditingUser({ name: '', username: '', role: UserRole.OPERATOR, password: '' }); setShowUserModal(true); }} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg shadow-indigo-600/20 hover:scale-[1.02] active:scale-95 transition-all">
          + Novo Usuário
        </button>
      </div>
      <div className="bg-white rounded-[3rem] border border-slate-100 shadow-sm overflow-hidden">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50/80 border-b border-slate-100">
              <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Usuário</th>
              <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Login</th>
              <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Nível de Acesso</th>
              <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {usersList.map((u) => (
              <tr key={u.id} className="group hover:bg-slate-50/50 transition-all">
                <td className="px-8 py-6">
                  <div className="flex items-center gap-4">
                    <div className={`w-12 h-12 rounded-xl flex items-center justify-center font-black text-lg ${u.role === UserRole.MASTER ? 'bg-indigo-50 text-indigo-600' : 'bg-slate-100 text-slate-400'}`}>
                      {u.name.charAt(0)}
                    </div>
                    <span className="font-black text-slate-900 text-sm">{u.name}</span>
                  </div>
                </td>
                <td className="px-8 py-6">
                  <span className="font-mono text-xs text-slate-500">@{u.username}</span>
                </td>
                <td className="px-8 py-6">
                  <span className={`px-4 py-1.5 rounded-full text-[9px] font-black uppercase tracking-widest ${
                    u.role === UserRole.MASTER ? 'bg-slate-900 text-white' : 
                    u.role === UserRole.ADMIN ? 'bg-amber-100 text-amber-700' : 'bg-slate-100 text-slate-500'
                  }`}>
                    {u.role}
                  </span>
                </td>
                <td className="px-8 py-6 text-right">
                  <div className="flex justify-end gap-3 opacity-0 group-hover:opacity-100 transition-all">
                    <button onClick={() => { setEditingUser(u); setShowUserModal(true); }} className="w-10 h-10 bg-white border border-slate-100 rounded-xl flex items-center justify-center text-slate-400 hover:text-indigo-600 hover:shadow-lg transition-all">✏️</button>
                    <button onClick={() => handleDeleteUser(u.id)} className="w-10 h-10 bg-white border border-slate-100 rounded-xl flex items-center justify-center text-slate-400 hover:text-rose-600 hover:shadow-lg transition-all">🗑️</button>
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );

  const stats = useMemo(() => {
    const success = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const totalVal = success.reduce((a, b) => a + Number(b.amount), 0);
    const pix = success.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    return {
      total: totalVal,
      pixPercent: ((pix / (totalVal || 1)) * 100).toFixed(1),
      txCount: transactions.length
    };
  }, [transactions]);

  if (setupRequired) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-6">
        <div className="bg-white w-full max-w-lg rounded-[3rem] p-12 shadow-2xl animate-in zoom-in duration-500">
          <div className="text-center mb-10">
            <div className="w-20 h-20 bg-indigo-600 rounded-[2rem] flex items-center justify-center text-3xl mx-auto mb-6 text-white font-black shadow-xl shadow-indigo-500/20">N</div>
            <h2 className="text-3xl font-black text-slate-900 tracking-tight">Primeiro Acesso</h2>
            <p className="text-slate-500 font-medium mt-2">Crie a conta MASTER para gerenciar seu estabelecimento.</p>
          </div>
          <form onSubmit={handleCreateMaster} className="space-y-6">
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1 tracking-widest">Nome do Proprietário</label>
              <input type="text" required value={setupData.name} onChange={e => setSetupData({...setupData, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none focus:ring-4 focus:ring-indigo-500/10" placeholder="Seu Nome Completo" />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1 tracking-widest">Login de Acesso</label>
              <input type="text" required value={setupData.username} onChange={e => setSetupData({...setupData, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none focus:ring-4 focus:ring-indigo-500/10" placeholder="Ex: master" />
            </div>
            <div className="space-y-2">
              <label className="text-[10px] font-black text-slate-400 uppercase ml-1 tracking-widest">Senha de Segurança</label>
              <input type="password" required value={setupData.password} onChange={e => setSetupData({...setupData, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none focus:ring-4 focus:ring-indigo-500/10" placeholder="Mínimo 8 caracteres" />
            </div>
            <button type="submit" disabled={isSavingUser} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl hover:bg-indigo-600 transition-all">
              {isSavingUser ? 'Configurando...' : 'Finalizar Instalação Pro'}
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} currentUser={currentUser} onLogout={() => { setCurrentUser(null); localStorage.removeItem('nexus_user'); window.location.reload(); }} />
      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-24 bg-white/70 backdrop-blur-xl border-b border-slate-100 flex items-center justify-between px-12 sticky top-0 z-40">
          <div className="flex flex-col">
            <h2 className="text-2xl font-black text-slate-900 tracking-tight leading-none uppercase">NexusTEF <span className="text-indigo-600">Pro</span></h2>
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.3em] mt-2">{activeTab}</span>
          </div>
          {currentUser && (
            <div className="flex items-center gap-4 bg-slate-50 p-2 pr-5 rounded-2xl border border-slate-100">
              <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center text-xl shadow-sm">👤</div>
              <div className="text-left">
                <p className="text-xs font-black text-slate-900 leading-none uppercase tracking-tight">{currentUser.name}</p>
                <p className="text-[9px] font-bold text-indigo-500 uppercase tracking-widest mt-1">{currentUser.role}</p>
              </div>
            </div>
          )}
        </header>

        <main className="p-12 max-w-[1500px] w-full mx-auto">
          {activeTab === 'dashboard' && (
            <div className="space-y-12">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
                <StatCard label="Faturamento" value={`R$ ${stats.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} icon="💰" color="bg-indigo-50" />
                <StatCard label="Taxa PIX" value={`${stats.pixPercent}%`} icon="⚡" color="bg-emerald-50" trend="12%" trendUp />
                <StatCard label="Produtos" value={productsList.length} icon="📦" color="bg-amber-50" />
                <StatCard label="Tx Hoje" value={stats.txCount} icon="🔄" color="bg-slate-50" />
              </div>
              <FiscalMonitor states={SEFAZ_STATES} />
            </div>
          )}
          {activeTab === 'products' && renderProducts()}
          {activeTab === 'establishment' && renderEstablishment()}
          {activeTab === 'users' && renderUsers()}
          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}

          {(activeTab === 'fiscal' || activeTab === 'certificates' || activeTab === 'simulator') && (
            <div className="p-20 text-center bg-white rounded-[4rem] border border-slate-100 border-dashed">
              <p className="text-2xl font-black text-slate-300 uppercase tracking-widest">Seção em Desenvolvimento</p>
              <p className="text-sm text-slate-400 font-medium mt-2">Módulos TEF V6 e Integração Sefaz sendo carregados...</p>
            </div>
          )}
        </main>
      </div>

      {/* User Modal */}
      {showUserModal && editingUser && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6 animate-in zoom-in duration-300">
          <div className="bg-white p-12 rounded-[3.5rem] w-full max-w-md shadow-2xl">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight uppercase">Configurar Usuário</h3>
            <form onSubmit={handleSaveUser} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nome Completo</label>
                <input type="text" required value={editingUser.name} onChange={e => setEditingUser({...editingUser, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Login</label>
                <input type="text" required value={editingUser.username} onChange={e => setEditingUser({...editingUser, username: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Senha {editingUser.id ? '(Opcional)' : ''}</label>
                <input type="password" required={!editingUser.id} value={editingUser.password} onChange={e => setEditingUser({...editingUser, password: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" />
              </div>
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nível de Acesso</label>
                <select value={editingUser.role} onChange={e => setEditingUser({...editingUser, role: e.target.value as any})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none">
                  <option value={UserRole.OPERATOR}>Operador</option>
                  <option value={UserRole.ADMIN}>Administrador</option>
                  <option value={UserRole.MASTER}>Master</option>
                </select>
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowUserModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs">Cancelar</button>
                <button type="submit" className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs">Salvar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Product Modal */}
      {showProductModal && editingProduct && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[200] flex items-center justify-center p-6 animate-in zoom-in duration-300">
          <div className="bg-white p-12 rounded-[3.5rem] w-full max-w-lg shadow-2xl">
            <h3 className="text-2xl font-black text-slate-900 mb-8 tracking-tight uppercase">Configurar Produto</h3>
            <form onSubmit={handleSaveProduct} className="space-y-6">
              <div className="space-y-2">
                <label className="text-[10px] font-black text-slate-400 uppercase ml-1 tracking-widest">Nome do Produto</label>
                <input type="text" required value={editingProduct.name} onChange={e => setEditingProduct({...editingProduct, name: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" placeholder="Ex: Café Espresso" />
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1 tracking-widest">SKU / Cód. Barras</label>
                  <input type="text" required value={editingProduct.sku} onChange={e => setEditingProduct({...editingProduct, sku: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" placeholder="PROD-0001" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1 tracking-widest">Preço de Venda (R$)</label>
                  <input type="number" step="0.01" required value={editingProduct.price} onChange={e => setEditingProduct({...editingProduct, price: parseFloat(e.target.value)})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-6">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1 tracking-widest">Categoria</label>
                  <input type="text" required value={editingProduct.category} onChange={e => setEditingProduct({...editingProduct, category: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" placeholder="Ex: Bebidas" />
                </div>
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase ml-1 tracking-widest">Estoque Atual</label>
                  <input type="number" required value={editingProduct.stock} onChange={e => setEditingProduct({...editingProduct, stock: parseInt(e.target.value)})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" />
                </div>
              </div>

              <div className="flex gap-4 pt-6">
                <button type="button" onClick={() => setShowProductModal(false)} className="flex-1 py-5 bg-slate-100 text-slate-500 rounded-2xl font-black uppercase text-xs">Cancelar</button>
                <button type="submit" disabled={isSavingProduct} className="flex-1 py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl">
                  {isSavingProduct ? 'Processando...' : 'Salvar no Catálogo'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { CHART_DATA, SEFAZ_STATES, ALL_UFS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole, FiscalConfig, Product, Establishment } from './types';
import { getSmartInsights } from './services/geminiService';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [currentUser, setCurrentUser] = useState<User | null>({ id: 1, name: 'Administrador', username: 'admin', role: UserRole.MASTER });
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [productsList, setProductsList] = useState<Product[]>([]);
  const [fiscalConfig, setFiscalConfig] = useState<FiscalConfig>({
    cnpj: '', ie: '', razaoSocial: '', cscToken: '', cscId: '',
    ambiente: 'Homologação', serie: '1', ultimoNumero: 0, contingencia: false
  });
  const [establishment, setEstablishment] = useState<Establishment>({
    razaoSocial: '', nomeFantasia: '', cnpj: '', endereco: '', telefone: '', email: ''
  });

  const [isSimulating, setIsSimulating] = useState(false);
  const [isSavingFiscal, setIsSavingFiscal] = useState(false);
  const [isSavingEstablishment, setIsSavingEstablishment] = useState(false);
  const [isSavingProduct, setIsSavingProduct] = useState(false);
  const [isSavingCert, setIsSavingCert] = useState(false);

  const [showPixModal, setShowPixModal] = useState<Transaction | null>(null);
  const [showNoteModal, setShowNoteModal] = useState<Transaction | null>(null);
  const [showSuccessModal, setShowSuccessModal] = useState<Transaction | null>(null);
  const [showProductModal, setShowProductModal] = useState(false);
  const [showCertModal, setShowCertModal] = useState(false);
  const [showCardSimModal, setShowCardSimModal] = useState(false);

  const [simStep, setSimStep] = useState<'brand' | 'method' | 'installments'>('brand');
  const [simData, setSimData] = useState({ brand: '', method: PaymentMethod.CREDIT, installments: 1 });
  const [editingProduct, setEditingProduct] = useState<Partial<Product> | null>(null);
  const [editingCert, setEditingCert] = useState<Partial<DigitalCertificate> | null>(null);
  const [isCertifying, setIsCertifying] = useState(false);
  const [certPhase, setCertPhase] = useState<number>(0); 
  const [pendingTxToCertify, setPendingTxToCertify] = useState<string | null>(null);

  const safeFetch = async (url: string, options?: RequestInit) => {
    try {
      const response = await fetch(url, options);
      if (!response.ok) throw new Error(`Server returned ${response.status}`);
      const text = await response.text();
      try { return JSON.parse(text); } catch (e) { throw new Error("Invalid JSON response"); }
    } catch (e) {
      console.warn("API Fallback triggered:", e);
      return { status: 'error', message: 'Offline Mode' };
    }
  };

  const loadData = async () => {
    const [txData, certData, fiscalData, prodData, estData] = await Promise.all([
      safeFetch(`${API_URL}?action=get_transactions`),
      safeFetch(`${API_URL}?action=get_certificates`),
      safeFetch(`${API_URL}?action=get_fiscal_config`),
      safeFetch(`${API_URL}?action=get_products`),
      safeFetch(`${API_URL}?action=get_establishment`)
    ]);

    if (Array.isArray(txData)) setTransactions(txData);
    if (Array.isArray(certData)) setCertificates(certData);
    if (fiscalData && !fiscalData.status) setFiscalConfig(fiscalData);
    if (Array.isArray(prodData)) setProductsList(prodData);
    if (estData && !estData.status) setEstablishment(estData);
  };

  useEffect(() => { loadData(); }, []);

  const handleSaveProduct = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingProduct(true);
    const data = await safeFetch(`${API_URL}?action=save_product`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingProduct)
    });
    if (data.status === 'success') {
      setShowProductModal(false);
      setEditingProduct(null);
      loadData();
    }
    setIsSavingProduct(false);
  };

  const handleSaveCert = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingCert(true);
    const data = await safeFetch(`${API_URL}?action=save_certificate`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(editingCert)
    });
    if (data.status === 'success') {
      setShowCertModal(false);
      setEditingCert(null);
      loadData();
    }
    setIsSavingCert(false);
  };

  const handleSaveEstablishment = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsSavingEstablishment(true);
    const data = await safeFetch(`${API_URL}?action=save_establishment`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(establishment)
    });
    if (data.status === 'success') {
      alert('Dados da empresa salvos!');
    }
    setIsSavingEstablishment(false);
  };

  const simulateTransaction = async (method: PaymentMethod, details?: { brand: string, installments: number }) => {
    setIsSimulating(true);
    const amount = Math.floor(Math.random() * 500) + 10.5;
    const txId = `TX-${Math.floor(Math.random() * 90000 + 10000)}`;

    if (method === PaymentMethod.PIX) {
      const pixTx: Transaction = {
        id: txId,
        timestamp: new Date().toISOString(),
        amount: amount,
        method: PaymentMethod.PIX,
        status: PaymentStatus.PENDING,
        terminalId: 'TERM-PIX',
        segment: establishment.nomeFantasia || 'Venda Nexus',
        pixQrCode: `https://api.qrserver.com/v1/create-qr-code/?size=250x250&data=PIX-${txId}`
      };
      setShowPixModal(pixTx);
      setIsSimulating(false);
      setTimeout(() => {
        setTransactions(prev => [{...pixTx, status: PaymentStatus.SUCCESS}, ...prev]);
        setShowPixModal(null);
        setShowSuccessModal({...pixTx, status: PaymentStatus.SUCCESS});
      }, 3000);
    } else {
      await new Promise(r => setTimeout(r, 1500));
      const cardTx: Transaction = {
        id: txId,
        timestamp: new Date().toISOString(),
        amount: amount,
        method: method,
        status: PaymentStatus.SUCCESS,
        terminalId: 'TERM-CARD',
        segment: establishment.nomeFantasia || 'Venda Nexus',
        cardBrand: details?.brand,
        installments: details?.installments
      };
      setTransactions(prev => [cardTx, ...prev]);
      setIsSimulating(false);
      setShowCardSimModal(false);
      setShowSuccessModal(cardTx);
    }
  };

  const handleCertify = async (txId: string) => {
    setPendingTxToCertify(txId);
    setIsCertifying(true);
    setCertPhase(1); await new Promise(r => setTimeout(r, 500));
    setCertPhase(2); await new Promise(r => setTimeout(r, 500));
    setCertPhase(3); await new Promise(r => setTimeout(r, 500));

    const data = await safeFetch(`${API_URL}?action=certify_transaction`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ txId })
    });

    if (data.status === 'success') {
      setCertPhase(4);
      await new Promise(r => setTimeout(r, 500));
      loadData();
    }
    setIsCertifying(false);
    setCertPhase(0);
    setPendingTxToCertify(null);
  };

  const stats = useMemo(() => {
    const success = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    const totalVal = success.reduce((a, b) => a + Number(b.amount), 0);
    const pix = success.filter(t => t.method === PaymentMethod.PIX).reduce((a, b) => a + Number(b.amount), 0);
    return {
      total: totalVal,
      pixPercent: ((pix / (totalVal || 1)) * 100).toFixed(1),
      txCount: transactions.length
    };
  }, [transactions]);

  const renderSimulator = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <h3 className="text-3xl font-black text-slate-900 tracking-tight">Checkout TEF V6</h3>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
        <button onClick={() => simulateTransaction(PaymentMethod.PIX)} className="bg-white p-12 rounded-[3.5rem] border border-slate-100 shadow-sm hover:shadow-2xl transition-all text-left group">
          <div className="text-4xl mb-6 bg-emerald-50 w-16 h-16 flex items-center justify-center rounded-2xl group-hover:rotate-12 transition-transform">⚡</div>
          <h4 className="text-2xl font-black text-slate-900 mb-2">Simular PIX</h4>
          <p className="text-sm text-slate-400 font-medium">QR Code Dinâmico com confirmação automática.</p>
        </button>
        <button onClick={() => { setSimStep('brand'); setShowCardSimModal(true); }} className="bg-white p-12 rounded-[3.5rem] border border-slate-100 shadow-sm hover:shadow-2xl transition-all text-left group">
          <div className="text-4xl mb-6 bg-indigo-50 w-16 h-16 flex items-center justify-center rounded-2xl group-hover:-rotate-12 transition-transform">💳</div>
          <h4 className="text-2xl font-black text-slate-900 mb-2">Cartão (Débito/Crédito)</h4>
          <p className="text-sm text-slate-400 font-medium">Simulação de Pinpad integrado multi-bandeira.</p>
        </button>
      </div>
    </div>
  );

  const renderProducts = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <div className="flex justify-between items-end">
        <div>
          <h3 className="text-3xl font-black text-slate-900 tracking-tight">Produtos</h3>
          <p className="text-slate-500 font-medium">Gestão de inventário e preços para o checkout.</p>
        </div>
        <button onClick={() => { setEditingProduct({ name: '', sku: '', price: 0, category: '', stock: 0 }); setShowProductModal(true); }} className="px-8 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg">
          + Novo Produto
        </button>
      </div>
      <div className="bg-white rounded-[3rem] border border-slate-100 overflow-hidden shadow-sm">
        <table className="w-full text-left">
          <thead>
            <tr className="bg-slate-50 border-b border-slate-100">
              <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Produto</th>
              <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Categoria</th>
              <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-center">Estoque</th>
              <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest">Preço</th>
              <th className="px-8 py-6 text-[10px] font-black text-slate-400 uppercase tracking-widest text-right">Ações</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-50">
            {productsList.map(prod => (
              <tr key={prod.id} className="group hover:bg-slate-50/50 transition-all">
                <td className="px-8 py-6">
                  <p className="font-black text-slate-900 text-sm">{prod.name}</p>
                  <p className="text-[10px] text-slate-400 font-bold uppercase">{prod.sku}</p>
                </td>
                <td className="px-8 py-6">
                  <span className="px-3 py-1 bg-slate-100 text-slate-500 rounded-lg text-[10px] font-black uppercase">{prod.category}</span>
                </td>
                <td className="px-8 py-6 text-center font-mono text-sm font-bold">{prod.stock}</td>
                <td className="px-8 py-6 font-black text-slate-900 text-sm">R$ {Number(prod.price).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</td>
                <td className="px-8 py-6 text-right">
                  <button onClick={() => { setEditingProduct(prod); setShowProductModal(true); }} className="text-indigo-600 font-black text-[10px] uppercase">Editar</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    </div>
  );

  const renderFiscal = () => (
    <div className="space-y-8 animate-in slide-in-from-right duration-500">
      <h3 className="text-3xl font-black text-slate-900 tracking-tight">Emissão NFC-e</h3>
      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-1 bg-white p-8 rounded-[3rem] border border-slate-100 shadow-sm">
           <h4 className="text-[10px] font-black uppercase text-slate-400 mb-6">Status Sefaz</h4>
           <div className="space-y-4">
              {SEFAZ_STATES.slice(0, 5).map(s => (
                <div key={s.state} className="flex justify-between items-center text-xs font-bold">
                  <span className="text-slate-900">{s.state}</span>
                  <span className={`px-2 py-0.5 rounded ${s.status === 'Online' ? 'bg-emerald-50 text-emerald-600' : 'bg-rose-50 text-rose-600'}`}>{s.status}</span>
                </div>
              ))}
           </div>
           {isCertifying && (
             <div className="mt-8 bg-slate-900 p-6 rounded-3xl text-white">
                <p className="text-[10px] font-black text-indigo-400 uppercase mb-4 animate-pulse">Sincronizando lote...</p>
                <div className="space-y-2 text-[9px] font-bold">
                  <div className={certPhase >= 1 ? 'text-emerald-400' : 'text-slate-600'}>1. Gerando XML</div>
                  <div className={certPhase >= 2 ? 'text-emerald-400' : 'text-slate-600'}>2. Assinando Digitalmente</div>
                  <div className={certPhase >= 3 ? 'text-emerald-400' : 'text-slate-600'}>3. Transmissão em Lote</div>
                </div>
             </div>
           )}
        </div>
        <div className="lg:col-span-2 bg-white rounded-[3.5rem] border border-slate-100 shadow-sm overflow-hidden">
           <div className="p-8 border-b border-slate-50 flex justify-between items-center">
             <h4 className="text-xs font-black uppercase text-slate-900">Fila de Emissão</h4>
           </div>
           <div className="divide-y divide-slate-50">
             {transactions.map(tx => (
               <div key={tx.id} className="p-6 flex items-center justify-between">
                 <div>
                   <p className="text-sm font-black text-slate-900">R$ {tx.amount}</p>
                   <p className="text-[10px] text-slate-400 font-bold">{tx.id}</p>
                 </div>
                 {tx.fiscalNoteId ? (
                   <button onClick={() => setShowNoteModal(tx)} className="px-4 py-2 bg-emerald-50 text-emerald-600 rounded-xl font-black text-[9px] uppercase">Ver Nota</button>
                 ) : (
                   <button onClick={() => handleCertify(tx.id)} disabled={isCertifying} className="px-4 py-2 bg-indigo-600 text-white rounded-xl font-black text-[9px] uppercase disabled:opacity-50">Emitir NFC-e</button>
                 )}
               </div>
             ))}
           </div>
        </div>
      </div>
    </div>
  );

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} currentUser={currentUser} onLogout={() => {}} />
      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-24 bg-white/70 backdrop-blur-xl border-b border-slate-100 flex items-center justify-between px-12 sticky top-0 z-40">
          <h2 className="text-2xl font-black text-slate-900 tracking-tight leading-none uppercase">NexusTEF <span className="text-indigo-600">Pro</span></h2>
          <div className="flex items-center gap-4 bg-slate-50 p-2 pr-5 rounded-2xl border border-slate-100">
            <div className="w-12 h-12 bg-white rounded-xl flex items-center justify-center text-xl shadow-sm">👤</div>
            <div className="text-left">
              <p className="text-xs font-black text-slate-900 leading-none uppercase">Administrador</p>
              <p className="text-[9px] font-bold text-indigo-500 uppercase tracking-widest mt-1">Master</p>
            </div>
          </div>
        </header>

        <main className="p-12 max-w-[1500px] w-full mx-auto">
          {activeTab === 'dashboard' && (
            <div className="space-y-12">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
                <StatCard label="Faturamento" value={`R$ ${stats.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} icon="💰" color="bg-indigo-50" />
                <StatCard label="Taxa PIX" value={`${stats.pixPercent}%`} icon="⚡" color="bg-emerald-50" trend="12%" trendUp />
                <StatCard label="Produtos" value={productsList.length} icon="📦" color="bg-amber-50" />
                <StatCard label="Vendas Hoje" value={stats.txCount} icon="🔄" color="bg-slate-50" />
              </div>
              <FiscalMonitor states={SEFAZ_STATES} />
            </div>
          )}
          {activeTab === 'simulator' && renderSimulator()}
          {activeTab === 'products' && renderProducts()}
          {activeTab === 'fiscal' && renderFiscal()}
          {activeTab === 'establishment' && (
             <div className="max-w-4xl mx-auto space-y-8 animate-in slide-in-from-right duration-500">
                <h3 className="text-3xl font-black text-slate-900 tracking-tight">Dados da Empresa</h3>
                <form onSubmit={handleSaveEstablishment} className="bg-white p-12 rounded-[3.5rem] border border-slate-100 shadow-sm space-y-8">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div className="space-y-2 col-span-full"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Razão Social</label><input type="text" required value={establishment.razaoSocial} onChange={e => setEstablishment({...establishment, razaoSocial: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" /></div>
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">Nome Fantasia</label><input type="text" required value={establishment.nomeFantasia} onChange={e => setEstablishment({...establishment, nomeFantasia: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" /></div>
                    <div className="space-y-2"><label className="text-[10px] font-black text-slate-400 uppercase ml-1">CNPJ</label><input type="text" required value={establishment.cnpj} onChange={e => setEstablishment({...establishment, cnpj: e.target.value})} className="w-full bg-slate-50 border border-slate-100 rounded-2xl p-5 text-sm font-black outline-none" placeholder="00.000.000/0000-00" /></div>
                  </div>
                  <button type="submit" disabled={isSavingEstablishment} className="w-full py-5 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs tracking-widest">Salvar Empresa</button>
                </form>
             </div>
          )}
          {activeTab === 'certificates' && (
            <div className="space-y-8 animate-in slide-in-from-right duration-500">
              <div className="flex justify-between items-center">
                <h3 className="text-3xl font-black text-slate-900 tracking-tight">Certificados Digitais</h3>
                <button onClick={() => { setEditingCert({ alias: '', state: 'SP', type: 'A1', expirationDate: '' }); setShowCertModal(true); }} className="px-6 py-3 bg-indigo-600 text-white rounded-xl font-black text-xs uppercase">+ Novo Certificado</button>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                {certificates.map(c => (
                  <div key={c.id} className="bg-white p-6 rounded-[2rem] border border-slate-100 shadow-sm group hover:shadow-lg transition-all">
                    <div className="flex items-center gap-4 mb-4">
                      <div className="w-10 h-10 bg-slate-50 rounded-xl flex items-center justify-center text-xl">🔐</div>
                      <div>
                        <p className="font-black text-slate-900 leading-none">{c.alias}</p>
                        <p className="text-[9px] font-bold text-slate-400 uppercase tracking-widest mt-1">{c.state} • {c.type}</p>
                      </div>
                    </div>
                    <p className="text-[10px] font-black text-slate-400 uppercase">Expira em: {new Date(c.expirationDate).toLocaleDateString()}</p>
                  </div>
                ))}
              </div>
            </div>
          )}
          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}
        </main>
      </div>

      {/* Modals */}
      {showProductModal && editingProduct && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md z-[500] flex items-center justify-center p-6 animate-in zoom-in">
          <div className="bg-white p-12 rounded-[3.5rem] w-full max-w-lg shadow-2xl">
            <h3 className="text-2xl font-black text-slate-900 mb-8 uppercase">Produto</h3>
            <form onSubmit={handleSaveProduct} className="space-y-6">
              <input type="text" required placeholder="Nome" value={editingProduct.name} onChange={e => setEditingProduct({...editingProduct, name: e.target.value})} className="w-full bg-slate-50 p-5 rounded-2xl text-sm font-black outline-none" />
              <div className="grid grid-cols-2 gap-4">
                <input type="text" placeholder="SKU" value={editingProduct.sku} onChange={e => setEditingProduct({...editingProduct, sku: e.target.value})} className="w-full bg-slate-50 p-5 rounded-2xl text-sm font-black outline-none" />
                <input type="number" step="0.01" placeholder="Preço" value={editingProduct.price} onChange={e => setEditingProduct({...editingProduct, price: parseFloat(e.target.value)})} className="w-full bg-slate-50 p-5 rounded-2xl text-sm font-black outline-none" />
              </div>
              <div className="grid grid-cols-2 gap-4">
                <input type="text" placeholder="Categoria" value={editingProduct.category} onChange={e => setEditingProduct({...editingProduct, category: e.target.value})} className="w-full bg-slate-50 p-5 rounded-2xl text-sm font-black outline-none" />
                <input type="number" placeholder="Estoque" value={editingProduct.stock} onChange={e => setEditingProduct({...editingProduct, stock: parseInt(e.target.value)})} className="w-full bg-slate-50 p-5 rounded-2xl text-sm font-black outline-none" />
              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowProductModal(false)} className="flex-1 py-4 bg-slate-100 font-black text-xs uppercase">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase shadow-xl">Salvar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showPixModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-2xl z-[700] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[4rem] w-full max-w-md shadow-2xl text-center">
            <h3 className="text-2xl font-black mb-8">Pagamento PIX</h3>
            <div className="bg-slate-50 p-8 rounded-[3.5rem] mb-8 inline-block shadow-inner">
               <img src={showPixModal.pixQrCode} alt="PIX" className="w-48 h-48 mx-auto" />
            </div>
            <p className="text-4xl font-black text-slate-900 mb-8">R$ {Number(showPixModal.amount).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            <p className="text-xs font-bold text-emerald-500 uppercase animate-pulse">Aguardando confirmação do banco...</p>
            <button onClick={() => setShowPixModal(null)} className="mt-8 w-full py-4 text-slate-400 font-black text-[10px] uppercase">Cancelar Venda</button>
          </div>
        </div>
      )}

      {showSuccessModal && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-xl z-[600] flex items-center justify-center p-6 animate-in zoom-in">
           <div className="bg-white w-full max-w-sm rounded-[4rem] shadow-2xl p-12 text-center">
              <div className="w-24 h-24 bg-emerald-50 rounded-[2.5rem] flex items-center justify-center text-4xl mx-auto mb-8">✅</div>
              <h3 className="text-2xl font-black text-slate-900 mb-2">Venda Concluída!</h3>
              <p className="text-sm text-slate-400 font-medium mb-10">Pagamento autorizado pelo NexusTEF.</p>
              <button onClick={() => { handleCertify(showSuccessModal.id); setShowSuccessModal(null); setActiveTab('fiscal'); }} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl">Emitir NFC-e Agora</button>
              <button onClick={() => setShowSuccessModal(null)} className="mt-4 w-full py-4 text-slate-400 font-black text-[10px] uppercase">Fechar</button>
           </div>
        </div>
      )}

      {showNoteModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-md z-[500] flex items-center justify-center p-6">
           <div className="bg-white w-full max-w-sm rounded-[3.5rem] shadow-2xl overflow-hidden p-10">
              <div className="text-center font-mono text-[10px] space-y-2 border-b border-dashed pb-6 mb-6">
                 <p className="font-black text-sm uppercase">{establishment.nomeFantasia || 'NEXUS LOJA'}</p>
                 <p>{establishment.endereco}</p>
                 <p>CNPJ: {establishment.cnpj}</p>
              </div>
              <div className="font-mono text-[10px] space-y-4 mb-6">
                 <div className="flex justify-between font-black"><span>VENDA NEXUS {showNoteModal.id}</span><span>{showNoteModal.amount}</span></div>
                 <div className="flex justify-between border-t pt-2 font-black text-sm uppercase"><span>Total R$</span><span>{showNoteModal.amount}</span></div>
              </div>
              <div className="text-center space-y-4">
                 <img src={`https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=NFE-${showNoteModal.fiscalNoteId}`} className="w-32 h-32 mx-auto grayscale" />
                 <p className="text-[8px] font-black uppercase">Chave de Acesso: 3524 0100 0000 0000 0000 0000 0000 0000 0000</p>
                 <button onClick={() => window.print()} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs">Imprimir DANFE</button>
                 <button onClick={() => setShowNoteModal(null)} className="w-full text-slate-400 font-black text-[8px] uppercase">Fechar</button>
              </div>
           </div>
        </div>
      )}

      {showCardSimModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-2xl z-[700] flex items-center justify-center p-6 animate-in zoom-in">
           <div className="bg-white w-full max-w-sm rounded-[4rem] shadow-2xl overflow-hidden">
              <div className="bg-slate-900 p-8 text-center text-indigo-400 font-black text-xs uppercase tracking-[0.3em]">Pinpad Nexus V6</div>
              <div className="p-12">
                 {simStep === 'brand' && (
                    <div className="grid grid-cols-2 gap-4">
                       {['Visa', 'Mastercard', 'Elo', 'Amex'].map(brand => (
                          <button key={brand} onClick={() => { setSimData({...simData, brand}); setSimStep('method'); }} className="p-6 bg-slate-50 border rounded-3xl font-black text-slate-800 uppercase text-[10px] hover:bg-indigo-600 hover:text-white transition-all">{brand}</button>
                       ))}
                    </div>
                 )}
                 {simStep === 'method' && (
                    <div className="space-y-6">
                       <button onClick={() => simulateTransaction(PaymentMethod.DEBIT, { brand: simData.brand, installments: 1 })} className="w-full p-6 bg-indigo-600 text-white rounded-3xl font-black uppercase text-xs">Débito</button>
                       <button onClick={() => setSimStep('installments')} className="w-full p-6 bg-slate-50 rounded-3xl font-black uppercase text-xs">Crédito</button>
                    </div>
                 )}
                 {simStep === 'installments' && (
                    <div className="grid grid-cols-3 gap-3">
                       {[1, 2, 3, 4, 6, 12].map(n => (
                          <button key={n} onClick={() => simulateTransaction(PaymentMethod.CREDIT, { brand: simData.brand, installments: n })} className="p-4 bg-slate-50 border rounded-xl font-black text-slate-700 hover:bg-indigo-600 hover:text-white transition-all">{n}x</button>
                       ))}
                    </div>
                 )}
                 <button onClick={() => setShowCardSimModal(false)} className="w-full mt-8 py-3 text-slate-400 font-black text-[10px] uppercase">Cancelar</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

