              </div>
              <div className="flex gap-4 pt-4">
                <button type="button" onClick={() => setShowProductModal(false)} className="flex-1 py-4 bg-slate-100 font-black text-xs uppercase">Cancelar</button>
                <button type="submit" className="flex-1 py-4 bg-indigo-600 text-white rounded-2xl font-black text-xs uppercase shadow-xl">Salvar</button>
              </div>
            </form>
          </div>
        </div>
      )}

      {showPixModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-2xl z-[700] flex items-center justify-center p-6">
          <div className="bg-white p-12 rounded-[4rem] w-full max-w-md shadow-2xl text-center">
            <h3 className="text-2xl font-black mb-8">Pagamento PIX</h3>
            <div className="bg-slate-50 p-8 rounded-[3.5rem] mb-8 inline-block shadow-inner">
               <img src={showPixModal.pixQrCode} alt="PIX" className="w-48 h-48 mx-auto" />
            </div>
            <p className="text-4xl font-black text-slate-900 mb-8">R$ {Number(showPixModal.amount).toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
            <p className="text-xs font-bold text-emerald-500 uppercase animate-pulse">Aguardando confirmação do banco...</p>
            <button onClick={() => setShowPixModal(null)} className="mt-8 w-full py-4 text-slate-400 font-black text-[10px] uppercase">Cancelar Venda</button>
          </div>
        </div>
      )}

      {showSuccessModal && (
        <div className="fixed inset-0 bg-slate-900/90 backdrop-blur-xl z-[600] flex items-center justify-center p-6 animate-in zoom-in">
           <div className="bg-white w-full max-w-sm rounded-[4rem] shadow-2xl p-12 text-center">
              <div className="w-24 h-24 bg-emerald-50 rounded-[2.5rem] flex items-center justify-center text-4xl mx-auto mb-8">✅</div>
              <h3 className="text-2xl font-black text-slate-900 mb-2">Venda Concluída!</h3>
              <p className="text-sm text-slate-400 font-medium mb-10">Pagamento autorizado pelo NexusTEF.</p>
              <button onClick={() => { handleCertify(showSuccessModal.id); setShowSuccessModal(null); setActiveTab('fiscal'); }} className="w-full py-5 bg-indigo-600 text-white rounded-2xl font-black uppercase text-xs tracking-widest shadow-xl">Emitir NFC-e Agora</button>
              <button onClick={() => setShowSuccessModal(null)} className="mt-4 w-full py-4 text-slate-400 font-black text-[10px] uppercase">Fechar</button>
           </div>
        </div>
      )}

      {showNoteModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-md z-[500] flex items-center justify-center p-6">
           <div className="bg-white w-full max-w-sm rounded-[3.5rem] shadow-2xl overflow-hidden p-10">
              <div className="text-center font-mono text-[10px] space-y-2 border-b border-dashed pb-6 mb-6">
                 <p className="font-black text-sm uppercase">{establishment.nomeFantasia || 'NEXUS LOJA'}</p>
                 <p>{establishment.endereco}</p>
                 <p>CNPJ: {establishment.cnpj}</p>
              </div>
              <div className="font-mono text-[10px] space-y-4 mb-6">
                 <div className="flex justify-between font-black"><span>VENDA NEXUS {showNoteModal.id}</span><span>{showNoteModal.amount}</span></div>
                 <div className="flex justify-between border-t pt-2 font-black text-sm uppercase"><span>Total R$</span><span>{showNoteModal.amount}</span></div>
              </div>
              <div className="text-center space-y-4">
                 <img src={`https://api.qrserver.com/v1/create-qr-code/?size=150x150&data=NFE-${showNoteModal.fiscalNoteId}`} className="w-32 h-32 mx-auto grayscale" />
                 <p className="text-[8px] font-black uppercase">Chave de Acesso: 3524 0100 0000 0000 0000 0000 0000 0000 0000</p>
                 <button onClick={() => window.print()} className="w-full py-4 bg-slate-900 text-white rounded-2xl font-black uppercase text-xs">Imprimir DANFE</button>
                 <button onClick={() => setShowNoteModal(null)} className="w-full text-slate-400 font-black text-[8px] uppercase">Fechar</button>
              </div>
           </div>
        </div>
      )}

      {showCardSimModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-2xl z-[700] flex items-center justify-center p-6 animate-in zoom-in">
           <div className="bg-white w-full max-w-sm rounded-[4rem] shadow-2xl overflow-hidden">
              <div className="bg-slate-900 p-8 text-center text-indigo-400 font-black text-xs uppercase tracking-[0.3em]">Pinpad Nexus V6</div>
              <div className="p-12">
                 {simStep === 'brand' && (
                    <div className="grid grid-cols-2 gap-4">
                       {['Visa', 'Mastercard', 'Elo', 'Amex'].map(brand => (
                          <button key={brand} onClick={() => { setSimData({...simData, brand}); setSimStep('method'); }} className="p-6 bg-slate-50 border rounded-3xl font-black text-slate-800 uppercase text-[10px] hover:bg-indigo-600 hover:text-white transition-all">{brand}</button>
                       ))}
                    </div>
                 )}
                 {simStep === 'method' && (
                    <div className="space-y-6">
                       <button onClick={() => simulateTransaction(PaymentMethod.DEBIT, { brand: simData.brand, installments: 1 })} className="w-full p-6 bg-indigo-600 text-white rounded-3xl font-black uppercase text-xs">Débito</button>
                       <button onClick={() => setSimStep('installments')} className="w-full p-6 bg-slate-50 rounded-3xl font-black uppercase text-xs">Crédito</button>
                    </div>
                 )}
                 {simStep === 'installments' && (
                    <div className="grid grid-cols-3 gap-3">
                       {[1, 2, 3, 4, 6, 12].map(n => (
                          <button key={n} onClick={() => simulateTransaction(PaymentMethod.CREDIT, { brand: simData.brand, installments: n })} className="p-4 bg-slate-50 border rounded-xl font-black text-slate-700 hover:bg-indigo-600 hover:text-white transition-all">{n}x</button>
                       ))}
                    </div>
                 )}
                 <button onClick={() => setShowCardSimModal(false)} className="w-full mt-8 py-3 text-slate-400 font-black text-[10px] uppercase">Cancelar</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;

export enum PaymentStatus {
  SUCCESS = 'SUCCESS',
  PENDING = 'PENDING',
  FAILED = 'FAILED',
  REFUNDED = 'REFUNDED'
}

export enum PaymentMethod {
  CREDIT = 'Crédito',
  DEBIT = 'Débito',
  PIX = 'PIX',
  VOUCHER = 'Voucher'
}

export enum FiscalStatus {
  AUTHORIZED = 'Autorizada',
  REJECTED = 'Rejeitada',
  CONTINGENCY = 'Contingência',
  CANCELED = 'Cancelada'
}

export enum UserRole {
  MASTER = 'MASTER',
  ADMIN = 'ADMIN',
  OPERATOR = 'OPERATOR'
}

export interface BankAccount {
  id: number;
  bank_name: string;
  account_type: string;
  balance: number;
  last_sync: string;
  is_active: boolean;
}

export interface User {
  id: number;
  name: string;
  username: string;
  role: UserRole;
  created_at?: string;
}

export interface Product {
  id: number;
  name: string;
  sku: string;
  price: number;
  category: string;
  stock: number;
  created_at?: string;
}

export interface Transaction {
  id: string;
  timestamp: string;
  amount: number;
  method: PaymentMethod;
  status: PaymentStatus;
  terminalId: string;
  segment: string;
  fiscalNoteId?: string;
  fiscalStatus?: FiscalStatus;
  pixQrCode?: string;
  pixCopyPaste?: string;
  cardBrand?: string;
  installments?: number;
}

export interface DigitalCertificate {
  id: string;
  alias: string;
  expirationDate: string;
  state: string;
  status: 'Ativo' | 'Expirado' | 'Alerta';
  type: 'A1' | 'A3';
}

export interface SefazStatus {
  state: string;
  status: 'Online' | 'Offline' | 'Instável';
}

export interface FiscalConfig {
  cnpj: string;
  ie: string;
  razaoSocial: string;
  cscToken: string;
  cscId: string;
  ambiente: 'Produção' | 'Homologação';
  serie: string;
  ultimoNumero: number;
  contingencia: boolean;
}

export interface Establishment {
  razaoSocial: string;
  nomeFantasia: string;
  cnpj: string;
  endereco: string;
  telefone: string;
  email: string;
}

import React, { useState, useEffect, useMemo } from 'react';
import Sidebar from './components/Sidebar';
import StatCard from './components/StatCard';
import TransactionTable from './components/TransactionTable';
import FiscalMonitor from './components/FiscalMonitor';
import { SEFAZ_STATES, ALL_UFS } from './constants';
import { PaymentMethod, PaymentStatus, Transaction, FiscalStatus, DigitalCertificate, User, UserRole, BankAccount, Product, Establishment } from './types';
import { getSmartInsights } from './services/geminiService';

const API_URL = 'api.php';

const App: React.FC = () => {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [transactions, setTransactions] = useState<Transaction[]>([]);
  const [bankAccounts, setBankAccounts] = useState<BankAccount[]>([]);
  const [certificates, setCertificates] = useState<DigitalCertificate[]>([]);
  const [productsList, setProductsList] = useState<Product[]>([]);
  const [establishment, setEstablishment] = useState<Establishment>({
    razaoSocial: '', nomeFantasia: '', cnpj: '', endereco: '', telefone: '', email: ''
  });

  const [isSimulating, setIsSimulating] = useState(false);
  const [showPixModal, setShowPixModal] = useState<Transaction | null>(null);
  const [showSuccessModal, setShowSuccessModal] = useState<Transaction | null>(null);
  const [showCardSimModal, setShowCardSimModal] = useState(false);
  const [simStep, setSimStep] = useState<'brand' | 'method' | 'installments'>('brand');
  const [simData, setSimData] = useState({ brand: '', method: PaymentMethod.CREDIT, installments: 1 });
  const [isCertifying, setIsCertifying] = useState(false);
  const [certPhase, setCertPhase] = useState(0);
  const [selectedUf, setSelectedUf] = useState('MT');
  const [activeCertId, setActiveCertId] = useState<string | null>(null);

  const safeFetch = async (url: string, options?: RequestInit) => {
    try {
      const response = await fetch(url, options);
      if (!response.ok) throw new Error(`HTTP ${response.status}`);
      return await response.json();
    } catch (e) {
      console.warn("API Error:", e);
      return [];
    }
  };

  const loadData = async () => {
    const [txData, certData, bankData, prodData, estData] = await Promise.all([
      safeFetch(`${API_URL}?action=get_transactions`),
      safeFetch(`${API_URL}?action=get_certificates`),
      safeFetch(`${API_URL}?action=get_bank_accounts`),
      safeFetch(`${API_URL}?action=get_products`),
      safeFetch(`${API_URL}?action=get_establishment`)
    ]);

    if (Array.isArray(txData)) setTransactions(txData);
    if (Array.isArray(bankData)) setBankAccounts(bankData);
    if (Array.isArray(prodData)) setProductsList(prodData);
    if (Array.isArray(certData)) {
      setCertificates(certData);
      const mtCert = certData.find(c => c.state === 'MT');
      if (mtCert) { setActiveCertId(mtCert.id); setSelectedUf('MT'); }
    }
    if (estData && !estData.status) setEstablishment(estData);
  };

  useEffect(() => { loadData(); }, []);

  const saveTransaction = async (tx: Transaction) => {
    await fetch(`${API_URL}?action=save_transaction`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(tx)
    });
    loadData();
  };

  const simulateTransaction = async (method: PaymentMethod, details?: { brand: string, installments: number }) => {
    setIsSimulating(true);
    const amount = Number((Math.random() * 500 + 10).toFixed(2));
    const txId = `TX-${Math.floor(Math.random() * 900000 + 100000)}`;

    const baseTx: Transaction = {
      id: txId,
      timestamp: new Date().toISOString(),
      amount: amount,
      method: method,
      status: PaymentStatus.PENDING,
      terminalId: 'TERM-NEXUS-V6',
      segment: establishment.nomeFantasia || 'Varejo Pro',
      cardBrand: details?.brand,
      installments: details?.installments || 1
    };

    if (method === PaymentMethod.PIX) {
      const pixTx = { ...baseTx, pixQrCode: `https://api.qrserver.com/v1/create-qr-code/?size=300x300&data=PIX-${txId}` };
      setShowPixModal(pixTx);
      setIsSimulating(false);
      setTimeout(() => {
        const successTx = { ...pixTx, status: PaymentStatus.SUCCESS };
        saveTransaction(successTx);
        setShowPixModal(null);
        setShowSuccessModal(successTx);
      }, 3000);
    } else {
      await new Promise(r => setTimeout(r, 2000)); // Simulando processamento adquirente
      const successTx = { ...baseTx, status: PaymentStatus.SUCCESS };
      saveTransaction(successTx);
      setIsSimulating(false);
      setShowCardSimModal(false);
      setShowSuccessModal(successTx);
    }
  };

  const handleCertify = async (txId: string) => {
    if (!activeCertId) return alert('Selecione um certificado válido.');
    setIsCertifying(true);
    for (let i = 1; i <= 3; i++) { setCertPhase(i); await new Promise(r => setTimeout(r, 600)); }
    const res = await safeFetch(`${API_URL}?action=certify_transaction`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ txId, certId: activeCertId, uf: selectedUf })
    });
    if (res.status === 'success') loadData();
    setIsCertifying(false);
    setCertPhase(0);
  };

  const totalBankBalance = useMemo(() => bankAccounts.reduce((acc, curr) => acc + Number(curr.balance), 0), [bankAccounts]);
  const stats = useMemo(() => {
    const success = transactions.filter(t => t.status === PaymentStatus.SUCCESS);
    return {
      total: success.reduce((a, b) => a + Number(b.amount), 0),
      count: success.length
    };
  }, [transactions]);

  return (
    <div className="min-h-screen flex bg-[#f8fafc]">
      <Sidebar activeTab={activeTab} setActiveTab={setActiveTab} currentUser={null} onLogout={() => {}} />
      <div className="flex-1 md:ml-64 flex flex-col min-w-0">
        <header className="h-24 bg-white/70 backdrop-blur-xl border-b border-slate-100 flex items-center justify-between px-12 sticky top-0 z-40">
          <div className="flex flex-col">
            <h2 className="text-2xl font-black text-slate-900 tracking-tight leading-none uppercase">NexusTEF <span className="text-indigo-600">Enterprise</span></h2>
            <span className="text-[10px] font-bold text-slate-400 uppercase tracking-[0.3em] mt-2">V6.0 • Multi-Bank Connected</span>
          </div>
          <div className="flex items-center gap-6">
             <div className="text-right">
                <p className="text-[10px] font-black text-slate-400 uppercase">Saldo Consolidado</p>
                <p className="text-lg font-black text-emerald-600">R$ {totalBankBalance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
             </div>
             <div className="w-px h-10 bg-slate-100"></div>
             <div className="flex items-center gap-3 bg-indigo-50 p-2 pr-4 rounded-2xl border border-indigo-100">
                <div className="w-10 h-10 bg-white rounded-xl flex items-center justify-center text-lg shadow-sm">👑</div>
                <div className="text-left">
                  <p className="text-xs font-black text-indigo-900 leading-none">MASTER</p>
                </div>
             </div>
          </div>
        </header>

        <main className="p-12 max-w-[1500px] w-full mx-auto">
          {activeTab === 'dashboard' && (
            <div className="space-y-12">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-8">
                <StatCard label="Total em Vendas" value={`R$ ${stats.total.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} icon="💰" color="bg-indigo-50" />
                <StatCard label="Disponível Bancos" value={`R$ ${totalBankBalance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} icon="🏦" color="bg-emerald-50" />
                <StatCard label="Pendências Fiscal" value={transactions.filter(t => !t.fiscalNoteId).length} icon="📝" color="bg-rose-50" />
                <StatCard label="Contas Integradas" value={bankAccounts.length} icon="🔗" color="bg-amber-50" />
              </div>
              <FiscalMonitor states={SEFAZ_STATES} />
            </div>
          )}

          {activeTab === 'simulator' && (
            <div className="space-y-8 animate-in slide-in-from-bottom duration-500">
              <h3 className="text-3xl font-black text-slate-900 tracking-tight">Terminal de Vendas</h3>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <button onClick={() => simulateTransaction(PaymentMethod.PIX)} className="bg-white p-12 rounded-[3.5rem] border border-slate-100 shadow-sm hover:shadow-2xl transition-all group">
                  <div className="text-5xl mb-6 bg-emerald-50 w-20 h-20 flex items-center justify-center rounded-[2rem] mx-auto group-hover:rotate-12 transition-transform">⚡</div>
                  <h4 className="text-2xl font-black text-slate-900">Venda PIX</h4>
                  <p className="text-sm text-slate-400 mt-2">Liquidação imediata com QR Code dinâmico.</p>
                </button>
                <button onClick={() => { setSimStep('brand'); setShowCardSimModal(true); }} className="bg-white p-12 rounded-[3.5rem] border border-slate-100 shadow-sm hover:shadow-2xl transition-all group">
                  <div className="text-5xl mb-6 bg-indigo-50 w-20 h-20 flex items-center justify-center rounded-[2rem] mx-auto group-hover:-rotate-12 transition-transform">💳</div>
                  <h4 className="text-2xl font-black text-slate-900">Cartão de Crédito/Débito</h4>
                  <p className="text-sm text-slate-400 mt-2">Simular conexão com Pinpad e Adquirentes.</p>
                </button>
              </div>
            </div>
          )}

          {activeTab === 'fiscal' && (
            <div className="space-y-8">
               <div className="bg-slate-900 p-12 rounded-[4rem] text-white flex justify-between items-center shadow-2xl">
                  <div className="max-w-md">
                     <h3 className="text-3xl font-black mb-4">Módulo Sefaz MT</h3>
                     <p className="text-indigo-300 text-sm">O sistema está configurado para emitir NFC-e em Mato Grosso com prioridade máxima.</p>
                  </div>
                  <div className="bg-white/10 p-6 rounded-3xl border border-white/10">
                     <p className="text-[10px] font-black uppercase text-indigo-400 mb-2">Estado Ativo</p>
                     <select value={selectedUf} onChange={e => setSelectedUf(e.target.value)} className="bg-transparent text-xl font-black outline-none cursor-pointer">
                        {ALL_UFS.map(uf => <option key={uf} value={uf} className="bg-slate-900">{uf}</option>)}
                     </select>
                  </div>
               </div>
               <TransactionTable transactions={transactions} />
            </div>
          )}

          {activeTab === 'transactions' && <TransactionTable transactions={transactions} />}
        </main>
      </div>

      {/* PIX Modal */}
      {showPixModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-2xl z-[1000] flex items-center justify-center p-6">
           <div className="bg-white p-12 rounded-[5rem] w-full max-w-md shadow-2xl text-center animate-in zoom-in duration-300">
              <h3 className="text-2xl font-black mb-8 text-slate-900">Aguardando PIX...</h3>
              <div className="bg-slate-50 p-10 rounded-[4rem] mb-10 shadow-inner">
                 <img src={showPixModal.pixQrCode} className="w-56 h-56 mx-auto" alt="QR" />
              </div>
              <p className="text-5xl font-black text-slate-900 mb-4">R$ {showPixModal.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</p>
              <div className="flex items-center justify-center gap-2 text-emerald-500 font-black text-xs uppercase animate-pulse">
                 <div className="w-2 h-2 rounded-full bg-emerald-500"></div>
                 Status: Aguardando Pagador
              </div>
           </div>
        </div>
      )}

      {/* Success Modal */}
      {showSuccessModal && (
        <div className="fixed inset-0 bg-emerald-950/40 backdrop-blur-3xl z-[1100] flex items-center justify-center p-6">
           <div className="bg-white p-12 rounded-[5rem] w-full max-w-sm text-center shadow-2xl animate-in bounce-in duration-500">
              <div className="w-24 h-24 bg-emerald-50 rounded-[3rem] flex items-center justify-center text-5xl mx-auto mb-8 shadow-inner">✨</div>
              <h4 className="text-2xl font-black text-slate-900 mb-2">Sucesso!</h4>
              <p className="text-sm text-slate-400 mb-10">Venda autorizada e gravada com sucesso no NexusTEF.</p>
              <button onClick={() => { handleCertify(showSuccessModal.id); setShowSuccessModal(null); setActiveTab('fiscal'); }} className="w-full py-6 bg-indigo-600 text-white rounded-3xl font-black uppercase text-xs tracking-widest hover:bg-slate-900 transition-all shadow-xl">Emitir Fiscal Agora</button>
              <button onClick={() => setShowSuccessModal(null)} className="mt-4 text-[10px] font-black text-slate-400 uppercase">Fechar</button>
           </div>
        </div>
      )}

      {/* Card Simulator Modal */}
      {showCardSimModal && (
        <div className="fixed inset-0 bg-slate-900/95 backdrop-blur-2xl z-[1000] flex items-center justify-center p-6 animate-in zoom-in">
           <div className="bg-white w-full max-w-sm rounded-[4rem] shadow-2xl overflow-hidden">
              <div className="bg-slate-900 p-8 text-center text-indigo-400 font-black text-xs uppercase tracking-[0.3em] border-b border-indigo-500/20">Nexus V6 Pinpad</div>
              <div className="p-12">
                 {simStep === 'brand' && (
                    <div className="grid grid-cols-2 gap-4">
                       {['Visa', 'Mastercard', 'Elo', 'Amex'].map(brand => (
                          <button key={brand} onClick={() => { setSimData({...simData, brand}); setSimStep('method'); }} className="p-6 bg-slate-50 border border-slate-100 rounded-3xl font-black text-slate-800 uppercase text-[10px] hover:bg-indigo-600 hover:text-white transition-all shadow-sm">{brand}</button>
                       ))}
                    </div>
                 )}
                 {simStep === 'method' && (
                    <div className="space-y-4">
                       <button onClick={() => simulateTransaction(PaymentMethod.DEBIT, { brand: simData.brand, installments: 1 })} className="w-full py-6 bg-indigo-600 text-white rounded-3xl font-black uppercase text-xs shadow-xl">Débito</button>
                       <button onClick={() => setSimStep('installments')} className="w-full py-6 bg-slate-50 text-slate-900 rounded-3xl font-black uppercase text-xs border border-slate-100">Crédito</button>
                    </div>
                 )}
                 {simStep === 'installments' && (
                    <div className="grid grid-cols-3 gap-3">
                       {[1, 2, 3, 4, 6, 12].map(n => (
                          <button key={n} onClick={() => simulateTransaction(PaymentMethod.CREDIT, { brand: simData.brand, installments: n })} className="p-4 bg-slate-50 border rounded-xl font-black text-slate-700 hover:bg-indigo-600 hover:text-white transition-all">{n}x</button>
                       ))}
                    </div>
                 )}
                 <button onClick={() => setShowCardSimModal(false)} className="w-full mt-10 py-3 text-slate-400 font-black text-[10px] uppercase">Cancelar Operação</button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { User } from '../types';

interface SidebarProps {
  activeTab: string;
  setActiveTab: (tab: string) => void;
  currentUser: User | null;
  onLogout: () => void;
}

